INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500001,4,'和差倍比问题','某高校机械学院有甲、乙、丙三个专业，学生人数之比是8:7:5。已知

该学院三个专业学生的男女总人数之比是3:1,甲、乙两个专业学生的男女人
数之比分别是7:3和6:1,则丙专业学生的男女人数之比是?','[{"label":"A","content":"7:2"},{"label":"B","content":"4:1"},{"label":"C","content":"15:4"},{"label":"D","content":"17:8"}]','D','本题可采用赋值法⑨,根据甲乙丙人数之比，可赋值人数分别为80人、70人、50人，总数为200人，其中男生共有150人、女生共有50人；
根据甲专业男女人数比为7:3,可得甲专业男生为56人，女生为24人；
根据乙专业男女人数比为6:1,可得乙专业男生为60人，女生为10人；
则丙专业男女人数比=(150-56-60):(50-24-10)=34:16=17:8,答案为 D 选项。','数量关系600题','进阶','published','{"globalNumber":1,"sourceNumber":1,"typeLabel":"和差倍比问题","stemRich":[{"text":"某高校机械学院有甲、乙、丙三个专业，学生人数之比是8:7:5。已知\n\n该学院三个专业学生的男女总人数之比是3:1,甲、乙两个专业学生的男女人\n数之比分别是7:3和6:1,则丙专业学生的男女人数之比是?"}],"annotatedStemRich":[{"text":"某高校机械学院有甲、乙、丙三个专业，学生人数之比是8:7:5。已知\n\n该学院三个专业学生的男女总人数之比是3:1,甲、乙两个专业学生的男女人\n数之比分别是7:3和6:1,则丙专业学生的男女人数之比是?"}],"annotatedOptionRich":{"A":[{"text":"7:2"}],"B":[{"text":"4:1"}],"C":[{"text":"15:4"}],"D":[{"text":"17:8\n"}]},"practicalAnalysis":"本题可采用赋值法⑨,根据甲乙丙人数之比，可赋值人数分别为80人、70人、50人，总数为200人，其中男生共有150人、女生共有50人；\n根据甲专业男女人数比为7:3,可得甲专业男生为56人，女生为24人；\n根据乙专业男女人数比为6:1,可得乙专业男生为60人，女生为10人；\n则丙专业男女人数比=(150-56-60):(50-24-10)=34:16=17:8,答案为 D 选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500002,4,'工程问题','市社保中心引进机器人提高服务效率。某岗位小张、小王和小李完结一单任务分别需要6分钟、5分钟和4分钟，3人一天最多可完结259单。机器人处理一单仅需2分钟，处理工单中的80%可正常完结，剩余20%仍需人工重新办理。若某天小张出差，则当天小王、小李和机器人(机器人与人的工作时间相同)最多可完结的工单总量为多少?','[{"label":"A","content":"357 单"},{"label":"B","content":"399 单"},{"label":"C","content":"427 单"},{"label":"D","content":"469 单\n①"}]','A','由“某岗位小张、小王和小李完结一单任务分别需要6分钟、 5分钟和4分钟”,可知，小张、小王和小李每小时完结任务的单数分别为10单、 12单和15单；
由“3人一天最多可完结259单”,可得一天的工作时间=259÷(10+12+15)=7 小时。
已知机器人每小时可处理60÷2=30单，处理工单中的80%可正常完结，剩余20%仍需人工重新办理，即机器人每小时可处理30×80%=24单；
即小王、小李和机器人一天可完结的工单量=(12+15+24)×7=357单② ,答案为A 选项。

②花生批注：
只需考虑机器人正常完结
工单，和小王小李每日完
结工单数即可，小王小李
是否帮助机器人处理工单，不影响三者总量。','数量关系600题','进阶','published','{"globalNumber":2,"sourceNumber":2,"typeLabel":"工程问题","stemRich":[{"text":"市社保中心引进机器人提高服务效率。某岗位小张、小王和小李完结一单 任务分别需要6分钟、5分钟和4分钟，3人一天最多可完结259单。机器人 处理一单仅需2分钟，处理工单中的80%可正常完结，剩余20%仍需人工重新 办理。若某天小张出差，则当天小王、小李和机器人(机器人与人的工作时间 相同)最多可完结的工单总量为多少?"}],"annotatedStemRich":[{"text":"市社保中心引进机器人提高服务效率。某岗位小张、小王和小李完结一单 任务分别需要6分钟、5分钟和4分钟，3人一天最多可完结259单。机器人 处理一单仅需2分钟，处理工单中的80%可正常完结，剩余20%仍需人工重新 办理。若某天小张出差，则当天小王、小李和机器人(机器人与人的工作时间 相同)最多可完结的工单总量为多少?"}],"annotatedOptionRich":{"A":[{"text":" 357 单"}],"B":[{"text":"  399 单"}],"C":[{"text":"  427 单"}],"D":[{"text":"  469 单\n①花生批注：\n"},{"text":"赋值法常用使用时机：","bold":true},{"text":"\n①题目中只有比例关系， 无具体数字；\n②符合 的关系 ，\n给出A的数字，B、C可赋值；\n③解不定方程时的赋零法： 若求的是A+B+C 的和，\n可设某个未知数为0,\n再求出另外两个未知数， 和不变；\n④对于恒等关系或恒成立 其他关系，可赋值用特殊 情况判断正误；\n⑤对于几何问题，若所求 为长度、面积、体积等的 比值，可采用赋值法。\n本题属于第①种情况。\n数量关系600\n②花生批注：\n只需考虑机器人正常完结\n"},{"text":"工单，和小王小李每日完","bold":true},{"text":"\n结工单数即可，小王小李\n"},{"text":"是否帮助机器人处理工单，","bold":true},{"text":" "},{"text":"不影响三者总量。","bold":true},{"text":"\n③花生批注：\n虽然二者运动方式不同， 但同时出发同时到达，\n即二者平均速度相同。\n④花生批注：\n匀变速运动速度常用公式：\nV=V₀+at,\nV₀为初始速度，a 为加速度。\n本题也可求得a,\n 则11:00速 度=V₀+at=1+1×3=4。\n"}]},"practicalAnalysis":"由“某岗位小张、小王和小李完结一单任务分别需要6分钟、 5分钟和4分钟”,可知，小张、小王和小李每小时完结任务的单数分别为10单、 12单和15单；\n由“3人一天最多可完结259单”,可得一天的工作时间=259÷(10+12+15)=7 小时。\n已知机器人每小时可处理60÷2=30单，处理工单中的80%可正常完结，剩余20%仍需人工重新办理，即机器人每小时可处理30×80%=24单；\n即小王、小李和机器人一天可完结的工单量=(12+15+24)×7=357单② ,答案为A 选项。","notes":[{"marker":"②","text":"只需考虑机器人正常完结\n工单，和小王小李每日完\n结工单数即可，小王小李\n是否帮助机器人处理工单，不影响三者总量。","matchScore":0.169}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500003,4,'行程问题之匀变速运动','甲和乙两人8:00同时从A地出发前往B地，其中乙全程匀速，甲出发时
的速度是乙的一半，但全程均匀加速。已知10:00甲追上乙，11:00甲到达B地。

问乙什么时间到达B地?','[{"label":"A","content":"11: 30"},{"label":"B","content":"11:45"},{"label":"C","content":"12:00"},{"label":"D","content":"12: 15"}]','B','本题可采用赋值法，根据“甲出发时的速度是乙的一半”, 赋值甲出发时速度为1,乙速度为2。
根据“甲和乙两人8:00同时从A地出发前往B 地，10:00甲追上乙”,可知8:00到10:00,甲乙平均速度相等，都为2⁹ ;
可求出甲的末速度(10:00时的
速度)=2×2- 1=3;甲从8:00的速度1加速到10:00的速度3,按此速度， 11:00甲的速度应为4④,即甲走完全程的平均速度=2 .5,全程距离 =2.5×3=7.5;
则乙全程耗时=7.5÷2=3.75小时，11:45到达，答案为B 选项。

④花生批注：
匀变速运动速度常用公式：
V=V₀+at,
V₀为初始速度，a 为加速度。
本题也可求得a,
则11:00速度=V₀+at=1+1×3=4。','数量关系600题','进阶','published','{"globalNumber":3,"sourceNumber":3,"typeLabel":"行程问题之匀变速运动","stemRich":[{"text":"甲和乙两人8:00同时从A地出发前往B地，其中乙全程匀速，甲出发时\n的速度是乙的一半，但全程均匀加速。已知10:00甲追上乙，11:00甲到达B地。\n\n问乙什么时间到达B地?"}],"annotatedStemRich":[{"text":"甲和乙两人8:00同时从A地出发前往B地，其中乙全程匀速，甲出发时\n的速度是乙的一半，但全程均匀加速。已知10:00甲追上乙，11:00甲到达B地。\n\n问乙什么时间到达B地?"}],"annotatedOptionRich":{"A":[{"text":"   "},{"text":"11: ","bold":true},{"text":"30"}],"B":[{"text":"11:45"}],"C":[{"text":"12:00"}],"D":[{"text":"   "},{"text":"12: ","bold":true},{"text":"15\n"}]},"practicalAnalysis":"本题可采用赋值法，根据“甲出发时的速度是乙的一半”, 赋值甲出发时速度为1,乙速度为2。\n根据“甲和乙两人8:00同时从A地出发前往B 地，10:00甲追上乙”,可知8:00到10:00,甲乙平均速度相等，都为2⁹ ;\n可求出甲的末速度(10:00时的\n速度)=2×2- 1=3;甲从8:00的速度1加速到10:00的速度3,按此速度， 11:00甲的速度应为4④,即甲走完全程的平均速度=2 .5,全程距离 =2.5×3=7.5;\n则乙全程耗时=7.5÷2=3.75小时，11:45到达，答案为B 选项。","notes":[{"marker":"④","text":"匀变速运动速度常用公式：\nV=V₀+at,\nV₀为初始速度，a 为加速度。\n本题也可求得a,\n则11:00速度=V₀+at=1+1×3=4。","matchScore":0.082}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500004,4,'几何问题','一块梯形空地ABCD如图所示，点E、G和F、H分别为所在边的三等分点，
