INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500005,4,'概率问题之条件概率','销售员小刘为客户准备了A、B、C三个方案。已知客户接受方案A的概率
为40%。如果接受方案A, 则接受方案B的概率为60%,反之为30%。客户如果

A或 B方案都不接受，则接受C方案的概率为90%,反之为10%。问将3个方案
按照客户接受概率从高到低排列，以下正确的是哪个?','[{"label":"A","content":"A>B>C"},{"label":"B","content":"A>C>B"},{"label":"C","content":"B>C>A"},{"label":"D","content":"C>B>A"}]','D','根据题意可知客户接受A 方案的概率为40%。
接受B方案有两种情况：①接受A 方案的前提下接受B 方案概率 =40%×60%=24%; ②不接受A 方案的前提下接受B方案概率=(1-40%)×30%=18%, 则接受B 方案的概率=18%+24%=42%。
⑤

⑤花生批注：
不接受A 方案的概率为
1-40%;
在此前提下，不接受B方案
的概率=(1-40%)×(1-30%)。

⑥花生批注：
同时不接受A、B方案的概率为42%,则至少接受一个的概率为1-42%。
接受C 方案有两种情况：①不接受A、B方案的前提下接受C 方案的概率 =(1-40%)×(1-30%)×90% ⑤=42%×90%=37.8%;② A、B 方案至少接受一个的前提下接受C 方案的概率=(1-42%)⑥×10%=5.8%。则接受C 方案的概率 =37.8%+5.8%=43.6%。
综上，概率从高到底排列为C>B>A, 答案为D 选项。','数量关系600题','进阶','published','{"globalNumber":5,"sourceNumber":5,"typeLabel":"概率问题之条件概率","stemRich":[{"text":"销售员小刘为客户准备了A、B、C三个方案。已知客户接受方案A的概率\n为40%。如果接受方案A, 则接受方案B的概率为60%,反之为30%。客户如果\n\nA或 B方案都不接受，则接受C方案的概率为90%,反之为10%。问将3个方案\n按照客户接受概率从高到低排列，以下正确的是哪个?"}],"annotatedStemRich":[{"text":"销售员小刘为客户准备了A、B、C三个方案。已知客户接受方案A的概率\n为40%。如果接受方案A, 则接受方案B的概率为60%,反之为30%。客户如果\n\nA或 B方案都不接受，则接受C方案的概率为90%,反之为10%。问将3个方案\n按照客户接受概率从高到低排列，以下正确的是哪个?"}],"annotatedOptionRich":{"A":[{"text":"A>B>C"}],"B":[{"text":"A>C>B"}],"C":[{"text":"B>C>A","bold":true}],"D":[{"text":"C>B>A","bold":true},{"text":"\n"}]},"practicalAnalysis":"根据题意可知客户接受A 方案的概率为40%。\n接受B方案有两种情况：①接受A 方案的前提下接受B 方案概率 =40%×60%=24%; ②不接受A 方案的前提下接受B方案概率=(1-40%)×30%=18%, 则接受B 方案的概率=18%+24%=42%。\n⑤","notes":[{"marker":"⑤","text":"不接受A 方案的概率为\n1-40%;\n在此前提下，不接受B方案\n的概率=(1-40%)×(1-30%)。","matchScore":0.268},{"marker":"⑥","text":"同时不接受A、B方案的概率为42%,则至少接受一个的概率为1-42%。\n接受C 方案有两种情况：①不接受A、B方案的前提下接受C 方案的概率 =(1-40%)×(1-30%)×90% ⑤=42%×90%=37.8%;② A、B 方案至少接受一个的前提下接受C 方案的概率=(1-42%)⑥×10%=5.8%。则接受C 方案的概率 =37.8%+5.8%=43.6%。\n综上，概率从高到底排列为C>B>A, 答案为D 选项。","matchScore":0.421}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500006,4,'容斥问题','某公司有80人报名参加会计、法律和技术三项培训中的一项或多项，三
项培训的报名人数比为6:5:4。已知同时参加会计和法律培训的人数，和同
时参加法律和技术培训的人数，分别是同时参加会计和技术培训的人数的70%
和80%,且无人同时参加3项培训，则只参加技术培训的有多少人?','[{"label":"A","content":"4"},{"label":"B","content":"6"},{"label":"C","content":"8"},{"label":"D","content":"10"}]','D','根据三项培训报名人数比例设参加会计、法律、技术培训的人数分别为6x、5x、4x。同时参加会计和技术培训的人数、同时参加会计和法律培训的人数、同时参加法律和技术培训的人数分别为y、0.7y、0.8y。
根据容斥公式可列方程：80=6x+5x+4x-0.7y-0.8y-y,化简得80=15x-2.5y②。
由图所示⑧,只参加技术培训的人数=4x-1.8y, 由题意可知， y应是10的倍数⑨:
同时参加会计和法律培训的人数为0.7y, 人数为整数，即y 为10的倍数。
y 为10时，x=7,则只参加技术培训的人数=4×7-1.8×10=10,答案为D选项。

⑦花生批注：
容斥问题常用公式：
全部人数一圈外人数=人次之和-重复部分。

⑧花生批注：
会计6x 法律5x
