INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500007,4,'方阵问题','某灯光秀表演中，无人机群先排列成红、绿两个正方形实心方阵，然后融

合并变换灯光，形成一个黄色的正方框形空心方阵。原红方阵最外侧每边有8
架无人机，且原红方阵恰好可填满黄方阵的空心，原绿方阵最外侧每边的无人

机数量比黄方阵少4架。则参加灯光秀表演的无人机共有多少架?','[{"label":"A","content":"260"},{"label":"B","content":"233"},{"label":"C","content":"196"},{"label":"D","content":"185"}]','A','可设原绿方阵最外侧每边的无人机数量为x, 黄方阵最外侧每边的无人机数量为x+4。
利用前后无人机数量相等可列式：x²+8²=(x+4)²-8², 解得x=14 。可得出参加灯光秀的无人机共有14²+8²=260架，答案为A选项①。
⑪

①花生批注：
赋值法常用使用时机：
①题目中只有比例关系，无具体数字；
②符合的关系，
给出A的数字，B、C可赋值；
③解不定方程时的赋零法：若求的是A+B+C 的和，
可设某个未知数为0,
再求出另外两个未知数，和不变；
④对于恒等关系或恒成立其他关系，可赋值用特殊情况判断正误；
⑤对于几何问题，若所求为长度、面积、体积等的比值，可采用赋值法。
本题属于第①种情况。

⑩花生批注：
方阵问题常用知识点：
①方阵总人数=最外层每边
人数² ;
②每层人数=每边人数 ×4-4;
③相邻两层人数差为8。
某灯光秀表演中，无人机群先排列成红、绿两个正方形实心方阵，然后融合并变换灯光，形成一个黄色的正方框形空心方阵。原红方阵最外侧每边有8 架无人机，且原红方阵恰好可填满黄方阵的空心，原绿方阵最外侧每边的无人机数量比黄方阵少4架。则参加灯光秀表演的无人机共有多少架?

