INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500013,4,'和差倍比与不定方程问题','题(可
某政府机关将甲、乙两个部门合并。合并前，甲、乙两部门的男女人数之
比 分 别 为 4 : 1 和 3 : 2 ,男 女 党 员 人 数 之 比 分 别 为 9 : 2 和 9 : 4 ,乙 部 门 女 党
员人数占本部门人数的比重是甲部门的两倍。合并后，若男女人数之比为7:3,
则男女党员人数之比为多少?','[{"label":"A","content":"18:5"},{"label":"B","content":"27:8"},{"label":"C","content":"3:1"},{"label":"D","content":"27:10"}]','C','由“某政府机关将甲、乙两个部门合并”可知，女性占比
将部门女性占比带入十字交叉③可求出甲、乙部门总人数之比，即：
甲部门：
乙部门：
甲乙部门人数之比为1:1,则两部门人数相等。又因“甲、乙男女党员人数之比分别为9:2 和 9 : 4 ,乙部门女党员人数占本部门人数的比重是甲部门的两倍”可得④,甲、乙部门男党员人数均为9份，女党员人数分别为2份、 4份，则男女党员人数之比=(9+9):(2+4)=3:1,答案为C 选项。

③花生批注：
十字交叉法使用方法和适用题型：
符合整体和两部分的关系
且可写成A= 形式的都可适用十字交叉法，将 A 代入十字式子可求得C之比；
常用题型有平均数问题(可求得人数之比),
可求得成本之比；
可求得溶液之比),比例
可求得整体之比);
例如本题：总人数为整体，甲乙两个部门为两个部分，
符合 ,则可使用十字交叉法解题。

④花生批注：
甲乙两部门总人数相等.
女生党员占比为1:2.
则乙部门女生党员是甲部门的2倍，假设乙部门女党员为4a (乙部门男党员9a),
则甲部门女党员为2a, (甲部门男党员为9a)。
其中L₁ 、L₂ 作为两个小草地的边，应计算两次，外围的长应计算一次，则“长”共被计算6次，总长为12x;
L₃、L₄、L₅作为两个小草地的边，应计算两次，外围的宽应计算一次，则“宽”共被计算8次，总长为 8x;
综上，小草地周长之和 = 1 2x+8x=20x=100, 则 x=5, 草地面积 = 5 × 1 0 = 5 0 平方米，答案为 B 选项。

⑫花生批注：
最后四台可以直接给某个部门，保证和其他部门人数不相同即可；
例如：1、2、3、4、5、6、
11,或 1 、2、3、4、5、7、
10,等；
也可分别分给某两个、三个、四个部门；
例如：1、2、3、5、6、7、
8,或1、2、3、4、5、8、9, 等等。','数量关系600题','进阶','published','{"globalNumber":13,"sourceNumber":3,"typeLabel":"和差倍比与不定方程问题","stemRich":[{"text":"题(可\n某政府机关将甲、乙两个部门合并。合并前，甲、乙两部门的男女人数之\n比 分 别 为 4 : 1 和 3 : 2 ,男 女 党 员 人 数 之 比 分 别 为 9 : 2 和 9 : 4 ,乙 部 门 女 党\n员人数占本部门人数的比重是甲部门的两倍。合并后，若男女人数之比为7:3,\n则男女党员人数之比为多少?"}],"annotatedStemRich":[{"text":"题(可\n某政府机关将甲、乙两个部门合并。合并前，甲、乙两部门的男女人数之\n比 分 别 为 4 : 1 和 3 : 2 ,男 女 党 员 人 数 之 比 分 别 为 9 : 2 和 9 : 4 ,乙 部 门 女 党\n员人数占本部门人数的比重是甲部门的两倍。合并后，若男女人数之比为7:3,\n则男女党员人数之比为多少?"}],"annotatedOptionRich":{"A":[{"text":"18:5"}],"B":[{"text":"27:8"}],"C":[{"text":"3:1"}],"D":[{"text":"27:10\n"}]},"practicalAnalysis":"由“某政府机关将甲、乙两个部门合并”可知，女性占比\n将部门女性占比带入十字交叉③可求出甲、乙部门总人数之比，即：\n甲部门：\n乙部门：\n甲乙部门人数之比为1:1,则两部门人数相等。又因“甲、乙男女党员人数之比分别为9:2 和 9 : 4 ,乙部门女党员人数占本部门人数的比重是甲部门的两倍”可得④,甲、乙部门男党员人数均为9份，女党员人数分别为2份、 4份，则男女党员人数之比=(9+9):(2+4)=3:1,答案为C 选项。","notes":[{"marker":"③","text":"十字交叉法使用方法和适用题型：\n符合整体和两部分的关系\n且可写成A= 形式的都可适用十字交叉法，将 A 代入十字式子可求得C之比；\n常用题型有平均数问题(可求得人数之比),\n可求得成本之比；\n可求得溶液之比),比例\n可求得整体之比);\n例如本题：总人数为整体，甲乙两个部门为两个部分，\n符合 ,则可使用十字交叉法解题。","matchScore":0.152},{"marker":"④","text":"甲乙两部门总人数相等.\n女生党员占比为1:2.\n则乙部门女生党员是甲部门的2倍，假设乙部门女党员为4a (乙部门男党员9a),\n则甲部门女党员为2a, (甲部门男党员为9a)。\n其中L₁ 、L₂ 作为两个小草地的边，应计算两次，外围的长应计算一次，则“长”共被计算6次，总长为12x;\nL₃、L₄、L₅作为两个小草地的边，应计算两次，外围的宽应计算一次，则“宽”共被计算8次，总长为 8x;\n综上，小草地周长之和 = 1 2x+8x=20x=100, 则 x=5, 草地面积 = 5 × 1 0 = 5 0 平方米，答案为 B 选项。","matchScore":0.306},{"marker":"⑫","text":"最后四台可以直接给某个部门，保证和其他部门人数不相同即可；\n例如：1、2、3、4、5、6、\n11,或 1 、2、3、4、5、7、\n10,等；\n也可分别分给某两个、三个、四个部门；\n例如：1、2、3、5、6、7、\n8,或1、2、3、4、5、8、9, 等等。","matchScore":0.093}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500014,4,'最值问题之函数最值','某商店销售 一 批灯具，每套成本价格为650元，销售价格为900元，每日
可以销售12套。 一 套灯具的价格每降价25元，日销售量可以增加3套。当商
家实现每日利润最大化时，每日利润较原来增加多少元?','[{"label":"A","content":"625"},{"label":"B","content":"675"},{"label":"C","content":"825"},{"label":"D","content":"900"}]','B','现每日利润为250×12=3000元；设灯具降价x 次，每日的总利润为 y 元。根据题意和函数最值公式可列式： y=(250-25x)(12+3x), 当 x=3 时，利润最大⑤,此时最大利润y=3675 元，即较原来增加675元，答案为 B 选项。
