INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500015,4,'排列组合问题之特殊情境','y最大。
扶贫干部某日需要走访村内6个贫困户甲、乙、丙、丁、戊和己。已知甲
和乙的走访次序要相邻，丙要在丁之前走访，戊要在丙之前走访，己只能在第
一个或最后一个走访。问走访顺序有多少种不同的安排方式?','[{"label":"A","content":"24"},{"label":"B","content":"16"},{"label":"C","content":"48"},{"label":"D","content":"32"}]','B','方法一：根据题意，丙丁戊只有一种顺序，即按照戊、丙、丁排列，此时形成四个空；将甲乙捆绑选择一个空位，且注意甲乙内部排序，即共有4×2种可能；最后己只能放在第一或最后一个，有2种可能。综上，走访顺序共有4×2×2=16种不同的安排方式。
方法二⑥: 把题目看作定序问题+相邻问题，将甲乙捆绑后(注意内部排序)再和丙丁戊全排列，即A2×A4; 由于丙丁戊的顺序确定，根据定序问题公式，再除掉A;
最后考虑己的位置，首位或末尾A², 则一共有种情况，
答案为B 选项。

⑥花生批注：
排列组合八大特殊情境之一的定序问题(其他七大为相邻问题、不相邻问题、重复排列、相同元素分配、平均分堆问题、环形排列、错位排序):
n 个元素全排列，其中有m 个元素相对顺序不变，
则情况数为
例如此题：戊、丙、丁相对顺序固定。
定序问题：情况数=总体全排列÷定序(或完全相同)个体全排列。','数量关系600题','进阶','published','{"globalNumber":15,"sourceNumber":5,"typeLabel":"排列组合问题之特殊情境","stemRich":[{"text":"y最大。\n扶贫干部某日需要走访村内6个贫困户甲、乙、丙、丁、戊和己。已知甲\n和乙的走访次序要相邻，丙要在丁之前走访，戊要在丙之前走访，己只能在第\n一个或最后一个走访。问走访顺序有多少种不同的安排方式?"}],"annotatedStemRich":[{"text":"y最大。\n扶贫干部某日需要走访村内6个贫困户甲、乙、丙、丁、戊和己。已知甲\n和乙的走访次序要相邻，丙要在丁之前走访，戊要在丙之前走访，己只能在第\n一个或最后一个走访。问走访顺序有多少种不同的安排方式?"}],"annotatedOptionRich":{"A":[{"text":"24"}],"B":[{"text":"16"}],"C":[{"text":"48","bold":true}],"D":[{"text":"32","bold":true},{"text":"\n"}]},"practicalAnalysis":"方法一：根据题意，丙丁戊只有一种顺序，即按照戊、丙、丁排列，此时形成四个空；将甲乙捆绑选择一个空位，且注意甲乙内部排序，即共有4×2种可能；最后己只能放在第一或最后一个，有2种可能。综上，走访顺序共有4×2×2=16种不同的安排方式。\n方法二⑥: 把题目看作定序问题+相邻问题，将甲乙捆绑后(注意内部排序)再和丙丁戊全排列，即A2×A4; 由于丙丁戊的顺序确定，根据定序问题公式，再除掉A;\n最后考虑己的位置，首位或末尾A², 则一共有种情况，\n答案为B 选项。","notes":[{"marker":"⑥","text":"排列组合八大特殊情境之一的定序问题(其他七大为相邻问题、不相邻问题、重复排列、相同元素分配、平均分堆问题、环形排列、错位排序):\nn 个元素全排列，其中有m 个元素相对顺序不变，\n则情况数为\n例如此题：戊、丙、丁相对顺序固定。\n定序问题：情况数=总体全排列÷定序(或完全相同)个体全排列。","matchScore":0.1}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500016,4,'工程问题','某种商品有小箱和大箱两种包装， 一大箱这种商品有400件，张和王同时
开始制造这种商品，制造一小箱和一大箱这种商品后，张比王多做50件。如
果王此时的效率提高100%,并与张再共同制造一大箱这种商品，则王制造的总
件数比张多50件。问一小箱这种商品有多少件?','[{"label":"A","content":"50"},{"label":"B","content":"100"},{"label":"C","content":"150"},{"label":"D","content":"200"}]','C','根据题意，王最终总件数比张多50件(第一、二阶段), 则王提高效率后(第二阶段),王比张多生产100件⑦。
因提高效率后二人共同生产400件，则二人工作量分别为250和150件，王张效率比=5:3。则原来王张效率比=2.5:3=5:6.则提升效率前工作量之比=5:6,差1份对应50件。则王张完成总件数=(5+6)×50=550件⑧ , 所以一小箱=550-400=150件，则答案为C选项。

⑦花生批注：
需要注意：并非第二阶段王多制造50件，而是两阶段王一共多制造50件，由于第一阶段王少制造50件，则第二阶段王多制造100件。

⑧花生批注：
时间一定时，工作总量和工作效率成正比。','数量关系600题','进阶','published','{"globalNumber":16,"sourceNumber":6,"typeLabel":"工程问题","stemRich":[{"text":"某种商品有小箱和大箱两种包装， 一大箱这种商品有400件，张和王同时\n开始制造这种商品，制造一小箱和一大箱这种商品后，张比王多做50件。如\n果王此时的效率提高100%,并与张再共同制造一大箱这种商品，则王制造的总\n件数比张多50件。问一小箱这种商品有多少件?"}],"annotatedStemRich":[{"text":"某种商品有小箱和大箱两种包装， 一大箱这种商品有400件，张和王同时\n开始制造这种商品，制造一小箱和一大箱这种商品后，张比王多做50件。如\n果王此时的效率提高100%,并与张再共同制造一大箱这种商品，则王制造的总\n件数比张多50件。问一小箱这种商品有多少件?"}],"annotatedOptionRich":{"A":[{"text":"50"}],"B":[{"text":"100"}],"C":[{"text":"150","bold":true}],"D":[{"text":"200","bold":true},{"text":"\n"}]},"practicalAnalysis":"根据题意，王最终总件数比张多50件(第一、二阶段), 则王提高效率后(第二阶段),王比张多生产100件⑦。\n因提高效率后二人共同生产400件，则二人工作量分别为250和150件，王张效率比=5:3。则原来王张效率比=2.5:3=5:6.则提升效率前工作量之比=5:6,差1份对应50件。则王张完成总件数=(5+6)×50=550件⑧ , 所以一小箱=550-400=150件，则答案为C选项。","notes":[{"marker":"⑦","text":"需要注意：并非第二阶段王多制造50件，而是两阶段王一共多制造50件，由于第一阶段王少制造50件，则第二阶段王多制造100件。","matchScore":0.118},{"marker":"⑧","text":"时间一定时，工作总量和工作效率成正比。","matchScore":0.025}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500017,4,'数列问题','某校按字母A到 Z的顺序给班级编号，按班级编号加01、02、03,……给
每位学生按顺序定学号，若A～K班级人数从15人起每班递增1名，之后每班

按编号顺序递减2名，则第256名学生的学号是多少?','[{"label":"A","content":"N11"},{"label":"B","content":"M12"},{"label":"C","content":"M13"},{"label":"D","content":"N10"}]','C','A～ K班级共有11个，其中第 6 个班级 F 班有 1 5 + 5 = 2 0 人⑨, 所以A～K班级总人数为11×20=220人⑩:
