INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500022,4,'排列组合问题','甲、乙、丙、丁、戊5门课安排在先后4个学期开课，每个学期至少1门。

已知甲不与其他任何一门课安排在同一学期，乙和丙均不能在第一个学期或最
后一个学期开课，丁必须在戊和甲之后的学期开课，那么这5门课有多少种不

同的安排方式?','[{"label":"A","content":"5"},{"label":"B","content":"6"},{"label":"C","content":"7"},{"label":"D","content":"8\n13"}]','D','根据“乙丙均不能在第一个学期或最后一个学期开学”可知，乙丙应安排在中间两个学期，可分情况讨论：
①乙丙先安排在中间的不同学期， A2; 根据“丁在甲戊之后”可知，丁只能在最后一学期，此时后三个学期均有安排，则甲只能在第一学期；再为戊在
中间两学期选择一个位置即可，
;;
此时一共有种安排；
②乙丙安排在中间的相同学期，先为乙丙选择一个学期， ; 此时剩余三
个学期，丁一定在最后，另外两门课程全排列即可，
u
u
此时一共有 4 种安排；
综上所述，这5门课程一共有8种安排，答案为D选项。','数量关系600题','进阶','published','{"globalNumber":22,"sourceNumber":2,"typeLabel":"排列组合问题","stemRich":[{"text":"甲、乙、丙、丁、戊5门课安排在先后4个学期开课，每个学期至少1门。\n\n已知甲不与其他任何一门课安排在同一学期，乙和丙均不能在第一个学期或最\n后一个学期开课，丁必须在戊和甲之后的学期开课，那么这5门课有多少种不\n\n同的安排方式?"}],"annotatedStemRich":[{"text":"甲、乙、丙、丁、戊5门课安排在先后4个学期开课，每个学期至少1门。\n\n已知甲不与其他任何一门课安排在同一学期，乙和丙均不能在第一个学期或最\n后一个学期开课，丁必须在戊和甲之后的学期开课，那么这5门课有多少种不\n\n同的安排方式?"}],"annotatedOptionRich":{"A":[{"text":"5"}],"B":[{"text":"6"}],"C":[{"text":"7"}],"D":[{"text":"8\n13\n"}]},"practicalAnalysis":"根据“乙丙均不能在第一个学期或最后一个学期开学”可知，乙丙应安排在中间两个学期，可分情况讨论：\n①乙丙先安排在中间的不同学期， A2; 根据“丁在甲戊之后”可知，丁只能在最后一学期，此时后三个学期均有安排，则甲只能在第一学期；再为戊在\n中间两学期选择一个位置即可，\n;;\n此时一共有种安排；\n②乙丙安排在中间的相同学期，先为乙丙选择一个学期， ; 此时剩余三\n个学期，丁一定在最后，另外两门课程全排列即可，\nu\nu\n此时一共有 4 种安排；\n综上所述，这5门课程一共有8种安排，答案为D选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500023,4,'工程问题','甲、乙、丙、丁共同完成一项工程，其中甲的效率是乙的1.25倍，丙的
效率是丁的1.5倍。甲、丁合作3天后，变为乙、丙合作，又过了4天后，剩

下的工作量恰好可以由甲和乙合作1天完成。已知甲单独完成需要20天，那
么丙的效率是甲的多少倍?','[{"label":"A","content":"0.5"},{"label":"B","content":"1"},{"label":"C","content":"1.5"},{"label":"D","content":"2"}]','D','根据不同完工情况，可列方程： 3甲+3丁+4乙+4丙+甲+ 乙=20甲，化简为： 4甲+3丁+5乙+4丙=20甲；
因所求为甲丙的效率倍数，则可将乙丁根据比例替换为甲丙；
根据“甲的效率是乙的1.25倍”,则等式中的5乙=4甲；
根据“丙的效率是丁的1.5倍”,则等式中的3丁=2丙；
代入等式得：4甲+2丙+4甲+4丙=20甲，12甲=6丙，即丙是甲的2倍，答案为D选项。','数量关系600题','进阶','published','{"globalNumber":23,"sourceNumber":3,"typeLabel":"工程问题","stemRich":[{"text":"甲、乙、丙、丁共同完成一项工程，其中甲的效率是乙的1.25倍，丙的\n效率是丁的1.5倍。甲、丁合作3天后，变为乙、丙合作，又过了4天后，剩\n\n下的工作量恰好可以由甲和乙合作1天完成。已知甲单独完成需要20天，那\n么丙的效率是甲的多少倍?"}],"annotatedStemRich":[{"text":"甲、乙、丙、丁共同完成一项工程，其中甲的效率是乙的1.25倍，丙的\n效率是丁的1.5倍。甲、丁合作3天后，变为乙、丙合作，又过了4天后，剩\n\n下的工作量恰好可以由甲和乙合作1天完成。已知甲单独完成需要20天，那\n么丙的效率是甲的多少倍?"}],"annotatedOptionRich":{"A":[{"text":"0.5"}],"B":[{"text":"1"}],"C":[{"text":"1.5"}],"D":[{"text":"2\n"}]},"practicalAnalysis":"根据不同完工情况，可列方程： 3甲+3丁+4乙+4丙+甲+ 乙=20甲，化简为： 4甲+3丁+5乙+4丙=20甲；\n因所求为甲丙的效率倍数，则可将乙丁根据比例替换为甲丙；\n根据“甲的效率是乙的1.25倍”,则等式中的5乙=4甲；\n根据“丙的效率是丁的1.5倍”,则等式中的3丁=2丙；\n代入等式得：4甲+2丙+4甲+4丙=20甲，12甲=6丙，即丙是甲的2倍，答案为D选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500024,4,'经济利润问题+统筹规划问题','某文具厂计划每周生产A、B两款文件夹共9000个，其中A款文件夹每个

