INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500034,4,'和差倍比与不定方程问题','小明和小李约好一起拼装模型，小明拼装了8个A 模型， 4 个B 模型，2 个 C 模型，共用了118个螺丝钉；小李拼装了同样类型的A模型 5 个，B模型3个， C 模型2个，共用了83个螺丝钉，那么拼装一个A模型，一个B 模型，一个C 模型共需要螺丝钉多少个?','[{"label":"A","content":"24"},{"label":"B","content":"26"},{"label":"C","content":"30"},{"label":"D","content":"32"}]','A','根据题意可列等式：①8A+4B+2C=118.②5A+3B+2C=83; 观察可得：② - ①÷2=A+B+C=24,答案为A选项②。
