INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500037,4,'等差数列问题','桌上整齐摆放着若干只相同玻璃杯，除一只空杯外，其余杯中都放有彩色
7d;
珠子，共有45颗。如果在有彩色珠子的每个杯中取1颗放入空杯，则只需调
数；
整玻璃杯的位置，即可与最初完全一样。问桌上共有多少只玻璃杯?','[{"label":"A","content":"7"},{"label":"B","content":"8"},{"label":"C","content":"9"},{"label":"D","content":"10"}]','D','设共有 n 只玻璃杯，根据“最后调整玻璃杯的位置可与最初完全一样”可知，原来有玻璃珠的杯子内的珠子均减少1,最初的空杯最后变为装珠子最多的杯子。故原来杯子中珠子数为公差为1的等差数列，首项为0(对
应空杯),末项为(n-1), 根据等差数列求和公式⑬可得解得 n=10, 答案为D 选项⑨

⑬花生批注：
再进行大量刷题训练后，应对45、55两个数字非常敏感，45为1到9之和， 55为1到10之和；
所以此题其他玻璃杯的彩色珠子数可猜测为从1到 9,分别拿出1颗珠子后，
变为0到8,共拿出9个
珠子，空杯变为9;
即变动前后均为0至9的数列，共有10只玻璃杯。
即0.25小时可完成300份文件，4小时完成文件=16×300=4800份，答案为 C选项。','数量关系600题','进阶','published','{"globalNumber":37,"sourceNumber":7,"typeLabel":"等差数列问题","stemRich":[{"text":"桌上整齐摆放着若干只相同玻璃杯，除一只空杯外，其余杯中都放有彩色\n7d;\n珠子，共有45颗。如果在有彩色珠子的每个杯中取1颗放入空杯，则只需调\n数；\n整玻璃杯的位置，即可与最初完全一样。问桌上共有多少只玻璃杯?"}],"annotatedStemRich":[{"text":"桌上整齐摆放着若干只相同玻璃杯，除一只空杯外，其余杯中都放有彩色\n7d;\n珠子，共有45颗。如果在有彩色珠子的每个杯中取1颗放入空杯，则只需调\n数；\n整玻璃杯的位置，即可与最初完全一样。问桌上共有多少只玻璃杯?"}],"annotatedOptionRich":{"A":[{"text":"7"}],"B":[{"text":"8"}],"C":[{"text":"9"}],"D":[{"text":"10","bold":true},{"text":"\n"}]},"practicalAnalysis":"设共有 n 只玻璃杯，根据“最后调整玻璃杯的位置可与最初完全一样”可知，原来有玻璃珠的杯子内的珠子均减少1,最初的空杯最后变为装珠子最多的杯子。故原来杯子中珠子数为公差为1的等差数列，首项为0(对\n应空杯),末项为(n-1), 根据等差数列求和公式⑬可得解得 n=10, 答案为D 选项⑨","notes":[{"marker":"⑬","text":"再进行大量刷题训练后，应对45、55两个数字非常敏感，45为1到9之和， 55为1到10之和；\n所以此题其他玻璃杯的彩色珠子数可猜测为从1到 9,分别拿出1颗珠子后，\n变为0到8,共拿出9个\n珠子，空杯变为9;\n即变动前后均为0至9的数列，共有10只玻璃杯。\n即0.25小时可完成300份文件，4小时完成文件=16×300=4800份，答案为 C选项。","matchScore":0.158}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500038,4,'最值问题','后，
