INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500039,4,'几何问题之最短距离','如图，圆锥高6 √ 3厘米，底面半径为6厘米，一只蚂蚁从A 点沿圆锥侧面爬行到B 点，则最短的距离为多少厘米?','[{"label":"A","content":"12"},{"label":"B","content":"12√2"},{"label":"C","content":"6π"},{"label":"D","content":"24"}]','B','圆锥高为6 √ 3,底面半径为6,则圆锥母线长为12 ⑤;圆锥底面周长=2 πR =12π,即原圆锥展开后的扇形弧长为12π;
原圆锥展开后的半径为12,周长为2πR=24π, 则扇形恰好为半圆，如下图所示：
要让蚂蚁爬行的距离最短，则蚂蚁应沿着 △ AOB 的斜边爬行，由于 AO=0B, 故△ AOB为等腰直角三角形，则 AB=12√2, 答案为B 选项。

⑮花生批注：
圆锥的母线(围成此圆锥所用扇形的半径)、底面半径及高构成直角三角形，其中母线是直角三角形的
斜边，代入a²=b²+c², 求得
母线长为12。
PS: 该直角三角形为 30°60°直角三角形，三边比为1:√3:2。

⑯花生批注：
等腰直角三角形是七大常考图形(正六边形、正三角形、圆、矩形、30度60度直角三角形、345直角三角形、等腰直接三角形)之一，三边关系为1:1:√2, 其中√2为斜边。','数量关系600题','进阶','published','{"globalNumber":39,"sourceNumber":9,"typeLabel":"几何问题之最短距离","stemRich":[{"text":"如图，圆锥高6 √ 3厘米，底面半径为6厘米， 一 只蚂蚁从A 点沿圆锥侧面 爬行到B 点，则最短的距离为多少厘米?"}],"annotatedStemRich":[{"text":"如图，圆锥高6 √ 3厘米，底面半径为6厘米， 一 只蚂蚁从A 点沿圆锥侧面 爬行到B 点，则最短的距离为多少厘米?"}],"annotatedOptionRich":{"A":[{"text":"12","bold":true}],"B":[{"text":"12√2"}],"C":[{"text":"6π"}],"D":[{"text":"24\n"}]},"practicalAnalysis":"圆锥高为6 √ 3,底面半径为6,则圆锥母线长为12 ⑤;圆锥底面周长=2 πR =12π,即原圆锥展开后的扇形弧长为12π;\n原圆锥展开后的半径为12,周长为2πR=24π, 则扇形恰好为半圆，如下图所示：\n要让蚂蚁爬行的距离最短，则蚂蚁应沿着 △ AOB 的斜边爬行，由于 AO=0B, 故△ AOB为等腰直角三角形，则 AB=12√2, 答案为B 选项。","notes":[{"marker":"⑮","text":"圆锥的母线(围成此圆锥所用扇形的半径)、底面半径及高构成直角三角形，其中母线是直角三角形的\n斜边，代入a²=b²+c², 求得\n母线长为12。\nPS: 该直角三角形为 30°60°直角三角形，三边比为1:√3:2。","matchScore":0.212},{"marker":"⑯","text":"等腰直角三角形是七大常考图形(正六边形、正三角形、圆、矩形、30度60度直角三角形、345直角三角形、等腰直接三角形)之一，三边关系为1:1:√2, 其中√2为斜边。","matchScore":0.113}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500040,4,'排列组合问题','某公司现有6箱不同的水果，安排三个配送员送到A 、B、C 三个不同的仓
