INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500041,4,'和差倍比问题','小王在纸上写了5个数，已知每4个数之和分别为76、77、81、84、86,

