INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500045,4,'概率问题+容斥问题','某单位要抽调若干人员下乡扶贫，小王、小李、小张都报了名，但因工作

需要，若选小李或小张，就不能选小王。已知三人入选的概率都是0.2,但小李、
小张同时入选的概率是0.1,则三人中有人入选的概率是多少?','[{"label":"A","content":"0.3"},{"label":"B","content":"0.4"},{"label":"C","content":"0.5"},{"label":"D","content":"0.6"}]','C','本题的关键在于理解三人入选的概率都是0.2,0.2的概率是包含了只有自己入选和与其他人同时入选的情况。
根据“若选小李或小张，就不能选小王”可知，三人不能同时入选，入选情况只能分为只有1人入选和2人入选两类。
①只有1人入选。小王单独入选概率为0.2⑤,小李单独入选概率=小李入选概率一小李、小张同时入选概率=0.2-0.1=0.1,小张单独入选概率同理为0.1。只有1人入选概率为0.2+0.1+0.1=0.4;
②有2人入选。因若选小李或小张，就不能选小王，所以只有小李、小张同时入选一种情况，概率0.1;
因此，三人有人入选的概率=0.4+0.1=0.5⁶,答案为C选项。

②花生批注：
合作完工问题：
无需关注如何工作，
四人同时开工同时结束，','数量关系600题','进阶','published','{"globalNumber":45,"sourceNumber":5,"typeLabel":"概率问题+容斥问题","stemRich":[{"text":"某单位要抽调若干人员下乡扶贫，小王、小李、小张都报了名，但因工作\n\n需要，若选小李或小张，就不能选小王。已知三人入选的概率都是0.2,但小李、\n小张同时入选的概率是0.1,则三人中有人入选的概率是多少?"}],"annotatedStemRich":[{"text":"某单位要抽调若干人员下乡扶贫，小王、小李、小张都报了名，但因工作\n\n需要，若选小李或小张，就不能选小王。已知三人入选的概率都是0.2,但小李、\n小张同时入选的概率是0.1,则三人中有人入选的概率是多少?"}],"annotatedOptionRich":{"A":[{"text":"0.3"}],"B":[{"text":"0.4"}],"C":[{"text":"0.5"}],"D":[{"text":"0.6\n"}]},"practicalAnalysis":"本题的关键在于理解三人入选的概率都是0.2,0.2的概率是包含了只有自己入选和与其他人同时入选的情况。\n根据“若选小李或小张，就不能选小王”可知，三人不能同时入选，入选情况只能分为只有1人入选和2人入选两类。\n①只有1人入选。小王单独入选概率为0.2⑤,小李单独入选概率=小李入选概率一小李、小张同时入选概率=0.2-0.1=0.1,小张单独入选概率同理为0.1。只有1人入选概率为0.2+0.1+0.1=0.4;\n②有2人入选。因若选小李或小张，就不能选小王，所以只有小李、小张同时入选一种情况，概率0.1;\n因此，三人有人入选的概率=0.4+0.1=0.5⁶,答案为C选项。","notes":[{"marker":"②","text":"合作完工问题：\n无需关注如何工作，\n四人同时开工同时结束，","matchScore":0.036}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500046,4,'几何问题之等比放缩+蝴蝶模型','一个三角形公园ABC内的道路如下图中实线所示。已知AE=EF=FB,
AD=DC,且黑色部分为人工湖。问公园总面积是人工湖面积的多少倍?










27






0 0','[{"label":"A","content":"9"},{"label":"B","content":"12"},{"label":"C","content":"16"},{"label":"D","content":"18"}]','D','首先可关注△ ED0 与 △ CF0, 根据“ AE=EF,AD=DC”,
可知ED 为 △ AFC 的中位线，故 ED //FC 且 ED:FC=1:2 , 进而可得出
△ ED0∽△CF0, 且相似比为1:2;
假设黑色部分面积为1,根据等比放缩性质可知，△ CF0 面积为4⑦;
再关注△CFO 与 △EF0, 两个三角形等高，面积比即等于底边长之比，则
△ EF0 面积为2,进而可得出△ CEF 面积=4+2=6。
△ CAE、△CEF、△CFB 等高且底相等，故三者面积都为6,△ABC 面积为三者面积之和18。所以公园面积：人工湖面积=18:1=18,答案为D 选项⑧。

⑦花生批注：
几何等比放缩性质：
边长(半径)比为n: 1, 则周长为n 倍，面积为n² 倍，体积为n³ 倍。

⑧花生批注：
考场上也可用直尺量出
△ABC与△ED0的底和高，计算面积作比，快速秒杀。','数量关系600题','进阶','published','{"globalNumber":46,"sourceNumber":6,"typeLabel":"几何问题之等比放缩+蝴蝶模型 【难度评价】★★☆","stemRich":[{"text":"一个三角形公园ABC内的道路如下图中实线所示。已知AE=EF=FB,\nAD=DC,且黑色部分为人工湖。问公园总面积是人工湖面积的多少倍?\n\n\n\n\n\n\n\n\n\n\n27\n\n\n\n\n\n\n0 0"}],"annotatedStemRich":[{"text":"一个三角形公园ABC内的道路如下图中实线所示。已知AE=EF=FB,\nAD=DC,且黑色部分为人工湖。问公园总面积是人工湖面积的多少倍?\n\n\n\n\n\n\n\n\n\n\n27\n\n\n\n\n\n\n0 0"}],"annotatedOptionRich":{"A":[{"text":"9","bold":true}],"B":[{"text":"12","bold":true}],"C":[{"text":"16","bold":true}],"D":[{"text":"18","bold":true},{"text":"\n"}]},"practicalAnalysis":"首先可关注△ ED0 与 △ CF0, 根据“ AE=EF,AD=DC”,\n可知ED 为 △ AFC 的中位线，故 ED //FC 且 ED:FC=1:2 , 进而可得出\n△ ED0∽△CF0, 且相似比为1:2;\n假设黑色部分面积为1,根据等比放缩性质可知，△ CF0 面积为4⑦;\n再关注△CFO 与 △EF0, 两个三角形等高，面积比即等于底边长之比，则\n△ EF0 面积为2,进而可得出△ CEF 面积=4+2=6。\n△ CAE、△CEF、△CFB 等高且底相等，故三者面积都为6,△ABC 面积为三者面积之和18。所以公园面积：人工湖面积=18:1=18,答案为D 选项⑧。","notes":[{"marker":"⑦","text":"几何等比放缩性质：\n边长(半径)比为n: 1, 则周长为n 倍，面积为n² 倍，体积为n³ 倍。","matchScore":0.097},{"marker":"⑧","text":"考场上也可用直尺量出\n△ABC与△ED0的底和高，计算面积作比，快速秒杀。","matchScore":0.056}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500047,4,'浓度问题之类浓度问题','将一叠文件分为若干组，每组正好有10份文件。已知其中2组文件中有
楚或 18份通知，其余每组文件中最多有5份通知，且所有文件中通知占比正好为
“最
60%。那么这叠文件最多可能有多少份?
“有','[{"label":"A","content":"50"},{"label":"B","content":"60"},{"label":"C","content":"70"},{"label":"D","content":"80"}]','D','题目给出已有的2组文件(20份)中有18份通知，此部分通知占比为90%。要想整体占比为60%,另一部分通知占比应小于60%,同时，另一部分占比越接近60%,带来下降效果越小，所需用量越多，即可让另一部分的每组文件中都有5份通知，即另一部分的通知占比为50%⑨;
采用十字交叉法可得：
18份通知组： 1
5份通知组： 3
可求得18份通知组文件数与5份通知组文件数之比为1:3,故最多有 20+60=80份文件，答案为D选项。
IHA海IGOGK0

