INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500054,4,'经济利润问题','某企业花费3456万元改造了一条自动化生产线，单位产品人工成本降低

了50%,非人工成本降低了10%,单日产量扩大了一倍，已知改造前的单位产
品人工成本是非人工成本的3倍，改造后每天的人工成本比非人工成本高3.6

万元。问多少天后新生产线降低的成本可与花费的改造成本相抵?','[{"label":"A","content":"480"},{"label":"B","content":"300"},{"label":"C","content":"360"},{"label":"D","content":"540"}]','C','为方便计算可赋值改造前单日产量为1,则改造后单日产量为2,设改造前单位产品非人工成本为x 万元，根据题意可知改造前后数据如下表：
单位产品人工成本
单位产品非人工成本
单日产量
改造前
3x
X
1
改造后

⑤花生批注：
改造后每件产品节约成本 =(3x+x)-(1.5x+0.9x);
改造后每日产量为2,
则每天节约成本需乘以2。
则改造后每天节约成本=[(3x+x)-(1.5x+0.9x)]×2 ⑤=3.2x=9.6 万元，则抵消成本需要3456÷9.6=360天，答案为C 选项。','数量关系600题','进阶','published','{"globalNumber":54,"sourceNumber":4,"typeLabel":"经济利润问题","stemRich":[{"text":"某企业花费3456万元改造了一条自动化生产线，单位产品人工成本降低\n\n了50%,非人工成本降低了10%,单日产量扩大了一倍，已知改造前的单位产\n品人工成本是非人工成本的3倍，改造后每天的人工成本比非人工成本高3.6\n\n万元。问多少天后新生产线降低的成本可与花费的改造成本相抵?"}],"annotatedStemRich":[{"text":"某企业花费3456万元改造了一条自动化生产线，单位产品人工成本降低\n\n了50%,非人工成本降低了10%,单日产量扩大了一倍，已知改造前的单位产\n品人工成本是非人工成本的3倍，改造后每天的人工成本比非人工成本高3.6\n\n万元。问多少天后新生产线降低的成本可与花费的改造成本相抵?"}],"annotatedOptionRich":{"A":[{"text":"480"}],"B":[{"text":"300"}],"C":[{"text":"360"}],"D":[{"text":"540\n"}]},"practicalAnalysis":"为方便计算可赋值改造前单日产量为1,则改造后单日产量为2,设改造前单位产品非人工成本为x 万元，根据题意可知改造前后数据如下表：\n单位产品人工成本\n单位产品非人工成本\n单日产量\n改造前\n3x\nX\n1\n改造后","notes":[{"marker":"⑤","text":"改造后每件产品节约成本 =(3x+x)-(1.5x+0.9x);\n改造后每日产量为2,\n则每天节约成本需乘以2。\n则改造后每天节约成本=[(3x+x)-(1.5x+0.9x)]×2 ⑤=3.2x=9.6 万元，则抵消成本需要3456÷9.6=360天，答案为C 选项。","matchScore":0.189}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500055,4,'和差倍比问题','A、B 两个小组分别有4人和6人，调换前两组平均年龄相同。在A组的甲 调入B组、B组的乙调入A组后，A组平均年龄比B组大5岁。那么甲的年龄比乙?','[{"label":"A","content":"大24岁"},{"label":"B","content":"大12岁"},{"label":"C","content":"小12岁"},{"label":"D","content":"小24岁"}]','C','方法一：A组的甲调入 B 组、B组的乙调入A 组后，A 组平均年龄比B组大，因此甲的年龄应小于乙，排除A 、B选项；
此时只剩余两个选项，可采用代入法：
代入 C 选项，如果甲的年龄比乙小12岁，对调后A 组的平均年龄增加了 12÷4=3岁，B组的平均年龄减少了12÷6=2岁，此时A 组平均年龄比B组大5 岁成立，答案确定为C选项。
⑥

⑥花生批注：
A组调走了甲，调来了乙，需要减去甲加上乙，
即：一甲+乙=-(甲-乙); B组调来了甲，调走了乙，需要加上甲减去乙，
即：+甲-乙=+(甲-乙)。','数量关系600题','进阶','published','{"globalNumber":55,"sourceNumber":5,"typeLabel":"和差倍比问题","stemRich":[{"text":"A、B 两个小组分别有4人和6人，调换前两组平均年龄相同。在A组的甲 调入B组、B组的乙调入A组后，A组平均年龄比B组大5岁。那么甲的年龄比乙?"}],"annotatedStemRich":[{"text":"A、B 两个小组分别有4人和6人，调换前两组平均年龄相同。在A组的甲 调入B组、B组的乙调入A组后，A组平均年龄比B组大5岁。那么甲的年龄比乙?"}],"annotatedOptionRich":{"A":[{"text":"B 两个小组分别有4人和6人，调换前两组平均年龄相同。在A组的甲 调入B组、B组的乙调入A组后，A组平均年龄比B组大5岁。那么甲的年龄比乙?\nA.  大24岁"}],"B":[{"text":"  大12岁"}],"C":[{"text":" 小12岁"}],"D":[{"text":" 小24岁\n"}]},"practicalAnalysis":"方法一：A组的甲调入 B 组、B组的乙调入A 组后，A 组平均年龄比B组大，因此甲的年龄应小于乙，排除A 、B选项；\n此时只剩余两个选项，可采用代入法：\n代入 C 选项，如果甲的年龄比乙小12岁，对调后A 组的平均年龄增加了 12÷4=3岁，B组的平均年龄减少了12÷6=2岁，此时A 组平均年龄比B组大5 岁成立，答案确定为C选项。\n⑥","notes":[{"marker":"⑥","text":"A组调走了甲，调来了乙，需要减去甲加上乙，\n即：一甲+乙=-(甲-乙); B组调来了甲，调走了乙，需要加上甲减去乙，\n即：+甲-乙=+(甲-乙)。","matchScore":0.041}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500056,4,'一般排列组合问题','某次会议邀请4所高校每所各2位学者作报告。在某日上午、下午和晚上
的三个时间段分别安排3位、3位和2位学者依次作报告，且同一所高校的2

位学者不安排在同一时间段内作报告。问8人的报告次序有多少种不同的安排
方式?','[{"label":"A","content":"不到5000种"},{"label":"B","content":"5000～10000 种之间"},{"label":"C","content":"10001～20000 种之间"},{"label":"D","content":"超过20000种"}]','C','根据题意可知，晚上时段需要2位不同高校的学者作报告，
即C2×C2×C2; 未被选到的两个高校的4位学者，因为无法在同一时段，需
要依次分配到上午、下午两个时段，即 ;此时上午下午分别还需要一
位学者，可将剩余2位学者(晚上两位学者的同校学者)分配到两个时段即可， A2;
此时还需要将三个时段内的学者进行排序，即A³×A³×A;②
综上，一共有C2×C2×C2×A2×A2×A²×A³×A³×A2=13824 种安
排情况，答案为C选项。

②花生批注：
注意此时时间单位为分钟，注意单位换算。','数量关系600题','进阶','published','{"globalNumber":56,"sourceNumber":6,"typeLabel":"一般排列组合问题","stemRich":[{"text":"某次会议邀请4所高校每所各2位学者作报告。在某日上午、下午和晚上\n的三个时间段分别安排3位、3位和2位学者依次作报告，且同一所高校的2\n\n位学者不安排在同一时间段内作报告。问8人的报告次序有多少种不同的安排\n方式?"}],"annotatedStemRich":[{"text":"某次会议邀请4所高校每所各2位学者作报告。在某日上午、下午和晚上\n的三个时间段分别安排3位、3位和2位学者依次作报告，且同一所高校的2\n\n位学者不安排在同一时间段内作报告。问8人的报告次序有多少种不同的安排\n方式?"}],"annotatedOptionRich":{"A":[{"text":" 不到5000种"}],"B":[{"text":"5000～10000    种之间"}],"C":[{"text":"10001～20000   种之间"}],"D":[{"text":" 超过20000种\n"}]},"practicalAnalysis":"根据题意可知，晚上时段需要2位不同高校的学者作报告，\n即C2×C2×C2; 未被选到的两个高校的4位学者，因为无法在同一时段，需\n要依次分配到上午、下午两个时段，即 ;此时上午下午分别还需要一\n位学者，可将剩余2位学者(晚上两位学者的同校学者)分配到两个时段即可， A2;\n此时还需要将三个时段内的学者进行排序，即A³×A³×A;②\n综上，一共有C2×C2×C2×A2×A2×A²×A³×A³×A2=13824 种安\n排情况，答案为C选项。","notes":[{"marker":"②","text":"注意此时时间单位为分钟，注意单位换算。","matchScore":0.023}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500057,4,'几何问题之等比放缩','如图所示：3个同心圆的半径比为1:2:3。∠AOB=120°, 那么阴影部
分和非阴影部分的面积比为多少?','[{"label":"A","content":"1:2"},{"label":"B","content":"2:3"},{"label":"C","content":"3:4"},{"label":"D","content":"4:5"}]','D','如图所示⑧,先观察a 区部分，由小到大，扇形半径之比为 1:2:3,根据几何等比放缩性质 ⑨,三部分面积之比为1:4:9,即 a₁=1, a₂=4-1=3,a₃=9-4=5;
根据∠ AOB=120° 可知，b₁ 面积是a1的 2 倍，即 b₁=2;
同 a 区，b 区由小到大三部分面积之比也是1:4:9=2:8:18,即 b₁=2, b₂=8-2=6,b₃=18-8=10;
综上，阴影部分和非阴影部分的面积比 =(a₁+b₂+a₃):(a₂+b₁+b₃) =(1+6+5):(3+2+10)=12:15=4:5, 答案为D 选项。
⑧

⑨花生批注：
几何等比放缩性质：
边长(半径)比为n:1,
则周长为n 倍，面积为n² 倍，体积为n³ 倍。','数量关系600题','进阶','published','{"globalNumber":57,"sourceNumber":7,"typeLabel":"几何问题之等比放缩","stemRich":[{"text":"如图所示：3个同心圆的半径比为1:2:3。∠AOB=120°, 那么阴影部\n分和非阴影部分的面积比为多少?"}],"annotatedStemRich":[{"text":"如图所示：3个同心圆的半径比为1:2:3。∠AOB=120°, 那么阴影部\n分和非阴影部分的面积比为多少?"}],"annotatedOptionRich":{"A":[{"text":"1:2"}],"B":[{"text":"2:3"}],"C":[{"text":"3:4","bold":true}],"D":[{"text":"4:5","bold":true},{"text":"\n"}]},"practicalAnalysis":"如图所示⑧,先观察a 区部分，由小到大，扇形半径之比为 1:2:3,根据几何等比放缩性质 ⑨,三部分面积之比为1:4:9,即 a₁=1, a₂=4-1=3,a₃=9-4=5;\n根据∠ AOB=120° 可知，b₁ 面积是a1的 2 倍，即 b₁=2;\n同 a 区，b 区由小到大三部分面积之比也是1:4:9=2:8:18,即 b₁=2, b₂=8-2=6,b₃=18-8=10;\n综上，阴影部分和非阴影部分的面积比 =(a₁+b₂+a₃):(a₂+b₁+b₃) =(1+6+5):(3+2+10)=12:15=4:5, 答案为D 选项。\n⑧","notes":[{"marker":"⑨","text":"几何等比放缩性质：\n边长(半径)比为n:1,\n则周长为n 倍，面积为n² 倍，体积为n³ 倍。","matchScore":0.218}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500058,4,'容斥问题','某科学家做了一项实验，通过向若干只狒狒提供不限量的香蕉和香肠以研
究其食性。结果表明，90%的狒狒有进食，其中吃香蕉的狒狒是吃香肠的狒狒

数量的3倍，而两种食物都吃的狒狒是只吃香肠的狒狒数量的 ,则未进食的

狒狒是只吃香蕉的狒狒数量的多少倍?','[{"label":"A","content":"（图形选项，见题目原图）"},{"label":"B","content":"（图形选项，见题目原图）"},{"label":"C","content":"（图形选项，见题目原图）"},{"label":"D","content":"（图形选项，见题目原图）"}]','C','容斥问题可画图解决，根据“两种食物都吃的狒狒是只吃香肠的狒狒数量的 ,可假设只吃香肠的有3只，则两种食物都吃的有2只，吃香肠的共有5只；
根据“吃香蕉的狒狒是吃香肠的狒狒数量的3倍”可知，吃香蕉的有15只，只吃香蕉的有13只；
此时进食的狒狒共有13+2+3=18只，占比为90%,则不进食的狒狒占比 10%,有2只；
综上，未进食的狒狒与只吃香蕉的狒狒之 , 答案为C 选项。','数量关系600题','进阶','published','{"globalNumber":58,"sourceNumber":8,"typeLabel":"容斥问题","stemRich":[{"text":"某科学家做了一项实验，通过向若干只狒狒提供不限量的香蕉和香肠以研\n究其食性。结果表明，90%的狒狒有进食，其中吃香蕉的狒狒是吃香肠的狒狒\n\n数量的3倍，而两种食物都吃的狒狒是只吃香肠的狒狒数量的 ,则未进食的\n\n狒狒是只吃香蕉的狒狒数量的多少倍?"}],"annotatedStemRich":[{"text":"某科学家做了一项实验，通过向若干只狒狒提供不限量的香蕉和香肠以研\n究其食性。结果表明，90%的狒狒有进食，其中吃香蕉的狒狒是吃香肠的狒狒\n\n数量的3倍，而两种食物都吃的狒狒是只吃香肠的狒狒数量的 ,则未进食的\n\n狒狒是只吃香蕉的狒狒数量的多少倍?"}],"annotatedOptionRich":{"A":[{"text":"（图形选项，见题目原图）"}],"B":[{"text":"（图形选项，见题目原图）"}],"C":[{"text":"（图形选项，见题目原图）"}],"D":[{"text":"（图形选项，见题目原图）"}]},"practicalAnalysis":"容斥问题可画图解决，根据“两种食物都吃的狒狒是只吃香肠的狒狒数量的 ,可假设只吃香肠的有3只，则两种食物都吃的有2只，吃香肠的共有5只；\n根据“吃香蕉的狒狒是吃香肠的狒狒数量的3倍”可知，吃香蕉的有15只，只吃香蕉的有13只；\n此时进食的狒狒共有13+2+3=18只，占比为90%,则不进食的狒狒占比 10%,有2只；\n综上，未进食的狒狒与只吃香蕉的狒狒之 , 答案为C 选项。","notes":[],"missingOptionLabels":["A","B","C","D"],"pairingMode":"word-type-anchor-and-number","imageKeys":["numeric/20260717/quantity/500058.png"],"imageSourcePage":41}','numeric/20260717/quantity/500058.png');
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500059,4,'浓度问题+概率问题+整除性质','甲、乙两个箱子中分别装有不同数量的某种商品，总数不到100件。如果

从甲或乙箱子中随机拿出1件这种商品，拿到次品的概率分别为5%和10%。如
果将两箱内的商品混合后再随机拿出1件，则拿到次品的概率为6%,从乙箱中
随机拿出3件这种商品，均不为次品的概率X 在以下哪个范围内? 35







o','[{"label":"A","content":"X<72%"},{"label":"B","content":"72%≤X<81%"},{"label":"C","content":"81%≤X<90%"},{"label":"D","content":"90%≤X"}]','A','根据“拿到次品的概率为6%” ,可知甲乙共有50件商品，又根据“如果从甲或乙箱子中随机拿出1件这种商品，拿到次品的概率分别为5% 和10%。”可采用十字交叉法：
甲：5%
乙：10%
可得甲、乙箱子中商品件数之比为4:1,故乙箱子装有商品10件，其中有9件正品和1件次品。所以从乙箱子随机拿3件，均不为次品的概率
答案为A 选项。

⑩花生批注：
随机拿出3件这种商品，均不为次品的概率X 在以下哪个范围内? 35

⑪花生批注：
,可知总数为50 的倍数，总数小于100, 故总数为50。

⑫花生批注：
十字交叉法使用方法和适
用题型：
符合整体和两部分的关系且
可写成形式的都可适用十字交叉法，将A 代入十字式子可求得C之比；常用题型有平均数问题(可求得人数之比等),利润
求得成本之比；
可求得定价之比，等等),浓度
可求得溶液之比),比例关系
求得整体之比)。
本题总件数为整体，甲乙为两部分，拿到甲的次品
符则可使用十字交叉法解题。','数量关系600题','进阶','published','{"globalNumber":59,"sourceNumber":9,"typeLabel":"浓度问题+概率问题+整除性质","stemRich":[{"text":"甲、乙两个箱子中分别装有不同数量的某种商品，总数不到100件。如果\n\n从甲或乙箱子中随机拿出1件这种商品，拿到次品的概率分别为5%和10%。如\n果将两箱内的商品混合后再随机拿出1件，则拿到次品的概率为6%,从乙箱中\n随机拿出3件这种商品，均不为次品的概率X 在以下哪个范围内? 35\n\n\n\n\n\n\n\no"}],"annotatedStemRich":[{"text":"甲、乙两个箱子中分别装有不同数量的某种商品，总数不到100件。如果\n\n从甲或乙箱子中随机拿出1件这种商品，拿到次品的概率分别为5%和10%。如\n果将两箱内的商品混合后再随机拿出1件，则拿到次品的概率为6%,从乙箱中\n随机拿出3件这种商品，均不为次品的概率X 在以下哪个范围内? 35\n\n\n\n\n\n\n\no"}],"annotatedOptionRich":{"A":[{"text":"X<72%"}],"B":[{"text":"72%≤X<81%"}],"C":[{"text":"81%≤X<90%"}],"D":[{"text":"90%≤X\n"}]},"practicalAnalysis":"根据“拿到次品的概率为6%” ,可知甲乙共有50件商品，又根据“如果从甲或乙箱子中随机拿出1件这种商品，拿到次品的概率分别为5% 和10%。”可采用十字交叉法：\n甲：5%\n乙：10%\n可得甲、乙箱子中商品件数之比为4:1,故乙箱子装有商品10件，其中有9件正品和1件次品。所以从乙箱子随机拿3件，均不为次品的概率\n答案为A 选项。","notes":[{"marker":"⑩","text":"随机拿出3件这种商品，均不为次品的概率X 在以下哪个范围内? 35","matchScore":0.317},{"marker":"⑪","text":",可知总数为50 的倍数，总数小于100, 故总数为50。","matchScore":0.096},{"marker":"⑫","text":"十字交叉法使用方法和适\n用题型：\n符合整体和两部分的关系且\n可写成形式的都可适用十字交叉法，将A 代入十字式子可求得C之比；常用题型有平均数问题(可求得人数之比等),利润\n求得成本之比；\n可求得定价之比，等等),浓度\n可求得溶液之比),比例关系\n求得整体之比)。\n本题总件数为整体，甲乙为两部分，拿到甲的次品\n符则可使用十字交叉法解题。","matchScore":0.612}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500060,4,'简单计算','在下表中，小方格中的字母均为整数。若各行之和、各列之和、各对角线
