INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500061,4,'和差倍比与不定方程问题','某旅游公司定制甲、乙两种纪念品，第一次共定制50个。试销后根据反馈，

