INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500062,4,'和差倍比与不定方程问题','某企业去年全年收入1200万元，支出960万元。今年上半年和下半年，

企业支出比去年同期分别减少20%和15%,且全年收入与去年相同，总体盈余(收
入-支出)比去年增加172万元。问今年上半年支出比下半年?','[{"label":"A","content":"少160万元"},{"label":"B","content":"多160万元"},{"label":"C","content":"少108万元"},{"label":"D","content":"多108万元"}]','D','设去年上半年支出为 x, 下半年支出为y, 根据去年支出和今年支出减少量可列方程：①x+y=960,②0.2x+0.15y=172①。解得x=560, y=400。
①

①花生批注：
因为收入相同，盈余增加的量就是支出减少的量。
根据下降率可求今年上半年支出为560×(100%-20%)=448万元；今年的下半年支出为400×(100%-15%)=340万元。二者之差=448-340=108万元，答案为D选项。

⑦花生批注：
本题也可根据5、9、101的最小公倍数4545列方程：
即180000≤4545X≤189999; 该思路容易理解，但求解不易。

②花生批注：
共有60+42=102人','数量关系600题','进阶','published','{"globalNumber":62,"sourceNumber":2,"typeLabel":"和差倍比与不定方程问题","stemRich":[{"text":"某企业去年全年收入1200万元，支出960万元。今年上半年和下半年，\n\n企业支出比去年同期分别减少20%和15%,且全年收入与去年相同，总体盈余(收\n入-支出)比去年增加172万元。问今年上半年支出比下半年?"}],"annotatedStemRich":[{"text":"某企业去年全年收入1200万元，支出960万元。今年上半年和下半年，\n\n企业支出比去年同期分别减少20%和15%,且全年收入与去年相同，总体盈余(收\n入-支出)比去年增加172万元。问今年上半年支出比下半年?"}],"annotatedOptionRich":{"A":[{"text":" 少160万元"}],"B":[{"text":"  多160万元"}],"C":[{"text":" 少108万元"}],"D":[{"text":"  多108万元\n"}]},"practicalAnalysis":"设去年上半年支出为 x, 下半年支出为y, 根据去年支出和今年支出减少量可列方程：①x+y=960,②0.2x+0.15y=172①。解得x=560, y=400。\n①","notes":[{"marker":"①","text":"因为收入相同，盈余增加的量就是支出减少的量。\n根据下降率可求今年上半年支出为560×(100%-20%)=448万元；今年的下半年支出为400×(100%-15%)=340万元。二者之差=448-340=108万元，答案为D选项。","matchScore":0.319},{"marker":"⑦","text":"本题也可根据5、9、101的最小公倍数4545列方程：\n即180000≤4545X≤189999; 该思路容易理解，但求解不易。","matchScore":0.082},{"marker":"②","text":"共有60+42=102人","matchScore":0.038}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500063,4,'工程问题','某地采用传统销售模式，销售一批鸡蛋需要20天，销售一批桃子需要25天。

为推动销售，当地开启县领导直播带货模式，直播带货期间，鸡蛋的销售效率
提高为原来的2倍，桃子销售效率为原来的3倍；其余销售时间依然按照传统
模式进行，结果两种产品同时销售完成。那么销售期间直播带货的天数为多少

天?','[{"label":"A","content":"3"},{"label":"B","content":"5\n②"},{"label":"C","content":"8"},{"label":"D","content":"10"}]','B','②直播带货期间鸡蛋销售效率提高为原来的2倍，即传统销售和直播销售效率比=1:2,销售相同数量鸡蛋，传统销售和直播销售时间比 =2:1,即每直播带货一天，可减少1天用时；
同理，直播带货期间桃子销售效率提高为原来的3倍，即传统销售和直播销售效率比=1:3,销售相同数量桃子，传统销售和直播销售时间比=3:1, 即每直播带货一天，可减少2天用时；
假设直播带货天数为t, 根据“同时销售完成(即销售时间相等)”可列方程： 20-t=25-2t, 解得 t=5, 即直播带货5天，答案为B选项。
②12t+4t''=100,解得t=5。

②花生批注：
本题也可采用赋值法。
方法一：
可赋值鸡蛋、桃子传统销售效率均为1,即鸡蛋、桃子总量分别为20、25;
设直播带货天数t, 传统销售天数t'', 可列方程：
①2t+t³=20,
②3t+t''=25, 解得t=5; 方法二：
可赋值鸡蛋桃子原销售总量均为100,则鸡蛋销售效率为5,桃子销售效率为4; 设直播带货天数t, 传统销售天数t'', 可列方程：
①10t+5t’=100,
