INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500064,4,'行程问题','甲乙从A 地同时出发沿相同路线骑行去B地，甲匀速骑行，乙按比甲快
20%的速度骑行半程后降速为甲的一半，甲追上乙后又骑行了10分钟到达B地。

那么甲骑行用时多少分钟?','[{"label":"A","content":"24"},{"label":"B","content":"29"},{"label":"C","content":"32"},{"label":"D","content":"34"}]','A','如图所示，乙骑行前半程时，甲乙速度比=5:6,二者路程比=5:6,假设半程路程为6份(全程为12份),则乙走完半程时，甲走了5份，二者距离差=1份距离③ ;
之后乙速度变为2.5,甲乙速度比=5:2.5=2:1,甲追上乙时，二者路程比=2:1,即甲走2份距离，乙走1份距离⑨ ;
此时，甲距离终点还有5份距离，10分钟可走完，即1份需要2分钟，全程12份需要24分钟，答案为A选项。
③','数量关系600题','进阶','published','{"globalNumber":64,"sourceNumber":4,"typeLabel":"行程问题","stemRich":[{"text":"甲乙从A 地同时出发沿相同路线骑行去B地，甲匀速骑行，乙按比甲快\n20%的速度骑行半程后降速为甲的一半，甲追上乙后又骑行了10分钟到达B地。\n\n那么甲骑行用时多少分钟?"}],"annotatedStemRich":[{"text":"甲乙从A 地同时出发沿相同路线骑行去B地，甲匀速骑行，乙按比甲快\n20%的速度骑行半程后降速为甲的一半，甲追上乙后又骑行了10分钟到达B地。\n\n那么甲骑行用时多少分钟?"}],"annotatedOptionRich":{"A":[{"text":"24"}],"B":[{"text":"29"}],"C":[{"text":"32","bold":true}],"D":[{"text":"34","bold":true},{"text":"\n"}]},"practicalAnalysis":"如图所示，乙骑行前半程时，甲乙速度比=5:6,二者路程比=5:6,假设半程路程为6份(全程为12份),则乙走完半程时，甲走了5份，二者距离差=1份距离③ ;\n之后乙速度变为2.5,甲乙速度比=5:2.5=2:1,甲追上乙时，二者路程比=2:1,即甲走2份距离，乙走1份距离⑨ ;\n此时，甲距离终点还有5份距离，10分钟可走完，即1份需要2分钟，全程12份需要24分钟，答案为A选项。\n③","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500065,4,'概率问题之几何概型','某商店门口排了一列100米长的直线队伍，小明随机站在队伍的某处。小
明的妈妈在队伍里随机找个位置喊小明的名字，如果小明距离她不超过25米，
就能听到。问小明听到他妈妈呼喊的概率是多少?

B.


C. D.','[{"label":"A","content":"（图形选项，见题目原图）"},{"label":"B","content":"（图形选项，见题目原图）"},{"label":"C","content":"（图形选项，见题目原图）"},{"label":"D","content":"（图形选项，见题目原图）"}]','C','根据题意可画图⑤ :
