INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500067,4,'和差倍比与不定方程问题+整除问题','某企业员工编号为6位自然数，其中前两位代表入职年份的最后两位数，

