INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500072,4,'年龄问题','2018年父亲年龄是女儿年龄的6倍，是母亲年龄的1.2倍。已知女儿出生
当年(按0岁计算)母亲24岁，则哪一年父母年龄之和是女儿的4倍?','[{"label":"A","content":"2036"},{"label":"B","content":"2039"},{"label":"C","content":"2042"},{"label":"D","content":"2045"}]','B','设2018年母亲年龄为a, 则父亲年龄为1.2a, 女儿年龄为0.2a;
根据“年龄差不变”可知，a-0.2a=0.8a=24, 解得 a=30, 即2018年三人年龄分别为36岁、30岁、6岁；
设 t 年后父母年龄之和是女儿的4倍，可列方程：36+t+30+t=4×(6+t), 解得t=21, 即2039年满足题目要求，答案为B 选项。','数量关系600题','进阶','published','{"globalNumber":72,"sourceNumber":2,"typeLabel":"年龄问题","stemRich":[{"text":"2018年父亲年龄是女儿年龄的6倍，是母亲年龄的1.2倍。已知女儿出生\n当年(按0岁计算)母亲24岁，则哪一年父母年龄之和是女儿的4倍?"}],"annotatedStemRich":[{"text":"2018年父亲年龄是女儿年龄的6倍，是母亲年龄的1.2倍。已知女儿出生\n当年(按0岁计算)母亲24岁，则哪一年父母年龄之和是女儿的4倍?"}],"annotatedOptionRich":{"A":[{"text":"2036"}],"B":[{"text":"2039"}],"C":[{"text":"2042"}],"D":[{"text":"2045\n"}]},"practicalAnalysis":"设2018年母亲年龄为a, 则父亲年龄为1.2a, 女儿年龄为0.2a;\n根据“年龄差不变”可知，a-0.2a=0.8a=24, 解得 a=30, 即2018年三人年龄分别为36岁、30岁、6岁；\n设 t 年后父母年龄之和是女儿的4倍，可列方程：36+t+30+t=4×(6+t), 解得t=21, 即2039年满足题目要求，答案为B 选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500073,4,'工程问题','某超市设有10个人工收银台。周末10个收银台全开，顾客结账平均排队
20分钟。为提高效率，超市撤了4个人工收银台，并改造为6个自助收银台。

若自助收银的效率是人工收银效率的90%。改造后，周末当人工收银台和自助
收银台全开，预计顾客结账平均排队耗时约为多少分钟?','[{"label":"A","content":"12 分钟"},{"label":"B","content":"14 分钟"},{"label":"C","content":"16 分钟"},{"label":"D","content":"18 分钟"}]','D','假设原来人工收银台效率为1,则原来效率和为10,现在效率和=6个人工收银台效率+6个自助收银台效率=6+6×0.9=11.4;
排队时间和结账效率应成反比 ⑧,效率比=10:11 .4,则时间比 =11.4:10=20:t, ,答案为D选项。

③花生批注：
可以把解决排队问题当作“工作总量”,平均排队时间即“完成工作”的时间，收银效率即解决排队问题的效率，所以效率和时间成反比。','数量关系600题','进阶','published','{"globalNumber":73,"sourceNumber":3,"typeLabel":"工程问题","stemRich":[{"text":"某超市设有10个人工收银台。周末10个收银台全开，顾客结账平均排队\n20分钟。为提高效率，超市撤了4个人工收银台，并改造为6个自助收银台。\n\n若自助收银的效率是人工收银效率的90%。改造后，周末当人工收银台和自助\n收银台全开，预计顾客结账平均排队耗时约为多少分钟?"}],"annotatedStemRich":[{"text":"某超市设有10个人工收银台。周末10个收银台全开，顾客结账平均排队\n20分钟。为提高效率，超市撤了4个人工收银台，并改造为6个自助收银台。\n\n若自助收银的效率是人工收银效率的90%。改造后，周末当人工收银台和自助\n收银台全开，预计顾客结账平均排队耗时约为多少分钟?"}],"annotatedOptionRich":{"A":[{"text":"12  分钟"}],"B":[{"text":"14  分钟"}],"C":[{"text":"16  分钟"}],"D":[{"text":"18  分钟\n"}]},"practicalAnalysis":"假设原来人工收银台效率为1,则原来效率和为10,现在效率和=6个人工收银台效率+6个自助收银台效率=6+6×0.9=11.4;\n排队时间和结账效率应成反比 ⑧,效率比=10:11 .4,则时间比 =11.4:10=20:t, ,答案为D选项。","notes":[{"marker":"③","text":"可以把解决排队问题当作“工作总量”,平均排队时间即“完成工作”的时间，收银效率即解决排队问题的效率，所以效率和时间成反比。","matchScore":0.181}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
