INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500086,4,'日期星期问题','某市在工作日对本地机动车实行尾号限行，规则为：周一限行“1”“9”,

： 周二限行“2”“8”,周三限行“3”“7”,周四限行“4”“6”,周五限行“5”“0”。
干星
已知某年7月份尾号“1”“9”和“5”“0”的限行天数一样多，则该年的7
期内
星期 月1日是周几?
