INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500092,4,'工程问题','一项工程由甲、乙两种设备完成，2台甲设备的工作量恰好是5台乙设备
的工作量。5台甲设备和10台乙设备工作4天后，剩余的工作量恰好是2台乙
设备5天的工作量。那么10台甲设备和5台乙设备工作2天，可完成总工作

量的比例是多少?','[{"label":"A","content":"40%"},{"label":"B","content":"50%"},{"label":"C","content":"60%"},{"label":"D","content":"70%"}]','C','根据题意可知甲乙效率之比为5:2③,直接将甲乙效率分别 2甲=5乙，则甲：乙=5:2。赋值为5、2;
(5甲+10乙)×4+2乙×5=200,即工作总量为200;(10甲+5乙)×2 =120,即后者完成比例为120÷200=60%,答案为C 选项。

