INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500093,4,'和差倍比问题','老李家的草莓园开展采摘活动，每位游客进园可以免费吃，并且带走2斤
草莓。每位游客在采摘过程中平均吃1斤草莓。目前老李家的草莓园估计有成

熟草莓2000斤，并且每天还会有40斤草莓成熟，为保证采摘活动至少可以持
续20天，那么平均每天最多接待多少位游客?','[{"label":"A","content":"36"},{"label":"B","content":"46"},{"label":"C","content":"56"},{"label":"D","content":"66"}]','B','按照最少持续时间20天计算，草莓园一共有草莓2000+20×40 =2800斤，每天可供应草莓=2800÷20=140斤；每位游客“连吃带拿”草莓3斤，则每天可接待游客数量=140÷3≈46.7人，需向下取整，即每天最多接待46 位游客，答案为B 选项。','数量关系600题','进阶','published','{"globalNumber":93,"sourceNumber":3,"typeLabel":"和差倍比问题","stemRich":[{"text":"老李家的草莓园开展采摘活动，每位游客进园可以免费吃，并且带走2斤\n草莓。每位游客在采摘过程中平均吃1斤草莓。目前老李家的草莓园估计有成\n\n熟草莓2000斤，并且每天还会有40斤草莓成熟，为保证采摘活动至少可以持\n续20天，那么平均每天最多接待多少位游客?"}],"annotatedStemRich":[{"text":"老李家的草莓园开展采摘活动，每位游客进园可以免费吃，并且带走2斤\n草莓。每位游客在采摘过程中平均吃1斤草莓。目前老李家的草莓园估计有成\n\n熟草莓2000斤，并且每天还会有40斤草莓成熟，为保证采摘活动至少可以持\n续20天，那么平均每天最多接待多少位游客?"}],"annotatedOptionRich":{"A":[{"text":"36"}],"B":[{"text":"46"}],"C":[{"text":"56"}],"D":[{"text":"66\n"}]},"practicalAnalysis":"按照最少持续时间20天计算，草莓园一共有草莓2000+20×40 =2800斤，每天可供应草莓=2800÷20=140斤；每位游客“连吃带拿”草莓3斤，则每天可接待游客数量=140÷3≈46.7人，需向下取整，即每天最多接待46 位游客，答案为B 选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
