INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500096,4,'行程问题','小孟驾驶汽车沿一条笔直公路匀速行驶。某一时刻，小孟先看到路边的第
一个里程碑，上面刻的公里数X为两位数。半小时后，他又看到第二个里程碑，
上面刻的公里数Y恰好由X的十位数和个位数交换位置所成。又过了半小时，
他看到第三个里程碑，上面刻的Z 恰好由X的两位数中间添一个0所成。再过
一小时，小孟自看到第一个里程碑起共驾驶了多少公里?','[{"label":"A","content":"120"},{"label":"B","content":"150"},{"label":"C","content":"180"},{"label":"D","content":"200"}]','C','假设第一个里程碑的十位为 a, 个位为b, 则 X=10a+b, Y=10b+a,Z=100a+b ⑦;
由于小孟是匀速行驶，所以X 、Y 、Z 构成等差数列，则2Y=X+Z, 可解得 6a=b; 由于a 、b 都要小于10,则a 只能是 1 ,b 只能是6;
代入式子得： X=16,Z=106, 即前一小时行驶90km, 一共2小时，共行驶 180km, 答案为C选项⑨

⑦花生批注：
第一个里程碑：a 是十位，所以要表示成10a;
第二个里程碑：b 是十位，所以要表示成10b;
第三个里程碑：a 是百位，所以要表示成100a。','数量关系600题','进阶','published','{"globalNumber":96,"sourceNumber":6,"typeLabel":"行程问题","stemRich":[{"text":"小孟驾驶汽车沿一条笔直公路匀速行驶。某一时刻，小孟先看到路边的第\n一个里程碑，上面刻的公里数X为两位数。半小时后，他又看到第二个里程碑，\n上面刻的公里数Y恰好由X的十位数和个位数交换位置所成。又过了半小时，\n他看到第三个里程碑，上面刻的Z 恰好由X的两位数中间添一个0所成。再过\n一小时，小孟自看到第一个里程碑起共驾驶了多少公里?"}],"annotatedStemRich":[{"text":"小孟驾驶汽车沿一条笔直公路匀速行驶。某一时刻，小孟先看到路边的第\n一个里程碑，上面刻的公里数X为两位数。半小时后，他又看到第二个里程碑，\n上面刻的公里数Y恰好由X的十位数和个位数交换位置所成。又过了半小时，\n他看到第三个里程碑，上面刻的Z 恰好由X的两位数中间添一个0所成。再过\n一小时，小孟自看到第一个里程碑起共驾驶了多少公里?"}],"annotatedOptionRich":{"A":[{"text":"120"}],"B":[{"text":"150"}],"C":[{"text":"180"}],"D":[{"text":"200\n"},{"text":"数量关系600","bold":true},{"text":"\n"}]},"practicalAnalysis":"假设第一个里程碑的十位为 a, 个位为b, 则 X=10a+b, Y=10b+a,Z=100a+b ⑦;\n由于小孟是匀速行驶，所以X 、Y 、Z 构成等差数列，则2Y=X+Z, 可解得 6a=b; 由于a 、b 都要小于10,则a 只能是 1 ,b 只能是6;\n代入式子得： X=16,Z=106, 即前一小时行驶90km, 一共2小时，共行驶 180km, 答案为C选项⑨","notes":[{"marker":"⑦","text":"第一个里程碑：a 是十位，所以要表示成10a;\n第二个里程碑：b 是十位，所以要表示成10b;\n第三个里程碑：a 是百位，所以要表示成100a。","matchScore":0.132}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500097,4,'容斥问题','嘉乐中学49名学生参加音乐兴趣班，每人至少参加一个班。已知参加钢
琴班的有28人，参加吉他班的有35人，参加二胡班的有19人，其中有3名

学生三个兴趣班都参加了。该校有多少名学生只参加了一个兴趣班?','[{"label":"A","content":"16"},{"label":"B","content":"17\n⑨"},{"label":"C","content":"18"},{"label":"D","content":"19\n容斥问题常用解题方式：\n①直接代入公式：全部人数一圈外人数=人次之和一重复部分；\n②有时需要另一种计数方式，圈内总人数=只参加一种的人数+只参加两种的人数+……+所有都参加的人数(此公式只在部分题目中需要使用，编者称之为隐含公式)。\n易错点：\n误将“符合A和B”当做“只符合 A和 B” , 前者包含“符合A、B、C”的元素，而后者不包含。"}]','D','根据容斥公式⑨:总人数=总人次-只参加两项人数-2×三项都参加人数，可得只参加两项人数=28+35+19-2×3-49=27人；
再根据公式：总人数=只参加一项人数+只参加两项人数+三项都参加人数，可得只参加一个兴趣班人数=49-27-3=19人，答案为D选项。

⑨花生批注：
C.18 D.19
