INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500103,4,'日期星期问题','股数
缅甸 一 周有8天，多的1天是把星期三上午和下午拆分成了2天，星期三
角三
上半天仍称为星期三而星期三下半天则成为“罗喉”。已知2022年1月1日
是周六，那么2020年上半年和下半年“罗瞑”的天数相差多少个?
3),
、17)','[{"label":"A","content":"0"},{"label":"B","content":"1"},{"label":"C","content":"2"},{"label":"D","content":"3"}]','B','2020年1月1日到2022年1月1日，星期应往后推3天④ , 2022年1月1日是周六，则可逆推2020年1月1日是周三；
⑤

③花生批注：
三角形三边比例为勾股数时，则该三角形为直角三角形。
常见勾股数：
(3、4、5),(5、12、13),
(7、24、25),(8、15、17)

④花生批注：
平年(365天=52周+1天 ) 星期往后推1天，
闰年(366天=52周+2天)
星期往后推2天； 2020年为闰年， 2021年为平年。
缅甸一周有8天，多的1天是把星期三上午和下午拆分成了2天，星期三上半天仍称为星期三而星期三下半天则成为“罗喉”。已知2022年1月1日是周六，那么2020年上半年和下半年“罗瞑”的天数相差多少个?

⑤花生批注：
2 0 2 0 年 1 月 1 日至6月30日，共182天，包含26周，共26个“罗睽”; 2 0 2 0 年 7 月 1 日至12月31日，共184天，包含26周余2天 ⑤,余下两天为周三周四，即共27个“罗睽”;二者相差1天，答案为B 选项。
因 1 月 1日是周三，
则之后第182天(26周整) 的7月1日也是周三；
下半年可分成“周三周四 +26 周”。','数量关系600题','进阶','published','{"globalNumber":103,"sourceNumber":3,"typeLabel":"日期星期问题","stemRich":[{"text":"股数\n缅甸 一 周有8天，多的1天是把星期三上午和下午拆分成了2天，星期三\n角三\n上半天仍称为星期三而星期三下半天则成为“罗喉”。已知2022年1月1日\n是周六，那么2020年上半年和下半年“罗瞑”的天数相差多少个?\n3),\n、17)"}],"annotatedStemRich":[{"text":"股数\n缅甸 一 周有8天，多的1天是把星期三上午和下午拆分成了2天，星期三\n角三\n上半天仍称为星期三而星期三下半天则成为“罗喉”。已知2022年1月1日\n是周六，那么2020年上半年和下半年“罗瞑”的天数相差多少个?\n3),\n、17)"}],"annotatedOptionRich":{"A":[{"text":"0"}],"B":[{"text":"1"}],"C":[{"text":"2"}],"D":[{"text":"3\n"}]},"practicalAnalysis":"2020年1月1日到2022年1月1日，星期应往后推3天④ , 2022年1月1日是周六，则可逆推2020年1月1日是周三；\n⑤","notes":[{"marker":"③","text":"三角形三边比例为勾股数时，则该三角形为直角三角形。\n常见勾股数：\n(3、4、5),(5、12、13),\n(7、24、25),(8、15、17)","matchScore":0.312},{"marker":"④","text":"平年(365天=52周+1天 ) 星期往后推1天，\n闰年(366天=52周+2天)\n星期往后推2天； 2020年为闰年， 2021年为平年。\n缅甸一周有8天，多的1天是把星期三上午和下午拆分成了2天，星期三上半天仍称为星期三而星期三下半天则成为“罗喉”。已知2022年1月1日是周六，那么2020年上半年和下半年“罗瞑”的天数相差多少个?","matchScore":0.81},{"marker":"⑤","text":"2 0 2 0 年 1 月 1 日至6月30日，共182天，包含26周，共26个“罗睽”; 2 0 2 0 年 7 月 1 日至12月31日，共184天，包含26周余2天 ⑤,余下两天为周三周四，即共27个“罗睽”;二者相差1天，答案为B 选项。\n因 1 月 1日是周三，\n则之后第182天(26周整) 的7月1日也是周三；\n下半年可分成“周三周四 +26 周”。","matchScore":0.207}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500104,4,'工程问题','工厂生产某产品，如按正常计划生产，每天生产50个，则在4月底完工；

如每天生产60个，则在4月12日完工；如每天生产90个， 会再提前25天⑥ 。
前25 那么原计划完工时间是几月几日?
产60','[{"label":"A","content":"4 月 2 4 日"},{"label":"B","content":"4 月 2 5 日"},{"label":"C","content":"4 月 2 6 日"},{"label":"D","content":"4 月 2 7 日"}]','D','⑦每天生产60个和90个的生产效率之比=60:90=2:3,生产总量相同，时间比=3:2,则一份对应25天，即每天生产60个需要75天；
每天生产50个和60个的效率比=50:60=5:6,时间比=6:5,即5份对应75天时间，1份为15天，后者提前一份时间(15天)可在4月12日完工，即计划完工时间为4月27日，答案为D选项。
⑦

⑥花生批注：
需要注意：
并非较正常计划提前25
天，而是较“每天生产60 个”提前25天。
工厂生产某产品，如按正常计划生产，每天生产50个，则在4月底完工；如每天生产60个，则在4月12日完工；如每天生产90个，会再提前25天⑥ 。那么原计划完工时间是几月几日?

⑦花生批注：
本题也可采用方程法解题：
假设每天生产60个需要x 天，则 6 0x=90×(x-25),
解得x=75,
总工作量=60×75;
每天生产50个，
需要时间=60×75÷50=90天；即原计划完工时间
