INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500110,4,'年龄问题+最值问题之和定最值','公司研发部门共5名员工，年龄各不相同，其中年龄最大的比最小的大10

岁。某年，年龄最大的2人年龄之和是最小的2人年龄之和的1.25倍；2年后，
除年龄排名居中的1人外其余4人年龄之和为125岁。那么再过2年，年龄排

名第三的员工最大可能为多少岁?','[{"label":"A","content":"33"},{"label":"B","content":"34"},{"label":"C","content":"35"},{"label":"D","content":"36"}]','C','根据“2年后除年龄排名居中的1人外其余4人年龄之和为 125岁”可知，2年前，此4人年龄和=125-2×4=117岁；
根据“某年年龄最大的2人年龄之和是最小的2人年龄之和的1.25倍”可知，二者之比 = 5 : 4 ,即年龄最大2人年,年龄最小 2人年龄和为52岁；
要想年龄第三的员工年龄尽量大，则年龄第二的员工年龄应尽量大，年龄最大的员工尽量小⑨,即当年年龄第一、第二、第三的员工年龄分别为33岁、 32岁、31 岁；
根据“年龄最大的比最小的大10岁”可知，当年年龄最小的员工是23岁，第二小的员工是29岁，符合大小排序；
则当年后的4年(2年后再过2年),年龄第三的员工最大可能35岁，答案为C 选项。

⑬花生批注：
年龄第三要小于年龄第二，年龄第一和第二和一定，第二尽量大，则第一尽量小。','数量关系600题','进阶','published','{"globalNumber":110,"sourceNumber":10,"typeLabel":"年龄问题+最值问题之和定最值","stemRich":[{"text":"公司研发部门共5名员工，年龄各不相同，其中年龄最大的比最小的大10\n\n岁。某年，年龄最大的2人年龄之和是最小的2人年龄之和的1.25倍；2年后，\n除年龄排名居中的1人外其余4人年龄之和为125岁。那么再过2年，年龄排\n\n名第三的员工最大可能为多少岁?"}],"annotatedStemRich":[{"text":"公司研发部门共5名员工，年龄各不相同，其中年龄最大的比最小的大10\n\n岁。某年，年龄最大的2人年龄之和是最小的2人年龄之和的1.25倍；2年后，\n除年龄排名居中的1人外其余4人年龄之和为125岁。那么再过2年，年龄排\n\n名第三的员工最大可能为多少岁?"}],"annotatedOptionRich":{"A":[{"text":"33"}],"B":[{"text":"34"}],"C":[{"text":"35","bold":true}],"D":[{"text":"36","bold":true},{"text":"\n"}]},"practicalAnalysis":"根据“2年后除年龄排名居中的1人外其余4人年龄之和为 125岁”可知，2年前，此4人年龄和=125-2×4=117岁；\n根据“某年年龄最大的2人年龄之和是最小的2人年龄之和的1.25倍”可知，二者之比 = 5 : 4 ,即年龄最大2人年,年龄最小 2人年龄和为52岁；\n要想年龄第三的员工年龄尽量大，则年龄第二的员工年龄应尽量大，年龄最大的员工尽量小⑨,即当年年龄第一、第二、第三的员工年龄分别为33岁、 32岁、31 岁；\n根据“年龄最大的比最小的大10岁”可知，当年年龄最小的员工是23岁，第二小的员工是29岁，符合大小排序；\n则当年后的4年(2年后再过2年),年龄第三的员工最大可能35岁，答案为C 选项。","notes":[{"marker":"⑬","text":"年龄第三要小于年龄第二，年龄第一和第二和一定，第二尽量大，则第一尽量小。","matchScore":0.098}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
