INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500115,4,'日期星期问题+等差数列','小明做值日的时候发现教室的挂历上显示的是一周前的日期，于是小明将挂历的日期翻到今天，恰好所翻页的日期加起来是175。问今天是几号?','[{"label":"A","content":"24"},{"label":"B","content":"25"},{"label":"C","content":"28"},{"label":"D","content":"29"}]','D','利用等差数列⑤求和公式可得：S,=175=7× 中位数，解得中位数为25(第4天),则第7天为28号，今天为29号，答案为D选项。

⑤花生批注：
等差数列常用知识点：
aₙ=a₁+(n-1)d, a.=aₙ+(m-n)d; 例如，
a₆=a₁+5d,a ₁0=a₃+7d;
S,=n×中位数=n×平均数；例如，1、3、5、7、9, 数列之和=5×5=25;
例如，2、4、6、8, 数量之和=20。','数量关系600题','进阶','published','{"globalNumber":115,"sourceNumber":5,"typeLabel":"日期星期问题+等差数列","stemRich":[{"text":"小明做值日的时候发现教室的挂历上显示的是一周前的日期，于是小明将 挂历的日期翻到今天，恰好所翻页的日期加起来是175。问今天是几号?"}],"annotatedStemRich":[{"text":"小明做值日的时候发现教室的挂历上显示的是一周前的日期，于是小明将 挂历的日期翻到今天，恰好所翻页的日期加起来是175。问今天是几号?"}],"annotatedOptionRich":{"A":[{"text":"24"}],"B":[{"text":"25","bold":true}],"C":[{"text":"28"}],"D":[{"text":"29\n"}]},"practicalAnalysis":"利用等差数列⑤求和公式可得：S,=175=7× 中位数，解得中位数为25(第4天),则第7天为28号，今天为29号，答案为D选项。","notes":[{"marker":"⑤","text":"等差数列常用知识点：\naₙ=a₁+(n-1)d, a.=aₙ+(m-n)d; 例如，\na₆=a₁+5d,a ₁0=a₃+7d;\nS,=n×中位数=n×平均数；例如，1、3、5、7、9, 数列之和=5×5=25;\n例如，2、4、6、8, 数量之和=20。","matchScore":0.097}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500116,4,'几何问题','小明有一个底面半径为10厘米的圆柱形水瓶，小红往里面加水，水深9
