INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500118,4,'一般排列组合问题','甲、 乙两名 职工负 责国庆7天长 假的值 班工作 ，每天 安排 1人值 班。已 知
乙至少值了2天班，且在国庆期间任一 天结束后，甲的累计值班天数都比乙的多。
面，
问两人的值班日期安排有多少种不同的可能?
可。','[{"label":"A","content":"6"},{"label":"B","content":"9"},{"label":"C","content":"10"},{"label":"D","content":"14"}]','D','⑨根据题意可知乙值班天数只能为2天或者3天，且乙最早从3号开始值班才能满足条件。⑩ 分情况讨论。
当乙值班 2 天时：先让乙在剩余的 5 天内选择 2 天，共有 C²=10 种安排，但此时包含“甲甲乙乙甲甲甲”的情况，需要排除，其他情况均满足要求，即有10- 1=9种可能四；
当乙值班3天时：若要满足在国庆期间任一天结束后，甲的累计值班天数都比乙的多，须确保最后一天必为乙 ②,再让乙从剩余4天选2天，共有C²=6 种安排，但此时包含“甲甲乙乙甲甲乙”的情况，需要排除，其他的情况均满足要求，即有6-1=5种可能；
综上，满足所有条件的情况数共有9+5=14种，答案为D 选项。

⑨花生批注：
此题也可枚举，尽量全面，枚举出超过10种情况即可。

⑩花生批注：
若乙1号值班，则1号结束时甲的值班天数比乙少，不符合要求；若甲1号值班，乙2号值班，则2号结束时甲的值班天数与乙一样多，不符合要求。故乙最早从3 号开始值班，甲在1、2号值班。

⑪花生批注：
当乙值班3天时，必然有“甲甲甲甲乙乙乙”“甲甲甲乙甲乙乙”等等情况满足题目要求，一定大于10种可能，答案只能选D选项。

⑫花生批注：
若最后一天为甲，则存在甲、乙均3天的情况。
例：“甲甲甲乙乙乙甲、甲甲乙乙乙甲甲”等情况。','数量关系600题','进阶','published','{"globalNumber":118,"sourceNumber":8,"typeLabel":"一般排列组合问题","stemRich":[{"text":"甲、 乙两名 职工负 责国庆7天长 假的值 班工作 ，每天 安排 1人值 班。已 知\n乙至少值了2天班，且在国庆期间任一 天结束后，甲的累计值班天数都比乙的多。\n面，\n问两人的值班日期安排有多少种不同的可能?\n可。"}],"annotatedStemRich":[{"text":"甲、 乙两名 职工负 责国庆7天长 假的值 班工作 ，每天 安排 1人值 班。已 知\n乙至少值了2天班，且在国庆期间任一 天结束后，甲的累计值班天数都比乙的多。\n面，\n问两人的值班日期安排有多少种不同的可能?\n可。"}],"annotatedOptionRich":{"A":[{"text":"6"}],"B":[{"text":"9"}],"C":[{"text":"10"}],"D":[{"text":"14\n"}]},"practicalAnalysis":"⑨根据题意可知乙值班天数只能为2天或者3天，且乙最早从3号开始值班才能满足条件。⑩ 分情况讨论。\n当乙值班 2 天时：先让乙在剩余的 5 天内选择 2 天，共有 C²=10 种安排，但此时包含“甲甲乙乙甲甲甲”的情况，需要排除，其他情况均满足要求，即有10- 1=9种可能四；\n当乙值班3天时：若要满足在国庆期间任一天结束后，甲的累计值班天数都比乙的多，须确保最后一天必为乙 ②,再让乙从剩余4天选2天，共有C²=6 种安排，但此时包含“甲甲乙乙甲甲乙”的情况，需要排除，其他的情况均满足要求，即有6-1=5种可能；\n综上，满足所有条件的情况数共有9+5=14种，答案为D 选项。","notes":[{"marker":"⑨","text":"此题也可枚举，尽量全面，枚举出超过10种情况即可。","matchScore":0.026},{"marker":"⑩","text":"若乙1号值班，则1号结束时甲的值班天数比乙少，不符合要求；若甲1号值班，乙2号值班，则2号结束时甲的值班天数与乙一样多，不符合要求。故乙最早从3 号开始值班，甲在1、2号值班。","matchScore":0.151},{"marker":"⑪","text":"当乙值班3天时，必然有“甲甲甲甲乙乙乙”“甲甲甲乙甲乙乙”等等情况满足题目要求，一定大于10种可能，答案只能选D选项。","matchScore":0.173},{"marker":"⑫","text":"若最后一天为甲，则存在甲、乙均3天的情况。\n例：“甲甲甲乙乙乙甲、甲甲乙乙乙甲甲”等情况。","matchScore":0.101}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500119,4,'和差倍比问题','一项考试每人需参加8次测验，最终成绩为去掉最高分与最低分后剩余成
绩的平均值。小张参加这项考试，每次测验分数各不相同且均为大于70、小于

90的整数。已知前3次的平均分比前5次的高2分，后3次的平均分比后5次
的低2分，第4次和第5次平均分为80分， 第2次和第7次成绩被去掉。那

么第2次和第7次的成绩最少差多少分?','[{"label":"A","content":"10"},{"label":"B","content":"11"},{"label":"C","content":"12"},{"label":"D","content":"18"}]','C','要想第2次和第7次成绩之差尽量小，应“大的”尽量小，“小的”尽量大；
设前 5 次平均分为x, 则前 3 次为 x+2, 根据题意可列方程为
3(x+2)+160=5x, 解得x=83, 则前三次平均分为85分；
设后3次平均分为y, 则后5次为y+2, 可列方程：3y+160=5(y+2), 解得 y=75, 则后三次平均分为75;
根据所求结果可知，前三次平均分高，第2次“大的”应尽量小，可取值 86;第7次“小的”应尽量大，取值74;
综上，二者分差最小为12分，答案为C 选项。

⑬花生批注：
前三次分数可分别为86、','数量关系600题','进阶','published','{"globalNumber":119,"sourceNumber":9,"typeLabel":"和差倍比问题","stemRich":[{"text":"一项考试每人需参加8次测验，最终成绩为去掉最高分与最低分后剩余成\n绩的平均值。小张参加这项考试，每次测验分数各不相同且均为大于70、小于\n\n90的整数。已知前3次的平均分比前5次的高2分，后3次的平均分比后5次\n的低2分，第4次和第5次平均分为80分， 第2次和第7次成绩被去掉。那\n\n么第2次和第7次的成绩最少差多少分?"}],"annotatedStemRich":[{"text":"一项考试每人需参加8次测验，最终成绩为去掉最高分与最低分后剩余成\n绩的平均值。小张参加这项考试，每次测验分数各不相同且均为大于70、小于\n\n90的整数。已知前3次的平均分比前5次的高2分，后3次的平均分比后5次\n的低2分，第4次和第5次平均分为80分， 第2次和第7次成绩被去掉。那\n\n么第2次和第7次的成绩最少差多少分?"}],"annotatedOptionRich":{"A":[{"text":"10"}],"B":[{"text":"11"}],"C":[{"text":"12"}],"D":[{"text":"18\n"}]},"practicalAnalysis":"要想第2次和第7次成绩之差尽量小，应“大的”尽量小，“小的”尽量大；\n设前 5 次平均分为x, 则前 3 次为 x+2, 根据题意可列方程为\n3(x+2)+160=5x, 解得x=83, 则前三次平均分为85分；\n设后3次平均分为y, 则后5次为y+2, 可列方程：3y+160=5(y+2), 解得 y=75, 则后三次平均分为75;\n根据所求结果可知，前三次平均分高，第2次“大的”应尽量小，可取值 86;第7次“小的”应尽量大，取值74;\n综上，二者分差最小为12分，答案为C 选项。","notes":[{"marker":"⑬","text":"前三次分数可分别为86、","matchScore":0.044}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500120,4,'行程问题','甲、乙两人以相同速度一起骑车从A地前往B地。同行1小时后，两人休
息20分钟，然后甲继续原速出发，此时乙发现有重要物品未带，原速返回A

地去取，到达A地后立即开车前往B地。最终乙比甲提前12分钟到达B地。
已知开车速度是骑行速度的5倍，那么甲全程用了多少分钟?','[{"label":"A","content":"165"},{"label":"B","content":"175"},{"label":"C","content":"185"},{"label":"D","content":"195"}]','C','如图所示⑩,设二者同行1小时后到达M 点，此时甲继续从 ⑭花生批注：
