INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500121,4,'年龄问题','爷爷和孙子的属相相同。孙子今年13岁，此后5年内的某一年，爷爷年

龄恰好是孙子年龄的4倍，则爷爷比孙子大多少岁?','[{"label":"A","content":"60"},{"label":"B","content":"72"},{"label":"C","content":"36"},{"label":"D","content":"48"}]','D','爷爷和孙子属相相同，二者年龄差应是12的倍数。某一年爷爷年龄是孙子4倍，爷爷年龄为偶数，二者年龄差也是偶数，即孙子年龄也应为偶数。
假设验证即可：
1 年后，孙子14岁，爷爷是其4倍，即56岁，二者年龄差非12倍数；
2年后，孙子15岁，非偶数；
3年后，孙子16岁，爷爷是其4倍，即64岁，二者年龄差为48,是12倍数，所以爷爷比孙子大48岁，答案为D选项。','数量关系600题','进阶','published','{"globalNumber":121,"sourceNumber":1,"typeLabel":"年龄问题","stemRich":[{"text":"爷爷和孙子的属相相同。孙子今年13岁，此后5年内的某一年，爷爷年\n\n龄恰好是孙子年龄的4倍，则爷爷比孙子大多少岁?"}],"annotatedStemRich":[{"text":"爷爷和孙子的属相相同。孙子今年13岁，此后5年内的某一年，爷爷年\n\n龄恰好是孙子年龄的4倍，则爷爷比孙子大多少岁?"}],"annotatedOptionRich":{"A":[{"text":"60"}],"B":[{"text":"72"}],"C":[{"text":"36"}],"D":[{"text":"48\n"}]},"practicalAnalysis":"爷爷和孙子属相相同，二者年龄差应是12的倍数。某一年爷爷年龄是孙子4倍，爷爷年龄为偶数，二者年龄差也是偶数，即孙子年龄也应为偶数。\n假设验证即可：\n1 年后，孙子14岁，爷爷是其4倍，即56岁，二者年龄差非12倍数；\n2年后，孙子15岁，非偶数；\n3年后，孙子16岁，爷爷是其4倍，即64岁，二者年龄差为48,是12倍数，所以爷爷比孙子大48岁，答案为D选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500122,4,'和差倍比问题','老刘家有100亩草场，平均每亩草场年产草料4吨。草场上饲养了羊、驴、

牛共252头，平均每头羊年需草料1吨，每头驴年需草料2吨，每头牛年需草料
5吨。去年老刘家草场恰好能满足草料需求，今年老刘没有饲养羊，但驴和牛的

数量都翻了一倍，草场仍恰好满足草料需求，则老刘家去年饲养了多少头牛?','[{"label":"A","content":"32"},{"label":"B","content":"33"},{"label":"C","content":"34"},{"label":"D","content":"35\n①"}]','A','由题意可知，草场每年可生产100×4-400吨草料。设去年养了
x 头牛，y 头驴，(252-x-y) 头羊。可列方程组：
