INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500124,4,'工程问题','甲、乙两个工程队合作完成一项工程，甲每工作3天休息1天，乙每工作

5天休息2天。若甲先工作，2天后乙加入，则再用21天完工；若乙先工作，
12天后甲加入，则再用15天完工。甲单独完成该项工程需要的天数是多少?','[{"label":"A","content":"43"},{"label":"B","content":"44"},{"label":"C","content":"47"},{"label":"D","content":"48"}]','C','已知条件为不同完工情况，拆解后根据工作量相同列方程即可。
第一种工作方式：甲工程队在23天的工作时间内.有18天在工作，5天在休息，乙工程队在21天的工作时间内，有15天在工作，6天在休息④;
第二种工作方式：甲工程队在15天的工作时间内，有12天在工作，3天在休息，乙工程队在27天的工作时间内，有20天在工作，7天在休息⑤;
可列式：18甲+15乙=12甲+20乙，解得6甲=5乙，即甲效率为5,乙效率为6,带回方程，可得工作总量=5×18+6×15=180;
甲每4天为一周期，可完成15份工作，即一共需要180÷15=12个周期，但需要注意，最后一个周期三天完工无需休息⑥,即共需要48-1=47天，答案为C选项。

④花生批注：
甲的工作时间：
23÷(3+1)=5……3, 5×3+3=18天；
乙的工作时间：
21÷(5+2)=3, 3×5=15天。

⑤花生批注：
甲的工作时间：
15÷(3+1)=3……3, 3×3+3=12 天；
乙的工作时间：
27÷(5+2)=3……5,
3×5+5=20天。

⑥花生批注：
甲工程队每个工作周期的最后一天为休息，所以最后一个工作周期应不考虑休息的时间，故而减1。','数量关系600题','进阶','published','{"globalNumber":124,"sourceNumber":4,"typeLabel":"工程问题","stemRich":[{"text":"甲、乙两个工程队合作完成一项工程，甲每工作3天休息1天，乙每工作\n\n5天休息2天。若甲先工作，2天后乙加入，则再用21天完工；若乙先工作，\n12天后甲加入，则再用15天完工。甲单独完成该项工程需要的天数是多少?"}],"annotatedStemRich":[{"text":"甲、乙两个工程队合作完成一项工程，甲每工作3天休息1天，乙每工作\n\n5天休息2天。若甲先工作，2天后乙加入，则再用21天完工；若乙先工作，\n12天后甲加入，则再用15天完工。甲单独完成该项工程需要的天数是多少?"}],"annotatedOptionRich":{"A":[{"text":"43"}],"B":[{"text":"44"}],"C":[{"text":"47"}],"D":[{"text":"48\n"}]},"practicalAnalysis":"已知条件为不同完工情况，拆解后根据工作量相同列方程即可。\n第一种工作方式：甲工程队在23天的工作时间内.有18天在工作，5天在休息，乙工程队在21天的工作时间内，有15天在工作，6天在休息④;\n第二种工作方式：甲工程队在15天的工作时间内，有12天在工作，3天在休息，乙工程队在27天的工作时间内，有20天在工作，7天在休息⑤;\n可列式：18甲+15乙=12甲+20乙，解得6甲=5乙，即甲效率为5,乙效率为6,带回方程，可得工作总量=5×18+6×15=180;\n甲每4天为一周期，可完成15份工作，即一共需要180÷15=12个周期，但需要注意，最后一个周期三天完工无需休息⑥,即共需要48-1=47天，答案为C选项。","notes":[{"marker":"④","text":"甲的工作时间：\n23÷(3+1)=5……3, 5×3+3=18天；\n乙的工作时间：\n21÷(5+2)=3, 3×5=15天。","matchScore":0.101},{"marker":"⑤","text":"甲的工作时间：\n15÷(3+1)=3……3, 3×3+3=12 天；\n乙的工作时间：\n27÷(5+2)=3……5,\n3×5+5=20天。","matchScore":0.107},{"marker":"⑥","text":"甲工程队每个工作周期的最后一天为休息，所以最后一个工作周期应不考虑休息的时间，故而减1。","matchScore":0.126}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500125,4,'行程问题','甲、乙两人分别从A、B两地同时出发，6小时后在A、B两地中点相遇，
如果甲每小时多走8公里，乙提前2小时出发，则甲、乙两人仍在中点相遇，
那么A、B两地相距多少公里?','[{"label":"A","content":"168"},{"label":"B","content":"192"},{"label":"C","content":"256"},{"label":"D","content":"304"}]','B','由题意同时出发在中点相遇，可知原先甲乙速度相同。
第二次乙速度不变，走到中点所用时间依然是6小时，乙提前2小时出发⑦, 即甲晚出发2小时，甲提速后走到中点用时为4小时；
单独看甲，甲两次所用时间之比为6:4=3:2,即速度比为2:3,提速一份=8km/h, 原来速度为2份=16km/h, 则AB=(16+16)×6=192km, 答案为B选项。
⑦

⑦花生批注：
或者理解为：
甲乙同时出发到达中点原先需要6小时，现在乙提前2小时出发，速度不变，则甲出发时乙还有四小时的路程到达中点。
因此甲用4个小时的时间走完原先需要6小时的路程。','数量关系600题','进阶','published','{"globalNumber":125,"sourceNumber":5,"typeLabel":"行程问题","stemRich":[{"text":"甲、乙两人分别从A、B两地同时出发，6小时后在A、B两地中点相遇，\n如果甲每小时多走8公里，乙提前2小时出发，则甲、乙两人仍在中点相遇，\n那么A、B两地相距多少公里?"}],"annotatedStemRich":[{"text":"甲、乙两人分别从A、B两地同时出发，6小时后在A、B两地中点相遇，\n如果甲每小时多走8公里，乙提前2小时出发，则甲、乙两人仍在中点相遇，\n那么A、B两地相距多少公里?"}],"annotatedOptionRich":{"A":[{"text":"168"}],"B":[{"text":"192"}],"C":[{"text":"256"}],"D":[{"text":"304\n"}]},"practicalAnalysis":"由题意同时出发在中点相遇，可知原先甲乙速度相同。\n第二次乙速度不变，走到中点所用时间依然是6小时，乙提前2小时出发⑦, 即甲晚出发2小时，甲提速后走到中点用时为4小时；\n单独看甲，甲两次所用时间之比为6:4=3:2,即速度比为2:3,提速一份=8km/h, 原来速度为2份=16km/h, 则AB=(16+16)×6=192km, 答案为B选项。\n⑦","notes":[{"marker":"⑦","text":"或者理解为：\n甲乙同时出发到达中点原先需要6小时，现在乙提前2小时出发，速度不变，则甲出发时乙还有四小时的路程到达中点。\n因此甲用4个小时的时间走完原先需要6小时的路程。","matchScore":0.211}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500126,4,'最值问题','一个暗箱装有12个编号从1到12的乒乓球，甲、乙、丙三人轮流从暗箱

中摸球，每人每次摸一个球且不放回。将所有球摸完后，三人所摸出的球上的
编号之和相等，并且甲摸出了1号球和3号球，乙摸出了6号球和11号球。

丙摸出的球编号最大为多少?','[{"label":"A","content":"7"},{"label":"B","content":"8"},{"label":"C","content":"9"},{"label":"D","content":"10"}]','C','可将12个球分为1号和12号、2号和11号、3号和10号、 4号和9号、5号和8号、6号和7号共6组，甲乙丙从中各分配2组，以保证三人的编号和相等。
