INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500128,4,'几何问题','若将一个长方形的长缩短1厘米，宽加长8厘米，所得新长方形的周长和
面积分别是原长方形的2倍和4倍，则原长方形的长是多少厘米?','[{"label":"A","content":"4 厘米"},{"label":"B","content":"5 厘米"},{"label":"C","content":"6 厘米"},{"label":"D","content":"7 厘米"}]','B','“长缩短1厘米，宽加长8厘米”,即周长共增加7×2=14cm; 根据“周长变为原来2倍”可知之前周长为14cm, 即长、宽之和为7;
代入选项验证：
A选项：原长方形长、宽分别为4、3,原来面积为12,变化后面积 =3×11=33,并非4倍关系；
