INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500129,4,'经济利润问题','小张从银行贷款60万元，采取等额本金的还款方式，20年还清，贷款年
利率4.1%。小张第二个月需还款多少元?','[{"label":"A","content":"4550.0"},{"label":"B","content":"4541.5"},{"label":"C","content":"5137.0"},{"label":"D","content":"5290.5"}]','B','等额本金还款方式是在还款期内把贷款数总额等分，每月偿还同等数额的本金和上月还完后的剩余贷款在该月所产生的利息。⑧
每月需还的等额本金=60÷20÷12=0.25万元=2500元，第二月还款时的剩余贷款=600000-2500=597500元，单月利息=597500×4.1%÷12=2041.5元，故第二月需还款金额=2500+2041.5=4541.5万元，答案为B选项。
⑧

⑧花生批注：
除此以外还有等额本息的还款方式(了解):
指借款人每月归还相等的金额，其中既包括一部分本金，也包括当期应支付的利息，即计算出所有利息后，将所有本息平均到每个月还款。
