INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500130,4,'容斥问题之容斥最值','一次期末考试，某班同学成绩统计如下表：
三门功课
数学90分 语文90分 英语90分 数学和英语 数学和语文 语文和英语
没有一门
以上 以上 以上 90分以上 90分以上 90分以上
90分以上
23人 21人 20人 8人 6人 10人 5人
求：这个班最多有多少人?
：','[{"label":"A","content":"45"},{"label":"B","content":"51"},{"label":"C","content":"53"},{"label":"D","content":"55"}]','B','设班级总数为 x, 其中三门都90分以上的为y, 根据容斥公式⑨可列式：x-5=23+21+20-8-6-10+y, 化简得x=45+y 。y 最多为 6①,那么x 此时最大为45+6=51人，答案为B 选项。

⑨花生批注：
容斥问题常用解题方式：
全部人数一圈外人数=人
次之和一重复部分。
其中，三门功课都在90分以上的被数了3次，减掉 3次，需要加回1次。

⑩花生批注：
数学和语文90分以上的有 6 人，则三门都90以上的最多是6人。','数量关系600题','进阶','published','{"globalNumber":130,"sourceNumber":10,"typeLabel":"容斥问题之容斥最值","stemRich":[{"text":"一次期末考试，某班同学成绩统计如下表：\n三门功课\n数学90分 语文90分 英语90分 数学和英语 数学和语文 语文和英语\n没有一门\n以上 以上 以上 90分以上 90分以上 90分以上\n90分以上\n23人 21人 20人 8人 6人 10人 5人\n求：这个班最多有多少人?\n："}],"annotatedStemRich":[{"text":"一次期末考试，某班同学成绩统计如下表：\n三门功课\n数学90分 语文90分 英语90分 数学和英语 数学和语文 语文和英语\n没有一门\n以上 以上 以上 90分以上 90分以上 90分以上\n90分以上\n23人 21人 20人 8人 6人 10人 5人\n求：这个班最多有多少人?\n："}],"annotatedOptionRich":{"A":[{"text":"45"}],"B":[{"text":"51"}],"C":[{"text":"53"}],"D":[{"text":"55\n"}]},"practicalAnalysis":"设班级总数为 x, 其中三门都90分以上的为y, 根据容斥公式⑨可列式：x-5=23+21+20-8-6-10+y, 化简得x=45+y 。y 最多为 6①,那么x 此时最大为45+6=51人，答案为B 选项。","notes":[{"marker":"⑨","text":"容斥问题常用解题方式：\n全部人数一圈外人数=人\n次之和一重复部分。\n其中，三门功课都在90分以上的被数了3次，减掉 3次，需要加回1次。","matchScore":0.126},{"marker":"⑩","text":"数学和语文90分以上的有 6 人，则三门都90以上的最多是6人。","matchScore":0.202}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500131,4,'工程问题','乙生产线每天比甲生产线多生产5件产品，两条生产线同时开工，乙生产
450件产品所用的时间比甲少1天。乙生产450件产品后设备需检修，每天产

量比之前减少10件，又生产若干天后结束生产任务，此时两条生产线产量相同。
