INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500133,4,'概率问题','桌上有20张正面向上的卡片，每次任选其中的3张翻面后放置于原位。
