INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500136,4,'周期循环问题','如右图所示，一个正方体木块六个面上分别写着数字，相对面上两个数字
的和为20。现在正方体木块的上面是9,正面是13,右面是5。如果先将木块

从左向右翻转2018次，再由前向后翻转2019次，这时木块正面数字是多少?','[{"label":"A","content":"9"},{"label":"B","content":"11"},{"label":"C","content":"13"},{"label":"D","content":"15\n79\n\n\n\n\n\n\n0\no"}]','B','正方体相对面上两个数字之和为20,即13的对面是7、9的对面是11、5的对面是15。
先将木块从左向右翻转2018次，无论翻转多少次，正面和背面数字不发生变化，顶面4个面一个循环周期，2018÷4=504余2,即顶面从9变为15再变为11 6;
再由前向后翻转2019次，无论翻转多少次，左面和右面数字不发生变化，正面4个面一个循环周期， 2019÷4=504余30 ,即正面由13变为9再变为7 再变为11 ⑤,答案为B 选项。
⑧

⑦花生批注：
从前往后翻转3次，
相当于从后往前翻转1次；即11成为正面。','数量关系600题','进阶','published','{"globalNumber":136,"sourceNumber":6,"typeLabel":"周期循环问题","stemRich":[{"text":"如右图所示，一个正方体木块六个面上分别写着数字，相对面上两个数字\n的和为20。现在正方体木块的上面是9,正面是13,右面是5。如果先将木块\n\n从左向右翻转2018次，再由前向后翻转2019次，这时木块正面数字是多少?"}],"annotatedStemRich":[{"text":"如右图所示，一个正方体木块六个面上分别写着数字，相对面上两个数字\n的和为20。现在正方体木块的上面是9,正面是13,右面是5。如果先将木块\n\n从左向右翻转2018次，再由前向后翻转2019次，这时木块正面数字是多少?"}],"annotatedOptionRich":{"A":[{"text":"9"}],"B":[{"text":"11"}],"C":[{"text":"13"}],"D":[{"text":"15\n79\n\n\n\n\n\n\n0\no"}]},"practicalAnalysis":"正方体相对面上两个数字之和为20,即13的对面是7、9的对面是11、5的对面是15。\n先将木块从左向右翻转2018次，无论翻转多少次，正面和背面数字不发生变化，顶面4个面一个循环周期，2018÷4=504余2,即顶面从9变为15再变为11 6;\n再由前向后翻转2019次，无论翻转多少次，左面和右面数字不发生变化，正面4个面一个循环周期， 2019÷4=504余30 ,即正面由13变为9再变为7 再变为11 ⑤,答案为B 选项。\n⑧","notes":[{"marker":"⑦","text":"从前往后翻转3次，\n相当于从后往前翻转1次；即11成为正面。","matchScore":0.264}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number","imageKeys":["numeric/20260717/quantity/500136.png"],"imageSourcePage":85}','numeric/20260717/quantity/500136.png');
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500137,4,'等差数列问题','某小学毕业生拍集体照，老师和学生共150人，站成n 排 ( n≥2), 且
后一排比前一排多1人。问符合条件的n 有多少个?','[{"label":"A","content":"2"},{"label":"B","content":"3"},{"label":"C","content":"4"},{"label":"D","content":"5"}]','D','方法一：每排人数构成公差为1的等差数列，可按照奇数项、偶数项分类讨论：
若是奇数项数列 (n 为奇数),总人数=中间项×项数，即为整数， n 可取3、5、15;若 n=25, 此时中间项为首项为负数，不符合实际情况，即n 为奇数时，只能取3、5、150;
若是偶数项数列 ( n 为偶数),总人数=中间两项平均数×项数，假设中
间两项为a 、a +1, 则二者平均数为a+0.5, 即 ⑪业为 a+0.5,n 可取4、 12; 若 n=20, 中间两项平均数为7.5,即中间两项分别为7、8,此时首项为负数，
不符合实际情况，即 n 为偶数时，可取4、12;
综上，符合条件的n 共有5个，答案为D 选项。
方法二：设第一排有x 人 ( x≥1 且为正整数),则第n 排有x+n-1 人。根
化
简可得
00,n≤17; 又因为 2x-1 必为奇数，
则、 n 必为一奇一偶，且将300因式分解为两数相乘，满足一奇一偶且n≤17 的情况有3×100、4×75、5×60、12×25、15×20。
因此n 可取3、4、5、12、15共5个数，答案为D 选项。

⑪花生批注：
150 =2× 75, n 必须包
含两个2因子；
这样2×3×5×5/2×2, 尾数为0.5;
在两个2因子的基础上，可再有1个3因子或2个5 因子。','数量关系600题','进阶','published','{"globalNumber":137,"sourceNumber":7,"typeLabel":"等差数列问题⑨","stemRich":[{"text":"某小学毕业生拍集体照，老师和学生共150人，站成n 排 ( n≥2), 且\n后一排比前一排多1人。问符合条件的n 有多少个?"}],"annotatedStemRich":[{"text":"某小学毕业生拍集体照，老师和学生共150人，站成n 排 ( n≥2), 且\n后一排比前一排多1人。问符合条件的n 有多少个?"}],"annotatedOptionRich":{"A":[{"text":"2"}],"B":[{"text":"3"}],"C":[{"text":"4"}],"D":[{"text":"5\n"}]},"practicalAnalysis":"方法一：每排人数构成公差为1的等差数列，可按照奇数项、偶数项分类讨论：\n若是奇数项数列 (n 为奇数),总人数=中间项×项数，即为整数， n 可取3、5、15;若 n=25, 此时中间项为首项为负数，不符合实际情况，即n 为奇数时，只能取3、5、150;\n若是偶数项数列 ( n 为偶数),总人数=中间两项平均数×项数，假设中\n间两项为a 、a +1, 则二者平均数为a+0.5, 即 ⑪业为 a+0.5,n 可取4、 12; 若 n=20, 中间两项平均数为7.5,即中间两项分别为7、8,此时首项为负数，\n不符合实际情况，即 n 为偶数时，可取4、12;\n综上，符合条件的n 共有5个，答案为D 选项。\n方法二：设第一排有x 人 ( x≥1 且为正整数),则第n 排有x+n-1 人。根\n化\n简可得\n00,n≤17; 又因为 2x-1 必为奇数，\n则、 n 必为一奇一偶，且将300因式分解为两数相乘，满足一奇一偶且n≤17 的情况有3×100、4×75、5×60、12×25、15×20。\n因此n 可取3、4、5、12、15共5个数，答案为D 选项。","notes":[{"marker":"⑪","text":"150 =2× 75, n 必须包\n含两个2因子；\n这样2×3×5×5/2×2, 尾数为0.5;\n在两个2因子的基础上，可再有1个3因子或2个5 因子。","matchScore":0.073}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500138,4,'和差倍比问题','浮雕银杯是我国古代常见的一种盛酒容器，有大银杯和小银杯之分。已知

5个大银杯加1个小银杯，可以盛酒3斛(斛，是古代的 一 种容量单位),5
个小银杯加1个大银杯，可以盛酒2斛，则1斛酒至多可以倒满小银杯的数量

