INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500139,4,'容斥问题之容斥最值','，根
式为 有100名员工去年和今年均参加考核，考核结果分为优、良、中、差四个
等次。今年考核结果为优的人数是去年的1 . 2倍，今年考核结果为良及以下的
人员占比比去年低15个百分点。问两年考核结果均为优的人数至少为多少人?','[{"label":"A","content":"55"},{"label":"B","content":"65\n100\n75 90\n均优秀\n两年都不优秀"},{"label":"C","content":"75"},{"label":"D","content":"85"}]','B','今年考核结果为良及以下的人员占比比去年低15个百分点，即今年考核为优的人员占比高了15个百分点，100×15%=15人，即今年考核结果为优的人员比去年多15人，同时是去年的1 . 2倍(即增长率为20%), 则去年考核
100- 两年都不优秀人员 =75+90-两年都优秀人员，要使两年考核结果均为优的人数最少，则两年都不优秀人员取最小值0,则两年考核结果均为优的人数 =75+90-100=65人。
为优的人 , 今年考核为优的人员 = 7 5 + 1 5 = 9 0 人。
根据容斥原理可知，两年考核均为优秀的人员最小值=75+90- 100=65人，答案为B 选项。⑬
⑭

⑫花生批注：
可利用资料分析知识点，根据变化情况求基期，公式为
有100名员工去年和今年均参加考核，考核结果分为优、良、中、差四个等次。今年考核结果为优的人数是去年的1 . 2倍，今年考核结果为良及以下的人员占比比去年低15个百分点。问两年考核结果均为优的人数至少为多少人?

⑬花生批注：
A.55 B.65
100
75 90
均优秀
两年都不优秀
