INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500141,4,'牛吃草问题','某零件生产车间每天产量固定且目前有一定库存，车间用货车将库存零件运往买方仓库。如每天运24车，5天刚好运完；如每天运18车，8天刚好运完。现每天运x 车，4天后车间生产效率提高了50%,又用了7天运完存货。问x 可能的最小值为多少?','[{"label":"A","content":"18"},{"label":"B","content":"19"},{"label":"C","content":"20"},{"label":"D","content":"21"}]','A','此题为典型的牛吃草① 问题。
第一步：
第二步：原有草(即库存)=(24-8)×5=80;
第三步：根据运出总量=库存+生产量，可列方程： (7+4) x=80+8×4+8×','数量关系600题','进阶','published','{"globalNumber":141,"sourceNumber":1,"typeLabel":"牛吃草问题","stemRich":[{"text":"某零件生产车间每天产量固定且目前有一定库存，车间用货车将库存零件 运往买方仓库。如每天运24车，5天刚好运完；如每天运18车，8天刚好运完。 现 每 天 运x  车，4天后车间生产效率提高了50%,又用了7天运完存货。问x  可能的最小值为多少?"}],"annotatedStemRich":[{"text":"某零件生产车间每天产量固定且目前有一定库存，车间用货车将库存零件 运往买方仓库。如每天运24车，5天刚好运完；如每天运18车，8天刚好运完。 现 每 天 运x  车，4天后车间生产效率提高了50%,又用了7天运完存货。问x  可能的最小值为多少?"}],"annotatedOptionRich":{"A":[{"text":"18"}],"B":[{"text":"19"}],"C":[{"text":"20","bold":true}],"D":[{"text":"21\n"}]},"practicalAnalysis":"此题为典型的牛吃草① 问题。\n第一步：\n第二步：原有草(即库存)=(24-8)×5=80;\n第三步：根据运出总量=库存+生产量，可列方程： (7+4) x=80+8×4+8×","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500142,4,'不定方程问题','去 文具 店购 买文 具用 品 ，已 知买7盒 水彩 笔、 3瓶 墨水 、1 个 笔记 本共 需
要 50 元 ， 买 10 盒 水彩 笔 、 4瓶 墨 水 、 1本 笔记 本共 需要 69元 。 问 若 买 2盒 水
