INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500147,4,'行程问题之流水问题','甲、乙两船分别从上游的A地和下游的B地同时出发相向匀速行驶。甲船

2小时后到达B地 ，随后立刻返航以原功率行驶，在3小时后与乙船同时到达
A地。则两船如果同时从A地出发前往B地，甲船比乙船提前到达的时间在以
下哪个范围内?','[{"label":"A","content":"低于半小时"},{"label":"B","content":"半小时～1小时之间"},{"label":"C","content":"1 小时～1个半小时之间"},{"label":"D","content":"高于1个半小时"}]','B','甲船顺流而下需要2小时，逆流而上需要3小时，则2(V甲 +V水)=3( V甲-V水 ) ,解 得 V甲=5V水，S=2×6 V水=12V水；
同 样 从B 地逆流而上到达A 地，乙船需要5小时，则3(V甲-V水)=12V水 =5( V乙-V 水 ) ,解 得V乙=3.4V水；
如果乙船也从A地顺流而下，所需时间=12V水÷(V乙+V水)=12÷4.4≈2.73 小时，即甲船比乙船快0.73小时，答案为B 选项。','数量关系600题','进阶','published','{"globalNumber":147,"sourceNumber":7,"typeLabel":"行程问题之流水问题","stemRich":[{"text":"甲、乙两船分别从上游的A地和下游的B地同时出发相向匀速行驶。甲船\n\n2小时后到达B地 ，随后立刻返航以原功率行驶，在3小时后与乙船同时到达\nA地。则两船如果同时从A地出发前往B地，甲船比乙船提前到达的时间在以\n下哪个范围内?"}],"annotatedStemRich":[{"text":"甲、乙两船分别从上游的A地和下游的B地同时出发相向匀速行驶。甲船\n\n2小时后到达B地 ，随后立刻返航以原功率行驶，在3小时后与乙船同时到达\nA地。则两船如果同时从A地出发前往B地，甲船比乙船提前到达的时间在以\n下哪个范围内?"}],"annotatedOptionRich":{"A":[{"text":" 低于半小时"}],"B":[{"text":"  半小时～1小时之间"}],"C":[{"text":"1  小时～1个半小时之间"}],"D":[{"text":"  高于1个半小时\n"}]},"practicalAnalysis":"甲船顺流而下需要2小时，逆流而上需要3小时，则2(V甲 +V水)=3( V甲-V水 ) ,解 得 V甲=5V水，S=2×6 V水=12V水；\n同 样 从B 地逆流而上到达A 地，乙船需要5小时，则3(V甲-V水)=12V水 =5( V乙-V 水 ) ,解 得V乙=3.4V水；\n如果乙船也从A地顺流而下，所需时间=12V水÷(V乙+V水)=12÷4.4≈2.73 小时，即甲船比乙船快0.73小时，答案为B 选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
