INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500149,4,'容斥问题','某中学58名学生参加体育社团，每人至少参加一个社团。已知参加篮球
社团的有31人，参加乒乓球社团的有37人，参加足球的有19人，其中有5

名学生三个社团都参加了。该校有多少名学生只参加了一个社团?','[{"label":"A","content":"31"},{"label":"B","content":"32"},{"label":"C","content":"33"},{"label":"D","content":"34"}]','D','根据容斥公式⑨:总人数三总人次-只参加两项人数-2×三项都参加人数，可得只参加两项人数=31+37+19-2×5-58=19人；
再根据公式：总人数=只参加一项人数+只参加两项人数+三项都参加人数，可得只参加一个社团人数=58-19-5=34人，答案为D选项。
⑨

⑨花生批注：
容斥问题常用解题方式：
①直接代入公式：全部人数-圈外人数=人次之和- 重复部分；
②有时需要另一种计数方式，圈内总人数=只参加一种的人数+只参加两种的人数+……+所有都参加的人数(此公式只在部分题目中需要使用，编者称之为隐含公式)。
易错点：误将“符合A和 B”当做“只符合 A和 B”, 前者包含“符合 A、B、C”的元素，而后者不包含。','数量关系600题','进阶','published','{"globalNumber":149,"sourceNumber":9,"typeLabel":"容斥问题","stemRich":[{"text":"某中学58名学生参加体育社团，每人至少参加一个社团。已知参加篮球\n社团的有31人，参加乒乓球社团的有37人，参加足球的有19人，其中有5\n\n名学生三个社团都参加了。该校有多少名学生只参加了一个社团?"}],"annotatedStemRich":[{"text":"某中学58名学生参加体育社团，每人至少参加一个社团。已知参加篮球\n社团的有31人，参加乒乓球社团的有37人，参加足球的有19人，其中有5\n\n名学生三个社团都参加了。该校有多少名学生只参加了一个社团?"}],"annotatedOptionRich":{"A":[{"text":"31"}],"B":[{"text":"32"}],"C":[{"text":"33"}],"D":[{"text":"34\n"}]},"practicalAnalysis":"根据容斥公式⑨:总人数三总人次-只参加两项人数-2×三项都参加人数，可得只参加两项人数=31+37+19-2×5-58=19人；\n再根据公式：总人数=只参加一项人数+只参加两项人数+三项都参加人数，可得只参加一个社团人数=58-19-5=34人，答案为D选项。\n⑨","notes":[{"marker":"⑨","text":"容斥问题常用解题方式：\n①直接代入公式：全部人数-圈外人数=人次之和- 重复部分；\n②有时需要另一种计数方式，圈内总人数=只参加一种的人数+只参加两种的人数+……+所有都参加的人数(此公式只在部分题目中需要使用，编者称之为隐含公式)。\n易错点：误将“符合A和 B”当做“只符合 A和 B”, 前者包含“符合 A、B、C”的元素，而后者不包含。","matchScore":0.149}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500150,4,'几何问题之等比放缩','气象学中，24小时内降落在某面积上的雨水深度叫做日降雨量(不考虑渗

漏、蒸发、流失等损耗，单位：mm), 将日降雨量记为w, 其等级划分如下：
小雨(0.1≤w<10), 中雨(10≤w<25), 大雨(25≤w<50), 暴雨(50≤w

<100)。某地某日用一个圆锥形容器接了24小时的雨水(如下图所示),则
该地日降雨量等级是什么?','[{"label":"A","content":"暴雨"},{"label":"B","content":"大雨"},{"label":"C","content":"中雨"},{"label":"D","content":"小雨"}]','C','根据题意可知，日降水量应是底面为直径300mm 的圆的圆柱体内的雨水深度；
观察圆锥体，雨水和整个圆锥高度比为1:2,根据几何等比放缩性质四可知，体积比为1:8;又因为相同底面积的锥体和柱体的体积比为1:3,则雨水体
积是整个对应圆柱体体积的
若将雨水倒入底面为直径300mm 的圆的圆柱体体内，其高度为 ⑪ ≈16.6 7mm, 即该日降水等级为中雨，答案为C选项。

⑩花生批注：
几何等比放缩性质：
若边长(包括半径)为n倍，则周长也为n 倍，面积为 n² 倍，体积为n³ 倍。

⑪花生批注：
底面积一定，体积和高度成正比，雨水体积是圆柱的。则高度也是圆柱的','数量关系600题','进阶','published','{"globalNumber":150,"sourceNumber":10,"typeLabel":"几何问题之等比放缩","stemRich":[{"text":"气象学中，24小时内降落在某面积上的雨水深度叫做日降雨量(不考虑渗\n\n漏、蒸发、流失等损耗，单位：mm), 将日降雨量记为w, 其等级划分如下：\n小雨(0.1≤w<10), 中雨(10≤w<25), 大雨(25≤w<50), 暴雨(50≤w\n\n<100)。某地某日用一个圆锥形容器接了24小时的雨水(如下图所示),则\n该地日降雨量等级是什么?"}],"annotatedStemRich":[{"text":"气象学中，24小时内降落在某面积上的雨水深度叫做日降雨量(不考虑渗\n\n漏、蒸发、流失等损耗，单位：mm), 将日降雨量记为w, 其等级划分如下：\n小雨(0.1≤w<10), 中雨(10≤w<25), 大雨(25≤w<50), 暴雨(50≤w\n\n<100)。某地某日用一个圆锥形容器接了24小时的雨水(如下图所示),则\n该地日降雨量等级是什么?"}],"annotatedOptionRich":{"A":[{"text":" 暴雨"}],"B":[{"text":"  大雨"}],"C":[{"text":"  中雨"}],"D":[{"text":"  小雨\n"}]},"practicalAnalysis":"根据题意可知，日降水量应是底面为直径300mm 的圆的圆柱体内的雨水深度；\n观察圆锥体，雨水和整个圆锥高度比为1:2,根据几何等比放缩性质四可知，体积比为1:8;又因为相同底面积的锥体和柱体的体积比为1:3,则雨水体\n积是整个对应圆柱体体积的\n若将雨水倒入底面为直径300mm 的圆的圆柱体体内，其高度为 ⑪ ≈16.6 7mm, 即该日降水等级为中雨，答案为C选项。","notes":[{"marker":"⑩","text":"几何等比放缩性质：\n若边长(包括半径)为n倍，则周长也为n 倍，面积为 n² 倍，体积为n³ 倍。","matchScore":0.093},{"marker":"⑪","text":"底面积一定，体积和高度成正比，雨水体积是圆柱的。则高度也是圆柱的","matchScore":0.075}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
