INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500152,4,'日期星期问题','甲、乙、丙三人均每隔一定时间去一次健身房锻炼。甲每隔2天去一次，
