INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500153,4,'行程问题之相遇追及','一条圆形跑道长500米，甲、乙两人从不同起点同时出发，均沿顺时针方

向匀速跑步。已知甲跑了600米后第一次追上乙，此后甲加速20%继续前进，
又跑了1200米后第二次追上乙。问甲出发后多少米第一次到达乙的出发点?','[{"label":"A","content":"180"},{"label":"B","content":"150"},{"label":"C","content":"120"},{"label":"D","content":"100"}]','A','从甲第一次追上乙到甲加速第二次追上乙的期间，甲比乙多跑一圈(500m), 甲跑了1200m, 乙跑了1200-500=700m; 相同时间内，速度和距离成正比，即1.2V甲：V乙=1200:700,化简得V甲：V乙=10:7;
出发至甲第一次追上乙，相同时间内，距离和速度成正比，10:7= 600m:420m, 则甲第一次追上乙时，乙跑了420m, 甲比乙多跑180m, 即出发时甲落后乙180m, 出发后需要跑180m 才到达乙的出发点，答案为A 选项。','数量关系600题','进阶','published','{"globalNumber":153,"sourceNumber":3,"typeLabel":"行程问题之相遇追及","stemRich":[{"text":"一条圆形跑道长500米，甲、乙两人从不同起点同时出发，均沿顺时针方\n\n向匀速跑步。已知甲跑了600米后第一次追上乙，此后甲加速20%继续前进，\n又跑了1200米后第二次追上乙。问甲出发后多少米第一次到达乙的出发点?"}],"annotatedStemRich":[{"text":"一条圆形跑道长500米，甲、乙两人从不同起点同时出发，均沿顺时针方\n\n向匀速跑步。已知甲跑了600米后第一次追上乙，此后甲加速20%继续前进，\n又跑了1200米后第二次追上乙。问甲出发后多少米第一次到达乙的出发点?"}],"annotatedOptionRich":{"A":[{"text":"180"}],"B":[{"text":"150"}],"C":[{"text":"120"}],"D":[{"text":"100\n"}]},"practicalAnalysis":"从甲第一次追上乙到甲加速第二次追上乙的期间，甲比乙多跑一圈(500m), 甲跑了1200m, 乙跑了1200-500=700m; 相同时间内，速度和距离成正比，即1.2V甲：V乙=1200:700,化简得V甲：V乙=10:7;\n出发至甲第一次追上乙，相同时间内，距离和速度成正比，10:7= 600m:420m, 则甲第一次追上乙时，乙跑了420m, 甲比乙多跑180m, 即出发时甲落后乙180m, 出发后需要跑180m 才到达乙的出发点，答案为A 选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500154,4,'排列组合问题之特殊情境','某空军基地举行飞行训练，有8架歼击机、3架预警直升机、2架反潜直
升机参与训练，每架飞机编号不同。训练时，需派出3架歼击机、2架预警直

升机、1架反潜直升机进行起降飞行。若每次只能起飞1架飞机，其中3架歼
击机必须相邻起飞，2架预警直升机不能相邻起飞，那么不同的起飞方式有多
少种?','[{"label":"A","content":"504"},{"label":"B","content":"4032"},{"label":"C","content":"8064"},{"label":"D","content":"24192"}]','D','根据题干要求，先选飞机：从8架歼击机中选3架，C³; 从 3架预警直升机中选2架， C3; 从2架反潜直升机中选1架， C2。
