INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500160,4,'几何问题之等比放缩','一个高为10厘米，底面半径为5厘米的圆锥体塑料零件置于水中，底面
朝上且与水面平行，其浮出水面部分的高为2厘米。那么当该零件底面朝下且
与水面平行置于水中时，浮出水面部分的高在以下哪个范围内?(零件始终不

接触水底)','[{"label":"A","content":"不到6厘米"},{"label":"B","content":"6～ 7 厘米之间"},{"label":"C","content":"7～8 厘米之间"},{"label":"D","content":"超过8厘米"}]','C','底面朝上放置时，露出水面的高度为2,说明水下高度为8. 水下圆锥体和整个圆锥体的高度比为4:5①, 根据等比放缩性质，体积比为
⑬

⑫花生批注：
几何等比放缩性质：
若边长(或半径)为n 倍，则周长也为n 倍，面积为 n² 倍，体积为n³ 倍。
一个高为10厘米，底面半径为5厘米的圆锥体塑料零件置于水中，底面朝上且与水面平行，其浮出水面部分的高为2厘米。那么当该零件底面朝下且与水面平行置于水中时，浮出水面部分的高在以下哪个范围内?(零件始终不接触水底)

⑬花生批注：
64:125 ; 可以设整个圆锥体体积为125,排水体积为64;
