INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500162,4,'经济利润问题','一款手机有两个型号，存储容量分别为64G和256G, 销售价分别为每台 1600元和2000元，其他无区别。已知64G存储器的成本是256G 存储器的一半，是单台手机其他成本之和的20%,而销售一台256G 手机的利润比64G 手机高150元。问销售64G和256G 手机各10万台，利润为多少万元?','[{"label":"A","content":"3500"},{"label":"B","content":"5600"},{"label":"C","content":"6400"},{"label":"D","content":"7000\n①"}]','A','根据“64G 存储器的成本是256G 存储器的一半”,可设64G 存储器的成本是x 元，则256G 存储器的成本是2x 元，单台手机其他成本之和为5x 元；由此可知，64G 手机总成本为6x 元，256G 手机总成本为7x元。
