INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500174,4,'经济利润之分段计费问题','甲、乙、丙三人一起拼车，统一出发，到不同地点。他们约定合

乘部分车 费平摊。已知甲、乙、丙三人实际支付费用分别为14元
、28元、48元，那么 在此次拼车过程中，乙节约了多少钱?','[{"label":"A","content":"14 元"},{"label":"B","content":"28 元"},{"label":"C","content":"42 元"},{"label":"D","content":"48 元"}]','C','根据题意可将本次路程分为三段，第一段三人各支付14元，则第一段总车费为42元；第二段乙和丙各支付了28-14=14元④,则第二段总费用为28元；
综上，若乙单独坐车需支付42+28=70元，拼车节约了70-28=42元，答案为 C选项。
④

④花生批注：
乙一共支付了28元，第一段支付14元，则第二段也支付14元；
甲支付的车费最少，则甲最先下车；乙支付的第二少，则第二个下车。','数量关系600题','进阶','published','{"globalNumber":174,"sourceNumber":4,"typeLabel":"经济利润之分段计费问题","stemRich":[{"text":"甲、乙、丙三人一起拼车，统一出发，到不同地点。他们约定合\n\n乘部分车 费平摊。已知甲、乙、丙三人实际支付费用分别为14元\n、28元、48元，那么 在此次拼车过程中，乙节约了多少钱?"}],"annotatedStemRich":[{"text":"甲、乙、丙三人一起拼车，统一出发，到不同地点。他们约定合\n\n乘部分车 费平摊。已知甲、乙、丙三人实际支付费用分别为14元\n、28元、48元，那么 在此次拼车过程中，乙节约了多少钱?"}],"annotatedOptionRich":{"A":[{"text":"  14 元"}],"B":[{"text":"28   元"}],"C":[{"text":"  42 "},{"text":"元","bold":true}],"D":[{"text":"48   元\n"}]},"practicalAnalysis":"根据题意可将本次路程分为三段，第一段三人各支付14元，则第一段总车费为42元；第二段乙和丙各支付了28-14=14元④,则第二段总费用为28元；\n综上，若乙单独坐车需支付42+28=70元，拼车节约了70-28=42元，答案为 C选项。\n④","notes":[{"marker":"④","text":"乙一共支付了28元，第一段支付14元，则第二段也支付14元；\n甲支付的车费最少，则甲最先下车；乙支付的第二少，则第二个下车。","matchScore":0.184}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500175,4,'和差倍比问题','体操队有正式队员和候补队员共18人，候补队员比正式队员
