INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500177,4,'几何问题','某游乐园在一个平地中央挖了一个球形下沉广场，广场直径为

200米，最 深处50米，那么这个球形的直径为多少米?','[{"label":"A","content":"125"},{"label":"B","content":"200"},{"label":"C","content":"225"},{"label":"D","content":"250"}]','D','根据题意作图，最深处为0''A, 广场直径200米，即O''B=100 米，设球半径OB 为 R,O''A=50 米，则00''=OA-0''A=(R-50) 米。
根据勾股定理， OB²=0''B²+00''², 即 R²=100²+(R-50)², 解得R=125 米，则球
形直径为2R=2×125=250 米，答案为D选项。','数量关系600题','进阶','published','{"globalNumber":177,"sourceNumber":7,"typeLabel":"几何问题","stemRich":[{"text":"某游乐园在一个平地中央挖了一个球形下沉广场，广场直径为\n\n200米，最 深处50米，那么这个球形的直径为多少米?"}],"annotatedStemRich":[{"text":"某游乐园在一个平地中央挖了一个球形下沉广场，广场直径为\n\n200米，最 深处50米，那么这个球形的直径为多少米?"}],"annotatedOptionRich":{"A":[{"text":"125"}],"B":[{"text":"200"}],"C":[{"text":"225"}],"D":[{"text":"250\n"}]},"practicalAnalysis":"根据题意作图，最深处为0''A, 广场直径200米，即O''B=100 米，设球半径OB 为 R,O''A=50 米，则00''=OA-0''A=(R-50) 米。\n根据勾股定理， OB²=0''B²+00''², 即 R²=100²+(R-50)², 解得R=125 米，则球\n形直径为2R=2×125=250 米，答案为D选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500178,4,'容斥问题+排列组合问题','数方 某科研机构准备选派种植专家、气象专家和水利专家前往农村指
参加
种人 导工作。 现已从专家库选出备选的6名人选，已知擅长种植的人数
人数
中需 是擅长气象的2倍， 擅长水利的人数是擅长气象的2.5倍；有5人
含公
擅长2个领域，其中同时擅长种 植和气象的有1人，同时擅长水利
和气象的有1人。如果最终选派3人前往， 且要求涵盖3个领域，
专家
人数 那么有多少种不同的组合?
1,
解得','[{"label":"A","content":"13"},{"label":"B","content":"14"},{"label":"C","content":"15"},{"label":"D","content":"16"}]','D','根据题意可知，气象、种植、水利专家人数之比=1:2:2 .5 =2:4:5;
如图所示⑨,将擅长2个领域的5人填入图中，剩余1人为只会水利的专家；如图所示，种植圈外只有2人(乙、己),不可能出现3人均不会种植的
情况 ⑨;同理，水利圈外只有1人(甲),不可能出现3人均不会水利的情况；但是，气象圈外有4人(丙、丁、戊、己),若从中选择3人，则无人会气象，无法涵盖3个领域。
由此，可通过“全部减不符”求解，选派3人且涵盖3个领域的情况数 = C³-C³=16 种，答案为D 选项。

⑩花生批注：
除己外的五人，气象、种植、水利专家人数之比 =2:4:4;
剩余的己只能是只会水利，这样比例才符合2:4:5; 若剩余的己是三种都会，比例变为3:5:5,不符合题目要求。','数量关系600题','进阶','published','{"globalNumber":178,"sourceNumber":8,"typeLabel":"容斥问题⑧+排列组合问题","stemRich":[{"text":"数方 某科研机构准备选派种植专家、气象专家和水利专家前往农村指\n参加\n种人 导工作。 现已从专家库选出备选的6名人选，已知擅长种植的人数\n人数\n中需 是擅长气象的2倍， 擅长水利的人数是擅长气象的2.5倍；有5人\n含公\n擅长2个领域，其中同时擅长种 植和气象的有1人，同时擅长水利\n和气象的有1人。如果最终选派3人前往， 且要求涵盖3个领域，\n专家\n人数 那么有多少种不同的组合?\n1,\n解得"}],"annotatedStemRich":[{"text":"数方 某科研机构准备选派种植专家、气象专家和水利专家前往农村指\n参加\n种人 导工作。 现已从专家库选出备选的6名人选，已知擅长种植的人数\n人数\n中需 是擅长气象的2倍， 擅长水利的人数是擅长气象的2.5倍；有5人\n含公\n擅长2个领域，其中同时擅长种 植和气象的有1人，同时擅长水利\n和气象的有1人。如果最终选派3人前往， 且要求涵盖3个领域，\n专家\n人数 那么有多少种不同的组合?\n1,\n解得"}],"annotatedOptionRich":{"A":[{"text":"13"}],"B":[{"text":"14"}],"C":[{"text":"15"}],"D":[{"text":"16\n"}]},"practicalAnalysis":"根据题意可知，气象、种植、水利专家人数之比=1:2:2 .5 =2:4:5;\n如图所示⑨,将擅长2个领域的5人填入图中，剩余1人为只会水利的专家；如图所示，种植圈外只有2人(乙、己),不可能出现3人均不会种植的\n情况 ⑨;同理，水利圈外只有1人(甲),不可能出现3人均不会水利的情况；但是，气象圈外有4人(丙、丁、戊、己),若从中选择3人，则无人会气象，无法涵盖3个领域。\n由此，可通过“全部减不符”求解，选派3人且涵盖3个领域的情况数 = C³-C³=16 种，答案为D 选项。","notes":[{"marker":"⑩","text":"除己外的五人，气象、种植、水利专家人数之比 =2:4:4;\n剩余的己只能是只会水利，这样比例才符合2:4:5; 若剩余的己是三种都会，比例变为3:5:5,不符合题目要求。","matchScore":0.137}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500179,4,'和差倍比问题','甲单位职工人数是乙单位的2倍，两个单位所有职工中正好有一半是党员。其中甲单位职工中党员占比比乙单位高15个百分点，且甲单位的职工中群众人数比乙单位多18人。问甲单位职工中，党员比群众多多少人?','[{"label":"A","content":"6"},{"label":"B","content":"8"},{"label":"C","content":"10"},{"label":"D","content":"12"}]','D','设乙单位职工数为 x, 则甲单位职工数为2x; 设乙单位群众数为y, 则甲单位群众数为y+18;
根据两个单位职工中有一半是党员②可列式：1.5x=y+y+18;
根据甲单位党员占比比乙高15个百分点⑬可列式：
解得x=60,y=36, 则甲单位有职工120人，其中群众54人，党员66人，
⑨

