INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500182,4,'工程问题','某单位办事大厅有3个相同的办事窗口，2天最多可以办理600笔业务，每个窗口办理单笔业务的用时均相同。现对该办事大厅进行流程优化，增设2 个与以前相同的办事窗口，且每个办事窗口办理每笔业务的用时缩短到以前的问优化后的办事大厅办理6000笔业务最少需要多少天?','[{"label":"A","content":"8"},{"label":"B","content":"10"},{"label":"C","content":"12"},{"label":"D","content":"15"}]','A','每天办理业务=窗口数×每个窗口效率，根据题意，窗口数变为原来效率变为原来1 . 5 ②,则每天办理业务变为原来的
倍，即每天办理300×2.5=750笔业务，则办理6000笔业务
最少需要6000÷750=8天，答案为A选项。

