INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500183,4,'行程问题+几何问题','一个半径为120米的圆形人工湖正中有一个半径为60米的圆形人工岛。

甲从岛的正北岸边出发，以 1 米 /秒的速度匀速划船前往湖的正南岸边，则最
少需要多长时间?','[{"label":"A","content":"不到3分45秒"},{"label":"B","content":"3 分45秒～4分之间"},{"label":"C","content":"4 分～4分15秒之间"},{"label":"D","content":"超过4分15秒"}]','B','如图所示③,要想用时最少，应路程最短，即甲应先绕岛从 A点走到C 点，再从C 点直线走到B 点；
OB 为圆形人工湖半径120m,OC 为圆形人工岛半径60m,BC 为圆的切线， ∠0CB=90°, 三角形OCB 为30°60°直角三角形，则CB长度为60√3m④;
∠ COB=60°, 则∠AOC=120°, 圆弧 AC为周长的, 即
