INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500189,4,'经济利润问题之分批销售问题','某商店购进一批篮球，定价为进价的125%,在售出进货量的20%后，商店决定打折促销。篮球全部卖完后，商家在该批篮球上总获利15%,问该商店这次促销价为定价的多少折?','[{"label":"A","content":"8"},{"label":"B","content":"8.5"},{"label":"C","content":"9"},{"label":"D","content":"9.5"}]','C','设进价为100,定价则为125,总数量为1份，打了x 折；
