INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500194,4,'行程问题之流水问题+追及问题','一艘维修快艇沿着河流逆流而上执行维修任务，快艇航行到途中某处时工具包掉进了河里，1 0 分钟后，驾驶员到达目的地时发现工具包丢失后立即返回追寻。已知水的流速为每秒1米，如果工具包会浮在水面上漂流，那么驾驶员将在距离丢失处多少米的地方找回工具包?','[{"label":"A","content":"640"},{"label":"B","content":"900"},{"label":"C","content":"1080"},{"label":"D","content":"1200"}]','D','②设快艇速度为V, 掉落处到目的地距离=600×( V-1)⑨; 快艇到达目的地时，工具包已经漂流10分钟(600秒),即已经飘走600m;
此时快艇顺流而下追赶工具包，快艇顺流而下的速度为V+1, 追及距离为
600×(V-1)+600=600V, 则 ,此时工具包已经
顺水飘流1200秒，距离丢失处1200m, 答案为D 选项。
②

②花生批注：
考场秒杀：
把工具包当作参照点，快艇逆水而上行驶10分钟的距离 ( V逆=V-1,V水=1,方向相反，二者速度和=V, 即二者距离=10分钟×V),
顺水而下也需要10分钟 (V顺 =V+1,V水=1,方向相同，速度差=V, 走10分钟×V 的距离需要10分钟),即一共20分钟，工具包距离丢失处=1200×1=1200m。
即掉下遗失物逆流n分钟，
顺流追上也需要n 分钟。','数量关系600题','进阶','published','{"globalNumber":194,"sourceNumber":4,"typeLabel":"行程问题之流水问题+追及问题","stemRich":[{"text":"一艘维修快艇沿着河流逆流而上执行维修任务，快艇航行到途中某处时工 具包掉进了河里，1 0 分 钟 后 ，驾驶员到达目的地时发现工具包丢失后立即返回 追寻。已知水的流速为每秒1米，如果工具包会浮在水面上漂流，那么驾驶员 将在距离丢失处多少米的地方找回工具包?"}],"annotatedStemRich":[{"text":"一艘维修快艇沿着河流逆流而上执行维修任务，快艇航行到途中某处时工 具包掉进了河里，1 0 分 钟 后 ，驾驶员到达目的地时发现工具包丢失后立即返回 追寻。已知水的流速为每秒1米，如果工具包会浮在水面上漂流，那么驾驶员 将在距离丢失处多少米的地方找回工具包?"}],"annotatedOptionRich":{"A":[{"text":"640"}],"B":[{"text":"900"}],"C":[{"text":"1080"}],"D":[{"text":"1200\n"}]},"practicalAnalysis":"②设快艇速度为V, 掉落处到目的地距离=600×( V-1)⑨; 快艇到达目的地时，工具包已经漂流10分钟(600秒),即已经飘走600m;\n此时快艇顺流而下追赶工具包，快艇顺流而下的速度为V+1, 追及距离为\n600×(V-1)+600=600V, 则 ,此时工具包已经\n顺水飘流1200秒，距离丢失处1200m, 答案为D 选项。\n②","notes":[{"marker":"②","text":"考场秒杀：\n把工具包当作参照点，快艇逆水而上行驶10分钟的距离 ( V逆=V-1,V水=1,方向相反，二者速度和=V, 即二者距离=10分钟×V),\n顺水而下也需要10分钟 (V顺 =V+1,V水=1,方向相同，速度差=V, 走10分钟×V 的距离需要10分钟),即一共20分钟，工具包距离丢失处=1200×1=1200m。\n即掉下遗失物逆流n分钟，\n顺流追上也需要n 分钟。","matchScore":0.167}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
