INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500196,4,'容斥问题','某大型相亲类综艺节目举办线下联谊活动，在签到时每人可以抽
取一张礼 物卡，凡是抽中有编号的礼物卡均有玫瑰花赠送，抽到“

谢谢参与”的则赠送 一盒面巾纸。带有编号的礼物卡共100张，

编号1～100,按礼物卡标签号发 放奖品的规则如下：
(1)标签号为2的倍数，领2枝玫瑰

(2)标签号为3的倍数，领3枝玫瑰
(3)标签号既是2的倍数，又是3的倍数可重复领奖

(4)其他标签号均领1枝玫瑰

那么本次联谊活动应准备玫瑰花多少枝?','[{"label":"A","content":"215"},{"label":"B","content":"232"},{"label":"C","content":"312"},{"label":"D","content":"416"}]','B','2的倍数有100÷2=50人，需要准备50×2=100枝玫瑰；3的倍数有100÷3=33人，需要准备33×3=99枝玫瑰；同时是2和3的倍数有100÷6=16人，则2或3倍数的共有50+33-16=67人，其他标签有100-67=33人，还需准备33枝玫瑰；
