INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500197,4,'日期星期问题','2019年1月12日是星期六，那么,2040年1月12日是星期几?','[{"label":"A","content":"星期二"},{"label":"B","content":"星期三"},{"label":"C","content":"星期四"},{"label":"D","content":"星期五"}]','C','闰年④为52周零2天，平年为52周零1天，从2019年1月
12日起，经过21年，到2040年1月12日。
其中闰年有2020、2024、2028、2032、2036共5年，每年不是整周的零头的天数加起来共1×21+5=26天=3周余5天，即2040年1月12日为星期六往后数5天，即星期四，答案为C 选项。

④花生批注：
非整百年份：能被4整除的是闰年(如2024年);整百年份：能被400整除的是闰年(如2000年是闰年， 1900年不是)。','数量关系600题','进阶','published','{"globalNumber":197,"sourceNumber":7,"typeLabel":"日期星期问题","stemRich":[{"text":"2019年1月12日是星期六，那么,2040年1月12日是星期几?"}],"annotatedStemRich":[{"text":"2019年1月12日是星期六，那么,2040年1月12日是星期几?"}],"annotatedOptionRich":{"A":[{"text":" 星期二"}],"B":[{"text":"  星期三"}],"C":[{"text":"  星期四"}],"D":[{"text":"  星期五\n"}]},"practicalAnalysis":"闰年④为52周零2天，平年为52周零1天，从2019年1月\n12日起，经过21年，到2040年1月12日。\n其中闰年有2020、2024、2028、2032、2036共5年，每年不是整周的零头的天数加起来共1×21+5=26天=3周余5天，即2040年1月12日为星期六往后数5天，即星期四，答案为C 选项。","notes":[{"marker":"④","text":"非整百年份：能被4整除的是闰年(如2024年);整百年份：能被400整除的是闰年(如2000年是闰年， 1900年不是)。","matchScore":0.153}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500198,4,'排列组合之两人同组概率问题','某中学在7月暑期每个周一至周五开设一节书法学习课。学生可自愿选择

时间段进行学习。已知小李每周随机选择4天学习，小王每周随机选择2天学习，
问在连续2周时间内，小王恰好每次学习均能遇到小李的概率是多少?','[{"label":"A","content":"（图形选项，见题目原图）"},{"label":"B","content":"（图形选项，见题目原图）"},{"label":"C","content":"（图形选项，见题目原图）"},{"label":"D","content":"（图形选项，见题目原图）"}]','B','若要满足题干条件，需让小王从小李学习的4天中随机选择2天。全部的情况：小王从连续2周各选2天，情况数为C3×C² ;
