INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500199,4,'和差倍比问题','甲、乙两家大型医疗公司的负责人各带一名助手参加展会订购医疗器械。
最终订单显示：每人各自订购了不同种类医疗器械，且其订购的每种医疗器械

台数恰巧等于他所订医疗器械的种类数。每人订购的医疗器械种类数都未超过
15类，并且两位负责人所订购的医疗器械台数不同，但都比自己的助手多购

45台。问甲、乙两公司一共订购了多少台医疗器械?','[{"label":"A","content":"150"},{"label":"B","content":"170"},{"label":"C","content":"210"},{"label":"D","content":"240"}]','B','假设某人订购了x 种医疗器械，每种医疗器械台数为x 台 ( 其订购的每种医疗器械台数恰巧等于他所订医疗器械的种类数),即订购总数为平方数。
根据“每人订购的医疗器械种类数都未超过15类”,即平方数最大为 15×15,即在1至15的平方数中，找出两组差值为45的平方数。
⑤','数量关系600题','进阶','published','{"globalNumber":199,"sourceNumber":9,"typeLabel":"和差倍比问题","stemRich":[{"text":"甲、乙两家大型医疗公司的负责人各带一名助手参加展会订购医疗器械。\n最终订单显示：每人各自订购了不同种类医疗器械，且其订购的每种医疗器械\n\n台数恰巧等于他所订医疗器械的种类数。每人订购的医疗器械种类数都未超过\n15类，并且两位负责人所订购的医疗器械台数不同，但都比自己的助手多购\n\n45台。问甲、乙两公司一共订购了多少台医疗器械?"}],"annotatedStemRich":[{"text":"甲、乙两家大型医疗公司的负责人各带一名助手参加展会订购医疗器械。\n最终订单显示：每人各自订购了不同种类医疗器械，且其订购的每种医疗器械\n\n台数恰巧等于他所订医疗器械的种类数。每人订购的医疗器械种类数都未超过\n15类，并且两位负责人所订购的医疗器械台数不同，但都比自己的助手多购\n\n45台。问甲、乙两公司一共订购了多少台医疗器械?"}],"annotatedOptionRich":{"A":[{"text":"150"}],"B":[{"text":"170"}],"C":[{"text":"210"}],"D":[{"text":"240\n"}]},"practicalAnalysis":"假设某人订购了x 种医疗器械，每种医疗器械台数为x 台 ( 其订购的每种医疗器械台数恰巧等于他所订医疗器械的种类数),即订购总数为平方数。\n根据“每人订购的医疗器械种类数都未超过15类”,即平方数最大为 15×15,即在1至15的平方数中，找出两组差值为45的平方数。\n⑤","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500200,4,'工程问题+统筹规划问题','甲、乙两条生产线生产A和B 两种产品。其中甲生产线生产A、B产品的

效率分别是乙生产线的2倍和3倍。现有2种产品各X件的生产任务，企业安
排甲和乙生产线合作尽快完成任务，最终甲总共生产了1.5X件产品。问乙在
单位时间内生产A的件数是生产B 件数的多少倍?','[{"label":"A","content":"（图形选项，见题目原图）"},{"label":"B","content":"（图形选项，见题目原图）"},{"label":"C","content":"（图形选项，见题目原图）"},{"label":"D","content":"（图形选项，见题目原图）"}]','A','根据题意可知，乙相对更擅长A产品，可安排乙生产A产品，甲先生产B 产品，之后再和乙合作生产A产品。
设乙生产B 产品的效率为1,生产A产品的效率为n⑥, 则甲生产B 产品的效率为3,生产A产品的效率为2n;
一共有2X 件产品，甲生产了1.5X 件产品(先生产X 件 B产品再生产0.5X 件A产品),则乙生产0 .5X 件 A产品；
二人生产时间相同，可据此列式： , 解得 , 即
单位时间内乙生产 A的效率是B的倍，生产的件数也是生产倍，答案
为A选项。

⑥花生批注：
所求为“乙在单位时间内生产A的件数是生产B件数的多少倍”,即乙生产A的效率是生产B的效率的多少倍，可设生产A的效率为n, 生产B的效率为1(即分母为 1), 求出n 即倍数。','数量关系600题','进阶','published','{"globalNumber":200,"sourceNumber":10,"typeLabel":"工程问题+统筹规划问题","stemRich":[{"text":"甲、乙两条生产线生产A和B 两种产品。其中甲生产线生产A、B产品的\n\n效率分别是乙生产线的2倍和3倍。现有2种产品各X件的生产任务，企业安\n排甲和乙生产线合作尽快完成任务，最终甲总共生产了1.5X件产品。问乙在\n单位时间内生产A的件数是生产B 件数的多少倍?"}],"annotatedStemRich":[{"text":"甲、乙两条生产线生产A和B 两种产品。其中甲生产线生产A、B产品的\n\n效率分别是乙生产线的2倍和3倍。现有2种产品各X件的生产任务，企业安\n排甲和乙生产线合作尽快完成任务，最终甲总共生产了1.5X件产品。问乙在\n单位时间内生产A的件数是生产B 件数的多少倍?"}],"annotatedOptionRich":{"A":[{"text":"（图形选项，见题目原图）"}],"B":[{"text":"（图形选项，见题目原图）"}],"C":[{"text":"（图形选项，见题目原图）"}],"D":[{"text":"（图形选项，见题目原图）"}]},"practicalAnalysis":"根据题意可知，乙相对更擅长A产品，可安排乙生产A产品，甲先生产B 产品，之后再和乙合作生产A产品。\n设乙生产B 产品的效率为1,生产A产品的效率为n⑥, 则甲生产B 产品的效率为3,生产A产品的效率为2n;\n一共有2X 件产品，甲生产了1.5X 件产品(先生产X 件 B产品再生产0.5X 件A产品),则乙生产0 .5X 件 A产品；\n二人生产时间相同，可据此列式： , 解得 , 即\n单位时间内乙生产 A的效率是B的倍，生产的件数也是生产倍，答案\n为A选项。","notes":[{"marker":"⑥","text":"所求为“乙在单位时间内生产A的件数是生产B件数的多少倍”,即乙生产A的效率是生产B的效率的多少倍，可设生产A的效率为n, 生产B的效率为1(即分母为 1), 求出n 即倍数。","matchScore":0.25}],"missingOptionLabels":["A","B","C","D"],"pairingMode":"word-type-anchor-and-number","imageKeys":["numeric/20260717/quantity/500200.png"],"imageSourcePage":133}','numeric/20260717/quantity/500200.png');
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500201,4,'最值问题之和定最值','一个快递分发点的快递员某天人均送件量为220件，最少的送
了200件。 已知有一名快递员送了260件，除他之外的快递员人均

送件量为218件。当天 该快递分发点的一名快递员送件量最多为多

少?','[{"label":"A","content":"542件"},{"label":"B","content":"560件"},{"label":"C","content":"582件"},{"label":"D","content":"596件"}]','B','设快递员为x 人，可根据快递总量列方程：220x=260+(x-1) ×218,解得 x=21 人，快递总量=220×21=4620件；
设送件量最多的快递员送了y 件，要想y 尽量大，其他人要尽量小，题目并未要求每人送件量相同，可让其余19人都送200件(已知有一名快递员送了260件),则y 最大=4620-200×19-260=560,答案为B选项。','数量关系600题','进阶','published','{"globalNumber":201,"sourceNumber":1,"typeLabel":"最值问题之和定最值","stemRich":[{"text":"一个快递分发点的快递员某天人均送件量为220件，最少的送\n了200件。 已知有一名快递员送了260件，除他之外的快递员人均\n\n送件量为218件。当天 该快递分发点的一名快递员送件量最多为多\n\n少?"}],"annotatedStemRich":[{"text":"一个快递分发点的快递员某天人均送件量为220件，最少的送\n了200件。 已知有一名快递员送了260件，除他之外的快递员人均\n\n送件量为218件。当天 该快递分发点的一名快递员送件量最多为多\n\n少?"}],"annotatedOptionRich":{"A":[{"text":" 542件"}],"B":[{"text":"  560件"}],"C":[{"text":" 582件"}],"D":[{"text":"  596件\n"}]},"practicalAnalysis":"设快递员为x 人，可根据快递总量列方程：220x=260+(x-1) ×218,解得 x=21 人，快递总量=220×21=4620件；\n设送件量最多的快递员送了y 件，要想y 尽量大，其他人要尽量小，题目并未要求每人送件量相同，可让其余19人都送200件(已知有一名快递员送了260件),则y 最大=4620-200×19-260=560,答案为B选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500202,4,'和差倍比问题','某企业参与兴办了甲、乙、丙、丁4个扶贫车间，共投资450万元，甲车间的投资额是其他三个车间投资额之和的一半，乙车间的投资额比丙车间高 25%,丁车间的投资额比乙、丙车间投资额之和低60万元。企业后期向4个车间追加了200万元投资，每个车间的追加投资额都不超过其余任一车间追加投资额的2倍，问总投资额最高和最低的车间，总投资额最多可能相差多少万元?','[{"label":"A","content":"70"},{"label":"B","content":"90"},{"label":"C","content":"110"},{"label":"D","content":"130"}]','C','根据题意可知甲车间投资额占总投资额的 ,即150万元，其他车间共投资300万元。
设丙车间的投资额为4x 万元，则乙车间的投资额为5x 万元，丁车间的投资额为(9x-60 )万元。可列方程：18x-60=300, 解得x=20, 故甲、乙、丙、丁 4个车间的投资额分别为150、100、80、120万元。
要想总投资额最高和最低的车间相差尽量多，甲车间追加投资额应最多，
丙车间追加投资额应最少①,设甲车间追加投资额为2y 万元，其余3个车间追加投资额都为y 万元。可列方程：5y=200, 解得y=40。
故总投资额最高和最低的车间，总投资额最多可能相差 150-80+40=110万元 ②

①花生批注：
原来投资额最高和最低的分别为甲、丙车间，对甲追加得越多，对丙追加得越少，他们的差距才会越大。

②花生批注：
追加后，两车间的差距会扩大y, 即40万元。','数量关系600题','进阶','published','{"globalNumber":202,"sourceNumber":2,"typeLabel":"和差倍比问题","stemRich":[{"text":"某企业参与兴办了甲、乙、丙、丁4个扶贫车间，共投资450万元，甲 车间的投资额是其他三个车间投资额之和的一半，乙车间的投资额比丙车间高 25%,丁车间的投资额比乙、丙车间投资额之和低60万元。企业后期向4个车 间追加了200万元投资，每个车间的追加投资额都不超过其余任一车间追加投 资额的2倍，问总投资额最高和最低的车间，总投资额最多可能相差多少万元?"}],"annotatedStemRich":[{"text":"某企业参与兴办了甲、乙、丙、丁4个扶贫车间，共投资450万元，甲 车间的投资额是其他三个车间投资额之和的一半，乙车间的投资额比丙车间高 25%,丁车间的投资额比乙、丙车间投资额之和低60万元。企业后期向4个车 间追加了200万元投资，每个车间的追加投资额都不超过其余任一车间追加投 资额的2倍，问总投资额最高和最低的车间，总投资额最多可能相差多少万元?"}],"annotatedOptionRich":{"A":[{"text":"70"}],"B":[{"text":"90"}],"C":[{"text":"110"}],"D":[{"text":"130\n"}]},"practicalAnalysis":"根据题意可知甲车间投资额占总投资额的 ,即150万元，其他车间共投资300万元。\n设丙车间的投资额为4x 万元，则乙车间的投资额为5x 万元，丁车间的投资额为(9x-60 )万元。可列方程：18x-60=300, 解得x=20, 故甲、乙、丙、丁 4个车间的投资额分别为150、100、80、120万元。\n要想总投资额最高和最低的车间相差尽量多，甲车间追加投资额应最多，\n丙车间追加投资额应最少①,设甲车间追加投资额为2y 万元，其余3个车间追加投资额都为y 万元。可列方程：5y=200, 解得y=40。\n故总投资额最高和最低的车间，总投资额最多可能相差 150-80+40=110万元 ②","notes":[{"marker":"①","text":"原来投资额最高和最低的分别为甲、丙车间，对甲追加得越多，对丙追加得越少，他们的差距才会越大。","matchScore":0.176},{"marker":"②","text":"追加后，两车间的差距会扩大y, 即40万元。","matchScore":0.063}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500203,4,'工程问题','甲、乙两人同时加工一批零件，速度比为3:2,当两人共同完成总任务

的一半后，甲生产速度降低20%,乙生产速度提高20%,当甲完成总任务的一
半时，还剩100个零件未加工，问这批零件总数在以下哪个范围内?

件，','[{"label":"A","content":"不到500"},{"label":"B","content":"500～800"},{"label":"C","content":"801～1200"},{"label":"D","content":"超过1200"}]','C','甲乙初始速度比为3:2,则速度调整后甲乙速度比变为2.4:2.4 =1:1,提速后甲乙速度相等。
