INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500208,4,'日期星期问题','7月的某一天，小张制定了一个读书计划：从今天开始，在每周的周一至周五晚上读党史系列丛书。如果小张每晚读20页，到7月28日刚好能读完第一卷，如果每天读30页，则到7月20日刚好能读完第一卷。如果7月1日是星期三，则小张是在7月几日制定的读书计划?','[{"label":"A","content":"2"},{"label":"B","content":"3"},{"label":"C","content":"5"},{"label":"D","content":"7"}]','B','7月1日是星期三，则7月22日是星期三③,7月20日为星期一。 7月21 日至7月28日包含一个周末 ⑨,共读书6天，所以若7月28日读完，比20日读完时多读8-2=6天。每天读30页与每天读20页所需天数比为2:3, 相差1份=6天，则每天读30页时所需天数为12天。
7月7日至20日是两周，可读书10天，7月6日是周一，7月3日是周五，加上这两天一共是12天，即7月3日制定的读书计划，答案为B选项。
⑬

