INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500214,4,'经济利润问题','为促进旅游业复苏，今年8月1日起至年底，某景区门票价格在原定价的基础上，工作日执行两折票价，双休日及法定节假日执行五折票价。预计门票打折后，每天的游客人数均比原来翻一番，已知打折前该景区双休日平均每天的游客人数是工作日的5倍，则打折后，该景区一周(该周无法定节假日)的门票收入是打折前的?','[{"label":"A","content":"0.5 倍"},{"label":"B","content":"0.6 倍"},{"label":"C","content":"0.7 倍"},{"label":"D","content":"0.8 倍"}]','D','题干只给出倍数关系，未涉及具体数值，可用赋值法，赋值门票原定价10元9,打折前工作日每天的游客人数为1,根据题意：
工作日票价
工作日人数
双休日票价
双休日人数
一周门票收入
打折前
10
1×5=5
10
1×5×2=10
10×5+10×10=150
打折后
10×20%=2
2×5=10
10×50%=5
2×10=20
2×10+5×20=120
打折后是打折前收入的120÷150=0.8倍，答案为D选项。','数量关系600题','进阶','published','{"globalNumber":214,"sourceNumber":4,"typeLabel":"经济利润问题","stemRich":[{"text":"为促进旅游业复苏，今年8月1日起至年底，某景区门票价格在原定价的基础上，工作日执行两折票价，双休日及法定节假日执行五折票价。预计门票打折后，每天的游客人数均比原来翻一番，已知打折前该景区双休日平均每天的游客人数是工作日的5倍，则打折后，该景区一周(该周无法定节假日)的门票收入是打折前的?"}],"annotatedStemRich":[{"text":"为促进旅游业复苏，今年8月1日起至年底，某景区门票价格在原定价的基础上，工作日执行两折票价，双休日及法定节假日执行五折票价。预计门票打折后，每天的游客人数均比原来翻一番，已知打折前该景区双休日平均每天的游客人数是工作日的5倍，则打折后，该景区一周(该周无法定节假日)的门票收入是打折前的?"}],"annotatedOptionRich":{"A":[{"text":"0.5    倍"}],"B":[{"text":"0.6    倍","bold":true}],"C":[{"text":"0.7    倍","bold":true}],"D":[{"text":"0.8    倍\n"}]},"practicalAnalysis":"题干只给出倍数关系，未涉及具体数值，可用赋值法，赋值门票原定价10元9,打折前工作日每天的游客人数为1,根据题意：\n工作日票价\n工作日人数\n双休日票价\n双休日人数\n一周门票收入\n打折前\n10\n1×5=5\n10\n1×5×2=10\n10×5+10×10=150\n打折后\n10×20%=2\n2×5=10\n10×50%=5\n2×10=20\n2×10+5×20=120\n打折后是打折前收入的120÷150=0.8倍，答案为D选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
