INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500216,4,'行程问题','甲、乙、丙三人沿着长为500米，宽为250米的长方形场地跑步，三人以

2:1:3的速度之比匀速顺时针跑步，当甲开跑时乙刚跑完 圈，丙开跑时
甲 跑了100米。问当乙跑完2圈时，甲与丙的位置关系如何?','[{"label":"A","content":"丙领先甲2350米"},{"label":"B","content":"丙领先甲2450米"},{"label":"C","content":"丙领先甲2900米"},{"label":"D","content":"丙领先甲3000米"}]','A','乙跑2圈时，去掉在甲开跑前跑的圈，甲开跑后，乙跑了
圈；甲乙速度比2:1,则相同时间甲跑了
丙开跑时，甲跑了100m, 即丙开跑后甲跑了4900m, 甲丙速度比为2:3, 则丙比甲多跑2450m②, 因最初丙落后甲100m, 则此时丙领先甲2350m, 答案为 A选项。','数量关系600题','进阶','published','{"globalNumber":216,"sourceNumber":6,"typeLabel":"行程问题","stemRich":[{"text":"甲、乙、丙三人沿着长为500米，宽为250米的长方形场地跑步，三人以\n\n2:1:3的速度之比匀速顺时针跑步，当甲开跑时乙刚跑完 圈，丙开跑时\n甲 跑了100米。问当乙跑完2圈时，甲与丙的位置关系如何?"}],"annotatedStemRich":[{"text":"甲、乙、丙三人沿着长为500米，宽为250米的长方形场地跑步，三人以\n\n2:1:3的速度之比匀速顺时针跑步，当甲开跑时乙刚跑完 圈，丙开跑时\n甲 跑了100米。问当乙跑完2圈时，甲与丙的位置关系如何?"}],"annotatedOptionRich":{"A":[{"text":"  丙领先甲2350米"}],"B":[{"text":"  丙领先甲2450米"}],"C":[{"text":"  丙领先甲2900米"}],"D":[{"text":"   丙领先甲3000米\n"}]},"practicalAnalysis":"乙跑2圈时，去掉在甲开跑前跑的圈，甲开跑后，乙跑了\n圈；甲乙速度比2:1,则相同时间甲跑了\n丙开跑时，甲跑了100m, 即丙开跑后甲跑了4900m, 甲丙速度比为2:3, 则丙比甲多跑2450m②, 因最初丙落后甲100m, 则此时丙领先甲2350m, 答案为 A选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500217,4,'概率问题','小陈上班要经过3个交通路口，在每个交通路口遇到红灯的概率分别为
30%、40%、50%,则他上班最多遇到1个红灯的概率为多少?','[{"label":"A","content":"35%"},{"label":"B","content":"56%"},{"label":"C","content":"65%"},{"label":"D","content":"79%"}]','C','小陈在3个路口遇到红灯概率分别为30%、40%、50%, 则没有遇到红灯的概率分别为70%、60%、50%。
最多遇到1个红灯可分情况讨论：
①没有遇到红灯：70%×60%×50%=21%;
②第1个路口遇到红灯：30%×60%×50%=9%;
③第2个路口遇到红灯：70%×40%×50%=14%
④第3个路口遇到红灯：70%×60%×50%=21%;
综上，最多遇到一个红灯的概率=21%+9%+14%+21%=65%,答案为C 选项。','数量关系600题','进阶','published','{"globalNumber":217,"sourceNumber":7,"typeLabel":"概率问题","stemRich":[{"text":"小陈上班要经过3个交通路口，在每个交通路口遇到红灯的概率分别为\n30%、40%、50%,则他上班最多遇到1个红灯的概率为多少?"}],"annotatedStemRich":[{"text":"小陈上班要经过3个交通路口，在每个交通路口遇到红灯的概率分别为\n30%、40%、50%,则他上班最多遇到1个红灯的概率为多少?"}],"annotatedOptionRich":{"A":[{"text":"35%"}],"B":[{"text":"56%"}],"C":[{"text":"65%"}],"D":[{"text":"79%\n"}]},"practicalAnalysis":"小陈在3个路口遇到红灯概率分别为30%、40%、50%, 则没有遇到红灯的概率分别为70%、60%、50%。\n最多遇到1个红灯可分情况讨论：\n①没有遇到红灯：70%×60%×50%=21%;\n②第1个路口遇到红灯：30%×60%×50%=9%;\n③第2个路口遇到红灯：70%×40%×50%=14%\n④第3个路口遇到红灯：70%×60%×50%=21%;\n综上，最多遇到一个红灯的概率=21%+9%+14%+21%=65%,答案为C 选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500218,4,'几何问题之几何计算','某公园有一个圆形的湖，在湖的直径EB处有一座观光桥，横穿整个湖。

园区在平行于观光桥的MN处建造了一片雕塑群，用以介绍中国古代礼仪与民俗，
其长度等于湖的半径。某游客在湖边与观光桥上边走边欣赏湖中的雕塑群，走
过了A、B、C、D四处位置。如图所示，A为该湖的圆心，N、D、C在一条线上，

且ND⊥AB。那么在这四处位置，游客的观察视角大于45°的有多少处?(观
察视角，即游客在该点处观看景物的视野张角，例如在D点处，其观察视角为

∠MDN)','[{"label":"A","content":"1"},{"label":"B","content":"2"},{"label":"C","content":"3"},{"label":"D","content":"4"}]','B','如图所示⑧ :
