INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500221,4,'年龄问题','已知某家族4位成员的年龄总和为142岁，且他们的年龄恰好成等差数列，若其中一位的年龄为47岁，则这4人中最年长者的年龄为多少岁?','[{"label":"A","content":"65 岁"},{"label":"B","content":"70 岁"},{"label":"C","content":"83 岁"},{"label":"D","content":"90 岁"}]','B','设四人年龄分别为 a₁ 、a₂ 、a₃ 、a4, 则 a₁+a₂+a₃+a₄=142;
a₁+a₄=a₂+a₃=142÷2=71。
已知其中一人的年龄为47,那么对应一人的年龄=71-47=24,根据选项可判断47并非最大年龄，所以a₂=24 、a₃=47, 即 d=23,a₄=70, 答案为 B 选项。','数量关系600题','进阶','published','{"globalNumber":221,"sourceNumber":1,"typeLabel":"年龄问题","stemRich":[{"text":"已知某家族4位成员的年龄总和为142岁，且他们的年龄恰好成等差数列， 若其中一位的年龄为47岁，则这4人中最年长者的年龄为多少岁?"}],"annotatedStemRich":[{"text":"已知某家族4位成员的年龄总和为142岁，且他们的年龄恰好成等差数列， 若其中一位的年龄为47岁，则这4人中最年长者的年龄为多少岁?"}],"annotatedOptionRich":{"A":[{"text":"65   岁"}],"B":[{"text":"  "},{"text":"70","bold":true},{"text":" "},{"text":"岁","bold":true}],"C":[{"text":"83  岁"}],"D":[{"text":"  90 岁\n"}]},"practicalAnalysis":"设四人年龄分别为 a₁ 、a₂ 、a₃ 、a4, 则 a₁+a₂+a₃+a₄=142;\na₁+a₄=a₂+a₃=142÷2=71。\n已知其中一人的年龄为47,那么对应一人的年龄=71-47=24,根据选项可判断47并非最大年龄，所以a₂=24 、a₃=47, 即 d=23,a₄=70, 答案为 B 选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500222,4,'统筹规划问题之天平称重','茗心茶厂在生产茶包时，发现一台机器故障，导致1袋茶包的重

