INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500224,4,'工程问题','师徒二人用15天合作生产1000个零件，前5天师傅的效率是徒

弟的2倍， 中间5天师傅休息，徒弟每天比原来多生产5个零件，最
后5天两人又一起工作， 师傅的效率不变，徒弟的效率比中间5天

提高了50%,徒弟这15天生产的零件 个数是多少个?','[{"label":"A","content":"450"},{"label":"B","content":"500"},{"label":"C","content":"550"},{"label":"D","content":"600"}]','B','设前5天徒弟每天生产x 个，师傅则生产2x个，中间5天徒弟生产x+5个，最后5天徒弟生产1.5x+7.5个，师傅依然是生产2x 个；
根据生产总量列方程：5(x+2x)+5(x+5)+5(x+1.5x+7.5)=1000, 解得x=25,
则徒弟生产的数 ,答案为B选项。

④花生批注：
师傅生产了10天，效率均为 2x, 工作总量为20x。','数量关系600题','进阶','published','{"globalNumber":224,"sourceNumber":4,"typeLabel":"工程问题","stemRich":[{"text":"师徒二人用15天合作生产1000个零件，前5天师傅的效率是徒\n\n弟的2倍， 中间5天师傅休息，徒弟每天比原来多生产5个零件，最\n后5天两人又一起工作， 师傅的效率不变，徒弟的效率比中间5天\n\n提高了50%,徒弟这15天生产的零件 个数是多少个?"}],"annotatedStemRich":[{"text":"师徒二人用15天合作生产1000个零件，前5天师傅的效率是徒\n\n弟的2倍， 中间5天师傅休息，徒弟每天比原来多生产5个零件，最\n后5天两人又一起工作， 师傅的效率不变，徒弟的效率比中间5天\n\n提高了50%,徒弟这15天生产的零件 个数是多少个?"}],"annotatedOptionRich":{"A":[{"text":"450"}],"B":[{"text":"500"}],"C":[{"text":"550"}],"D":[{"text":"600\n"}]},"practicalAnalysis":"设前5天徒弟每天生产x 个，师傅则生产2x个，中间5天徒弟生产x+5个，最后5天徒弟生产1.5x+7.5个，师傅依然是生产2x 个；\n根据生产总量列方程：5(x+2x)+5(x+5)+5(x+1.5x+7.5)=1000, 解得x=25,\n则徒弟生产的数 ,答案为B选项。","notes":[{"marker":"④","text":"师傅生产了10天，效率均为 2x, 工作总量为20x。","matchScore":0.097}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500225,4,'排列组合问题之特殊情境','某羽毛球团体比赛分为男单、女单、男双、女双、混双5个单项，决赛对阵双方为A队和B队。其中A 队的张某同时参加男双和混双，B队的李某同时参加女双和混双，其他人都只参加1个项目。如果同一个人不能连续参赛，那么这5个单项有多少种不同的排列方法?','[{"label":"A","content":"20"},{"label":"B","content":"36"},{"label":"C","content":"60"},{"label":"D","content":"72"}]','B','同一个人不能连续参赛，则男双和混双不能相邻、女双和混双不能相邻(但是男双和女双可以相邻);
可分情况讨论：
男双和女双不相邻：即不相邻问题⑤,先排男单和女单，即 ;形成3个空，男双、女双、混双有顺序的插入空中，即A3; 一共有 2种排法；
男双和女双相邻：即相邻问题⑥,将男双和女双捆绑，内部需要排序，即 A2; 再排男单和女单，即A2; 形成3个空，男双和女双、混双有顺序的插入
空中，即A3; 一共有A2×A²× 种排法；
综上，一共有12+24=36种排法，答案为B 选项。
⑤

⑤花生批注：
排列组合八大特殊情境之一的不相邻问题(其他七大为相邻问题、定序问题、相同元素分配、平均分堆
问题、环形排列、错位排序、重复排列):
不相邻问题采用插空法，先将没有位置要求的元素排好，再将不能相邻的元素插入空中。

⑥花生批注：
排列组合八大特殊情境之一的相邻问题(其他七大为不相邻问题、定序问题、相同元素分配、平均分堆
问题、环形排列、错位排序、重复排列):
相邻问题常用方法为捆绑法，将必须相邻的元素捆在一起，看作一个元素；
捆绑法需要注意两点：
总元素个数发生改变，捆
绑在一起的元素要考虑是否内部排序。

⑯花生批注：
排列组合八大特殊情境之一的定序问题(其他七大为相邻问题、不相邻问题、重复排列、相同元素分配、平均分堆问题、环形排列、错位排序):
n 个元素全排列，其中有m 个元素相对顺序不变，则
情况数为
平均分堆后自带顺序，但本题各组间无顺序，故需
要除以组数的全排列。','数量关系600题','进阶','published','{"globalNumber":225,"sourceNumber":5,"typeLabel":"排列组合问题之特殊情境","stemRich":[{"text":"某羽毛球团体比赛分为男单、女单、男双、女双、混双5个单项，决赛对 阵双方为A队和B队。其中A 队的张某同时参加男双和混双，B队的李某同时 参加女双和混双，其他人都只参加1个项目。如果同一个人不能连续参赛，那 么这5个单项有多少种不同的排列方法?"}],"annotatedStemRich":[{"text":"某羽毛球团体比赛分为男单、女单、男双、女双、混双5个单项，决赛对 阵双方为A队和B队。其中A 队的张某同时参加男双和混双，B队的李某同时 参加女双和混双，其他人都只参加1个项目。如果同一个人不能连续参赛，那 么这5个单项有多少种不同的排列方法?"}],"annotatedOptionRich":{"A":[{"text":"20"}],"B":[{"text":"36"}],"C":[{"text":"60"}],"D":[{"text":"72\n"}]},"practicalAnalysis":"同一个人不能连续参赛，则男双和混双不能相邻、女双和混双不能相邻(但是男双和女双可以相邻);\n可分情况讨论：\n男双和女双不相邻：即不相邻问题⑤,先排男单和女单，即 ;形成3个空，男双、女双、混双有顺序的插入空中，即A3; 一共有 2种排法；\n男双和女双相邻：即相邻问题⑥,将男双和女双捆绑，内部需要排序，即 A2; 再排男单和女单，即A2; 形成3个空，男双和女双、混双有顺序的插入\n空中，即A3; 一共有A2×A²× 种排法；\n综上，一共有12+24=36种排法，答案为B 选项。\n⑤","notes":[{"marker":"⑤","text":"排列组合八大特殊情境之一的不相邻问题(其他七大为相邻问题、定序问题、相同元素分配、平均分堆\n问题、环形排列、错位排序、重复排列):\n不相邻问题采用插空法，先将没有位置要求的元素排好，再将不能相邻的元素插入空中。","matchScore":0.112},{"marker":"⑥","text":"排列组合八大特殊情境之一的相邻问题(其他七大为不相邻问题、定序问题、相同元素分配、平均分堆\n问题、环形排列、错位排序、重复排列):\n相邻问题常用方法为捆绑法，将必须相邻的元素捆在一起，看作一个元素；\n捆绑法需要注意两点：\n总元素个数发生改变，捆\n绑在一起的元素要考虑是否内部排序。","matchScore":0.102},{"marker":"⑯","text":"排列组合八大特殊情境之一的定序问题(其他七大为相邻问题、不相邻问题、重复排列、相同元素分配、平均分堆问题、环形排列、错位排序):\nn 个元素全排列，其中有m 个元素相对顺序不变，则\n情况数为\n平均分堆后自带顺序，但本题各组间无顺序，故需\n要除以组数的全排列。","matchScore":0.091}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
