INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500227,4,'几何问题之等比放缩','一个重量为x 千克的圆台形容器如下图所示，其口部半径是底面半径的2

倍。在容器中装满水，总重量为9千克。从中倒出部分水使得液面高度为装满
时的一半，总重量下降到4.5千克。问x 的值在以下哪个范围内?','[{"label":"A","content":"x<1.5"},{"label":"B","content":"1.5≤x<2\np为MN中点，设AM=2, 则AP=3, AN=4。\n⑩"},{"label":"C","content":"2≤x<2.5"},{"label":"D","content":"x≥2.5"}]','C','如图所示，将圆台补成圆锥，a 、a+b 、a+b+c 三个圆锥高之比 AM:AP: AN=2:3:4°, 根据等比放缩性质可知三个圆锥体积之比=8:27:64, 即 a 部分体积为8,b 部分体积为27-8=19,c 部分体积为64-27=37①;
倒出c 部分的水，重量下降9-4.5=4.5千克，即37份体积对应4.5kg; 剩余的b 部分体积为19份，其中水的重量应稍大于2.25kg②,即 x 稍小于2.25kg, 答案为C 选项。

⑨花生批注：
一个重量为x 千克的圆台形容器如下图所示，其口部半径是底面半径的2 倍。在容器中装满水，总重量为9千克。从中倒出部分水使得液面高度为装满时的一半，总重量下降到4.5千克。问x 的值在以下哪个范围内?
△AMB 与△ANC 相似， BM:CN=1:2,
则 AM :AN=1:2,

⑩花生批注：
几何等比放缩性质：
若边长(或半径)为n 倍，
