INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500232,4,'经济利润问题','商店做促销活动，购买店内商品第一件原价，第二件(价格不高

于第一件) 4折，第三件(价格不高于第二件)1折。小刘买了1件

A和 2 件B商品，优 惠后的总价格相当于定价的56.25%。已知A
商品比B商品贵，则按原价买10 件A商品的钱最多可以按原价买多

少件B商品?','[{"label":"A","content":"20"},{"label":"B","content":"16"},{"label":"C","content":"14"},{"label":"D","content":"12"}]','C','根据题意，两件 B的原价为2B, 打折后价格为0.5B, 可看为打2.5折，则有：

②花生批注：
赋值法使用时机：
①题目中只有比例关系，无具体数字。
②符合的关系，给出 A的数字，B、C可赋值。
③对于恒等关系或恒成立其他关系，可赋值用特殊情况判断正误。
④对于几何问题，若所求为长度、面积、体积等的比值，可采用赋值法。
⑤解不定方程式的赋零法：若求的是A+B+C,可设某个未知数为0,再求出另外俩个未知数，和不变。
本题符合第一种情况

③花生批注：
本题也可采用方程法：
A+0.5B=(A+2B)×56.25%, 解得 A: B=10:7
赋值②A 一件10元， B 一件7元，则买10件
7
可得则
,
A 商品需要100元，最多可买14件B 商品。③','数量关系600题','进阶','published','{"globalNumber":232,"sourceNumber":2,"typeLabel":"经济利润问题","stemRich":[{"text":"商店做促销活动，购买店内商品第一件原价，第二件(价格不高\n\n于第一件) 4折，第三件(价格不高于第二件)1折。小刘买了1件\n\nA和 2 件B商品，优 惠后的总价格相当于定价的56.25%。已知A\n商品比B商品贵，则按原价买10 件A商品的钱最多可以按原价买多\n\n少件B商品?"}],"annotatedStemRich":[{"text":"商店做促销活动，购买店内商品第一件原价，第二件(价格不高\n\n于第一件) 4折，第三件(价格不高于第二件)1折。小刘买了1件\n\nA和 2 件B商品，优 惠后的总价格相当于定价的56.25%。已知A\n商品比B商品贵，则按原价买10 件A商品的钱最多可以按原价买多\n\n少件B商品?"}],"annotatedOptionRich":{"A":[{"text":"20"}],"B":[{"text":"16"}],"C":[{"text":"14"}],"D":[{"text":"12\n"}]},"practicalAnalysis":"根据题意，两件 B的原价为2B, 打折后价格为0.5B, 可看为打2.5折，则有：","notes":[{"marker":"②","text":"赋值法使用时机：\n①题目中只有比例关系，无具体数字。\n②符合的关系，给出 A的数字，B、C可赋值。\n③对于恒等关系或恒成立其他关系，可赋值用特殊情况判断正误。\n④对于几何问题，若所求为长度、面积、体积等的比值，可采用赋值法。\n⑤解不定方程式的赋零法：若求的是A+B+C,可设某个未知数为0,再求出另外俩个未知数，和不变。\n本题符合第一种情况","matchScore":0.029},{"marker":"③","text":"本题也可采用方程法：\nA+0.5B=(A+2B)×56.25%, 解得 A: B=10:7\n赋值②A 一件10元， B 一件7元，则买10件\n7\n可得则\n,\nA 商品需要100元，最多可买14件B 商品。③","matchScore":0.201}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
