INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500234,4,'行程问题','在 一 个即时战略电子游戏中，电子士兵以每分钟 一 米的速度沿 一 条固定路

线行军，任意两名士兵相遇后，都会掉头行进；行至路线的起点或终点时，便
停止前进并对此地的基地进行无差别攻击。玩家阿坤的基地距离魔王城堡基地

9 米 。游戏开始，他立即派出 一 名士兵，此后每隔1分钟派出1名士兵，共计7 名 。
一 名士兵出发半分钟后，魔王也从城堡基地每隔1分钟派出1名士兵，共计8名。
若之后双方均未继续派兵，则游戏开始多少分钟后，所有士兵均已开始攻击?','[{"label":"A","content":"16.5"},{"label":"B","content":"17"},{"label":"C","content":"17.5"},{"label":"D","content":"18\nIHA海IGOGKO"}]','A','因双方士兵速度相同，又有“任意两名士兵相遇后，都会掉头行进；行至路线的起点或终点时，便停止前进并对此地的基地进行无差别攻击”,可当作双方士兵相遇之后互换身份继续向前，由题干已知魔王派出小兵数多于玩家，即只考虑魔王派兵时间即可，魔王0.5分时派出第一名士兵，则应
在7.5分时派出最后一名士兵。分后开始攻击④,
④

④花生批注：
最后一名士兵不会遇到其他士兵，故一直行进到终点，开始攻击。
则游戏开始7.5+9=16.5分钟后，所有士兵均已开始攻击。','数量关系600题','进阶','published','{"globalNumber":234,"sourceNumber":4,"typeLabel":"行程问题","stemRich":[{"text":"在 一 个即时战略电子游戏中，电子士兵以每分钟 一 米的速度沿 一 条固定路\n\n线行军，任意两名士兵相遇后，都会掉头行进；行至路线的起点或终点时，便\n停止前进并对此地的基地进行无差别攻击。玩家阿坤的基地距离魔王城堡基地\n\n9 米 。游戏开始，他立即派出 一 名士兵，此后每隔1分钟派出1名士兵，共计7 名 。\n一 名士兵出发半分钟后，魔王也从城堡基地每隔1分钟派出1名士兵，共计8名。\n若之后双方均未继续派兵，则游戏开始多少分钟后，所有士兵均已开始攻击?"}],"annotatedStemRich":[{"text":"在 一 个即时战略电子游戏中，电子士兵以每分钟 一 米的速度沿 一 条固定路\n\n线行军，任意两名士兵相遇后，都会掉头行进；行至路线的起点或终点时，便\n停止前进并对此地的基地进行无差别攻击。玩家阿坤的基地距离魔王城堡基地\n\n9 米 。游戏开始，他立即派出 一 名士兵，此后每隔1分钟派出1名士兵，共计7 名 。\n一 名士兵出发半分钟后，魔王也从城堡基地每隔1分钟派出1名士兵，共计8名。\n若之后双方均未继续派兵，则游戏开始多少分钟后，所有士兵均已开始攻击?"}],"annotatedOptionRich":{"A":[{"text":"16.5"}],"B":[{"text":"17"}],"C":[{"text":"17.5"}],"D":[{"text":"18\n"},{"text":"IHA海IGOGKO                                                                                                                                                 练","bold":true},{"text":" "},{"text":"习","bold":true},{"text":" "},{"text":"题","bold":true},{"text":" "},{"text":"24","bold":true},{"text":"   "},{"text":"套","bold":true},{"text":"\n"}]},"practicalAnalysis":"因双方士兵速度相同，又有“任意两名士兵相遇后，都会掉头行进；行至路线的起点或终点时，便停止前进并对此地的基地进行无差别攻击”,可当作双方士兵相遇之后互换身份继续向前，由题干已知魔王派出小兵数多于玩家，即只考虑魔王派兵时间即可，魔王0.5分时派出第一名士兵，则应\n在7.5分时派出最后一名士兵。分后开始攻击④,\n④","notes":[{"marker":"④","text":"最后一名士兵不会遇到其他士兵，故一直行进到终点，开始攻击。\n则游戏开始7.5+9=16.5分钟后，所有士兵均已开始攻击。","matchScore":0.197}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500235,4,'排列组合与概率问题','有两排各6个连续的空车位，包含甲车、乙车在内的6辆车随机停入这12

个车位中，则以下哪种情况发生的概率最低?','[{"label":"A","content":"有一排正好停了2辆车"},{"label":"B","content":"甲车和乙车停在同一排的不相邻车位"},{"label":"C","content":"甲车停在某一排的中间两个车位之一"},{"label":"D","content":"甲车和乙车中至少有1辆停在靠边的车位"}]','B','总情况数相同，分别计算四个选项描述的情况数⑤ 即可：
A选项：先选择其中2辆车， C2, 再选择其中1排， C₂, 再从这排中有顺序的选取2个车位，A²; 在另外1排有顺序的选取4个车位， A%;
则总情况数为C²C¹A²At=15×2×30×30×12=900×360⑥;
B 选项：先从两排中挑一排C2, 甲乙从4个空车位形成的5个空中有顺序选取 2 个，A3; 其他4辆车在剩余10个车位中有顺序的选取4个， A↑;
则总情况数为C₂A₃A₀ =2×20×10×9×8×7=900×4×56, 少于A选项；
C 选项：两排中间共四个位置，甲任选一个，C4; 再排其他五辆车， A₁;
则总情况数为CA₁=4×11×10×9×8×7=90×44×56, 多于B 选项；
D选项：利用“全部减不符”解题，当甲乙两车停在中间时不符合条件。先排甲乙两车，8个不靠边车位任选2个停入， Ag, 再排其他四辆车， A↑。
总情况数为A₁₂-A₃Ao=12×11×10×9×8×7-8×7×10×9×8×7=90×56×76, 多于B 选项；
综上所述，最少的情况为B 选项，其概率最低，当选。
⑤

⑤花生批注：
符合要求的情况数越少，概率越低。','数量关系600题','进阶','published','{"globalNumber":235,"sourceNumber":5,"typeLabel":"排列组合与概率问题","stemRich":[{"text":"有两排各6个连续的空车位，包含甲车、乙车在内的6辆车随机停入这12\n\n个车位中，则以下哪种情况发生的概率最低?"}],"annotatedStemRich":[{"text":"有两排各6个连续的空车位，包含甲车、乙车在内的6辆车随机停入这12\n\n个车位中，则以下哪种情况发生的概率最低?"}],"annotatedOptionRich":{"A":[{"text":" 有一排正好停了2辆车"}],"B":[{"text":" 甲车和乙车停在同一排的不相邻车位"}],"C":[{"text":"  甲车停在某一排的中间两个车位之一"}],"D":[{"text":"  甲车和乙车中至少有1辆停在靠边的车位\n"}]},"practicalAnalysis":"总情况数相同，分别计算四个选项描述的情况数⑤ 即可：\nA选项：先选择其中2辆车， C2, 再选择其中1排， C₂, 再从这排中有顺序的选取2个车位，A²; 在另外1排有顺序的选取4个车位， A%;\n则总情况数为C²C¹A²At=15×2×30×30×12=900×360⑥;\nB 选项：先从两排中挑一排C2, 甲乙从4个空车位形成的5个空中有顺序选取 2 个，A3; 其他4辆车在剩余10个车位中有顺序的选取4个， A↑;\n则总情况数为C₂A₃A₀ =2×20×10×9×8×7=900×4×56, 少于A选项；\nC 选项：两排中间共四个位置，甲任选一个，C4; 再排其他五辆车， A₁;\n则总情况数为CA₁=4×11×10×9×8×7=90×44×56, 多于B 选项；\nD选项：利用“全部减不符”解题，当甲乙两车停在中间时不符合条件。先排甲乙两车，8个不靠边车位任选2个停入， Ag, 再排其他四辆车， A↑。\n总情况数为A₁₂-A₃Ao=12×11×10×9×8×7-8×7×10×9×8×7=90×56×76, 多于B 选项；\n综上所述，最少的情况为B 选项，其概率最低，当选。\n⑤","notes":[{"marker":"⑤","text":"符合要求的情况数越少，概率越低。","matchScore":0.051}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
