INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500239,4,'几何计算问题','如图所示，在直线L 上依次摆放着5个正方形。已知斜放置的

2个正方 形的面积分别是3和2。正放置的3个正方形的面积依次
是S₁ 、S₂ 、S₃, 且

S₂=S₃。问 S₁+S₂+S₃的值为多少?','[{"label":"A","content":"4"},{"label":"B","content":"5"},{"label":"C","content":"11"},{"label":"D","content":"13"}]','A','根据题意，S₂ 、S₃的面积相等，所以边长也相等，那么右边三个正方形所围成的两个三角形是全等的等腰直角三角形，斜边为 √2。
根据题意，可知 S₂ 、S₃的边长为1,那么面积也都是1。左边三个正方形所围成的两个三角形斜边一致、三个角都相等，则是两个全等的三角形。斜边是 √3,短直角边是1(S₂ 的边长),得长直角边即S的边长是 √3-1= √2, 则S₁ 的面积是2。⑨那么所求三个正方形的面积和是2+1+1=4。

⑬花生批注：
30度60度直角三角形是
七大常考图形(正六边形、正三角形、圆、矩形、 3060度直角三角形、 345
直角三角形、等腰直角三角形)之一，三边关系为 1:2: √3, 其中2为斜边。','数量关系600题','进阶','published','{"globalNumber":239,"sourceNumber":9,"typeLabel":"几何计算问题","stemRich":[{"text":"如图所示，在直线L 上依次摆放着5个正方形。已知斜放置的\n\n2个正方 形的面积分别是3和2。正放置的3个正方形的面积依次\n是S₁ 、S₂ 、S₃, 且\n\nS₂=S₃。问 S₁+S₂+S₃的值为多少?"}],"annotatedStemRich":[{"text":"如图所示，在直线L 上依次摆放着5个正方形。已知斜放置的\n\n2个正方 形的面积分别是3和2。正放置的3个正方形的面积依次\n是S₁ 、S₂ 、S₃, 且\n\nS₂=S₃。问 S₁+S₂+S₃的值为多少?"}],"annotatedOptionRich":{"A":[{"text":"4"}],"B":[{"text":"5"}],"C":[{"text":"11","bold":true}],"D":[{"text":"13","bold":true},{"text":"\n"}]},"practicalAnalysis":"根据题意，S₂ 、S₃的面积相等，所以边长也相等，那么右边三个正方形所围成的两个三角形是全等的等腰直角三角形，斜边为 √2。\n根据题意，可知 S₂ 、S₃的边长为1,那么面积也都是1。左边三个正方形所围成的两个三角形斜边一致、三个角都相等，则是两个全等的三角形。斜边是 √3,短直角边是1(S₂ 的边长),得长直角边即S的边长是 √3-1= √2, 则S₁ 的面积是2。⑨那么所求三个正方形的面积和是2+1+1=4。","notes":[{"marker":"⑬","text":"30度60度直角三角形是\n七大常考图形(正六边形、正三角形、圆、矩形、 3060度直角三角形、 345\n直角三角形、等腰直角三角形)之一，三边关系为 1:2: √3, 其中2为斜边。","matchScore":0.114}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
