INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500244,4,'排列组合问题之特殊情境','欲登上第10阶楼梯，如果规定每步只能跨上一阶或两阶，不同

的走法共 有多少种?','[{"label":"A","content":"34"},{"label":"B","content":"55"},{"label":"C","content":"89"},{"label":"D","content":"144"}]','C','可将每次登两级台阶看作相邻问题④,将两级台阶捆绑。具体情况见下表：
登2级台阶次数
列式
解释说明
情况数
