INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500245,4,'不定方程问题','小王经营一家鲜花网店，每位顾客均随机获赠一个装有一支康乃
馨、玫瑰 花或百合花的盲盒，3种盲盒的成本分别为3元、5元、8
