INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500246,4,'排列组合问题之特殊情境','某个为期2天的会议有8名发言人，每人在每天都要发言1次。已知第1 天的发言次序固定，第2天要求仅有3名发言人的发言次序与第1天一样，且另有2人正好交换发言次序，问共有多少种不同的安排方式?','[{"label":"A","content":"不到500种"},{"label":"B","content":"500～1000 种之间"},{"label":"C","content":"1000～2000 种之间"},{"label":"D","content":"超过2000种\n2y+5z=55\n2y 为偶数，5z 应为奇数； z=1时，y=25, 超过总人数，排除；\nz=3 时，y=20, 此时x=1, 符合题意。"}]','C','先选择3人和第一天发言次序不变，即C³; 再选择2人发言顺序正好交换，即C²; 剩余3人需要完全交换次序，即3人顺序和第一天都不能一样，可看作错位排序问题② ,只有2种情况；
