INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500247,4,'工程问题之合作完工问题','某电信运营商安排技术人员张俊、李明、赵华三人在广州荔湾区
、白云区 安装光纤宽带，荔湾区要安装900户，白云区要安装1250户
。已知张俊、李明、 赵华每天分别能安装24、30、32户，张俊在荔

湾区安装，赵华在白云区安装， 李明先在荔湾区安装，然后转到白

云区安装。如果荔湾、白云两区同时开工， 同时完工，则李明从荔
湾区转到白云区应在开工后第多少天?','[{"label":"A","content":"12"},{"label":"B","content":"11"},{"label":"C","content":"10"},{"label":"D","content":"9"}]','B','无论李明在荔湾区还是白云区工作，三人效率和不变且同时开始同时完工，即总完工时间=(900+1250)÷(24+30+32)=25天；
张俊一直在荔湾区工作，25天共完成25×24=600户的安装，剩余部分由
李明完成， ,即李明第11天去白云区工作，答案为B 选项。','数量关系600题','进阶','published','{"globalNumber":247,"sourceNumber":7,"typeLabel":"工程问题之合作完工问题","stemRich":[{"text":"某电信运营商安排技术人员张俊、李明、赵华三人在广州荔湾区\n、白云区 安装光纤宽带，荔湾区要安装900户，白云区要安装1250户\n。已知张俊、李明、 赵华每天分别能安装24、30、32户，张俊在荔\n\n湾区安装，赵华在白云区安装， 李明先在荔湾区安装，然后转到白\n\n云区安装。如果荔湾、白云两区同时开工， 同时完工，则李明从荔\n湾区转到白云区应在开工后第多少天?"}],"annotatedStemRich":[{"text":"某电信运营商安排技术人员张俊、李明、赵华三人在广州荔湾区\n、白云区 安装光纤宽带，荔湾区要安装900户，白云区要安装1250户\n。已知张俊、李明、 赵华每天分别能安装24、30、32户，张俊在荔\n\n湾区安装，赵华在白云区安装， 李明先在荔湾区安装，然后转到白\n\n云区安装。如果荔湾、白云两区同时开工， 同时完工，则李明从荔\n湾区转到白云区应在开工后第多少天?"}],"annotatedOptionRich":{"A":[{"text":"12"}],"B":[{"text":"11"}],"C":[{"text":"10"}],"D":[{"text":"9\n"}]},"practicalAnalysis":"无论李明在荔湾区还是白云区工作，三人效率和不变且同时开始同时完工，即总完工时间=(900+1250)÷(24+30+32)=25天；\n张俊一直在荔湾区工作，25天共完成25×24=600户的安装，剩余部分由\n李明完成， ,即李明第11天去白云区工作，答案为B 选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500248,4,'工程问题+统筹规划问题','有甲乙两项工作需要完成，若小王单独完成甲工作需要12天，单独完成乙工作需要20天，小孙单独完成甲工作需要10天，单独完成乙工作需要30天，如果每项工作都可以由两人合作，那么这两项工作都完成最少需要多少天?','[{"label":"A","content":"12"},{"label":"B","content":"14"},{"label":"C","content":"16"},{"label":"D","content":"18"}]','C','设甲工作量为60,则王效率为5,孙效率为6;设乙工作量为60,王效率为3,孙效率为2。可看出王擅长乙工作，孙擅长甲工作。
安排孙做甲工作，王做乙工作，10天后(60÷6)孙做完甲工作，再去和王共同完成乙工作，此时王已经做完3×10=30份乙工作，乙工作还剩余60- 30=30,二人合作还需要30÷(3+2)=6天。即一共需要10+6=16天，答案为C选项。','数量关系600题','进阶','published','{"globalNumber":248,"sourceNumber":8,"typeLabel":"工程问题+统筹规划问题","stemRich":[{"text":"有甲乙两项工作需要完成，若小王单独完成甲工作需要12天，单独完成 乙工作需要20天，小孙单独完成甲工作需要10天，单独完成乙工作需要30天， 如果每项工作都可以由两人合作，那么这两项工作都完成最少需要多少天?"}],"annotatedStemRich":[{"text":"有甲乙两项工作需要完成，若小王单独完成甲工作需要12天，单独完成 乙工作需要20天，小孙单独完成甲工作需要10天，单独完成乙工作需要30天， 如果每项工作都可以由两人合作，那么这两项工作都完成最少需要多少天?"}],"annotatedOptionRich":{"A":[{"text":"12"}],"B":[{"text":"14"}],"C":[{"text":"16"}],"D":[{"text":"18\n"}]},"practicalAnalysis":"设甲工作量为60,则王效率为5,孙效率为6;设乙工作量为60,王效率为3,孙效率为2。可看出王擅长乙工作，孙擅长甲工作。\n安排孙做甲工作，王做乙工作，10天后(60÷6)孙做完甲工作，再去和王共同完成乙工作，此时王已经做完3×10=30份乙工作，乙工作还剩余60- 30=30,二人合作还需要30÷(3+2)=6天。即一共需要10+6=16天，答案为C选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500249,4,'数列问题','一个空箱子，每次往里放1、2、4、8、16……个球，从第5次开

始，每次 放入后便取出11、15、19、23、27……个小球，问第几次

操作后箱子内小球数 多于900个?','[{"label":"A","content":"6 次"},{"label":"B","content":"7 次"},{"label":"C","content":"10 次"},{"label":"D","content":"11 次"}]','D','观察选项，7次操作后，分别放入1、2、4、8、16、32、64 个小球，即使不考虑取出，也不足900个，排除A、B选项。
剩余两个选项，可考虑代入：
10次操作后，分别放入1、2、4、8、16、32、64、128、256、512个小球，
可用等比数列求和公式求和，从第5次开始，分
别取出11、15、19、23、27、31个小球，即一共取出126个小球⑨;此时剩余
小球为897个，小于900个，排除；
综上，答案只能为D选项。
⑧

⑧花生批注：
1到2的n 次方数列求和公式=2+ -1。
例如：
1到2¹⁰的总和=2¹-1。

⑨花生批注：
等差数列通项公式：
a,=a₁+(n-1)d,a.=a,+(m-n)d 求和公式：
S=项数×中位数','数量关系600题','进阶','published','{"globalNumber":249,"sourceNumber":9,"typeLabel":"数列问题","stemRich":[{"text":"一个空箱子，每次往里放1、2、4、8、16……个球，从第5次开\n\n始，每次 放入后便取出11、15、19、23、27……个小球，问第几次\n\n操作后箱子内小球数 多于900个?"}],"annotatedStemRich":[{"text":"一个空箱子，每次往里放1、2、4、8、16……个球，从第5次开\n\n始，每次 放入后便取出11、15、19、23、27……个小球，问第几次\n\n操作后箱子内小球数 多于900个?"}],"annotatedOptionRich":{"A":[{"text":"6  次"}],"B":[{"text":"7   次"}],"C":[{"text":"10  次"}],"D":[{"text":"11  次\n"}]},"practicalAnalysis":"观察选项，7次操作后，分别放入1、2、4、8、16、32、64 个小球，即使不考虑取出，也不足900个，排除A、B选项。\n剩余两个选项，可考虑代入：\n10次操作后，分别放入1、2、4、8、16、32、64、128、256、512个小球，\n可用等比数列求和公式求和，从第5次开始，分\n别取出11、15、19、23、27、31个小球，即一共取出126个小球⑨;此时剩余\n小球为897个，小于900个，排除；\n综上，答案只能为D选项。\n⑧","notes":[{"marker":"⑧","text":"1到2的n 次方数列求和公式=2+ -1。\n例如：\n1到2¹⁰的总和=2¹-1。","matchScore":0.087},{"marker":"⑨","text":"等差数列通项公式：\na,=a₁+(n-1)d,a.=a,+(m-n)d 求和公式：\nS=项数×中位数","matchScore":0.07}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500250,4,'和差倍比问题','某省在新冠疫情期间派出包括传染科医生、重症科医生和护士在
内的三批 援鄂医疗队。三批医疗队中三者人数之比分别为4 :2:4

、5:2:3和4:3:3。 已知第二批医疗队中医生比护士多40人，且
传染科医生数逐批增加并成等差 数列，三批共派出护士113人，则

三批医疗队共有多少人?','[{"label":"A","content":"339"},{"label":"B","content":"350"},{"label":"C","content":"360"},{"label":"D","content":"390"}]','B','第二批医疗队中医生与护士之比为7:3,医生比护士多4份，对应40人，则1份对应10人，第二批医疗队一共有100人，其中传染科医生 50人；
设第一批每份为x 人，第三批每份为y 人，根据传染科医生数成等差数列⑩, 可列式：100=4x+4y, 解得x+y=25;
则三批医疗队共有 10x+100+10y=100+10(x+y) ①=350 人，答案为B 选项。

⑩花生批注：
4 x、50、4y 成等差数列， 2×中间项=前项+后项。','数量关系600题','进阶','published','{"globalNumber":250,"sourceNumber":10,"typeLabel":"和差倍比问题","stemRich":[{"text":"某省在新冠疫情期间派出包括传染科医生、重症科医生和护士在\n内的三批 援鄂医疗队。三批医疗队中三者人数之比分别为4 :2:4\n\n、5:2:3和4:3:3。 已知第二批医疗队中医生比护士多40人，且\n传染科医生数逐批增加并成等差 数列，三批共派出护士113人，则\n\n三批医疗队共有多少人?"}],"annotatedStemRich":[{"text":"某省在新冠疫情期间派出包括传染科医生、重症科医生和护士在\n内的三批 援鄂医疗队。三批医疗队中三者人数之比分别为4 :2:4\n\n、5:2:3和4:3:3。 已知第二批医疗队中医生比护士多40人，且\n传染科医生数逐批增加并成等差 数列，三批共派出护士113人，则\n\n三批医疗队共有多少人?"}],"annotatedOptionRich":{"A":[{"text":"339"}],"B":[{"text":"350"}],"C":[{"text":"360"}],"D":[{"text":"390\n"}]},"practicalAnalysis":"第二批医疗队中医生与护士之比为7:3,医生比护士多4份，对应40人，则1份对应10人，第二批医疗队一共有100人，其中传染科医生 50人；\n设第一批每份为x 人，第三批每份为y 人，根据传染科医生数成等差数列⑩, 可列式：100=4x+4y, 解得x+y=25;\n则三批医疗队共有 10x+100+10y=100+10(x+y) ①=350 人，答案为B 选项。","notes":[{"marker":"⑩","text":"4 x、50、4y 成等差数列， 2×中间项=前项+后项。","matchScore":0.078}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500251,4,'和差倍比问题','某单位本科、研究生学历的职工人数之比为7:5。上半年公开

招聘本科 毕业生若干人后，本科与研究生之比为3:1;下半年通过

引才计划引入研究生 若干人后，本科与研究生之比为15:8。已知
该年度引进的本科生比研究生多 10人，则该单位原有本科与研究

生学历的职工共多少人?','[{"label":"A","content":"12"},{"label":"B","content":"24"},{"label":"C","content":"36"},{"label":"D","content":"48"}]','B','上半年招聘的是本科毕业生，研究生人数不变，本科与研究生之比由7:5变为15:5(3:1),设一份为a, 则招聘本科人数为8份=8a;
下半年引进的是研究生，本科生人数不变，本科与研究生之比由15:5变为15:8,则引进研究生人数为3份=3a;
根据“该年度引进的本科生比研究生多10人”可列式： 8a-3a=5a=10 人，即 a=2;
则该单位原有本科与研究生共12份=24人，答案为B选项①。
①

