INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500261,4,'和差倍比问题','某网店同时针对','[{"label":"A","content":"1.5"},{"label":"B","content":"2"},{"label":"C","content":"2.5"},{"label":"D","content":"3"}]','D','方法一：
