INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500264,4,'行程问题','早上8:00,甲、乙两车开始在A、B两地之间往返运货，两车先
在A地装 货后驶往B地卸货，然后返回A地再装货，如是重复。

13:35甲完成了第四 次卸货，又过了2小时5分，乙完成了第五次
装货。已知两车均匀速行驶，每 次装货或卸货需要20分钟，则甲

