INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500266,4,'工程问题','甲和乙两条效率相同的生产线从早上不同时间开始生产同一种产品，到中 午
12:00时分别正好生产了x 件和y 件。已知乙生产x 件时，甲生产了54件； 甲生
产y 件时，乙生产了1.5x 件。如乙从9:00开始生产且12:00后两条生产 线仍保
，乙
持原有速度，问两条生产线生产的产品总量达到500件是在什么时候?
同，
均生','[{"label":"A","content":"16:30 之前"},{"label":"B","content":"16:30～17:00 之间"},{"label":"C","content":"17:00～17:30 之间"},{"label":"D","content":"17:30 之后"}]','D','甲乙效率相同，即任意时间二者生产量之差均相等且等于初始差值④⑤,则可列式：乙-甲=y-x=x-54=1.5x-y ⑥, 解得x=72,y=90。
乙在12点时，已生成90件产品，即每小时生产30件；甲乙在12:00时共生产72+90=162件产品，之后每小时可合作生产60件，则生产总量达到500 件需要时间=(500-162)÷60=5.5小时+,即17时30分之后，答案为D选项。

④花生批注：
假设最初甲生产x 件，乙生产0件，二者效率相同，设在某个时间点二者均生产了y 件产品，则二者生产量之差=(x+y)-(0+y)=x。

⑤花生批注：
生产效率相同，生产相同时间的产量相同，故产量差不变。

⑥花生批注：
y-x 代表12:00时的产量差
x-54 代表当乙生产x 件时
的产量差','数量关系600题','进阶','published','{"globalNumber":266,"sourceNumber":6,"typeLabel":"工程问题","stemRich":[{"text":"甲和乙两条效率相同的生产线从早上不同时间开始生产同一种产品，到中 午\n12:00时分别正好生产了x 件和y 件。已知乙生产x 件时，甲生产了54件； 甲生\n产y 件时，乙生产了1.5x 件。如乙从9:00开始生产且12:00后两条生产 线仍保\n，乙\n持原有速度，问两条生产线生产的产品总量达到500件是在什么时候?\n同，\n均生"}],"annotatedStemRich":[{"text":"甲和乙两条效率相同的生产线从早上不同时间开始生产同一种产品，到中 午\n12:00时分别正好生产了x 件和y 件。已知乙生产x 件时，甲生产了54件； 甲生\n产y 件时，乙生产了1.5x 件。如乙从9:00开始生产且12:00后两条生产 线仍保\n，乙\n持原有速度，问两条生产线生产的产品总量达到500件是在什么时候?\n同，\n均生"}],"annotatedOptionRich":{"A":[{"text":"16:30    之前"}],"B":[{"text":"  16:30～17:00 之间"}],"C":[{"text":"   17:00～17:30  之 间"}],"D":[{"text":"17:30     之 后\n"}]},"practicalAnalysis":"甲乙效率相同，即任意时间二者生产量之差均相等且等于初始差值④⑤,则可列式：乙-甲=y-x=x-54=1.5x-y ⑥, 解得x=72,y=90。\n乙在12点时，已生成90件产品，即每小时生产30件；甲乙在12:00时共生产72+90=162件产品，之后每小时可合作生产60件，则生产总量达到500 件需要时间=(500-162)÷60=5.5小时+,即17时30分之后，答案为D选项。","notes":[{"marker":"④","text":"假设最初甲生产x 件，乙生产0件，二者效率相同，设在某个时间点二者均生产了y 件产品，则二者生产量之差=(x+y)-(0+y)=x。","matchScore":0.317},{"marker":"⑤","text":"生产效率相同，生产相同时间的产量相同，故产量差不变。","matchScore":0.172},{"marker":"⑥","text":"y-x 代表12:00时的产量差\nx-54 代表当乙生产x 件时\n的产量差","matchScore":0.137}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
