INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500271,4,'整除问题','某篮球队共有九人，分三组举行三人制篮球赛，他们的球衣号码
分别是从 1号到9号，分组后发现三组的球衣号码之和不同，且最大

和是最小和的两倍。 则各组号码之和不可能是下列哪个数?','[{"label":"A","content":"10"},{"label":"B","content":"11"},{"label":"C","content":"12"},{"label":"D","content":"13"}]','D','所有球衣号码之和为45(3的倍数)①,最大和是最小和的两倍，即最大和+最小和为3的倍数，那么中间组号码和也应是3的倍数②:
观察选项，各选项均不能为最大和，并且只有C选项是3的倍数，有可能为中间组；
依次验证选项：
A 选项，如果10为最小和，则20为最大和，中间和为15,可能；
B选项，如果11为最小和，则22为最大和，中间和为12,可能；
C选项，如果12为最小和，则24为最大和，中间和为9,中间比最小小，不可能；如果12是中间和，则最小和加最大和为33,最小11最大22,可能；
D选项③,如果13为最小和，26为最大和，中间和为6,中间比最小小，不可能，当选。
①

①花生批注：
需要记住：
1 至 9 的数字和为45; 1至10的数字和为55。

②花生批注：
若 a 、b 均为n 的倍数，
则a+b 、a-b 也是n 的倍数。

③花生批注：
D选项并非3的倍数，不可能为中间组。','数量关系600题','进阶','published','{"globalNumber":271,"sourceNumber":1,"typeLabel":"整除问题","stemRich":[{"text":"某篮球队共有九人，分三组举行三人制篮球赛，他们的球衣号码\n分别是从 1号到9号，分组后发现三组的球衣号码之和不同，且最大\n\n和是最小和的两倍。 则各组号码之和不可能是下列哪个数?"}],"annotatedStemRich":[{"text":"某篮球队共有九人，分三组举行三人制篮球赛，他们的球衣号码\n分别是从 1号到9号，分组后发现三组的球衣号码之和不同，且最大\n\n和是最小和的两倍。 则各组号码之和不可能是下列哪个数?"}],"annotatedOptionRich":{"A":[{"text":"10"}],"B":[{"text":"11"}],"C":[{"text":"12"}],"D":[{"text":"13\n"}]},"practicalAnalysis":"所有球衣号码之和为45(3的倍数)①,最大和是最小和的两倍，即最大和+最小和为3的倍数，那么中间组号码和也应是3的倍数②:\n观察选项，各选项均不能为最大和，并且只有C选项是3的倍数，有可能为中间组；\n依次验证选项：\nA 选项，如果10为最小和，则20为最大和，中间和为15,可能；\nB选项，如果11为最小和，则22为最大和，中间和为12,可能；\nC选项，如果12为最小和，则24为最大和，中间和为9,中间比最小小，不可能；如果12是中间和，则最小和加最大和为33,最小11最大22,可能；\nD选项③,如果13为最小和，26为最大和，中间和为6,中间比最小小，不可能，当选。\n①","notes":[{"marker":"①","text":"需要记住：\n1 至 9 的数字和为45; 1至10的数字和为55。","matchScore":0.042},{"marker":"②","text":"若 a 、b 均为n 的倍数，\n则a+b 、a-b 也是n 的倍数。","matchScore":0.042},{"marker":"③","text":"D选项并非3的倍数，不可能为中间组。","matchScore":0.135}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500272,4,'工程问题+统筹规划问题','某单位需要搬家，可以使用甲、乙、丙三个搬家公司。单独完成该搬家任 务

