INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500273,4,'比赛问题','某市举办高校足球比赛，每所高校都要与其余所有参赛高校各进行一场比 赛
。积分规则为：胜一场积3分，平一场积1分，负一场积0分。已知此次比 赛的
