INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500274,4,'行程问题之环形运动','162
小李和老张同时在同一点沿同一环形跑道健身锻炼，小李跑步，老张慢走。若同向而行，小李追上老张所需时间是两人相向而行相遇所需时间的x 倍。假设两人运动均为匀速，且小李跑步是老张慢走速度的y 倍，则下列能反映x 与 y 关系的是?','[{"label":"A","content":"y"},{"label":"B","content":"y\n→x"},{"label":"C","content":"y"},{"label":"D","content":"y"}]','D','赋值老张慢走的速度为1,则小李跑步的速度为y, 相向而行相遇时间为t, 则同向而行追上时间为 xt。
根据行程问题相遇及追及公式，得 S=(y-1)×xt⑤=(y+1)×t, 整理得，
是反比例函数， D项图示最符合，当选。
⑤

⑤花生批注：
环形追及问题：
一圈=速度差×追及时间；环形相遇问题：
一圈=速度和×相遇时间。','数量关系600题','进阶','published','{"globalNumber":274,"sourceNumber":4,"typeLabel":"行程问题之环形运动","stemRich":[{"text":"162\n小李和老张同时在同一点沿同一环形跑道健身锻炼，小李跑步，老张慢走。若同向而行，小李追上老张所需时间是两人相向而行相遇所需时间的x 倍。假设两人运动均为匀速，且小李跑步是老张慢走速度的y 倍，则下列能反映x 与 y 关系的是?"}],"annotatedStemRich":[{"text":"162\n小李和老张同时在同一点沿同一环形跑道健身锻炼，小李跑步，老张慢走。若同向而行，小李追上老张所需时间是两人相向而行相遇所需时间的x 倍。假设两人运动均为匀速，且小李跑步是老张慢走速度的y 倍，则下列能反映x 与 y 关系的是?"}],"annotatedOptionRich":{"A":[{"text":"y","bold":true}],"B":[{"text":"y","bold":true},{"text":"\n→x"}],"C":[{"text":"y"}],"D":[{"text":"y\n"}]},"practicalAnalysis":"赋值老张慢走的速度为1,则小李跑步的速度为y, 相向而行相遇时间为t, 则同向而行追上时间为 xt。\n根据行程问题相遇及追及公式，得 S=(y-1)×xt⑤=(y+1)×t, 整理得，\n是反比例函数， D项图示最符合，当选。\n⑤","notes":[{"marker":"⑤","text":"环形追及问题：\n一圈=速度差×追及时间；环形相遇问题：\n一圈=速度和×相遇时间。","matchScore":0.092}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
