INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500279,4,'排列组合问题之爬楼梯模型','一个楼梯共有9级台阶，每步可以迈一级或二级台阶，问走完这个楼梯共
有多少种不同的走法?','[{"label":"A","content":"13"},{"label":"B","content":"32"},{"label":"C","content":"55"},{"label":"D","content":"86"}]','C','走到第1级台阶只有1种走法，走到第2级台阶有2种走法，走到第3级台阶可从第1 级迈二级台阶或从第2级迈1级台阶到达，即走到第 3级有1+2=3种走法；走到第4级台阶可从第2级迈二级台阶或从第3级迈1 级台阶到达，即走到第4级有2+3=5种走法；走到第5级台阶可从第3级迈二级台阶或从第4级迈1级台阶到达，即走到第5级有3+5=8种走法； ……由此可知，走到第n 级台阶的走法=走到第n-2 级台阶和走到第n-1 级台阶走法之和。
综上，走上1 级至9级台阶的走法数分别为1、2、3、5、8、13、21、','数量关系600题','进阶','published','{"globalNumber":279,"sourceNumber":9,"typeLabel":"排列组合问题之爬楼梯模型","stemRich":[{"text":"一个楼梯共有9级台阶，每步可以迈一级或二级台阶，问走完这个楼梯共\n有多少种不同的走法?"}],"annotatedStemRich":[{"text":"一个楼梯共有9级台阶，每步可以迈一级或二级台阶，问走完这个楼梯共\n有多少种不同的走法?"}],"annotatedOptionRich":{"A":[{"text":"13"}],"B":[{"text":"32"}],"C":[{"text":"55","bold":true}],"D":[{"text":"86","bold":true},{"text":"\n"}]},"practicalAnalysis":"走到第1级台阶只有1种走法，走到第2级台阶有2种走法，走到第3级台阶可从第1 级迈二级台阶或从第2级迈1级台阶到达，即走到第 3级有1+2=3种走法；走到第4级台阶可从第2级迈二级台阶或从第3级迈1 级台阶到达，即走到第4级有2+3=5种走法；走到第5级台阶可从第3级迈二级台阶或从第4级迈1级台阶到达，即走到第5级有3+5=8种走法； ……由此可知，走到第n 级台阶的走法=走到第n-2 级台阶和走到第n-1 级台阶走法之和。\n综上，走上1 级至9级台阶的走法数分别为1、2、3、5、8、13、21、","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500280,4,'最值问题','某公司开展爱心捐款活动，50名员工人均捐款81.5元。已知任意2名员

工捐款金额相差不超过10元，问该公司捐款83元及以上的员工最多可能有多
少人?','[{"label":"A","content":"40"},{"label":"B","content":"42"},{"label":"C","content":"44"},{"label":"D","content":"46"}]','B','②设捐款83元及以上的员工x 人，则83元以下的50-x 人。根据题意可知50名员工共捐款81.5×50=4075元。
要想 x 尽可能多，则捐款83元及以上的员工平均捐款额应尽量接近平均数，即 x 人人均捐款83元；捐款83元以下的员工平均捐款额应尽量远离平均数，由于任意2名员工捐款金额相差不超过10元，故剩余50-x 人每人捐款 83-10=73元；
根据捐款总额可列式：4075=83x+73(50-x), 解得 x=42.5, 即最多可能有 42人捐款83元及以上，答案为B选项。

⑫花生批注：
考场秒杀：
若考场无时间思考，最值问题可直接使用极限值；
即设捐款多的人均捐款83 元，捐款少的人均捐款 73元；
代入十字交叉式子：
83元83
73元73
即捐款83元的人数最大占比为
即最多有人，取整为42人。','数量关系600题','进阶','published','{"globalNumber":280,"sourceNumber":10,"typeLabel":"最值问题","stemRich":[{"text":"某公司开展爱心捐款活动，50名员工人均捐款81.5元。已知任意2名员\n\n工捐款金额相差不超过10元，问该公司捐款83元及以上的员工最多可能有多\n少人?"}],"annotatedStemRich":[{"text":"某公司开展爱心捐款活动，50名员工人均捐款81.5元。已知任意2名员\n\n工捐款金额相差不超过10元，问该公司捐款83元及以上的员工最多可能有多\n少人?"}],"annotatedOptionRich":{"A":[{"text":"40"}],"B":[{"text":"42","bold":true}],"C":[{"text":"44","bold":true}],"D":[{"text":"46","bold":true},{"text":"\n"}]},"practicalAnalysis":"②设捐款83元及以上的员工x 人，则83元以下的50-x 人。根据题意可知50名员工共捐款81.5×50=4075元。\n要想 x 尽可能多，则捐款83元及以上的员工平均捐款额应尽量接近平均数，即 x 人人均捐款83元；捐款83元以下的员工平均捐款额应尽量远离平均数，由于任意2名员工捐款金额相差不超过10元，故剩余50-x 人每人捐款 83-10=73元；\n根据捐款总额可列式：4075=83x+73(50-x), 解得 x=42.5, 即最多可能有 42人捐款83元及以上，答案为B选项。","notes":[{"marker":"⑫","text":"考场秒杀：\n若考场无时间思考，最值问题可直接使用极限值；\n即设捐款多的人均捐款83 元，捐款少的人均捐款 73元；\n代入十字交叉式子：\n83元83\n73元73\n即捐款83元的人数最大占比为\n即最多有人，取整为42人。","matchScore":0.121}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500281,4,'和差倍比问题','某个项目由甲、乙两人共同投资，约定总利润10万元以内的
部分甲得 80%, 10万元～20万元的部分甲得60%,20万元以上的部

分乙得60%。最终乙 分得的利润是甲的1.2倍。问如果总利润减半

，甲分得的利润比乙?','[{"label":"A","content":"少 1万元"},{"label":"B","content":"多 1万元"},{"label":"C","content":"少2万元"},{"label":"D","content":"多2万元"}]','B','设20万以上部分甲分得利润2x,则乙这部分分得利润为 3①x; 根据总利润倍数可列方程：3x+4+2=1.2×(8+6+2x), 解得x=18; 总利润 =20+2x+3x=110 万元；
若总利润减半，总利润变为55万元，20万以上部分乙可分得35×60%=21 万元，甲分得35-21=14万元；则甲总利润-乙总利润=(14+8+6)-(21+2+4)=1 万元，答案为B 选项。
①

①花生批注：
20万以上部分，甲分得 40%,乙分得60%,即乙是甲的1 . 5倍。','数量关系600题','进阶','published','{"globalNumber":281,"sourceNumber":1,"typeLabel":"和差倍比问题","stemRich":[{"text":"某个项目由甲、乙两人共同投资，约定总利润10万元以内的\n部分甲得 80%, 10万元～20万元的部分甲得60%,20万元以上的部\n\n分乙得60%。最终乙 分得的利润是甲的1.2倍。问如果总利润减半\n\n，甲分得的利润比乙?"}],"annotatedStemRich":[{"text":"某个项目由甲、乙两人共同投资，约定总利润10万元以内的\n部分甲得 80%, 10万元～20万元的部分甲得60%,20万元以上的部\n\n分乙得60%。最终乙 分得的利润是甲的1.2倍。问如果总利润减半\n\n，甲分得的利润比乙?"}],"annotatedOptionRich":{"A":[{"text":" 少 1万元"}],"B":[{"text":" 多 1万元"}],"C":[{"text":" 少2万元"}],"D":[{"text":"  多2万元\n"}]},"practicalAnalysis":"设20万以上部分甲分得利润2x,则乙这部分分得利润为 3①x; 根据总利润倍数可列方程：3x+4+2=1.2×(8+6+2x), 解得x=18; 总利润 =20+2x+3x=110 万元；\n若总利润减半，总利润变为55万元，20万以上部分乙可分得35×60%=21 万元，甲分得35-21=14万元；则甲总利润-乙总利润=(14+8+6)-(21+2+4)=1 万元，答案为B 选项。\n①","notes":[{"marker":"①","text":"20万以上部分，甲分得 40%,乙分得60%,即乙是甲的1 . 5倍。","matchScore":0.23}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500282,4,'经济利润问题','某网店销售一款衬衫，进价为100元，售价为150元。为回馈顾客，该网店开展一天的促销活动：每购买两件优惠20元，每购买三件优惠50元。已知促销当天的销售量是前一天的2倍，利润是前一天的1.5倍，每位顾客购买衬衫的数量均为两件或三件。促销当天，购买两件与购买三件衬衫的顾客人数比是?','[{"label":"A","content":"5:2"},{"label":"B","content":"5:3"},{"label":"C","content":"3:2"},{"label":"D","content":"3:1\n②"}]','A','设x 人购买衬衫数量为两件， y 人购买数量为三件；促销当天情况为：
人数
销售量(件)
利润(元)
购买两件x人
2x
50×2x-20x²=80x
购买三件y人
3y
50×3y-50y=100y
由“促销当天的销售量是前一天的2倍”可知，促销前销售量x+1.5y 件，利润为50(x+1.5y) 元；
根据“促销当天的利润是前一天的1.5倍”可列等式：1.5×50 (x+1.5y)= 80x+100y, 解得x:y=5:2, 答案为A 选项。','数量关系600题','进阶','published','{"globalNumber":282,"sourceNumber":2,"typeLabel":"经济利润问题","stemRich":[{"text":"某网店销售一款衬衫，进价为100元，售价为150元。为回馈顾客，该网 店开展一天的促销活动：每购买两件优惠20元，每购买三件优惠50元。已知 促销当天的销售量是前一天的2倍，利润是前一天的1.5倍，每位顾客购买 衬衫的数量均为两件或三件。促销当天，购买两件与购买三件衬衫的顾客人 数比是?"}],"annotatedStemRich":[{"text":"某网店销售一款衬衫，进价为100元，售价为150元。为回馈顾客，该网 店开展一天的促销活动：每购买两件优惠20元，每购买三件优惠50元。已知 促销当天的销售量是前一天的2倍，利润是前一天的1.5倍，每位顾客购买 衬衫的数量均为两件或三件。促销当天，购买两件与购买三件衬衫的顾客人 数比是?"}],"annotatedOptionRich":{"A":[{"text":"5:2"}],"B":[{"text":"5:3"}],"C":[{"text":"3:2"}],"D":[{"text":"3:1\n②花生批注：\n每2件优惠20元，即每个 购买两件的人优惠20元。\n③花生批注：\n整除性质：\n能被3整除：\n各位数字和能被3整除；\n能被9整除：\n各位数字和能被9整除；\n能被2、5整除：\n最后一位能被2、5整除；\n能被4、25整除：\n最后两位能被4、25整除； 能被8、125"},{"text":"整除：","bold":true},{"text":"\n最后三位能被8、125整除。\n④花生批注：\n"},{"text":"若三位数各位数字和为","bold":true},{"text":"\n27,需要999,不符合每个 数字用一次。\n"}]},"practicalAnalysis":"设x 人购买衬衫数量为两件， y 人购买数量为三件；促销当天情况为：\n人数\n销售量(件)\n利润(元)\n购买两件x人\n2x\n50×2x-20x²=80x\n购买三件y人\n3y\n50×3y-50y=100y\n由“促销当天的销售量是前一天的2倍”可知，促销前销售量x+1.5y 件，利润为50(x+1.5y) 元；\n根据“促销当天的利润是前一天的1.5倍”可列等式：1.5×50 (x+1.5y)= 80x+100y, 解得x:y=5:2, 答案为A 选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500283,4,'整除问题','1、2、3、4、5、6、7、8、9这九个数字各用一次，组成三个能被9整除
的三位数，这三个数的和最大是多少?','[{"label":"A","content":"2007"},{"label":"B","content":"2394"},{"label":"C","content":"2448"},{"label":"D","content":"2556"}]','C','1至9的数字和为45,各用一次组成3个能被9整除的三位数(数字和为9的倍数)③, 则这3个三位数各位数字和分别为9、18、18。
要使这三个数的和最大，则每个三位数百位上的数字应尽量大，先考虑和为9的三位数，百位最大可能为6,这个三位数是621;剩余两个三位数最大分别为954和873,则954+873+621=2448,答案为C选项。

③花生批注：
整除性质：
能被3整除：
各位数字和能被3整除；
能被9整除：
各位数字和能被9整除；
能被2、5整除：
最后一位能被2、5整除；
能被4、25整除：
最后两位能被4、25整除；能被8、125整除：
最后三位能被8、125整除。

④花生批注：
若三位数各位数字和为
27,需要999,不符合每个数字用一次。','数量关系600题','进阶','published','{"globalNumber":283,"sourceNumber":3,"typeLabel":"整除问题","stemRich":[{"text":"1、2、3、4、5、6、7、8、9这九个数字各用一次，组成三个能被9整除\n的三位数，这三个数的和最大是多少?"}],"annotatedStemRich":[{"text":"1、2、3、4、5、6、7、8、9这九个数字各用一次，组成三个能被9整除\n的三位数，这三个数的和最大是多少?"}],"annotatedOptionRich":{"A":[{"text":"2007"}],"B":[{"text":"2394"}],"C":[{"text":"2448"}],"D":[{"text":"2556\n"}]},"practicalAnalysis":"1至9的数字和为45,各用一次组成3个能被9整除的三位数(数字和为9的倍数)③, 则这3个三位数各位数字和分别为9、18、18。\n要使这三个数的和最大，则每个三位数百位上的数字应尽量大，先考虑和为9的三位数，百位最大可能为6,这个三位数是621;剩余两个三位数最大分别为954和873,则954+873+621=2448,答案为C选项。","notes":[{"marker":"③","text":"整除性质：\n能被3整除：\n各位数字和能被3整除；\n能被9整除：\n各位数字和能被9整除；\n能被2、5整除：\n最后一位能被2、5整除；\n能被4、25整除：\n最后两位能被4、25整除；能被8、125整除：\n最后三位能被8、125整除。","matchScore":0.145},{"marker":"④","text":"若三位数各位数字和为\n27,需要999,不符合每个数字用一次。","matchScore":0.208}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500284,4,'不定方程问题','某单位开展踏青活动，由单位领导们带领员工一行共50人去果
园体验采 摘水果，该单位负责果园中93棵果树的采摘，其中领导

每人负责6棵果树。 男员工每人负责4棵果树，女员工每人负责1棵

果树。则该单位男员工可能有 多少人?(男员工和女员工都不包含
领导)








数量关系','[{"label":"A","content":"9"},{"label":"B","content":"11"},{"label":"C","content":"13"},{"label":"D","content":"16"}]','B','设男员工有x 人，领导有y 人；假设全是女员工，则能采摘 50棵树，实际为93棵，多出43棵，每有1个领导多采摘5棵，每有1个男员工多采摘3棵，则可列方程：3x+5y=43;
由尾数法可知，5y 尾数只能是0或5,则3x 尾数只能为3或8,排除 A、 C选项，代入B 选项：x=11,y=2, 女员工为37人，符合题意，当选⑤。
⑤

