INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500285,4,'工程问题+数列问题','小张和小李负责生产1200个零件，小张每天均生产20个。小李第一天生 产

