INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500292,4,'和差倍比问题','商业街物业管理处采购了一批消毒液发放给街内的复工商户，如
果每个商 户分6瓶，最后剩余12瓶。如果多采购30%,则在给每个

商户分8瓶后还能剩 余10瓶。如果多采购80%,复工商户数量增加10家

，且每个商户分到的数量相同， 问每个商户最多可以分多少瓶?','[{"label":"A","content":"8"},{"label":"B","content":"9"},{"label":"C","content":"10"},{"label":"D","content":"12"}]','A','设复工商户数量为 x, 由“如果每个商户分6瓶，最后剩余 12瓶。如果多采购30%,则在给每个商户分8瓶后还能剩余10瓶。”,可列方程：8x+10=1.3×(6x+12), 解得x=28, 采购消毒液为6×28+12=180瓶；
如果多采购80%,即采购消毒液180×1.8=324瓶；复工商户增加10家，即复工商户=x+10=38 家；则每家最多分得324÷38≈8.5瓶，取整为8瓶，即在每个商户分到的数量相同的前提下，每个商户最多可分得8瓶，答案为A选项。','数量关系600题','进阶','published','{"globalNumber":292,"sourceNumber":2,"typeLabel":"和差倍比问题","stemRich":[{"text":"商业街物业管理处采购了一批消毒液发放给街内的复工商户，如\n果每个商 户分6瓶，最后剩余12瓶。如果多采购30%,则在给每个\n\n商户分8瓶后还能剩 余10瓶。如果多采购80%,复工商户数量增加10家\n\n，且每个商户分到的数量相同， 问每个商户最多可以分多少瓶?"}],"annotatedStemRich":[{"text":"商业街物业管理处采购了一批消毒液发放给街内的复工商户，如\n果每个商 户分6瓶，最后剩余12瓶。如果多采购30%,则在给每个\n\n商户分8瓶后还能剩 余10瓶。如果多采购80%,复工商户数量增加10家\n\n，且每个商户分到的数量相同， 问每个商户最多可以分多少瓶?"}],"annotatedOptionRich":{"A":[{"text":"8"}],"B":[{"text":"9"}],"C":[{"text":"10"}],"D":[{"text":"12\n"}]},"practicalAnalysis":"设复工商户数量为 x, 由“如果每个商户分6瓶，最后剩余 12瓶。如果多采购30%,则在给每个商户分8瓶后还能剩余10瓶。”,可列方程：8x+10=1.3×(6x+12), 解得x=28, 采购消毒液为6×28+12=180瓶；\n如果多采购80%,即采购消毒液180×1.8=324瓶；复工商户增加10家，即复工商户=x+10=38 家；则每家最多分得324÷38≈8.5瓶，取整为8瓶，即在每个商户分到的数量相同的前提下，每个商户最多可分得8瓶，答案为A选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500293,4,'工程问题','甲、乙两辆卡车运输一批货物，其中甲车每次能运输35箱货物

。甲车先 满载运输2次后，乙车加入并与甲车共同满载运输10次

完成任务，此时乙车 比甲车多运输10箱货物。问如果乙车单独执行
整个运输任务且每次都尽量装满， 最后一次运多少箱货物?','[{"label":"A","content":"10"},{"label":"B","content":"30"},{"label":"C","content":"33"},{"label":"D","content":"36"}]','C','根据题意，可知甲运输总量=35×2+35×10=420箱；根据乙车比甲车多运输10箱货物，则乙运输总量=420+10=430箱，每次运输量 =430÷10=4 3箱，则运输货物总量=420+430=850箱。
①

①花生批注：
若乙车单独运输，850÷43=19余33①,即最后一车运输33箱货物，答案为 C 选项。
前19趟运满43箱，最后一次运33箱。','数量关系600题','进阶','published','{"globalNumber":293,"sourceNumber":3,"typeLabel":"工程问题","stemRich":[{"text":"甲、乙两辆卡车运输一批货物，其中甲车每次能运输35箱货物\n\n。甲车先 满载运输2次后，乙车加入并与甲车共同满载运输10次\n\n完成任务，此时乙车 比甲车多运输10箱货物。问如果乙车单独执行\n整个运输任务且每次都尽量装满， 最后一次运多少箱货物?"}],"annotatedStemRich":[{"text":"甲、乙两辆卡车运输一批货物，其中甲车每次能运输35箱货物\n\n。甲车先 满载运输2次后，乙车加入并与甲车共同满载运输10次\n\n完成任务，此时乙车 比甲车多运输10箱货物。问如果乙车单独执行\n整个运输任务且每次都尽量装满， 最后一次运多少箱货物?"}],"annotatedOptionRich":{"A":[{"text":"10"}],"B":[{"text":"30"}],"C":[{"text":"33"}],"D":[{"text":"36\n"}]},"practicalAnalysis":"根据题意，可知甲运输总量=35×2+35×10=420箱；根据乙车比甲车多运输10箱货物，则乙运输总量=420+10=430箱，每次运输量 =430÷10=4 3箱，则运输货物总量=420+430=850箱。\n①","notes":[{"marker":"①","text":"若乙车单独运输，850÷43=19余33①,即最后一车运输33箱货物，答案为 C 选项。\n前19趟运满43箱，最后一次运33箱。","matchScore":0.233}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500294,4,'行程问题之相遇追及问题','已知','[{"label":"A","content":"30分钟"},{"label":"B","content":"45分钟"},{"label":"C","content":"60分钟"},{"label":"D","content":"75 分钟"}]','B','要想甲乙到达B地的时间差距最大，需要乙速度尽量小；乙先出发，要想相遇两次，应是甲追上乙后，乙在甲休息的最后一刻追上甲②;
“乙在甲休息的最后一刻追上甲”,甲出发半小时走了3km,乙在早出发 15分钟的情况下，在甲休息15分钟的最后一刻追上甲，即乙用了一小时追上甲，乙的速度为3km/h:
甲到达B 地需要走9÷6=1.5小时，其中需要休息两次，即出发后2小时到达 B 地③;乙到达 B地需要走9÷3=3小时，但乙早出发15分钟，若从甲出发计算，乙需要2小时45分钟到达B 地；
综上，甲乙到达B 地的时间最多相差45分钟，答案为B 选项。

②花生批注：
若提前追上甲，说明乙的速度并非满足“相遇两次”前提下的最小速度，二者达到时间之差也非最大。

③花生批注：
第三个半小时已经到达B 地，无需再计算休息时间，所以途中共休息2次。','数量关系600题','进阶','published','{"globalNumber":294,"sourceNumber":4,"typeLabel":"行程问题之相遇追及问题","stemRich":[{"text":"已知"}],"annotatedStemRich":[{"text":"已知"}],"annotatedOptionRich":{"A":[{"text":"  30分钟"}],"B":[{"text":"  45分钟"}],"C":[{"text":" 60分钟"}],"D":[{"text":" 75 分钟\n"}]},"practicalAnalysis":"要想甲乙到达B地的时间差距最大，需要乙速度尽量小；乙先出发，要想相遇两次，应是甲追上乙后，乙在甲休息的最后一刻追上甲②;\n“乙在甲休息的最后一刻追上甲”,甲出发半小时走了3km,乙在早出发 15分钟的情况下，在甲休息15分钟的最后一刻追上甲，即乙用了一小时追上甲，乙的速度为3km/h:\n甲到达B 地需要走9÷6=1.5小时，其中需要休息两次，即出发后2小时到达 B 地③;乙到达 B地需要走9÷3=3小时，但乙早出发15分钟，若从甲出发计算，乙需要2小时45分钟到达B 地；\n综上，甲乙到达B 地的时间最多相差45分钟，答案为B 选项。","notes":[{"marker":"②","text":"若提前追上甲，说明乙的速度并非满足“相遇两次”前提下的最小速度，二者达到时间之差也非最大。","matchScore":0.126},{"marker":"③","text":"第三个半小时已经到达B 地，无需再计算休息时间，所以途中共休息2次。","matchScore":0.097}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500295,4,'排列组合问题','超市中有10斤装、20斤装、50斤装三种规格的大米若干袋。某

