INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500297,4,'统筹规划问题','超市销售某种圆珠笔，单盒装的售价10元，5盒装的售价40元

，10盒装 的售价70元，20盒装的售价120元。现有两家企业来采
购这种圆珠笔，甲企 业的预算最多正好买92盒，乙企业的预算最

多正好买103盒。 问 ，两家企业 如果合买最多比分开买多采购多
少盒?','[{"label":"A","content":"3"},{"label":"B","content":"5"},{"label":"C","content":"8"},{"label":"D","content":"10"}]','B','购买92盒的最经济的买法是购买4个20盒装，1个10盒装， 2个单盒装，共需要4×120+70+2×10=570元，即甲的预算为570元；
购买103盒的最经济的买法是购买5个20盒装，3个单盒装，共需要 5×120+3×10=630元，即乙的预算为630元；
甲乙两企业总预算=630+570=1200元，可购买10个20盒装，即购买200盒，较单独购买多200-92-103=5盒，答案为B选项。','数量关系600题','进阶','published','{"globalNumber":297,"sourceNumber":7,"typeLabel":"统筹规划问题","stemRich":[{"text":"超市销售某种圆珠笔，单盒装的售价10元，5盒装的售价40元\n\n，10盒装 的售价70元，20盒装的售价120元。现有两家企业来采\n购这种圆珠笔，甲企 业的预算最多正好买92盒，乙企业的预算最\n\n多正好买103盒。 问 ，两家企业 如果合买最多比分开买多采购多\n少盒?"}],"annotatedStemRich":[{"text":"超市销售某种圆珠笔，单盒装的售价10元，5盒装的售价40元\n\n，10盒装 的售价70元，20盒装的售价120元。现有两家企业来采\n购这种圆珠笔，甲企 业的预算最多正好买92盒，乙企业的预算最\n\n多正好买103盒。 问 ，两家企业 如果合买最多比分开买多采购多\n少盒?"}],"annotatedOptionRich":{"A":[{"text":"3"}],"B":[{"text":"5"}],"C":[{"text":"8"}],"D":[{"text":"10\n"}]},"practicalAnalysis":"购买92盒的最经济的买法是购买4个20盒装，1个10盒装， 2个单盒装，共需要4×120+70+2×10=570元，即甲的预算为570元；\n购买103盒的最经济的买法是购买5个20盒装，3个单盒装，共需要 5×120+3×10=630元，即乙的预算为630元；\n甲乙两企业总预算=630+570=1200元，可购买10个20盒装，即购买200盒，较单独购买多200-92-103=5盒，答案为B选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
