INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500299,4,'日期星期问题','某家餐厅每个月的第五个星期六和第五个星期日是牛排的“超级折扣日”。
那么一年最多有多少个“超级折扣日”?','[{"label":"A","content":"8"},{"label":"B","content":"9"},{"label":"C","content":"10"},{"label":"D","content":"11"}]','C','问“最多”,可设该年为闰年，共366天；366天由52周和另外2天组成，52周会有104个周六和周日，若额外两天为周六和周日，则最多会有106个周六和周日；
每个月份都是由4周和“余下几天”组成，每月前四周都会有8个周六和周日，12个月份一共96个周六和周日；
那么剩余的106-96=10个周六和周日，必然分布在一些月份的“余下几天”中，这些周六和周日都是当月的第五个周六和周日，即均为“超级折扣日”, 答案为C 选项。','数量关系600题','进阶','published','{"globalNumber":299,"sourceNumber":9,"typeLabel":"日期星期问题","stemRich":[{"text":"某家餐厅每个月的第五个星期六和第五个星期日是牛排的“超级折扣日”。\n那么一年最多有多少个“超级折扣日”?"}],"annotatedStemRich":[{"text":"某家餐厅每个月的第五个星期六和第五个星期日是牛排的“超级折扣日”。\n那么一年最多有多少个“超级折扣日”?"}],"annotatedOptionRich":{"A":[{"text":"8"}],"B":[{"text":"9"}],"C":[{"text":"10"}],"D":[{"text":"11\n"}]},"practicalAnalysis":"问“最多”,可设该年为闰年，共366天；366天由52周和另外2天组成，52周会有104个周六和周日，若额外两天为周六和周日，则最多会有106个周六和周日；\n每个月份都是由4周和“余下几天”组成，每月前四周都会有8个周六和周日，12个月份一共96个周六和周日；\n那么剩余的106-96=10个周六和周日，必然分布在一些月份的“余下几天”中，这些周六和周日都是当月的第五个周六和周日，即均为“超级折扣日”, 答案为C 选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500300,4,'牛吃草问题','一座水电站水库上游每天有一定量的水流入，同时水库按照一定流量向下
排水发电，水库里的水足够A设施用电40天。因最近降雨多，水库上游水流入

量增加20%,于是每天多排掉原排水量的10%,但不用作发电，则仍够A 设施用
电40天。如果仍按照原排水量发电且不多排水，那么可供A设施使用多少天?','[{"label":"A","content":"45"},{"label":"B","content":"48"},{"label":"C","content":"50"},{"label":"D","content":"60"}]','C','流入量增加20%,排水量增加10%(但不用作发电),和之前用电天数一致，说明增加流入量和增加排水量相互抵消。即20%原流入量 =10%原排水量，设原流入量为10,则原排水量为20;
⑥

⑥花生批注：
挖空部分有五个面，其中增加的背面和减少的正面抵消掉，即增加了4个面。
设水库原有存水x,40 天的排水量应等于水库原有存水和40天流入量之和，可列方程：40×20=x+40×10, 解得x=400;
设降雨变多后(每日流入量增加20%,达到12)仍按照原排水量发电且不多排水可供A 设施使用y 天，可列方程：20y=400+12y,解得y=50, 答案为C选项。','数量关系600题','进阶','published','{"globalNumber":300,"sourceNumber":10,"typeLabel":"牛吃草问题","stemRich":[{"text":"一座水电站水库上游每天有一定量的水流入，同时水库按照一定流量向下\n排水发电，水库里的水足够A设施用电40天。因最近降雨多，水库上游水流入\n\n量增加20%,于是每天多排掉原排水量的10%,但不用作发电，则仍够A 设施用\n电40天。如果仍按照原排水量发电且不多排水，那么可供A设施使用多少天?"}],"annotatedStemRich":[{"text":"一座水电站水库上游每天有一定量的水流入，同时水库按照一定流量向下\n排水发电，水库里的水足够A设施用电40天。因最近降雨多，水库上游水流入\n\n量增加20%,于是每天多排掉原排水量的10%,但不用作发电，则仍够A 设施用\n电40天。如果仍按照原排水量发电且不多排水，那么可供A设施使用多少天?"}],"annotatedOptionRich":{"A":[{"text":"45"}],"B":[{"text":"48"}],"C":[{"text":"50"}],"D":[{"text":"60\n"}]},"practicalAnalysis":"流入量增加20%,排水量增加10%(但不用作发电),和之前用电天数一致，说明增加流入量和增加排水量相互抵消。即20%原流入量 =10%原排水量，设原流入量为10,则原排水量为20;\n⑥","notes":[{"marker":"⑥","text":"挖空部分有五个面，其中增加的背面和减少的正面抵消掉，即增加了4个面。\n设水库原有存水x,40 天的排水量应等于水库原有存水和40天流入量之和，可列方程：40×20=x+40×10, 解得x=400;\n设降雨变多后(每日流入量增加20%,达到12)仍按照原排水量发电且不多排水可供A 设施使用y 天，可列方程：20y=400+12y,解得y=50, 答案为C选项。","matchScore":0.23}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
