INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500305,4,'比赛问题+最值问题','甲乙两队各5名队员，甲队每名队员都要与乙队每名队员进行一
