INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500306,4,'行程问题之相遇追及','有一架自动扶梯共25级，每秒移动2阶。A从扶梯的起点处站立乘坐，两秒后B 从起点处以每秒1阶的速度向上走动。又过三秒后C来到扶梯起点处且以每秒4阶的速度向上跑。那么以下事件中最先发生的是?','[{"label":"A","content":"A 到达扶梯终点"},{"label":"B","content":"B 追上A"},{"label":"C","content":"C追上A"},{"label":"D","content":"C追上B\n数量关系"}]','B','把A 出发作为时间起点，依次计算四个选项所用时间即可。 A选项：A 到达扶梯终点用时=25÷2=12.5秒；
B选项：B出发时，A 已走了2×2=4级阶梯， B追上A所需时间=4÷(1- 0)=4秒②,加上B 晚出发的2秒，总共需6秒；
⑦

⑦花生批注：
追及时间=距离差÷速度差，A站立乘坐，速度为0。

⑧花生批注：
B 走的阶梯数等于扶梯走的阶梯和自己走的阶梯之和。
C选项： C出发时，A已走了2×5=10级阶梯，C 追上A 所需时间=10÷(4- 0)=2.5秒，加上C 晚出发的5秒，总共需7.5秒；
D选项：C出发时，B已走了2×3+1×3=9级阶梯⑧ , C 追上B 所需时间 =9÷(4-1)=3秒，加上C 晚出发的5秒，总共需8秒；
综上，答案为B 选项。','数量关系600题','进阶','published','{"globalNumber":306,"sourceNumber":6,"typeLabel":"行程问题之相遇追及","stemRich":[{"text":"有一架自动扶梯共25级，每秒移动2阶。A从扶梯的起点处站立乘坐，两 秒后B 从起点处以每秒1阶的速度向上走动。又过三秒后C来到扶梯起点处且 以每秒4阶的速度向上跑。那么以下事件中最先发生的是?"}],"annotatedStemRich":[{"text":"有一架自动扶梯共25级，每秒移动2阶。A从扶梯的起点处站立乘坐，两 秒后B 从起点处以每秒1阶的速度向上走动。又过三秒后C来到扶梯起点处且 以每秒4阶的速度向上跑。那么以下事件中最先发生的是?"}],"annotatedOptionRich":{"A":[{"text":"A 到达扶梯终点"}],"B":[{"text":"B  追上A"}],"C":[{"text":"  C追上A"}],"D":[{"text":"  C追上B\n数量关系\n"}]},"practicalAnalysis":"把A 出发作为时间起点，依次计算四个选项所用时间即可。 A选项：A 到达扶梯终点用时=25÷2=12.5秒；\nB选项：B出发时，A 已走了2×2=4级阶梯， B追上A所需时间=4÷(1- 0)=4秒②,加上B 晚出发的2秒，总共需6秒；\n⑦","notes":[{"marker":"⑦","text":"追及时间=距离差÷速度差，A站立乘坐，速度为0。","matchScore":0.106},{"marker":"⑧","text":"B 走的阶梯数等于扶梯走的阶梯和自己走的阶梯之和。\nC选项： C出发时，A已走了2×5=10级阶梯，C 追上A 所需时间=10÷(4- 0)=2.5秒，加上C 晚出发的5秒，总共需7.5秒；\nD选项：C出发时，B已走了2×3+1×3=9级阶梯⑧ , C 追上B 所需时间 =9÷(4-1)=3秒，加上C 晚出发的5秒，总共需8秒；\n综上，答案为B 选项。","matchScore":0.31}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
