INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500311,4,'工程问题','某工程队承担一项工程，由于天气原因，工期将延后10天。为了按期完工，需增加施工人员。若增加4人，工期会延后4天；若增加10人，工期将提前2 天。假设每人工作效率相同，为确保按期完工，则工程队最少应增加的施工人员数是多少人?','[{"label":"A","content":"6"},{"label":"B","content":"7"},{"label":"C","content":"8"},{"label":"D","content":"9"}]','C','设原工期为t 天，原施工人员为x 人，工人每天效率为1。根据完成情况可列方程： ①4(t+4)=6x ①, ②10(t-2)=12x ②, 解得x=20,
t=26;
则要确保按期完工，
取整为8,即最少增加8人，答案为C选项③。
①

①花生批注：
若增加4人，每天效率提升
4, t+4 天共多工作4(t+4) 份工作。相当于原来6天 (延后10天较延后4天多工作的6天)的工作量，即 6x。

②花生批注：
