INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500317,4,'整除问题+最值问题','某企业有甲和乙两个研发部门。其中甲部门有35%的员工有海外留学经历，

乙部门有32%的员工有海外留学经历。已知甲部门员工比乙部门多20人，则
两个研发部门最少可能有多少人没有海外留学经历?','[{"label":"A","content":"132"},{"label":"B","content":"146"},{"label":"C","content":"160"},{"label":"D","content":"174"}]','B','根据题意，甲部门员 ,即甲部门员工数为20的倍数，设20x 人；乙部门员工即乙部门员工数为 25的倍数，设25y 人；
⑨

⑨花生批注：
20x 、20 均为20的倍数，则25y 也是20的倍数， y 最小取4,此时 x=6。
