INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500321,4,'和差倍比问题','某区财政局年度考核，办公室与国库科平均得分90分，预算科
与政府采 购科平均得分84分，办公室与政府采购科平均得分86分

，政府采购科比预算 科多10分，国库科的得分比综合科多5分，

那么办公室、预算科、国库科、 政府采购科、综合科的平均得分
是多少分?','[{"label":"A","content":"84 分"},{"label":"B","content":"86 分"},{"label":"C","content":"88 分"},{"label":"D","content":"90 分"}]','C','根据“预算科与政府采购科平均得分为84分且后者比前者多 10分” ,可求得政府采购科为89分、预算科79分①;
根据“办公室与政府采购科平均得分86分”,可求得办公室为83分；
根据“办公室与国库科平均得分90分”,可求得国库科为97分；
根据“国库科的得分比综合科多5分”,可求得综合科为92分；
, 答案为C选项。
①

①花生批注：
二者距离平均分均为5分，则一个是(84+5)分，
一个是(84-5)分。','数量关系600题','进阶','published','{"globalNumber":321,"sourceNumber":1,"typeLabel":"和差倍比问题","stemRich":[{"text":"某区财政局年度考核，办公室与国库科平均得分90分，预算科\n与政府采 购科平均得分84分，办公室与政府采购科平均得分86分\n\n，政府采购科比预算 科多10分，国库科的得分比综合科多5分，\n\n那么办公室、预算科、国库科、 政府采购科、综合科的平均得分\n是多少分?"}],"annotatedStemRich":[{"text":"某区财政局年度考核，办公室与国库科平均得分90分，预算科\n与政府采 购科平均得分84分，办公室与政府采购科平均得分86分\n\n，政府采购科比预算 科多10分，国库科的得分比综合科多5分，\n\n那么办公室、预算科、国库科、 政府采购科、综合科的平均得分\n是多少分?"}],"annotatedOptionRich":{"A":[{"text":" 84 分"}],"B":[{"text":"86  分"}],"C":[{"text":" 88 分"}],"D":[{"text":"90   分\n"}]},"practicalAnalysis":"根据“预算科与政府采购科平均得分为84分且后者比前者多 10分” ,可求得政府采购科为89分、预算科79分①;\n根据“办公室与政府采购科平均得分86分”,可求得办公室为83分；\n根据“办公室与国库科平均得分90分”,可求得国库科为97分；\n根据“国库科的得分比综合科多5分”,可求得综合科为92分；\n, 答案为C选项。\n①","notes":[{"marker":"①","text":"二者距离平均分均为5分，则一个是(84+5)分，\n一个是(84-5)分。","matchScore":0.049}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500322,4,'年龄问题','2020年时，李某的年龄是自己工龄的4倍，且正好是张某年龄

