INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500332,4,'几何问题','甲、乙两个圆柱容器底面积之比为3:4,分别盛有7厘米高和

