INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500342,4,'统筹规划问题','某快餐店供应豆角炒肉和蛋炒饭各一份的套餐，甲和乙是该店的
员工。甲 每5分钟制作豆角炒肉6份或蛋炒饭10份，乙每5分钟

制作豆角炒肉4份或 蛋炒饭12份。要制作60份该套餐，甲乙合作

最少需要多少分钟?','[{"label":"A","content":"40"},{"label":"B","content":"45"},{"label":"C","content":"50"},{"label":"D","content":"55"}]','A','甲单位时间生产的豆角炒肉更多，乙单位时间生产的蛋炒饭更多，要想合作时间尽量少，应如此安排。
