INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500347,4,'行程问题之相遇追及问题','因
排
丙地为甲、乙两地之间高速公路上的一个测速点，其与甲地之间的距离是
与乙地之间距离的一半。A 、B 两车分别从甲地和乙地同时出发匀速相向而行，
第一次迎面相遇的位置距离丙地500米。两车到达对方出发地后立刻原路返回，
第二次两车相遇也为迎面相遇，问第二次相遇的位置一定?','[{"label":"A","content":"距离甲地1500米"},{"label":"B","content":"距离乙地1500米"},{"label":"C","content":"距离丙地1500米"},{"label":"D","content":"距离乙、丙中点1500米"}]','B','如图所示 ⑨,设甲丙距离为S, 乙丙距离为2S; 因为无法确定相遇点在丙的哪一侧，需要讨论：
若第一次相遇点在甲丙之间，则B的速度大于A 的 2 倍，当B 回到出发点乙时，A还没走到乙点，第二次相遇是B 从后面追上A, 并非迎面相遇，排除；
所以，第一次相遇点应在乙丙之间，则第一次相遇时，A 走了S+500 米；
第一次相遇二者共走了1个全程，第二次二者迎面相遇共走了3个全程 ①,即第二次相遇时， A 走了 3(S+500)=3S+1500 米，即走完全程(全程为3S) 又返回1500米，即距离乙地1500米，答案为B 选项。
