INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500348,4,'排列组合问题','为弘扬耕读文化，某校打造多样化“校外+校内”耕读文化教育基地，有

