INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500349,4,'几何问题之最短距离','A、B点和墙的位置如下图所示。现从A点出发以5米/秒的速度跑向墙， 接触到墙后再跑到B 点。问最少要多少秒到达B 点 ?
B
90米 30米
45米
墙','[{"label":"A","content":"30"},{"label":"B","content":"34"},{"label":"C","content":"38"},{"label":"D","content":"42"}]','A','如图所示⑬,作 A 点在墙另一侧的对称点A'', 连接A'' 、B 点，交墙于E 点，作BD 垂直于A''A 的延长线；
BD=90,A''D=120, 则 A''B=150, 由 A 到 E 再到 B 最短路程等于A''
B=150⑩, 最少需要150÷5=30秒，答案为 A选项。

⑩花生批注：
相同时间内，B 走过 2S+500, A 走过S-500, 距离比等于速度比，即B的速度是A的2倍以上。

⑭花生批注：
最短距离常用解法：
“两点之间线段距离最
短”,常用解法为“作对称点，连接两点，线段即为最短距离”。','数量关系600题','进阶','published','{"globalNumber":349,"sourceNumber":9,"typeLabel":"几何问题之最短距离","stemRich":[{"text":"A、B点和墙的位置如下图所示。现从A点出发以5米/秒的速度跑向墙， 接触到墙后再跑到B 点。问最少要多少秒到达B 点 ?\nB\n90米 30米\n45米\n墙"}],"annotatedStemRich":[{"text":"A、B点和墙的位置如下图所示。现从A点出发以5米/秒的速度跑向墙， 接触到墙后再跑到B 点。问最少要多少秒到达B 点 ?\nB\n90米 30米\n45米\n墙"}],"annotatedOptionRich":{"A":[{"text":"B点和墙的位置如下图所示。现从A点出发以5米/秒的速度跑向墙， 接触到墙后再跑到B 点。问最少要多少秒到达B 点 ?\nB\n90米    30米\n45米\n墙\nA.30"}],"B":[{"text":"34"}],"C":[{"text":"38","bold":true}],"D":[{"text":"42\n"}]},"practicalAnalysis":"如图所示⑬,作 A 点在墙另一侧的对称点A'', 连接A'' 、B 点，交墙于E 点，作BD 垂直于A''A 的延长线；\nBD=90,A''D=120, 则 A''B=150, 由 A 到 E 再到 B 最短路程等于A''\nB=150⑩, 最少需要150÷5=30秒，答案为 A选项。","notes":[{"marker":"⑩","text":"相同时间内，B 走过 2S+500, A 走过S-500, 距离比等于速度比，即B的速度是A的2倍以上。","matchScore":0.072},{"marker":"⑭","text":"最短距离常用解法：\n“两点之间线段距离最\n短”,常用解法为“作对称点，连接两点，线段即为最短距离”。","matchScore":0.123}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500350,4,'统筹规划问题','工匠师傅甲擅长制作工艺品A, 师傅乙擅长制作工艺品B, 当有

