INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500352,4,'行程问题','所求即为乙人数之比。
甲、乙两人从湖边某处同时出发，沿两条环湖路各自匀速行走。甲恰好用
2小时回到出发点，比乙晚到20 分钟，多走了2800米。若甲每分钟比乙多走

10米，则甲行走的速度是多少千米/小时?

209





m','[{"label":"A","content":"4.2千米/小时"},{"label":"B","content":"4.5 千米/小时"},{"label":"C","content":"4.8千米/小时"},{"label":"D","content":"5 .4 千米/小时"}]','D','甲每分钟比乙多走10米，乙用时120-20=100分钟回到出发点，当乙回到出发点时，甲比乙多走了100×10=1000米。
甲回到出发点时，一共比乙多走了2800米，因此在甲比乙晚到的20分钟内，甲走的路程为2800-1000=1800米，则甲行走的速度为1800÷20=90米/分，即5.4千米/时，答案为D选项。

②花生批注：
所求即为乙人数之比。

④花生批注：
aₙ=a₁+(n-1)d,
