INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500353,4,'数列问题','某种糖果的进价为12元/千克，现购进这种糖果若干千克，每
天销售10 千克，且从第二天起每天都比前一天降价2元/千克。

已知以6元/千克的价 格销售的那天正好卖完最后10千克，且总

销售额是总进货成本的2倍。问总 共进了多少千克这种糖果?','[{"label":"A","content":"180"},{"label":"B","content":"190"},{"label":"C","content":"160"},{"label":"D","content":"170"}]','B','根据“总销售额是总进货成本的2倍”可知，糖果的平均售价为12×2=24 元 /千克；
根据“从第二天起每天都比前一天降价2元/千克。已知以6元/千克的价格销售的那天正好卖完最后10千克”可知，每天糖果的售价构成末项为6, 公差为-2的等差数列；
