INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500356,4,'和差倍比问题','某高新技术企业为扩大业务，招收了两批新员工，原计划每批招
收的人数 相同，实际第二批多招了4人，结果第一批和第二批招收

后员工人数新增的百 分比相同。若第二批再多招6人，则员工总人数

是两次招收前员工人数的1.5倍。 该企业招收两批新员工前的员工人
数是多少人?','[{"label":"A","content":"96"},{"label":"B","content":"100"},{"label":"C","content":"104"},{"label":"D","content":"108"}]','B','因本题涉及员工新增百分比，正面列方程较为复杂①,,可考虑从选项代入：
B 选项为整百数，为方便计算可优先代入，根据“第二批多招6人，员工总人数是招收前的1.5倍”可知，两批招收新员工共100×50%-6=44人；根据“第二批多招4人”可知，两批分别招收20人、24人，则第一次增长率
,第二次增长两次新增百分比相同，符合题目要求，当选。

⑪花生批注：
设原员工人数为x 人，第一批招收人数为y, 则第二批招收 y+4;
可列方程：
①y+y+4+6=0.5x;
② 可解得x=100,y=20。','数量关系600题','进阶','published','{"globalNumber":356,"sourceNumber":6,"typeLabel":"和差倍比问题","stemRich":[{"text":"某高新技术企业为扩大业务，招收了两批新员工，原计划每批招\n收的人数 相同，实际第二批多招了4人，结果第一批和第二批招收\n\n后员工人数新增的百 分比相同。若第二批再多招6人，则员工总人数\n\n是两次招收前员工人数的1.5倍。 该企业招收两批新员工前的员工人\n数是多少人?"}],"annotatedStemRich":[{"text":"某高新技术企业为扩大业务，招收了两批新员工，原计划每批招\n收的人数 相同，实际第二批多招了4人，结果第一批和第二批招收\n\n后员工人数新增的百 分比相同。若第二批再多招6人，则员工总人数\n\n是两次招收前员工人数的1.5倍。 该企业招收两批新员工前的员工人\n数是多少人?"}],"annotatedOptionRich":{"A":[{"text":"96"}],"B":[{"text":"100"}],"C":[{"text":"104","bold":true}],"D":[{"text":"108","bold":true},{"text":"\n"}]},"practicalAnalysis":"因本题涉及员工新增百分比，正面列方程较为复杂①,,可考虑从选项代入：\nB 选项为整百数，为方便计算可优先代入，根据“第二批多招6人，员工总人数是招收前的1.5倍”可知，两批招收新员工共100×50%-6=44人；根据“第二批多招4人”可知，两批分别招收20人、24人，则第一次增长率\n,第二次增长两次新增百分比相同，符合题目要求，当选。","notes":[{"marker":"⑪","text":"设原员工人数为x 人，第一批招收人数为y, 则第二批招收 y+4;\n可列方程：\n①y+y+4+6=0.5x;\n② 可解得x=100,y=20。","matchScore":0.159}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500357,4,'工程问题','甲、乙两队单独完成某项工程分别需要10天、17天。甲队与乙
路：
间，
队按天轮 流做这项工程，甲队先做，最后是哪队第几天完工?
作总
和时','[{"label":"A","content":"甲队第11天"},{"label":"B","content":"甲队第13天"},{"label":"C","content":"乙队第12天"},{"label":"D","content":"乙队第14天"}]','B','已知条件为时间，可设最小公倍数170为工作总量，则甲乙效率分别为17、10;
二人按照“甲乙”顺序轮流，两天可完成27份工作，170÷27=6余8,即轮流6次(12天)后剩余8份工作，甲在第13天即可完成，答案为B选项。

⑫花生批注：
工程问题常用解题思路：
①若已知条件为时间，设最小公倍数为工作总量，根据工作总量和时间可求出效率。
②若已知条件为效率比，直接将其赋值为效率，根据效率和时间可求出工作总量。
③若已知条件为不同的工作情况，可根据工作量相同列方程求解。
此题已知各组完成工作
用时，赋值工作总量，可求各组工作效率。','数量关系600题','进阶','published','{"globalNumber":357,"sourceNumber":7,"typeLabel":"工程问题⑫","stemRich":[{"text":"甲、乙两队单独完成某项工程分别需要10天、17天。甲队与乙\n路：\n间，\n队按天轮 流做这项工程，甲队先做，最后是哪队第几天完工?\n作总\n和时"}],"annotatedStemRich":[{"text":"甲、乙两队单独完成某项工程分别需要10天、17天。甲队与乙\n路：\n间，\n队按天轮 流做这项工程，甲队先做，最后是哪队第几天完工?\n作总\n和时"}],"annotatedOptionRich":{"A":[{"text":" 甲队第11天"}],"B":[{"text":"  甲队第13天"}],"C":[{"text":"  乙队第12天"}],"D":[{"text":"  乙队第14天\n"}]},"practicalAnalysis":"已知条件为时间，可设最小公倍数170为工作总量，则甲乙效率分别为17、10;\n二人按照“甲乙”顺序轮流，两天可完成27份工作，170÷27=6余8,即轮流6次(12天)后剩余8份工作，甲在第13天即可完成，答案为B选项。","notes":[{"marker":"⑫","text":"工程问题常用解题思路：\n①若已知条件为时间，设最小公倍数为工作总量，根据工作总量和时间可求出效率。\n②若已知条件为效率比，直接将其赋值为效率，根据效率和时间可求出工作总量。\n③若已知条件为不同的工作情况，可根据工作量相同列方程求解。\n此题已知各组完成工作\n用时，赋值工作总量，可求各组工作效率。","matchScore":0.216}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500358,4,'最值问题之和定最值问题','部队射击比赛中，5名参赛的战士共击中了88次目标。已知任意2人击中的目标数量均互不相同，问射击成绩排前两名的战士至少击中了多少次目标?','[{"label":"A","content":"37"},{"label":"B","content":"39"},{"label":"C","content":"58"},{"label":"D","content":"82"}]','B','设射击成绩第一名的战士最少击中了x 次目标，要想前两名击中次数尽量少，其他几个部门应该尽可能大；
又因为击中数量互不相同，可根据总和列方程：x+x-1+x-2+x-3+x-4=88, 解得x=19.6; 因所设为x 的最小值，所以x 取整为20次，则前两名至少击中 20+19=39次，答案为B选项。
⑬

⑬花生批注：
和定最值问题的常用解法：
若各人不能相等：
问某人最多，则其他人尽量少，问某人最少，则其他人尽量多，但注意符合其排名要求；最后用总量列方程解题。
若各人可能相等：
