INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500361,4,'和差倍比问题','救灾部门紧急运送两批大米分给受灾群众。已知甲村人数是丙
村的2倍， 如果两批大米都给甲村，每人正好能分24斤；如果第一

批大米分给乙村，每 人正好能分12斤，第二批大米分给甲、乙、

丙三个村，每人正好能分4斤。 为尽量保障受灾群众的基本需求，
现决定另运送一批面粉分给甲村，并将两批 大米都分给乙、丙两村

。问乙、丙两村平均每人分到的大米重量在以下哪个范 围内?','[{"label":"A","content":"不到14斤"},{"label":"B","content":"14～15 斤之间"},{"label":"C","content":"15～16 斤之间"},{"label":"D","content":"16 斤以上"}]','B','根据题意，可将已知条件填入下表：
甲
乙
丙
2 x 人
y人
x 人
第一批大米
第二批大米
大米总和
12y
4×(2x+y+x)=12x+4y
24×2x=48x
