INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500363,4,'几何问题','长为10cm 的素菜蛋卷的制作方法是：用一张7cm×10cm的蛋皮
