INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500365,4,'排列组合问题','某单位开设a 、b、c、d、e、f 六门培训课程，员工自愿报名参

