INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500368,4,'几何问题+行程问题','甲、乙两部参加军事演习。甲部从大本营以60千米/小时的速度往西行进，

乙部晚半小时由大本营往东行进，速度比甲部慢。两部同时接到军令紧急集合，
集合地位于大本营正北某处。此时两部所在位置与集合地恰好构成有一角为30

度的直角三角形。若两部同时调整方向往集合地行军，且保持速度不变，则可
