INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500370,4,'方阵问题','某次运动会需组织长宽相等的方阵。组织方安排了一个鲜花方阵

边 和一个彩 旗方阵，两个方阵分别入场完毕后又合成一个方阵，鲜花
方阵的人恰好组成新 方阵的最外圈。已知彩旗方阵比鲜花方阵多28
数
人，则新方阵的总人数为?','[{"label":"A","content":"100"},{"label":"B","content":"144"},{"label":"C","content":"196"},{"label":"D","content":"256"}]','A','本题正面分析较为复杂，可考虑选项代入验证：
A选项，根据鲜花方阵和彩旗方阵的和与差可知，彩旗方阵为128÷2=64人，鲜花方阵为72÷2=36人②;新方阵为10×10方阵，最外层每边人数为10人，
最外圈人数为4×10-4=36人，恰好和鲜花方阵人数相等，当选⑨。

⑬花生批注：
其他选项：
