INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500371,4,'和差倍比问题','某工程由甲、乙两家企业共同参与，甲企业的实际出资额是乙企

