INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500378,4,'排列组合问题','某企业举行职业技能大赛，3个下属分公司均选2名员工参赛。

若同一分 公司的员工比赛时出场顺序不能相邻，则参赛的6名员工

不同的出场顺序共有 多少种?','[{"label":"A","content":"80 种"},{"label":"B","content":"120 种"},{"label":"C","content":"160 种"},{"label":"D","content":"240 种"}]','D','设6名员工分别为甲1、甲2、乙、乙2、丙1、丙2;分析过程如下：
①先从6人中任选一人，C₆, 假设选出的是甲1;
②再从甲公司以外的4人中任选一人，C, 假设选出的是乙；分情况讨论：
③若第三位选出的是甲2,则乙2只能在丙1丙2之间，丙公司二人进行排序， A;
④若第三位选出的是丙公司的一人，C2, 假设选出的是丙1,之后可从甲2 乙2中选出一人， ,之后再在剩余2人中选出一人即可C2;
综上，一共有种出场顺序，答案为D选项。

③花生批注：
B 成本
求得的是价格上涨之前的A 、B咖啡成本之比⑧,即50A:40B④=3:2, 解得A:B=6:5, 答案为C选项。
所求为原来成本之比。','数量关系600题','进阶','published','{"globalNumber":378,"sourceNumber":8,"typeLabel":"排列组合问题","stemRich":[{"text":"某企业举行职业技能大赛，3个下属分公司均选2名员工参赛。\n\n若同一分 公司的员工比赛时出场顺序不能相邻，则参赛的6名员工\n\n不同的出场顺序共有 多少种?"}],"annotatedStemRich":[{"text":"某企业举行职业技能大赛，3个下属分公司均选2名员工参赛。\n\n若同一分 公司的员工比赛时出场顺序不能相邻，则参赛的6名员工\n\n不同的出场顺序共有 多少种?"}],"annotatedOptionRich":{"A":[{"text":"80    种"}],"B":[{"text":"   120 种"}],"C":[{"text":"  160 种"}],"D":[{"text":"  240 种\n"}]},"practicalAnalysis":"设6名员工分别为甲1、甲2、乙、乙2、丙1、丙2;分析过程如下：\n①先从6人中任选一人，C₆, 假设选出的是甲1;\n②再从甲公司以外的4人中任选一人，C, 假设选出的是乙；分情况讨论：\n③若第三位选出的是甲2,则乙2只能在丙1丙2之间，丙公司二人进行排序， A;\n④若第三位选出的是丙公司的一人，C2, 假设选出的是丙1,之后可从甲2 乙2中选出一人， ,之后再在剩余2人中选出一人即可C2;\n综上，一共有种出场顺序，答案为D选项。","notes":[{"marker":"③","text":"B 成本\n求得的是价格上涨之前的A 、B咖啡成本之比⑧,即50A:40B④=3:2, 解得A:B=6:5, 答案为C选项。\n所求为原来成本之比。","matchScore":0.057}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500379,4,'容斥问题','某单位员工号从1至82,元旦活动全部参加，活动抽出数字5

与7,员工 号是5或7的倍数的均获奖，那么有多少员工获奖?','[{"label":"A","content":"30"},{"label":"B","content":"29"},{"label":"C","content":"27"},{"label":"D","content":"25"}]','D','工号为5的倍数的员工有82÷5=16余2,即16人；
工号为7的倍数的员工有82÷7=11余5,即11人；
5与7的最小公倍数为35,工号是5和7的共同倍数的员工有82÷35=2 余 1 2 ,即2人；
综上，获奖员工有16+11-2=25人⑨,答案为D选项。

⑨花生批注：
容斥问题常用解题方式：
①直接代入公式：全部人数一圈外人数=人数之和- 重复部分；
②有时需要另一种计数方式，圈内总人数=只参加一种的人数+只参加两种的人数+……+所有都参加的人数(此公式只在部分题目中需要使用，编者称之为隐含公式)。
易错点：误将“符合 A和 B”当做“只符合A 和B”, 前者包含“符合 A、B、C”的元素，而后者不包含。','数量关系600题','进阶','published','{"globalNumber":379,"sourceNumber":9,"typeLabel":"容斥问题","stemRich":[{"text":"某单位员工号从1至82,元旦活动全部参加，活动抽出数字5\n\n与7,员工 号是5或7的倍数的均获奖，那么有多少员工获奖?"}],"annotatedStemRich":[{"text":"某单位员工号从1至82,元旦活动全部参加，活动抽出数字5\n\n与7,员工 号是5或7的倍数的均获奖，那么有多少员工获奖?"}],"annotatedOptionRich":{"A":[{"text":"30"}],"B":[{"text":"29"}],"C":[{"text":"27"}],"D":[{"text":"25\n"}]},"practicalAnalysis":"工号为5的倍数的员工有82÷5=16余2,即16人；\n工号为7的倍数的员工有82÷7=11余5,即11人；\n5与7的最小公倍数为35,工号是5和7的共同倍数的员工有82÷35=2 余 1 2 ,即2人；\n综上，获奖员工有16+11-2=25人⑨,答案为D选项。","notes":[{"marker":"⑨","text":"容斥问题常用解题方式：\n①直接代入公式：全部人数一圈外人数=人数之和- 重复部分；\n②有时需要另一种计数方式，圈内总人数=只参加一种的人数+只参加两种的人数+……+所有都参加的人数(此公式只在部分题目中需要使用，编者称之为隐含公式)。\n易错点：误将“符合 A和 B”当做“只符合A 和B”, 前者包含“符合 A、B、C”的元素，而后者不包含。","matchScore":0.023}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500380,4,'最值问题','称
有4个盒子装有红白蓝绿四色粉笔各有若干支。任意2个盒子的
和
”, 粉笔的支 数和分别为12、23、31、46、54、65,粉笔支数最多的盒
C”
。 子里同一颜色最多的 粉笔至少有多少支(没有并列)?','[{"label":"A","content":"14"},{"label":"B","content":"13"},{"label":"C","content":"12"},{"label":"D","content":"11"}]','B','设4个盒子粉笔支数从大到小依次是a 、b 、c 、d。根据四个盒子的大小关系能够确定：a+b=65,a+c=54,c+d=12,b+d=23, 对于a+d 和 b+c 的和是35还是46是无法确定的。
由于两数相加和相减结果的奇偶性相同， b-c=b+d-(c+d)=23-12=11 。所以 b+c 的和是奇数，即 b+c=35 。联立b+c=35 和 b-c=11, 解得 b=21,c=10。
a=65-21=44, 即4个粉笔盒子数量最多的有44支。
设最多的粉笔数量至少有x 支，想要此颜色最少，则其他的颜色尽可能多，可根据和定最值解题思路列方程⑥: x+x-1+x-2+x-3=44, 解得x=12.5 。所设为 x 最少为12.5,取整为13支，答案为B 选项。

⑩花生批注：
和定最值常用解题思路：
①若各部分不能相等：问某部分最多，则其他部分尽量少，问某部分最少，则其他部分尽量多，但要注意符合其排名要求；“问什么设什么”,最后用总量列方程解题。
②若各部分可能相等：问第一名最少或问最后一名最多，可根据抽屉原理求出平均值求解。
本题属于第①种情况。','数量关系600题','进阶','published','{"globalNumber":380,"sourceNumber":10,"typeLabel":"最值问题","stemRich":[{"text":"称\n有4个盒子装有红白蓝绿四色粉笔各有若干支。任意2个盒子的\n和\n”, 粉笔的支 数和分别为12、23、31、46、54、65,粉笔支数最多的盒\nC”\n。 子里同一颜色最多的 粉笔至少有多少支(没有并列)?"}],"annotatedStemRich":[{"text":"称\n有4个盒子装有红白蓝绿四色粉笔各有若干支。任意2个盒子的\n和\n”, 粉笔的支 数和分别为12、23、31、46、54、65,粉笔支数最多的盒\nC”\n。 子里同一颜色最多的 粉笔至少有多少支(没有并列)?"}],"annotatedOptionRich":{"A":[{"text":"14"}],"B":[{"text":"13"}],"C":[{"text":"12"}],"D":[{"text":"11\n"}]},"practicalAnalysis":"设4个盒子粉笔支数从大到小依次是a 、b 、c 、d。根据四个盒子的大小关系能够确定：a+b=65,a+c=54,c+d=12,b+d=23, 对于a+d 和 b+c 的和是35还是46是无法确定的。\n由于两数相加和相减结果的奇偶性相同， b-c=b+d-(c+d)=23-12=11 。所以 b+c 的和是奇数，即 b+c=35 。联立b+c=35 和 b-c=11, 解得 b=21,c=10。\na=65-21=44, 即4个粉笔盒子数量最多的有44支。\n设最多的粉笔数量至少有x 支，想要此颜色最少，则其他的颜色尽可能多，可根据和定最值解题思路列方程⑥: x+x-1+x-2+x-3=44, 解得x=12.5 。所设为 x 最少为12.5,取整为13支，答案为B 选项。","notes":[{"marker":"⑩","text":"和定最值常用解题思路：\n①若各部分不能相等：问某部分最多，则其他部分尽量少，问某部分最少，则其他部分尽量多，但要注意符合其排名要求；“问什么设什么”,最后用总量列方程解题。\n②若各部分可能相等：问第一名最少或问最后一名最多，可根据抽屉原理求出平均值求解。\n本题属于第①种情况。","matchScore":0.125}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
