INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500384,4,'行程问题','甲、乙、丙从长360米的圆形跑道上的不同点同时出发，沿顺时
