INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500391,4,'和差倍比问题','同事甲、乙两人共携带120千克行李乘坐飞机，根据规定，甲单独托运则超重需支付200元，乙单独托运则超重需支付100元。若全部行李由一人负责托运，则超重需支付450元。问每位乘客的免费托运的行李最多为多少千克?','[{"label":"A","content":"20"},{"label":"B","content":"25"},{"label":"C","content":"30"},{"label":"D","content":"35"}]','C','设免费托运行李重量为x 千克，则超重120-2x 千克需支付 300元，超重120-x 千克需支付450元；超重部分费用相同，支付金额之比等于超重重量之比，则120-x=1.5(120-2x), 解得x=30, 答案为C选项。','数量关系600题','进阶','published','{"globalNumber":391,"sourceNumber":1,"typeLabel":"和差倍比问题","stemRich":[{"text":"同事甲、乙两人共携带120千克行李乘坐飞机，根据规定，甲单独托运则 超重需支付200元，乙单独托运则超重需支付100元。若全部行李由一人负责 托运，则超重需支付450元。问每位乘客的免费托运的行李最多为多少千克?"}],"annotatedStemRich":[{"text":"同事甲、乙两人共携带120千克行李乘坐飞机，根据规定，甲单独托运则 超重需支付200元，乙单独托运则超重需支付100元。若全部行李由一人负责 托运，则超重需支付450元。问每位乘客的免费托运的行李最多为多少千克?"}],"annotatedOptionRich":{"A":[{"text":"20"}],"B":[{"text":"25"}],"C":[{"text":"30"}],"D":[{"text":"35\n"}]},"practicalAnalysis":"设免费托运行李重量为x 千克，则超重120-2x 千克需支付 300元，超重120-x 千克需支付450元；超重部分费用相同，支付金额之比等于超重重量之比，则120-x=1.5(120-2x), 解得x=30, 答案为C选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
