INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500396,4,'行程问题','一个圆形的人工湖，直径为50公里，某游船从码头甲出发，匀速直线行驶30公里到码头乙停留36分钟，然后到与码头甲直线距离为50公里的码头丙，共用时2小时。问该游船从码头甲直线行驶到码头丙需用多少时间?','[{"label":"A","content":"50 分钟"},{"label":"B","content":"1 小时"},{"label":"C","content":"1 小时20分"},{"label":"D","content":"1 小时30分"}]','B','根据题意可画出右图⑨ :A为甲码头，B为乙码头，C为丙码头。如图可知 ∠B为90度，在直角△ ABC中：AB=30,AC=50,根据勾股定理可知 BC=40。
⑨

