INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500397,4,'排列组合问题','6名身高不同的学生站成人数相同的2排合影，要求后排学生的

身高必须 高于前排相同位置的学生，同一排中间位置的学生必须高
于靠边位置的人，有 多少种不同的安排方式?','[{"label":"A","content":"8"},{"label":"B","content":"12"},{"label":"C","content":"16"},{"label":"D","content":"36"}]','C','六个位置标号如图所示①,则最高同学只能在B 位，最矮同学只能在a 或 c 位，即C2 ( 设最矮同学在a 位 ) ;
之后可分情况讨论：
若第二矮同学在后排，那只能在最矮同学后面(即A位),此时第三矮同学只能在 c 位，另外两位同学可以均可在b位或C位②,即A²;
若第二矮同学在前排，那只能在c 位，此时另外三位同学均可在b位或A 位或 C 位⑲,即 A³ ;
综上，一共有C¹×(A²+A³)=2×(2+6)=16 种安排方式，答案为C 选项。

