INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500399,4,'比赛问题','在某次象棋公开赛的初赛中，每个选手都与其他选手比赛一局，

每局获胜 者得2分，失败者不得分，若出现平局则双方各得1分。
四 位 棋 迷 统 计 了 初 赛 中 全 部 选 手 的 得 分 ， 总 数 分 别 是

504,505,506,507。经核实只有一位棋迷统 计正确，那么这次比赛

共有多少名选手?','[{"label":"A","content":"22"},{"label":"B","content":"23"},{"label":"C","content":"24"},{"label":"D","content":"25"}]','B','每局比赛无论结果是胜负平，总分均为2分⑨,每个选手都与其他选手比赛一局，令选手总数为n, 则总局数为C², 得分总数为2×C²=n(n-1), 即两个相邻数之积；
参照选项可以试出23×22=506,因此选手总数为23名，答案为B 选项。
⑭

⑭花生批注：
若分出胜负，二人分别得 2分、0分，总分为2分；若是平局，二人均得到1 分，总分也为2分。','数量关系600题','进阶','published','{"globalNumber":399,"sourceNumber":9,"typeLabel":"比赛问题","stemRich":[{"text":"在某次象棋公开赛的初赛中，每个选手都与其他选手比赛一局，\n\n每局获胜 者得2分，失败者不得分，若出现平局则双方各得1分。\n四 位 棋 迷 统 计 了 初 赛 中 全 部 选 手 的 得 分 ， 总 数 分 别 是\n\n504,505,506,507。经核实只有一位棋迷统 计正确，那么这次比赛\n\n共有多少名选手?"}],"annotatedStemRich":[{"text":"在某次象棋公开赛的初赛中，每个选手都与其他选手比赛一局，\n\n每局获胜 者得2分，失败者不得分，若出现平局则双方各得1分。\n四 位 棋 迷 统 计 了 初 赛 中 全 部 选 手 的 得 分 ， 总 数 分 别 是\n\n504,505,506,507。经核实只有一位棋迷统 计正确，那么这次比赛\n\n共有多少名选手?"}],"annotatedOptionRich":{"A":[{"text":"22"}],"B":[{"text":"23"}],"C":[{"text":"24"}],"D":[{"text":"25\n"}]},"practicalAnalysis":"每局比赛无论结果是胜负平，总分均为2分⑨,每个选手都与其他选手比赛一局，令选手总数为n, 则总局数为C², 得分总数为2×C²=n(n-1), 即两个相邻数之积；\n参照选项可以试出23×22=506,因此选手总数为23名，答案为B 选项。\n⑭","notes":[{"marker":"⑭","text":"若分出胜负，二人分别得 2分、0分，总分为2分；若是平局，二人均得到1 分，总分也为2分。","matchScore":0.107}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500400,4,'几何问题','某工业园区内一区域如下图所示，三角形ABC与ACD为两个面积相等的直角三角形，AB长度是BC的2倍。现在区域内划出如图两个圆形区域摆放花坛，两个圆形均与图中两条边相切。已知B点到大圆、D点到小圆上任一点的最短
距离分别为AD长度的问大圆面积是小圆的多少倍?','[{"label":"A","content":"3 倍以下"},{"label":"B","content":"3～ 3.5\n\n倍之间"},{"label":"C","content":"3.5～4 倍之间"},{"label":"D","content":"4\n\n倍以上"}]','D','如图所示⑮,△ ABC 为直角三角形且AB=2BC, 则△ABC为 30°、60°直角三角形，即∠ ABC=60°;
又因为△ OMB 和△ ONB 为全等三角形，∠MBO=∠NB0=30°, 则△ OMB 也为30°、60°直角三角形， BO=r+ “最短距离”=2MO=2r, 即 B 到大圆的最短距离就等于大圆半径；同理， D 到小圆的最短距离也等于小圆的半径；
所以，大圆小圆的半径之比就等于B 点到大圆和 D点到小圆的最短距离之比，即二者之比等于5:2,根据等比放缩性质可知①,二者面积之比为 25:4,前者是后者的6 .25倍，答案为D 选项。

⑮花生批注：
