INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500401,4,'和差倍比问题','一个袋子里红球、白球、蓝球的数量比例为3:8:4,再向袋子
中放入14 个红球和若干个蓝球后，红球、白球、蓝球的数量比例

变为5:4:3。如果此 时从袋子里取出10个红球、6个白球和2个蓝

球后，袋子里剩余红球、白球、 蓝球的数量比例为多少?','[{"label":"A","content":"1:2:1"},{"label":"B","content":"2:3:1"},{"label":"C","content":"1:1:2"},{"label":"D","content":"1:1:1"}]','D','加入14个红球和若干蓝球后，白球数没有变，可按照“白球不变”统一比例，即原来比例为3:8:4,之后比例为10:8:6;
加入的14个红球对应7份，即一份=2球，现在分别有三种颜色的球20个、 16个、12个；
若取出10个红球、6个白球和2个蓝球，则三种球之比=10:10:10= 1:1:1, 答案为D选项。','数量关系600题','进阶','published','{"globalNumber":401,"sourceNumber":1,"typeLabel":"和差倍比问题","stemRich":[{"text":"一个袋子里红球、白球、蓝球的数量比例为3:8:4,再向袋子\n中放入14 个红球和若干个蓝球后，红球、白球、蓝球的数量比例\n\n变为5:4:3。如果此 时从袋子里取出10个红球、6个白球和2个蓝\n\n球后，袋子里剩余红球、白球、 蓝球的数量比例为多少?"}],"annotatedStemRich":[{"text":"一个袋子里红球、白球、蓝球的数量比例为3:8:4,再向袋子\n中放入14 个红球和若干个蓝球后，红球、白球、蓝球的数量比例\n\n变为5:4:3。如果此 时从袋子里取出10个红球、6个白球和2个蓝\n\n球后，袋子里剩余红球、白球、 蓝球的数量比例为多少?"}],"annotatedOptionRich":{"A":[{"text":"1:2:1"}],"B":[{"text":"2:3:1"}],"C":[{"text":"1:1:2"}],"D":[{"text":"1:1:1\n"}]},"practicalAnalysis":"加入14个红球和若干蓝球后，白球数没有变，可按照“白球不变”统一比例，即原来比例为3:8:4,之后比例为10:8:6;\n加入的14个红球对应7份，即一份=2球，现在分别有三种颜色的球20个、 16个、12个；\n若取出10个红球、6个白球和2个蓝球，则三种球之比=10:10:10= 1:1:1, 答案为D选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500402,4,'不定方程问题','某公司张、王、刘、李和陈5名销售员去年共完成24个项目的
销售。已 知每个项目只有1人负责销售，每人都至少完成了1个项

目且完成的项目数量 彼此不同。张完成的项目比刘少5个，李完

成的项目比陈多6个，且不是5人 中最多的，王完成的项目最少，
问张和李共完成多少个项目?','[{"label":"A","content":"10"},{"label":"B","content":"11"},{"label":"C","content":"12"},{"label":"D","content":"13"}]','C','根据题意可得下表：
销售员
张
王
刘
李
陈
合计
项目数
X
Z
x+5
y+6
y
24
根据项目总数可列方程：x+z+x+5+y+6+y=24, 解得z=13-2x-2y; 因为z最小， z只能为1①,即x+y=6, 张和李完成项目之和=x+y+6=6+6=12, 答案为C 选项。

①花生批注：
若z= 3, 则 2x+2y=10, x、y 不能同时大于z;
z 若更大，x 、y 更不能同时大于 z。','数量关系600题','进阶','published','{"globalNumber":402,"sourceNumber":2,"typeLabel":"不定方程问题","stemRich":[{"text":"某公司张、王、刘、李和陈5名销售员去年共完成24个项目的\n销售。已 知每个项目只有1人负责销售，每人都至少完成了1个项\n\n目且完成的项目数量 彼此不同。张完成的项目比刘少5个，李完\n\n成的项目比陈多6个，且不是5人 中最多的，王完成的项目最少，\n问张和李共完成多少个项目?"}],"annotatedStemRich":[{"text":"某公司张、王、刘、李和陈5名销售员去年共完成24个项目的\n销售。已 知每个项目只有1人负责销售，每人都至少完成了1个项\n\n目且完成的项目数量 彼此不同。张完成的项目比刘少5个，李完\n\n成的项目比陈多6个，且不是5人 中最多的，王完成的项目最少，\n问张和李共完成多少个项目?"}],"annotatedOptionRich":{"A":[{"text":"10"}],"B":[{"text":"11"}],"C":[{"text":"12"}],"D":[{"text":"13\n"}]},"practicalAnalysis":"根据题意可得下表：\n销售员\n张\n王\n刘\n李\n陈\n合计\n项目数\nX\nZ\nx+5\ny+6\ny\n24\n根据项目总数可列方程：x+z+x+5+y+6+y=24, 解得z=13-2x-2y; 因为z最小， z只能为1①,即x+y=6, 张和李完成项目之和=x+y+6=6+6=12, 答案为C 选项。","notes":[{"marker":"①","text":"若z= 3, 则 2x+2y=10, x、y 不能同时大于z;\nz 若更大，x 、y 更不能同时大于 z。","matchScore":0.044}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
