INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500404,4,'排列组合问题','某地发生山火，ABCDE等 5人加入灭火志愿者，每人从事救援物

资接收、 派发、驾驶摩托车运送救援物资、医疗救护4项工作之一
。每项至少一人，A、 B不会驾驶摩托车但能从事其他三项工作，

其余三人都能从事四项工作。问有 多少种不同方案?','[{"label":"A","content":"86"},{"label":"B","content":"112"},{"label":"C","content":"126"},{"label":"D","content":"152"}]','C','5人分配到4项工作中，每项至少一人，则有1项工作安排2人，驾驶摩托车这项工作比较特殊，对其进行分类讨论：
①驾驶摩托车的有1人，则从 C、D、E 三人中任选1人， C³₃; 再从其余4 人选出2人合并为一组，c2; 此时再将这一组和另外2人安排到不同的三种工作，即 A³;
