INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500405,4,'经济利润问题','某羽毛球俱乐部推出充值会员优惠活动，具体为月卡会员费用打八折，年卡会员费用打七折，充值总时长1年的月卡比1年的年卡所需费用，打折前后分别多88元和100元，问打折后充值18个月的会员最少需要?','[{"label":"A","content":"不到340元"},{"label":"B","content":"340～400 元之间"},{"label":"C","content":"400～460 元之间"},{"label":"D","content":"460 元以上"}]','B','设月卡打折前会员费用为x 元/月，年卡打折前会员费用为 y 元/年，可根据付费差值列方程： ①12 x-y=88,②12x×0.8-0.7y=100, 解得 x=32,y=296。
要打折后充值18个月费用最少，可充值一年年卡+6个月月卡，共计296 ×0.7+6×32×0.8=207.2+153.6=360.8元，对应B选项，当选。','数量关系600题','进阶','published','{"globalNumber":405,"sourceNumber":5,"typeLabel":"经济利润问题","stemRich":[{"text":"某羽毛球俱乐部推出充值会员优惠活动，具体为月卡会员费用打八折，年 卡会员费用打七折，充值总时长1年的月卡比1年的年卡所需费用，打折前后 分别多88元和100元， 问打折后充值18个月的会员最少需要?"}],"annotatedStemRich":[{"text":"某羽毛球俱乐部推出充值会员优惠活动，具体为月卡会员费用打八折，年 卡会员费用打七折，充值总时长1年的月卡比1年的年卡所需费用，打折前后 分别多88元和100元， 问打折后充值18个月的会员最少需要?"}],"annotatedOptionRich":{"A":[{"text":" 不到340元"}],"B":[{"text":"340～400    元之间"}],"C":[{"text":"400～460    元之间"}],"D":[{"text":"460  元以上\n"}]},"practicalAnalysis":"设月卡打折前会员费用为x 元/月，年卡打折前会员费用为 y 元/年，可根据付费差值列方程： ①12 x-y=88,②12x×0.8-0.7y=100, 解得 x=32,y=296。\n要打折后充值18个月费用最少，可充值一年年卡+6个月月卡，共计296 ×0.7+6×32×0.8=207.2+153.6=360.8元，对应B选项，当选。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500406,4,'最值问题之最不利问题','在边长为2的正方形中投入若干石子(石子大小忽略不计),问

至少投多 少个石子才能使这些石子中一定存在距离不超过 √2的两

个石子?','[{"label":"A","content":"5"},{"label":"B","content":"6"},{"label":"C","content":"7"},{"label":"D","content":"8"}]','A','根据题意，可构建最不利情况，开始投入的4个石子尽量远离(均在四个顶点上),第5颗石子也尽量远离前4颗石子，即投到对角线交点处；
边长为2的正方形对角线为2 √ 2,顶点到对角线交点距离为 √ 2,此时必然存在距离不超过 √ 2的两个石子③,即至少投5个石子可满足题意，答案为A 选项。
③

③花生批注：
距离不超过 √2,即距离小于或等于 √2。','数量关系600题','进阶','published','{"globalNumber":406,"sourceNumber":6,"typeLabel":"最值问题之最不利问题","stemRich":[{"text":"在边长为2的正方形中投入若干石子(石子大小忽略不计),问\n\n至少投多 少个石子才能使这些石子中一定存在距离不超过 √2的两\n\n个石子?"}],"annotatedStemRich":[{"text":"在边长为2的正方形中投入若干石子(石子大小忽略不计),问\n\n至少投多 少个石子才能使这些石子中一定存在距离不超过 √2的两\n\n个石子?"}],"annotatedOptionRich":{"A":[{"text":"5"}],"B":[{"text":"6"}],"C":[{"text":"7"}],"D":[{"text":"8\n"}]},"practicalAnalysis":"根据题意，可构建最不利情况，开始投入的4个石子尽量远离(均在四个顶点上),第5颗石子也尽量远离前4颗石子，即投到对角线交点处；\n边长为2的正方形对角线为2 √ 2,顶点到对角线交点距离为 √ 2,此时必然存在距离不超过 √ 2的两个石子③,即至少投5个石子可满足题意，答案为A 选项。\n③","notes":[{"marker":"③","text":"距离不超过 √2,即距离小于或等于 √2。","matchScore":0.079}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500407,4,'行程问题之相遇追及问题','小朗和小峰每晚都会绕着体育场跑步。某晚，小朗、小峰分别从

体育场的 一号门、三号门同时出发匀速跑步，6分钟后，两人迎面

相遇，相遇后，两人 继续匀速前进。小峰又跑了5分钟到达一号门
并由此进入体育场，横穿体育场 从三号门跑出，沿与小朗相同的方

向继续跑。已知小朗跑到三号门时，小峰距 三号门还有180米，小

峰又经过6分钟追上了小朗。则小朗的跑步速度为多少 千米/小时?','[{"label":"A","content":"6"},{"label":"B","content":"7.2"},{"label":"C","content":"9"},{"label":"D","content":"10.8"}]','C','如图所示⑨,小朗从一号门到第一次相遇点用了6分钟，小峰从相遇点到一号门用了5分钟，二者速度与时间成反比，则V明：V=5:6,
设V朗=5v, V峰=6v;
小朗跑到三号门时，小峰落后180米，用时6分钟追上小朗，即6×(6v-
5v)=180, 解得v=30 米/分钟，即V朗=5v=150 米/分钟=9千米/小时，答案为 C选项。','数量关系600题','进阶','published','{"globalNumber":407,"sourceNumber":7,"typeLabel":"行程问题之相遇追及问题","stemRich":[{"text":"小朗和小峰每晚都会绕着体育场跑步。某晚，小朗、小峰分别从\n\n体育场的 一号门、三号门同时出发匀速跑步，6分钟后，两人迎面\n\n相遇，相遇后，两人 继续匀速前进。小峰又跑了5分钟到达一号门\n并由此进入体育场，横穿体育场 从三号门跑出，沿与小朗相同的方\n\n向继续跑。已知小朗跑到三号门时，小峰距 三号门还有180米，小\n\n峰又经过6分钟追上了小朗。则小朗的跑步速度为多少 千米/小时?"}],"annotatedStemRich":[{"text":"小朗和小峰每晚都会绕着体育场跑步。某晚，小朗、小峰分别从\n\n体育场的 一号门、三号门同时出发匀速跑步，6分钟后，两人迎面\n\n相遇，相遇后，两人 继续匀速前进。小峰又跑了5分钟到达一号门\n并由此进入体育场，横穿体育场 从三号门跑出，沿与小朗相同的方\n\n向继续跑。已知小朗跑到三号门时，小峰距 三号门还有180米，小\n\n峰又经过6分钟追上了小朗。则小朗的跑步速度为多少 千米/小时?"}],"annotatedOptionRich":{"A":[{"text":"6"}],"B":[{"text":"7.2"}],"C":[{"text":"9","bold":true}],"D":[{"text":"10.8","bold":true},{"text":"\n"}]},"practicalAnalysis":"如图所示⑨,小朗从一号门到第一次相遇点用了6分钟，小峰从相遇点到一号门用了5分钟，二者速度与时间成反比，则V明：V=5:6,\n设V朗=5v, V峰=6v;\n小朗跑到三号门时，小峰落后180米，用时6分钟追上小朗，即6×(6v-\n5v)=180, 解得v=30 米/分钟，即V朗=5v=150 米/分钟=9千米/小时，答案为 C选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500408,4,'几何问题+概率问题','从正九边形的顶点中任选3个作为顶点绘制三角形，问其中等腰

三角形占 全部可画出三角形的比例在以下哪个范围内?','[{"label":"A","content":"低于28%"},{"label":"B","content":"在28%到33%之间"},{"label":"C","content":"在33%到40%之间"},{"label":"D","content":"高于40%"}]','C','从正九边形的9个顶点任选3个作为顶点绘制三角形，总的
