INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500409,4,'几何问题','平行四边形ABCD如下图所示，E为AB上的一点，F、G分别为

AC与 DE、 DB的交点。若AB=3AE,则四边形BEFG与ABCD的面积
之比是多少?








综上，四边形','[{"label":"A","content":"2:7"},{"label":"B","content":"3:13"},{"label":"C","content":"4:19"},{"label":"D","content":"5:24"}]','D','如下图所示，△AEF与△ CDF相似，AE:CD=AE: AB=1:3, 则 FH:Fl=1:3, 即FH:HI=1:4;
△ ABG 在AB 边上的高与平行四边形的高之比=1:2,故△ AEF与△ ABG 高之比=1:2.两个三角形面积之比=1:6⑥,设△AEF 面积为1,则△ ABG 面积为6.整个平行四边形面积为6×4=24⑦;
四边形BEFG的面积为△ ABG 与△ AEF 的面积之差，即6-1=5。
综上，四边形 BEFG 和平行四边形ABCD面积之比=5:24,答案为D选项。
⑥

⑥花生批注：
底边之比为1:3,高之比为1:2,所以面积之比为 1:6

⑦花生批注：
平行四边形对角线分成的四个三角形面积相等。','数量关系600题','进阶','published','{"globalNumber":409,"sourceNumber":9,"typeLabel":"几何问题","stemRich":[{"text":"平行四边形ABCD如下图所示，E为AB上的一点，F、G分别为\n\nAC与 DE、 DB的交点。若AB=3AE,则四边形BEFG与ABCD的面积\n之比是多少?\n\n\n\n\n\n\n\n\n综上，四边形"}],"annotatedStemRich":[{"text":"平行四边形ABCD如下图所示，E为AB上的一点，F、G分别为\n\nAC与 DE、 DB的交点。若AB=3AE,则四边形BEFG与ABCD的面积\n之比是多少?\n\n\n\n\n\n\n\n\n综上，四边形"}],"annotatedOptionRich":{"A":[{"text":"2:7"}],"B":[{"text":"3:13"}],"C":[{"text":"4:19","bold":true}],"D":[{"text":"5:24","bold":true},{"text":"\n"}]},"practicalAnalysis":"如下图所示，△AEF与△ CDF相似，AE:CD=AE: AB=1:3, 则 FH:Fl=1:3, 即FH:HI=1:4;\n△ ABG 在AB 边上的高与平行四边形的高之比=1:2,故△ AEF与△ ABG 高之比=1:2.两个三角形面积之比=1:6⑥,设△AEF 面积为1,则△ ABG 面积为6.整个平行四边形面积为6×4=24⑦;\n四边形BEFG的面积为△ ABG 与△ AEF 的面积之差，即6-1=5。\n综上，四边形 BEFG 和平行四边形ABCD面积之比=5:24,答案为D选项。\n⑥","notes":[{"marker":"⑥","text":"底边之比为1:3,高之比为1:2,所以面积之比为 1:6","matchScore":0.12},{"marker":"⑦","text":"平行四边形对角线分成的四个三角形面积相等。","matchScore":0.196}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
