INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500411,4,'和差倍比问题','某单位食堂后勤部门采购了一批大米，并将其平均分给了甲、乙
两个饭堂。 5周后，甲饭堂只剩余大米7千克；又过了1周，乙饭堂

也只剩余大米6千克， 已知甲、乙饭堂的就餐人数固定，前往甲饭

堂就餐的人数比乙饭堂多1人。如 果每人每周消耗大米1千克，则
这批大米共有多少千克?','[{"label":"A","content":"72"},{"label":"B","content":"84"},{"label":"C","content":"96"},{"label":"D","content":"108"}]','B','设去乙食堂吃饭的有x 人，则去甲食堂吃饭的有x+1 人，根据大米总量相等可列方程：5(x+1)+7=6x+6, 解得x=6; 则大米总量=2(6 x+6)=84 千克，答案为B选项。','数量关系600题','进阶','published','{"globalNumber":411,"sourceNumber":1,"typeLabel":"和差倍比问题","stemRich":[{"text":"某单位食堂后勤部门采购了一批大米，并将其平均分给了甲、乙\n两个饭堂。 5周后，甲饭堂只剩余大米7千克；又过了1周，乙饭堂\n\n也只剩余大米6千克， 已知甲、乙饭堂的就餐人数固定，前往甲饭\n\n堂就餐的人数比乙饭堂多1人。如 果每人每周消耗大米1千克，则\n这批大米共有多少千克?"}],"annotatedStemRich":[{"text":"某单位食堂后勤部门采购了一批大米，并将其平均分给了甲、乙\n两个饭堂。 5周后，甲饭堂只剩余大米7千克；又过了1周，乙饭堂\n\n也只剩余大米6千克， 已知甲、乙饭堂的就餐人数固定，前往甲饭\n\n堂就餐的人数比乙饭堂多1人。如 果每人每周消耗大米1千克，则\n这批大米共有多少千克?"}],"annotatedOptionRich":{"A":[{"text":"72"}],"B":[{"text":"84"}],"C":[{"text":"96"}],"D":[{"text":"108\n"}]},"practicalAnalysis":"设去乙食堂吃饭的有x 人，则去甲食堂吃饭的有x+1 人，根据大米总量相等可列方程：5(x+1)+7=6x+6, 解得x=6; 则大米总量=2(6 x+6)=84 千克，答案为B选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500412,4,'数的特性问题','某围棋队的两位选手小李与小张决定进行1次围棋比赛，两人轮

流先手开 局，第一局小李先手开局。甲、乙两人分别记录了全程比赛
，均显示共比赛18局， 结果为10:8。甲的记录显示为：小李胜10

局，小张胜8局，且先手者共胜8 局，但乙的记录显示为：先手者

共胜6局。问甲、乙两人的记录结果是?','[{"label":"A","content":"甲错乙对"},{"label":"B","content":"甲错乙错"},{"label":"C","content":"甲对乙错"},{"label":"D","content":"甲对乙对"}]','B','两人轮流先手开局，即两人均先手9局。设小李先手胜场为 x, 小张先手的胜场为y, 则小李先手负场为9-x 场(即小张后手胜场),小张先手负场为9-y 场(即小李后手胜场);
因二人记录结果均为10:8,则x+9-y=8 或10①,化简得x-y=1 或y-x=1, x 和y 的差为奇数，则x 、y 应为一奇一偶，二者之和(先手者胜场数)也应是奇数，甲记录的“先手者胜8局”、乙记录的“先手者胜6局”均为偶数，所以二人说法均错误②,答案为B 选项。
小李的先手胜场和后手胜场之和，即小李的总胜场应等于10或8场。
②

②花生批注：
二人记录的结果10:8和二人记录的先手者胜场数，奇偶性质矛盾，必然存在错误。','数量关系600题','进阶','published','{"globalNumber":412,"sourceNumber":2,"typeLabel":"数的特性问题","stemRich":[{"text":"某围棋队的两位选手小李与小张决定进行1次围棋比赛，两人轮\n\n流先手开 局，第一局小李先手开局。甲、乙两人分别记录了全程比赛\n，均显示共比赛18局， 结果为10:8。甲的记录显示为：小李胜10\n\n局，小张胜8局，且先手者共胜8 局，但乙的记录显示为：先手者\n\n共胜6局。问甲、乙两人的记录结果是?"}],"annotatedStemRich":[{"text":"某围棋队的两位选手小李与小张决定进行1次围棋比赛，两人轮\n\n流先手开 局，第一局小李先手开局。甲、乙两人分别记录了全程比赛\n，均显示共比赛18局， 结果为10:8。甲的记录显示为：小李胜10\n\n局，小张胜8局，且先手者共胜8 局，但乙的记录显示为：先手者\n\n共胜6局。问甲、乙两人的记录结果是?"}],"annotatedOptionRich":{"A":[{"text":"  甲错乙对"}],"B":[{"text":"  甲错乙错"}],"C":[{"text":"  甲对乙错"}],"D":[{"text":" 甲对乙对\n"}]},"practicalAnalysis":"两人轮流先手开局，即两人均先手9局。设小李先手胜场为 x, 小张先手的胜场为y, 则小李先手负场为9-x 场(即小张后手胜场),小张先手负场为9-y 场(即小李后手胜场);\n因二人记录结果均为10:8,则x+9-y=8 或10①,化简得x-y=1 或y-x=1, x 和y 的差为奇数，则x 、y 应为一奇一偶，二者之和(先手者胜场数)也应是奇数，甲记录的“先手者胜8局”、乙记录的“先手者胜6局”均为偶数，所以二人说法均错误②,答案为B 选项。\n小李的先手胜场和后手胜场之和，即小李的总胜场应等于10或8场。\n②","notes":[{"marker":"②","text":"二人记录的结果10:8和二人记录的先手者胜场数，奇偶性质矛盾，必然存在错误。","matchScore":0.136}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500413,4,'不定方程问题','“数艺杯”绘画比赛的决赛规则如下：由3位评委对11件作品进

行投票， 每位评委对每件作品可以投一票或者不投票；得3票的作
品为一等奖，得2票 的作品为二等奖，得1票的作品为三等奖，不

得票的作品为鼓励奖。已知三位 评委分别投出了6票、7票、8票，','[{"label":"A","content":"一等奖作品比三等奖作品多5件"},{"label":"B","content":"一等奖作品比二等奖作品多2件"},{"label":"C","content":"二等奖作品比一等奖作品多5件"},{"label":"D","content":"二等奖作品比三等奖作品多3件"}]','A','设获得一、二、三等奖的作品分别有x、y、z 件，根据题意可列方程：① x+y+z+3=11,②3x+2y+z=6+7+8, 通过②-①×2联立解得x-z=5, 故一等奖作品比三等奖作品多5件，答案为A 选项。','数量关系600题','进阶','published','{"globalNumber":413,"sourceNumber":3,"typeLabel":"不定方程问题","stemRich":[{"text":"“数艺杯”绘画比赛的决赛规则如下：由3位评委对11件作品进\n\n行投票， 每位评委对每件作品可以投一票或者不投票；得3票的作\n品为一等奖，得2票 的作品为二等奖，得1票的作品为三等奖，不\n\n得票的作品为鼓励奖。已知三位 评委分别投出了6票、7票、8票，"}],"annotatedStemRich":[{"text":"“数艺杯”绘画比赛的决赛规则如下：由3位评委对11件作品进\n\n行投票， 每位评委对每件作品可以投一票或者不投票；得3票的作\n品为一等奖，得2票 的作品为二等奖，得1票的作品为三等奖，不\n\n得票的作品为鼓励奖。已知三位 评委分别投出了6票、7票、8票，"}],"annotatedOptionRich":{"A":[{"text":" 一等奖作品比三等奖作品多5件"}],"B":[{"text":"  一等奖作品比二等奖作品多2件"}],"C":[{"text":"  二等奖作品比一等奖作品多5件"}],"D":[{"text":"  二等奖作品比三等奖作品多3件\n"}]},"practicalAnalysis":"设获得一、二、三等奖的作品分别有x、y、z 件，根据题意可列方程：① x+y+z+3=11,②3x+2y+z=6+7+8, 通过②-①×2联立解得x-z=5, 故一等奖作品比三等奖作品多5件，答案为A 选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500414,4,'和差倍比问题','港口仓库有4个不同重量的集装箱(均为整数吨),管理员将集
装箱重量 两两求和，并将得到的6个数都登记在册，后因保管不当

，数据中的最大值被 污渍遮盖。已知其余5个数据分别是23吨、
27吨、 30吨、31吨、34吨，则4 个集装箱中最重的为多少吨?','[{"label":"A","content":"17"},{"label":"B","content":"18"},{"label":"C","content":"21"},{"label":"D","content":"23"}]','C','设4个集装箱重量由大到小依次为a 、b 、c 、d, 根据题意可知①c+d=23,②b+d=27,③a+c=34,④a+d和b+c分别为30或31③;
依次代入选项验证
若a=23, 则c=11,d=12,b=15,第三大小于最小值，排除；
若a=21, 则c=13,d=10,b=17, 此时 a+d=31,b+c=30, 符合题意，答案为C选项④

③花生批注：
较小两数和为23;
最小和第二大和为27; 最大和第三大和为34;
最大和最小、次大和次小之和无法确定，分别对应30或 31。

④花生批注：
若a=17, 则c=17, 第一大和第三大相等，排除；
若a=18, 则 c=16,d=7,
b=20, 第二大超过了第一大，排除。','数量关系600题','进阶','published','{"globalNumber":414,"sourceNumber":4,"typeLabel":"和差倍比问题","stemRich":[{"text":"港口仓库有4个不同重量的集装箱(均为整数吨),管理员将集\n装箱重量 两两求和，并将得到的6个数都登记在册，后因保管不当\n\n，数据中的最大值被 污渍遮盖。已知其余5个数据分别是23吨、\n27吨、 30吨、31吨、34吨，则4 个集装箱中最重的为多少吨?"}],"annotatedStemRich":[{"text":"港口仓库有4个不同重量的集装箱(均为整数吨),管理员将集\n装箱重量 两两求和，并将得到的6个数都登记在册，后因保管不当\n\n，数据中的最大值被 污渍遮盖。已知其余5个数据分别是23吨、\n27吨、 30吨、31吨、34吨，则4 个集装箱中最重的为多少吨?"}],"annotatedOptionRich":{"A":[{"text":"17"}],"B":[{"text":"18"}],"C":[{"text":"21","bold":true}],"D":[{"text":"23","bold":true},{"text":"\n"}]},"practicalAnalysis":"设4个集装箱重量由大到小依次为a 、b 、c 、d, 根据题意可知①c+d=23,②b+d=27,③a+c=34,④a+d和b+c分别为30或31③;\n依次代入选项验证\n若a=23, 则c=11,d=12,b=15,第三大小于最小值，排除；\n若a=21, 则c=13,d=10,b=17, 此时 a+d=31,b+c=30, 符合题意，答案为C选项④","notes":[{"marker":"③","text":"较小两数和为23;\n最小和第二大和为27; 最大和第三大和为34;\n最大和最小、次大和次小之和无法确定，分别对应30或 31。","matchScore":0.118},{"marker":"④","text":"若a=17, 则c=17, 第一大和第三大相等，排除；\n若a=18, 则 c=16,d=7,\nb=20, 第二大超过了第一大，排除。","matchScore":0.081}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500415,4,'工程问题+统筹规划问题','若a=18, 则 c=16,d=7,
b=20, 第二大超过了第一
将 A、B两个工程交给甲、乙两个工程队实施，已知A工程甲、乙合作需
大，排除。
14小时完成，甲单独需18小时完成；B工程甲、乙合作需18小时完成，乙单
独需30小时完成。问如两个工程队同时开始工作且在完成所有工程之前中途
不休息，则完成时间最长和最短的实施方案，完成时间相差?','[{"label":"A","content":"不到10小时"},{"label":"B","content":"10～ 15 小时之间"},{"label":"C","content":"15～ 20 小时之间"},{"label":"D","content":"超过20小时"}]','D','已知条件为时间，可设最小公倍数126为 A工程工作总量，甲做A 工程效率为7,乙做A 工程效率为2;同理，可设最小公倍数90为B 工程工作总量，乙做B 工程效率为3,甲做B 工程效率为2;
由各自效率可知，甲较擅长做A 工程，乙较擅长做B 工程；
要完成时间最长，则甲做B 工程，乙做 A工程，甲工作90÷2=45小时后完成B 工程，此时乙做完45×2=90份A工程，二人合作完成A 工程剩余部分还需(126-90)÷(7+2)=4小时，即完工时间最长为45+4=49小时；
要完成时间最短，则甲做A 工程，乙做B 工程，甲工作126÷7=18小时后完成A 工程，此时乙做完18×3=54份B 工程，二人合作完成B 工程剩余部分还需(90-54)÷(3+2)=7.2小时，即完工时间最短为18+7.2=25.2小时；
综上，二者相差49-25.2=23.8小时，答案为D选项。
