INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500420,4,'概率问题之比赛类概率','甲和乙进行5局3胜的乒乓球比赛，甲每局获胜的概率是乙每局获胜概率
的1.5倍。问以下哪种情况发生的概率最大?','[{"label":"A","content":"比赛在3局内结束"},{"label":"B","content":"乙连胜3局获胜"},{"label":"C","content":"甲获胜且两人均无连胜"},{"label":"D","content":"乙用4局获胜"}]','A','根据“甲每局获胜概率是乙的1.5倍”可知，甲、乙的获胜概率分别为60%、40%⑩:
四个选项发生的概率依次如下：
A选项，比赛在3局内结束有甲全胜和乙全胜两种情况：甲全胜概率=0.6×0.6×0.6=0.216,乙全胜概率 = 0 . 4 × 0 . 4 × 0 . 4 = 0 . 0 6 4 , 总概率 =0.216+0.064=0.28;
B选项，乙连胜3局获胜共有三种情况：①乙前3局全胜概率=0.4×0.4× 0.4=0.064 ; ② 第 1 局负①,第2到第4局胜=0.6×0. 4×0. 4×0. 4=0.0384; ③前两局负，后三局胜=0.6×0.6×0.4×0.4×0.4=0.02304;总概率=0.064+ 0.0384+0.02304=0.12544;
C 选项，甲获胜且两人均无连胜只有1种情况，即甲第1、3、5局获胜，概率=0.6×0.4×0.6×0.4×0.6=0.03456;
D选项，乙用4局获胜，则第四局乙必须胜，前三局甲获胜1次，概率 =C³×0.6×0.4×0.4×0.4=0.1152;
综上，A选项发生概率最大，当选。

⑩花生批注：
二人获胜概率之和为100%。','数量关系600题','进阶','published','{"globalNumber":420,"sourceNumber":10,"typeLabel":"概率问题之比赛类概率","stemRich":[{"text":"甲和乙进行5局3胜的乒乓球比赛，甲每局获胜的概率是乙每局获胜概率\n的1.5倍。问以下哪种情况发生的概率最大?"}],"annotatedStemRich":[{"text":"甲和乙进行5局3胜的乒乓球比赛，甲每局获胜的概率是乙每局获胜概率\n的1.5倍。问以下哪种情况发生的概率最大?"}],"annotatedOptionRich":{"A":[{"text":"  比赛在3局内结束","bold":true}],"B":[{"text":"   乙连胜3局获胜"}],"C":[{"text":"  甲获胜且两人均无连胜"}],"D":[{"text":"  乙用4局获胜\n"}]},"practicalAnalysis":"根据“甲每局获胜概率是乙的1.5倍”可知，甲、乙的获胜概率分别为60%、40%⑩:\n四个选项发生的概率依次如下：\nA选项，比赛在3局内结束有甲全胜和乙全胜两种情况：甲全胜概率=0.6×0.6×0.6=0.216,乙全胜概率 = 0 . 4 × 0 . 4 × 0 . 4 = 0 . 0 6 4 , 总概率 =0.216+0.064=0.28;\nB选项，乙连胜3局获胜共有三种情况：①乙前3局全胜概率=0.4×0.4× 0.4=0.064 ; ② 第 1 局负①,第2到第4局胜=0.6×0. 4×0. 4×0. 4=0.0384; ③前两局负，后三局胜=0.6×0.6×0.4×0.4×0.4=0.02304;总概率=0.064+ 0.0384+0.02304=0.12544;\nC 选项，甲获胜且两人均无连胜只有1种情况，即甲第1、3、5局获胜，概率=0.6×0.4×0.6×0.4×0.6=0.03456;\nD选项，乙用4局获胜，则第四局乙必须胜，前三局甲获胜1次，概率 =C³×0.6×0.4×0.4×0.4=0.1152;\n综上，A选项发生概率最大，当选。","notes":[{"marker":"⑩","text":"二人获胜概率之和为100%。","matchScore":0.037}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
