INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500422,4,'牛吃草问题','由于连日暴雨，某水库水位急剧上升，逼近警戒水位。假设每天降雨量一致，若打开2个水闸放水，则3天后正好到达警戒水位；若打开3个水闸放水，则4天后正好到达警戒水位。气象台预报，大雨还将连续七天，流入水库的水量将比之前多20%。若不考虑水的蒸发，渗透和流失，则至少打开几个水闸，才能保证接下来的七天都不会到达警戒水位?','[{"label":"A","content":"5"},{"label":"B","content":"6"},{"label":"C","content":"7"},{"label":"D","content":"8"}]','B','此题为牛吃草问题的变型②,可代入公式：
第一步，可赋值每个水闸每天放水量为1,则根据两次降雨量差值求出每
日降雨量(即每日草生长量):
第二步，求出水库可容纳量(即原有草量):(6-2)×3=12③;
第三步，之后每日降雨量会增加20%,达到6×(1+20%)=7.2;设打开x 个水闸可保证接下来七天不会达到警戒水位，可列方程：(7.2-x)×7<12, 解得 x>5.5,x 向上取整为6,即至少要开6个水闸，答案为B 选项。

②花生批注：
本题不是“牛吃光了草”, 而是“草生长过快”,长满了“水库”。
每日降雨量，即每日草生长的量；
达到警戒水位，即草生长过快，长满了整个空间。

③花生批注：
每日降水量大于水闸排水量，即距离警戒水位还有 12份空间。','数量关系600题','进阶','published','{"globalNumber":422,"sourceNumber":2,"typeLabel":"牛吃草问题","stemRich":[{"text":"由于连日暴雨，某水库水位急剧上升，逼近警戒水位。假设每天降雨量一致，若打开2个水闸放水，则3天后正好到达警戒水位；若打开3个水闸放水，则4天后正好到达警戒水位。气象台预报，大雨还将连续七天，流入水库的水量将比之前多20%。若不考虑水的蒸发，渗透和流失，则至少打开几个水闸，才能保证接下来的七天都不会到达警戒水位?"}],"annotatedStemRich":[{"text":"由于连日暴雨，某水库水位急剧上升，逼近警戒水位。假设每天降雨量一致，若打开2个水闸放水，则3天后正好到达警戒水位；若打开3个水闸放水，则4天后正好到达警戒水位。气象台预报，大雨还将连续七天，流入水库的水量将比之前多20%。若不考虑水的蒸发，渗透和流失，则至少打开几个水闸，才能保证接下来的七天都不会到达警戒水位?"}],"annotatedOptionRich":{"A":[{"text":"5"}],"B":[{"text":"6"}],"C":[{"text":"7","bold":true}],"D":[{"text":"8","bold":true},{"text":"\n"}]},"practicalAnalysis":"此题为牛吃草问题的变型②,可代入公式：\n第一步，可赋值每个水闸每天放水量为1,则根据两次降雨量差值求出每\n日降雨量(即每日草生长量):\n第二步，求出水库可容纳量(即原有草量):(6-2)×3=12③;\n第三步，之后每日降雨量会增加20%,达到6×(1+20%)=7.2;设打开x 个水闸可保证接下来七天不会达到警戒水位，可列方程：(7.2-x)×7<12, 解得 x>5.5,x 向上取整为6,即至少要开6个水闸，答案为B 选项。","notes":[{"marker":"②","text":"本题不是“牛吃光了草”, 而是“草生长过快”,长满了“水库”。\n每日降雨量，即每日草生长的量；\n达到警戒水位，即草生长过快，长满了整个空间。","matchScore":0.296},{"marker":"③","text":"每日降水量大于水闸排水量，即距离警戒水位还有 12份空间。","matchScore":0.17}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500423,4,'工程问题','甲、乙、丙三个施工队负责修A、B两条工程量完全相同的公路，假如甲队、

乙队负责A公 路 ，丙 队 负 责B 公 路 ，则丙队要比甲队、乙队晚10天完成；如
果在上述条件下甲队分配 的工人或乙队分配 的工人去修B 公路，则两条

公 路同时竣工。如果甲队、乙队、丙队同时修A 公路，那么多少天可以完成?','[{"label":"A","content":"20"},{"label":"B","content":"21"},{"label":"C","content":"22"},{"label":"D","content":"23"}]','D','根据“甲分配的工人与乙分配的工人”结果相同可知，
可赋值甲有工人4x, 乙有工人 6x;
A、B 工程量相同，完工时间相同，说明调整后人数相同，可列式： 4x+6x-x= 丙 +x, 解得丙有工人8x;
设甲乙合作完成A 公路需要t 天，可列式： (4 x+6x)t=8x(t+10), 解得 t= 40, 即 A、B 工程量均为400x;
所以，三队合作修 A公路所需时间=400 x÷(4x+6x+8x)≈22.2 天，取整为23天，答案为D选项。','数量关系600题','进阶','published','{"globalNumber":423,"sourceNumber":3,"typeLabel":"工程问题","stemRich":[{"text":"甲、乙、丙三个施工队负责修A、B两条工程量完全相同的公路，假如甲队、\n\n乙队负责A公 路 ，丙 队 负 责B 公 路 ，则丙队要比甲队、乙队晚10天完成；如\n果在上述条件下甲队分配 的工人或乙队分配 的工人去修B 公路，则两条\n\n公 路同时竣工。如果甲队、乙队、丙队同时修A 公路，那么多少天可以完成?"}],"annotatedStemRich":[{"text":"甲、乙、丙三个施工队负责修A、B两条工程量完全相同的公路，假如甲队、\n\n乙队负责A公 路 ，丙 队 负 责B 公 路 ，则丙队要比甲队、乙队晚10天完成；如\n果在上述条件下甲队分配 的工人或乙队分配 的工人去修B 公路，则两条\n\n公 路同时竣工。如果甲队、乙队、丙队同时修A 公路，那么多少天可以完成?"}],"annotatedOptionRich":{"A":[{"text":"20"}],"B":[{"text":"21"}],"C":[{"text":"22"}],"D":[{"text":"23\n"}]},"practicalAnalysis":"根据“甲分配的工人与乙分配的工人”结果相同可知，\n可赋值甲有工人4x, 乙有工人 6x;\nA、B 工程量相同，完工时间相同，说明调整后人数相同，可列式： 4x+6x-x= 丙 +x, 解得丙有工人8x;\n设甲乙合作完成A 公路需要t 天，可列式： (4 x+6x)t=8x(t+10), 解得 t= 40, 即 A、B 工程量均为400x;\n所以，三队合作修 A公路所需时间=400 x÷(4x+6x+8x)≈22.2 天，取整为23天，答案为D选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500424,4,'行程问题','警校某班学生分两个小组在甲、乙两地间进行野外负重拉练。已

