INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500426,4,'数列问题','某水果种植特色镇创办水果加工厂，从去年年初开始通过电商平

台销售桃 汁、橙汁两种产品。从去年2月开始，每个月桃汁的销量都

比上个月多5000盒， 橙汁的销量都比上个月多2000盒。已知去年第
一季度桃汁的总销量比橙汁少 4.5万盒，则去年桃汁的销量比橙汁?','[{"label":"A","content":"少不到5万盒"},{"label":"B","content":"少5万盒以上"},{"label":"C","content":"多不到5万盒"},{"label":"D","content":"多5万盒以上"}]','A','设去年1月桃汁销量是x 万盒，橙汁销量是y 万盒，则去年
一季度销售桃汁x+x+0.5+x+1=3x+1.5, 销售橙汁y+y+0.2+y+0.4=3y+0.6; 根
据二者之差，可列式：3y+0.6-(3x+1.5)=4.5, 解得y-x=1.8;
即去年1月桃汁较橙汁少销售1.8万盒，之后每个月差距缩小0.3万盒，则去年12月桃汁与橙汁销售差值=-1.8+11×0.3=1.5万盒；
根据等差数列求和公式⑨,全年桃汁销量与橙汁销量的差
⑨

⑨花生批注：
所用公式为：
=6(- 1.8+1.5)=- 1.8万盒，即去年桃汁销量比橙汁少了1.8万盒，答案为 A 选项。','数量关系600题','进阶','published','{"globalNumber":426,"sourceNumber":6,"typeLabel":"数列问题","stemRich":[{"text":"某水果种植特色镇创办水果加工厂，从去年年初开始通过电商平\n\n台销售桃 汁、橙汁两种产品。从去年2月开始，每个月桃汁的销量都\n\n比上个月多5000盒， 橙汁的销量都比上个月多2000盒。已知去年第\n一季度桃汁的总销量比橙汁少 4.5万盒，则去年桃汁的销量比橙汁?"}],"annotatedStemRich":[{"text":"某水果种植特色镇创办水果加工厂，从去年年初开始通过电商平\n\n台销售桃 汁、橙汁两种产品。从去年2月开始，每个月桃汁的销量都\n\n比上个月多5000盒， 橙汁的销量都比上个月多2000盒。已知去年第\n一季度桃汁的总销量比橙汁少 4.5万盒，则去年桃汁的销量比橙汁?"}],"annotatedOptionRich":{"A":[{"text":" 少不到5万盒"}],"B":[{"text":" 少5万盒以上"}],"C":[{"text":" 多不到5万盒"}],"D":[{"text":" 多5万盒以上\n"}]},"practicalAnalysis":"设去年1月桃汁销量是x 万盒，橙汁销量是y 万盒，则去年\n一季度销售桃汁x+x+0.5+x+1=3x+1.5, 销售橙汁y+y+0.2+y+0.4=3y+0.6; 根\n据二者之差，可列式：3y+0.6-(3x+1.5)=4.5, 解得y-x=1.8;\n即去年1月桃汁较橙汁少销售1.8万盒，之后每个月差距缩小0.3万盒，则去年12月桃汁与橙汁销售差值=-1.8+11×0.3=1.5万盒；\n根据等差数列求和公式⑨,全年桃汁销量与橙汁销量的差\n⑨","notes":[{"marker":"⑨","text":"所用公式为：\n=6(- 1.8+1.5)=- 1.8万盒，即去年桃汁销量比橙汁少了1.8万盒，答案为 A 选项。","matchScore":0.172}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
