INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500428,4,'概率问题','甲、乙、丙三人未来3周均要去A、B、C三个地方调研，每人每个地方调研时长为1周。如每个人随机安排顺序，则每周三个人去的地方都不同的概率为?','[{"label":"A","content":"（图形选项，见题目原图）"},{"label":"B","content":"（图形选项，见题目原图）"},{"label":"C","content":"（图形选项，见题目原图）"},{"label":"D","content":"（图形选项，见题目原图）"}]','D','全部情况：甲、乙、丙每个人三周的调研方式都为 , 互相
不影响，总情况数为
4
4
符合要求的情况：第一周三个人随机选三个不同的地方，情况数为 A³=6, 第二周每个人去不同地方，且都不去自己上周去过的地方，即三个人错位排序②,情况数为2,第三周每个人都只去自己没去过的地方，情况数为1,因此符合要求的情况数一共有6×2×1=12种。
综上，所求概 ,答案为D 选项。
⑩

