INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500433,4,'行程问题之相遇追及问题','一个山丘的形状如下图所示。甲、乙两人同时从A点出发匀速

前往B 点， 到达B点后立刻返回。甲上坡速度为3米/秒，下坡速
度为5米/秒；乙上坡 速度为2米/秒，下坡速度为3米/秒。问两

人首次相遇时，距A点的路程为 多少米?','[{"label":"A","content":"108"},{"label":"B","content":"138"},{"label":"C","content":"150"},{"label":"D","content":"162"}]','B','甲的速度相对更快，先让甲到达 B 点，所需时间 =120÷3+60÷5=52秒，此时乙还未到达最高点；
此时可以让乙到达最高点，乙到达最高点需要120÷2=60秒，此时甲已经返回(60-52)×3=24米，二者相距60-24=36米④;
之后二者为相遇运动，甲乙路程比=速度比=3:3=1:1,即相遇在中点，距离最高点为18米，距离A 点距离=120+18=138米，答案为B选项。','数量关系600题','进阶','published','{"globalNumber":433,"sourceNumber":3,"typeLabel":"行程问题之相遇追及问题","stemRich":[{"text":"一个山丘的形状如下图所示。甲、乙两人同时从A点出发匀速\n\n前往B 点， 到达B点后立刻返回。甲上坡速度为3米/秒，下坡速\n度为5米/秒；乙上坡 速度为2米/秒，下坡速度为3米/秒。问两\n\n人首次相遇时，距A点的路程为 多少米?"}],"annotatedStemRich":[{"text":"一个山丘的形状如下图所示。甲、乙两人同时从A点出发匀速\n\n前往B 点， 到达B点后立刻返回。甲上坡速度为3米/秒，下坡速\n度为5米/秒；乙上坡 速度为2米/秒，下坡速度为3米/秒。问两\n\n人首次相遇时，距A点的路程为 多少米?"}],"annotatedOptionRich":{"A":[{"text":"108"}],"B":[{"text":"138"}],"C":[{"text":"150"}],"D":[{"text":"162\n"}]},"practicalAnalysis":"甲的速度相对更快，先让甲到达 B 点，所需时间 =120÷3+60÷5=52秒，此时乙还未到达最高点；\n此时可以让乙到达最高点，乙到达最高点需要120÷2=60秒，此时甲已经返回(60-52)×3=24米，二者相距60-24=36米④;\n之后二者为相遇运动，甲乙路程比=速度比=3:3=1:1,即相遇在中点，距离最高点为18米，距离A 点距离=120+18=138米，答案为B选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500434,4,'数的特性问题','甲、乙、丙三人去超市买了100元的商品，如果甲付钱，那么甲剩下的钱是乙、丙两人钱数之和的 ;如果乙付钱，则乙剩下的钱是甲、丙两人钱数之和的 ;如果丙付钱，丙用他的会员卡可享受9折优惠，结果丙剩下的钱是甲、乙两人钱数之和的 · 那么,甲、乙、丙三人开始时一共带了多少钱?
IHAG ◎公NGK0','[{"label":"A","content":"850 元"},{"label":"B","content":"900 元"},{"label":"C","content":"950 元"},{"label":"D","content":"1000 元"}]','A','根据题意可知，甲付了100元后，甲剩下的钱数是乙丙之和的可设乙丙是13份，则甲为2份，此时剩余钱数应是15的倍数；同理，乙付了100元后，剩余钱数也应是25的倍数⑤ ;
若享受9折优惠的丙付款，付款90元后，剩余钱数应是4的倍数⑥ ;
观察选项， A 选项、D 选项减去100是15和25的倍数，排除B 、C选项； D选项减去90后，并非4的倍数，排除；
综上，只有A 选项满足倍数要求，当选⑦。
⑤

⑤花生批注：
可设甲丙是16份，乙为9 份，此时剩余钱数是25份。

⑥花生批注：
可设甲乙是3份，丙为1份，此时剩余钱数是4份。

⑦花生批注：
题干中仅给出甲、乙、丙间的比例关系，可以优先采用数的特性快速解题，列三元一次方程组的方法计算量过大。','数量关系600题','进阶','published','{"globalNumber":434,"sourceNumber":4,"typeLabel":"数的特性问题","stemRich":[{"text":"甲、乙、丙三人去超市买了100元的商品，如果甲付钱，那么甲剩下的钱是乙、丙两人钱数之和的 ;如果乙付钱，则乙剩下的钱是甲、丙两人钱数之和的 ;如果丙付钱，丙用他的会员卡可享受9折优惠，结果丙剩下的钱是甲、乙两人钱数之和的 · 那么,甲、乙、丙三人开始时一共带了多少钱?\nIHAG ◎公NGK0"}],"annotatedStemRich":[{"text":"甲、乙、丙三人去超市买了100元的商品，如果甲付钱，那么甲剩下的钱是乙、丙两人钱数之和的 ;如果乙付钱，则乙剩下的钱是甲、丙两人钱数之和的 ;如果丙付钱，丙用他的会员卡可享受9折优惠，结果丙剩下的钱是甲、乙两人钱数之和的 · 那么,甲、乙、丙三人开始时一共带了多少钱?\nIHAG ◎公NGK0"}],"annotatedOptionRich":{"A":[{"text":"850   元","bold":true}],"B":[{"text":"900   元","bold":true}],"C":[{"text":"950  元"}],"D":[{"text":"1000    元\n"}]},"practicalAnalysis":"根据题意可知，甲付了100元后，甲剩下的钱数是乙丙之和的可设乙丙是13份，则甲为2份，此时剩余钱数应是15的倍数；同理，乙付了100元后，剩余钱数也应是25的倍数⑤ ;\n若享受9折优惠的丙付款，付款90元后，剩余钱数应是4的倍数⑥ ;\n观察选项， A 选项、D 选项减去100是15和25的倍数，排除B 、C选项； D选项减去90后，并非4的倍数，排除；\n综上，只有A 选项满足倍数要求，当选⑦。\n⑤","notes":[{"marker":"⑤","text":"可设甲丙是16份，乙为9 份，此时剩余钱数是25份。","matchScore":0.134},{"marker":"⑥","text":"可设甲乙是3份，丙为1份，此时剩余钱数是4份。","matchScore":0.114},{"marker":"⑦","text":"题干中仅给出甲、乙、丙间的比例关系，可以优先采用数的特性快速解题，列三元一次方程组的方法计算量过大。","matchScore":0.021}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500435,4,'和差倍比问题','某班举行数学测验，试题全部是选择题，共10题，每题1分，得分的部
分统计结果如下：
得分 10 9 8 2 1 0
……
人数 2 2 4 …… 5 3 8
已 知 ，得分至少为3分的，人均2x 分；得分最多为7分的，人均x 分 。
这个班级总人数是?','[{"label":"A","content":"（图形选项，见题目原图）"},{"label":"B","content":"57x+24"},{"label":"C","content":"x²+4"},{"label":"D","content":"x+4"}]','A','⑧设总人数为y, 则至少3分的人数=y-5-3-8=y-16, 得分最
多7分的人数=y-2-2-4=y-8;
根据上表可知，3分以下的总得分为2×5+1×3=13,7分以上的总得分为
10×2+9×2+8×4=70;
根据总分可列方程： (y- 16)×2x+13=(y-8)×x+70, 答案为A 选项。
解得
⑧

⑧花生批注：
考场秒杀：
题干给出
的平均分为2x 和x, x 应在分母上，只有A选项符合。','数量关系600题','进阶','published','{"globalNumber":435,"sourceNumber":5,"typeLabel":"和差倍比问题","stemRich":[{"text":"某班举行数学测验，试题全部是选择题，共10题，每题1分，得分的部\n分统计结果如下：\n得分 10 9 8 2 1 0\n……\n人数 2 2 4 …… 5 3 8\n已 知 ，得分至少为3分的，人均2x 分；得分最多为7分的，人均x 分 。\n这个班级总人数是?"}],"annotatedStemRich":[{"text":"某班举行数学测验，试题全部是选择题，共10题，每题1分，得分的部\n分统计结果如下：\n得分 10 9 8 2 1 0\n……\n人数 2 2 4 …… 5 3 8\n已 知 ，得分至少为3分的，人均2x 分；得分最多为7分的，人均x 分 。\n这个班级总人数是?"}],"annotatedOptionRich":{"A":[{"text":"（图形选项，见题目原图）"}],"B":[{"text":"57x+24"}],"C":[{"text":"x²+4","bold":true}],"D":[{"text":"  x+4","bold":true},{"text":"\n"}]},"practicalAnalysis":"⑧设总人数为y, 则至少3分的人数=y-5-3-8=y-16, 得分最\n多7分的人数=y-2-2-4=y-8;\n根据上表可知，3分以下的总得分为2×5+1×3=13,7分以上的总得分为\n10×2+9×2+8×4=70;\n根据总分可列方程： (y- 16)×2x+13=(y-8)×x+70, 答案为A 选项。\n解得\n⑧","notes":[{"marker":"⑧","text":"考场秒杀：\n题干给出\n的平均分为2x 和x, x 应在分母上，只有A选项符合。","matchScore":0.056}],"missingOptionLabels":["A"],"pairingMode":"word-type-anchor-and-number","imageKeys":["numeric/20260717/quantity/500435.png"],"imageSourcePage":345}','numeric/20260717/quantity/500435.png');
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500436,4,'最值问题之和定最值','100名学生参加百分制考试，所有学生的成绩都是整数，且平均

分为86.2 分。已知有70%的学生成绩不低于70分。问最多有多少学生

的成绩在70～75分?','[{"label":"A","content":"不到25人"},{"label":"B","content":"25～28 人"},{"label":"C","content":"29～32 人"},{"label":"D","content":"超过32人"}]','A','已知100名学生平均分为86.2分，则总分为8620分；70名学生分数≥70分，因为成绩都是整数，剩下30名学生分数≤69分。
70～75分低于平均分，要使70～75分的学生最多，则70～75分内的学生分数、低于70分的学生分数、高于75分的学生分数都应尽量高⑨,分别取75、69、100分；
令75分的学生有x 人，则高于75分的学生人数为70-x, 可列方程： 69×30+75x+100(70-x)=8620, 解得 x=18人，在A 选项范围内，当选。

⑨花生批注：
使用盐水思想，要使低于平均分的人数最多，则低于平均分的单个分数应和平均分的差距尽量小(距离短，人数多),即分数尽量高(或者75分、或者 69分);高于平均分的单个分数和平均分的差距尽量大(距离远，人数少), 分数尽量高(均为100分)。','数量关系600题','进阶','published','{"globalNumber":436,"sourceNumber":6,"typeLabel":"最值问题之和定最值","stemRich":[{"text":"100名学生参加百分制考试，所有学生的成绩都是整数，且平均\n\n分为86.2 分。已知有70%的学生成绩不低于70分。问最多有多少学生\n\n的成绩在70～75分?"}],"annotatedStemRich":[{"text":"100名学生参加百分制考试，所有学生的成绩都是整数，且平均\n\n分为86.2 分。已知有70%的学生成绩不低于70分。问最多有多少学生\n\n的成绩在70～75分?"}],"annotatedOptionRich":{"A":[{"text":" 不到25人"}],"B":[{"text":"25～28    人"}],"C":[{"text":"29～32  人"}],"D":[{"text":"  超过32人\n"}]},"practicalAnalysis":"已知100名学生平均分为86.2分，则总分为8620分；70名学生分数≥70分，因为成绩都是整数，剩下30名学生分数≤69分。\n70～75分低于平均分，要使70～75分的学生最多，则70～75分内的学生分数、低于70分的学生分数、高于75分的学生分数都应尽量高⑨,分别取75、69、100分；\n令75分的学生有x 人，则高于75分的学生人数为70-x, 可列方程： 69×30+75x+100(70-x)=8620, 解得 x=18人，在A 选项范围内，当选。","notes":[{"marker":"⑨","text":"使用盐水思想，要使低于平均分的人数最多，则低于平均分的单个分数应和平均分的差距尽量小(距离短，人数多),即分数尽量高(或者75分、或者 69分);高于平均分的单个分数和平均分的差距尽量大(距离远，人数少), 分数尽量高(均为100分)。","matchScore":0.2}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
