INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500438,4,'经济利润问题','张某早晨批发了1500元的苹果和葡萄，苹果每斤3 . 25元，葡萄每斤2 . 5元。到了下午全部售完后发现，苹果平均每斤盈利10%,而葡萄损耗严重，平均每斤亏损15%。两种水果共获利100元。问张某早晨批发了多少斤苹果?','[{"label":"A","content":"200"},{"label":"B","content":"80"},{"label":"C","content":"300"},{"label":"D","content":"400"}]','D','根据公式：利润 = 成本 × 利润率，苹果平均每斤盈利 =3 .25×10%=0 .325元；
已知共获利100元，即使不考虑葡萄的亏损，想获利100元，苹果也需要批发100÷0.325>300斤，只能选择D 选项②。
方程法：

⑫花生批注：
