INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500444,4,'行程问题之相遇追及问题','甲、乙两人分别从A 、B两地出发相向而行。甲每分钟走52米，乙每分钟

走70米，两人在途中的C 处 相 遇 。若甲提前4分钟出发，且速度不变，乙每
分钟走90米，则两人仍在C 处相遇。则A 、B 两地相距多少米?','[{"label":"A","content":"1960 米"},{"label":"B","content":"2196 米"},{"label":"C","content":"2884 米"},{"label":"D","content":"3200 米"}]','B','两次相遇点相同，且甲的速度不变，则甲的时间不变；第二次相遇而行甲提前4分钟出发，意味着乙晚出发4分钟，即用时少了4分钟 ⑥:
设第一次用时为t, 则70t=90(t-4)⑦,解得t=18; 则AB=18×(52+70)=2196 米⑤,答案为B选项。

⑤花生批注：
所以，丙中奖且乙不答案为D 选项。

⑥花生批注：
第二次甲的用时和第一次一样，乙晚出发4分钟，即乙第二次用时比第一次用时少了4分钟(第二次乙的速度提高，所以用时减少)。

⑦花生批注：
相遇点不变，乙两次行走的路程相等。','数量关系600题','进阶','published','{"globalNumber":444,"sourceNumber":4,"typeLabel":"行程问题之相遇追及问题","stemRich":[{"text":"甲、乙两人分别从A 、B两地出发相向而行。甲每分钟走52米，乙每分钟\n\n走70米，两人在途中的C 处 相 遇 。若甲提前4分钟出发，且速度不变，乙每\n分钟走90米，则两人仍在C 处相遇。则A 、B 两地相距多少米?"}],"annotatedStemRich":[{"text":"甲、乙两人分别从A 、B两地出发相向而行。甲每分钟走52米，乙每分钟\n\n走70米，两人在途中的C 处 相 遇 。若甲提前4分钟出发，且速度不变，乙每\n分钟走90米，则两人仍在C 处相遇。则A 、B 两地相距多少米?"}],"annotatedOptionRich":{"A":[{"text":"1960    米"}],"B":[{"text":"2196     米"}],"C":[{"text":"2884    米"}],"D":[{"text":"3200     米\n"}]},"practicalAnalysis":"两次相遇点相同，且甲的速度不变，则甲的时间不变；第二次相遇而行甲提前4分钟出发，意味着乙晚出发4分钟，即用时少了4分钟 ⑥:\n设第一次用时为t, 则70t=90(t-4)⑦,解得t=18; 则AB=18×(52+70)=2196 米⑤,答案为B选项。","notes":[{"marker":"⑤","text":"所以，丙中奖且乙不答案为D 选项。","matchScore":0.071},{"marker":"⑥","text":"第二次甲的用时和第一次一样，乙晚出发4分钟，即乙第二次用时比第一次用时少了4分钟(第二次乙的速度提高，所以用时减少)。","matchScore":0.257},{"marker":"⑦","text":"相遇点不变，乙两次行走的路程相等。","matchScore":0.104}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
