INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500446,4,'几何问题之几何计算','如图所示，小王买了一块直三棱柱形状的蛋糕ABC-A''B''c'', 其中 ∠ABC=90°,∠BAC =30°。为与两位室友分享，他切出一小块和原蛋糕形状相同的蛋糕ADE-A''D''E'', 其体积与原蛋糕的体积之比为1:3。若∠ADE =90°, 则线段AE 与BE的长度之比为多少?','[{"label":"A","content":"2:1"},{"label":"B","content":"3:2"},{"label":"C","content":"√3:1"},{"label":"D","content":"2:√3\n⑦"}]','A','切下的小蛋糕与原蛋糕高度相同，底面积与体积成正比，即
△ ADE 与△ ABC面积之比为1:3。根据等比放缩性质可知，二者边长之比为 1:√3,AE:AC=1:√3;
