INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500449,4,'最值问题之和定最值','某次考试有20道选择题和20道判断题，每题答对得3分，答错
得0分， 不答得1分。考生小王成绩为82分，且他选择题的答错数

比答对数多，问他 判断题至少答对了多少道?','[{"label":"A","content":"17"},{"label":"B","content":"18"},{"label":"C","content":"15"},{"label":"D","content":"16"}]','A','要想判断题答对的尽量少，则需要选择题得分尽量多，即选择题答对的尽量多；
因为选择题答错数比答对数多，可设答对9题⑩、答错10题，剩余1题为不答，则选择题得分为9×3+1=28分；
判断题需得到82-28=54分，要想答对数尽量少，则其他题目得分尽量多，都为“不答”。设判断题最少答对 x 题，可列式：3x+20-x=54, 解得x=17, 答案为A 选项。
⑯

⑯花生批注：
答对题数最多为 9 ,否则
答错数无法大于答对数；
答错数为10就大于答对数，剩余1题设为不答，这样得分会更多。','数量关系600题','进阶','published','{"globalNumber":449,"sourceNumber":9,"typeLabel":"最值问题之和定最值","stemRich":[{"text":"某次考试有20道选择题和20道判断题，每题答对得3分，答错\n得0分， 不答得1分。考生小王成绩为82分，且他选择题的答错数\n\n比答对数多，问他 判断题至少答对了多少道?"}],"annotatedStemRich":[{"text":"某次考试有20道选择题和20道判断题，每题答对得3分，答错\n得0分， 不答得1分。考生小王成绩为82分，且他选择题的答错数\n\n比答对数多，问他 判断题至少答对了多少道?"}],"annotatedOptionRich":{"A":[{"text":"17"}],"B":[{"text":"18"}],"C":[{"text":"15"}],"D":[{"text":"16\n"}]},"practicalAnalysis":"要想判断题答对的尽量少，则需要选择题得分尽量多，即选择题答对的尽量多；\n因为选择题答错数比答对数多，可设答对9题⑩、答错10题，剩余1题为不答，则选择题得分为9×3+1=28分；\n判断题需得到82-28=54分，要想答对数尽量少，则其他题目得分尽量多，都为“不答”。设判断题最少答对 x 题，可列式：3x+20-x=54, 解得x=17, 答案为A 选项。\n⑯","notes":[{"marker":"⑯","text":"答对题数最多为 9 ,否则\n答错数无法大于答对数；\n答错数为10就大于答对数，剩余1题设为不答，这样得分会更多。","matchScore":0.133}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500450,4,'工程问题','网格员小刘计划开展辖区居民信息核对工作已知要核对的居民信
息总数一 定，如果小刘每天核对30条，则最后一天余20条；如果

每天核对40条，则 最后一天余30条，且后一种计划比前一种可以

提前一周完成核对，若小刘每 天核对50条，则多少天完成核对?','[{"label":"A","content":"15"},{"label":"B","content":"16"},{"label":"C","content":"17"},{"label":"D","content":"18"}]','C','①假设按照第一种方式最后一天也核对30条，按照第二种方式最后一天也核对40条 .此时两种核对方式核对总信息数依然相等⑮:此时两
第二种需t-7 天；
种核对方式，每天效率比为30:40=3:4,时间比为4:3,则一份时间=7天；
则 30t-10=40(t-7)-10, 解得t=28。
即按照第一种核对方式需要4×7=28天，信息总数=28×30-10=830条⑨: 若每天核对50条，需要830÷50=16.6天，即需要17天完成，答案为C选项。
⑱

⑱花生批注：
此时总信息数相等，每天效率相等，则效率比和时间比成反比。','数量关系600题','进阶','published','{"globalNumber":450,"sourceNumber":10,"typeLabel":"工程问题","stemRich":[{"text":"网格员小刘计划开展辖区居民信息核对工作已知要核对的居民信\n息总数一 定，如果小刘每天核对30条，则最后一天余20条；如果\n\n每天核对40条，则 最后一天余30条，且后一种计划比前一种可以\n\n提前一周完成核对，若小刘每 天核对50条，则多少天完成核对?"}],"annotatedStemRich":[{"text":"网格员小刘计划开展辖区居民信息核对工作已知要核对的居民信\n息总数一 定，如果小刘每天核对30条，则最后一天余20条；如果\n\n每天核对40条，则 最后一天余30条，且后一种计划比前一种可以\n\n提前一周完成核对，若小刘每 天核对50条，则多少天完成核对?"}],"annotatedOptionRich":{"A":[{"text":"15"}],"B":[{"text":"16"}],"C":[{"text":"17"}],"D":[{"text":"18\n"}]},"practicalAnalysis":"①假设按照第一种方式最后一天也核对30条，按照第二种方式最后一天也核对40条 .此时两种核对方式核对总信息数依然相等⑮:此时两\n第二种需t-7 天；\n种核对方式，每天效率比为30:40=3:4,时间比为4:3,则一份时间=7天；\n则 30t-10=40(t-7)-10, 解得t=28。\n即按照第一种核对方式需要4×7=28天，信息总数=28×30-10=830条⑨: 若每天核对50条，需要830÷50=16.6天，即需要17天完成，答案为C选项。\n⑱","notes":[{"marker":"⑱","text":"此时总信息数相等，每天效率相等，则效率比和时间比成反比。","matchScore":0.143}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500451,4,'和差倍比问题','甲、乙两个单位人数相同，甲单位的党员占总人数的20%,乙单

位的党员 占总人数的25%。如果乙单位20名党员与甲单位20名群
众互换单位，则两个 单位党员占比相同。问两个单位共有党员多

少人?','[{"label":"A","content":"256"},{"label":"B","content":"288"},{"label":"C","content":"324"},{"label":"D","content":"360"}]','D','人员调整后，两个单位总人数依然相同，党员占比也相同，即党员人数相同；
设甲乙单位原来各有x 人，可根据党员人数相等列方程：0.2x+20=0.25x-20, 解得x=800, 共有党员800×0.2+800×0.25=360人，答案为D 选项。','数量关系600题','进阶','published','{"globalNumber":451,"sourceNumber":1,"typeLabel":"和差倍比问题","stemRich":[{"text":"甲、乙两个单位人数相同，甲单位的党员占总人数的20%,乙单\n\n位的党员 占总人数的25%。如果乙单位20名党员与甲单位20名群\n众互换单位，则两个 单位党员占比相同。问两个单位共有党员多\n\n少人?"}],"annotatedStemRich":[{"text":"甲、乙两个单位人数相同，甲单位的党员占总人数的20%,乙单\n\n位的党员 占总人数的25%。如果乙单位20名党员与甲单位20名群\n众互换单位，则两个 单位党员占比相同。问两个单位共有党员多\n\n少人?"}],"annotatedOptionRich":{"A":[{"text":"256"}],"B":[{"text":"288"}],"C":[{"text":"324"}],"D":[{"text":"360\n"}]},"practicalAnalysis":"人员调整后，两个单位总人数依然相同，党员占比也相同，即党员人数相同；\n设甲乙单位原来各有x 人，可根据党员人数相等列方程：0.2x+20=0.25x-20, 解得x=800, 共有党员800×0.2+800×0.25=360人，答案为D 选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500452,4,'数字特性问题+最值问题','某镇卫生院50多名医生被平均分配到13个基层诊所参与工作，

其中男医 生比女医生多4人。工作结束后，25%的男医生和一部分
女医生继续到邻镇4 个医疗点支援工作，这批人员中任意6人必有

男医生，且保证必有一个医疗点 的女医生多于1人。那么该卫生院

到邻镇支援工作的医生共有多少人?','[{"label":"A","content":"12 人"},{"label":"B","content":"1 4人"},{"label":"C","content":"16 人"},{"label":"D","content":"18 人"}]','A','能平均分配到13个基层诊所，只能是52名医生；男比女多 4人，则男医生28人，女医生24人① ;
根据“任意6人必有男医生”可知，女医生人数至多5人；根据“4个医疗点必有一个医疗点女医生多于1人”可知，女医生人数至少5人；
综上，去支援工作的女医生只能是5人，男医生有28×25%=7人，即一共 12人去临镇支援工作，答案为A 选项。','数量关系600题','进阶','published','{"globalNumber":452,"sourceNumber":2,"typeLabel":"数字特性问题+最值问题","stemRich":[{"text":"某镇卫生院50多名医生被平均分配到13个基层诊所参与工作，\n\n其中男医 生比女医生多4人。工作结束后，25%的男医生和一部分\n女医生继续到邻镇4 个医疗点支援工作，这批人员中任意6人必有\n\n男医生，且保证必有一个医疗点 的女医生多于1人。那么该卫生院\n\n到邻镇支援工作的医生共有多少人?"}],"annotatedStemRich":[{"text":"某镇卫生院50多名医生被平均分配到13个基层诊所参与工作，\n\n其中男医 生比女医生多4人。工作结束后，25%的男医生和一部分\n女医生继续到邻镇4 个医疗点支援工作，这批人员中任意6人必有\n\n男医生，且保证必有一个医疗点 的女医生多于1人。那么该卫生院\n\n到邻镇支援工作的医生共有多少人?"}],"annotatedOptionRich":{"A":[{"text":"  12 人"}],"B":[{"text":"1  4人"}],"C":[{"text":"  16 人"}],"D":[{"text":" 18 人\n"}]},"practicalAnalysis":"能平均分配到13个基层诊所，只能是52名医生；男比女多 4人，则男医生28人，女医生24人① ;\n根据“任意6人必有男医生”可知，女医生人数至多5人；根据“4个医疗点必有一个医疗点女医生多于1人”可知，女医生人数至少5人；\n综上，去支援工作的女医生只能是5人，男医生有28×25%=7人，即一共 12人去临镇支援工作，答案为A 选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500453,4,'几何问题+数列问题','如图，仓库有一堆管材，每一层的数量都比上一层多1根。搬运工人将管材逐根搬离，搬了99根后发现，管材堆少了3层，且剩余每层的管材数量都减少了3根。如果这堆管材刚好还剩10层，则剩下的管材共有多少根?','[{"label":"A","content":"245"},{"label":"B","content":"265"},{"label":"C","content":"305"},{"label":"D","content":"325"}]','B','根据“管材堆少了3层，剩余10层”可知，原来共有13层；
剩余的10层每层少3根，一共少了30根，则最上面3层共有99-30=69 根管材；
因为各层管材数成等差数列，则原来第2层有69÷3=23根②,即第1层22根，那么第13层有22+12=34根；
, 剩下管材数=364-99=265根，答案为B选项。','数量关系600题','进阶','published','{"globalNumber":453,"sourceNumber":3,"typeLabel":"几何问题+数列问题","stemRich":[{"text":"如图，仓库有一堆管材，每一层的数量都比上一层多1根。搬运工人将管 材逐根搬离，搬了99根后发现，管材堆少了3层，且剩余每层的管材数量都 减少了3根。如果这堆管材刚好还剩10层，则剩下的管材共有多少根?"}],"annotatedStemRich":[{"text":"如图，仓库有一堆管材，每一层的数量都比上一层多1根。搬运工人将管 材逐根搬离，搬了99根后发现，管材堆少了3层，且剩余每层的管材数量都 减少了3根。如果这堆管材刚好还剩10层，则剩下的管材共有多少根?"}],"annotatedOptionRich":{"A":[{"text":"245"}],"B":[{"text":"265"}],"C":[{"text":"305","bold":true}],"D":[{"text":"325","bold":true},{"text":"\n"}]},"practicalAnalysis":"根据“管材堆少了3层，剩余10层”可知，原来共有13层；\n剩余的10层每层少3根，一共少了30根，则最上面3层共有99-30=69 根管材；\n因为各层管材数成等差数列，则原来第2层有69÷3=23根②,即第1层22根，那么第13层有22+12=34根；\n, 剩下管材数=364-99=265根，答案为B选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500454,4,'排列组合问题','某自驾游车队由6辆车组成，车队的行车顺序有如下要求：甲车不能排在第一位，乙车必须排在最后一位，丙车必须排在前两位，且任一车辆均不得超车或并行。该车队的行车顺序共有多少种可能?','[{"label":"A","content":"36"},{"label":"B","content":"42"},{"label":"C","content":"48"},{"label":"D","content":"54"}]','B','根据题意可知，有“甲不能在第一位”、“丙必须在前两位”的特殊要求，可根据丙的位置分情况讨论：
①丙车排在第一位，乙车必须排在最后一位，剩下4辆车有顺序的排列：
A4 =24 种；
②丙车排第二位，甲不排第一位，乙车必须排在最后一位，先从其他3辆
车中选1辆排在第一位，剩余3辆车有顺序的排列：
*
*
综上，行车顺序共有24+18=42种可能，答案为B 选项。','数量关系600题','进阶','published','{"globalNumber":454,"sourceNumber":4,"typeLabel":"排列组合问题","stemRich":[{"text":"某自驾游车队由6辆车组成，车队的行车顺序有如下要求：甲车不能排在 第一位，乙车必须排在最后一位，丙车必须排在前两位，且任一车辆均不得超 车或并行。该车队的行车顺序共有多少种可能?"}],"annotatedStemRich":[{"text":"某自驾游车队由6辆车组成，车队的行车顺序有如下要求：甲车不能排在 第一位，乙车必须排在最后一位，丙车必须排在前两位，且任一车辆均不得超 车或并行。该车队的行车顺序共有多少种可能?"}],"annotatedOptionRich":{"A":[{"text":"36"}],"B":[{"text":"42"}],"C":[{"text":"48"}],"D":[{"text":"54\n"}]},"practicalAnalysis":"根据题意可知，有“甲不能在第一位”、“丙必须在前两位”的特殊要求，可根据丙的位置分情况讨论：\n①丙车排在第一位，乙车必须排在最后一位，剩下4辆车有顺序的排列：\nA4 =24 种；\n②丙车排第二位，甲不排第一位，乙车必须排在最后一位，先从其他3辆\n车中选1辆排在第一位，剩余3辆车有顺序的排列：\n*\n*\n综上，行车顺序共有24+18=42种可能，答案为B 选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500455,4,'周期循环问题+容斥问题','设备员吴工负责A,B,C 三个车间的设备巡查工作，A、B和 C车
间分别需 隔2、4天和7天巡检一次。3月1日，吴工巡检了三个车

间，则他在整个3月 有多少天不做车间的巡检工作?','[{"label":"A","content":"11"},{"label":"B","content":"12"},{"label":"C","content":"13"},{"label":"D","content":"14"}]','D','已知 A、B和 C 车间分别需隔2、4天和7天巡检一次，则巡查频率为每3、5天和8天一次。
3月1日吴工巡检三个车间，已知3月份有31天，剩下的30天中：
A 需要巡检30÷3=10次， B 需要巡检30÷5=6次， C需要巡检30÷8=3次；
A和 B同时需要巡检的次数为30÷15=2次， A和 C同时需要巡检的次数为 30÷24=1次， B 和 C同时需要巡检的次数为30÷40=0次；也没有A、B、C同时被巡检的情况。
则巡检的总天数=10+6+3-2-1=16天⑤,则休息30-16=14天，答案为D选项。
⑤

⑤花生批注：
同时巡检2个车间的日子被数了2次，需要减去1次。','数量关系600题','进阶','published','{"globalNumber":455,"sourceNumber":5,"typeLabel":"周期循环问题+容斥问题","stemRich":[{"text":"设备员吴工负责A,B,C 三个车间的设备巡查工作，A、B和 C车\n间分别需 隔2、4天和7天巡检一次。3月1日，吴工巡检了三个车\n\n间，则他在整个3月 有多少天不做车间的巡检工作?"}],"annotatedStemRich":[{"text":"设备员吴工负责A,B,C 三个车间的设备巡查工作，A、B和 C车\n间分别需 隔2、4天和7天巡检一次。3月1日，吴工巡检了三个车\n\n间，则他在整个3月 有多少天不做车间的巡检工作?"}],"annotatedOptionRich":{"A":[{"text":"11"}],"B":[{"text":"12"}],"C":[{"text":"13"}],"D":[{"text":"14\n"}]},"practicalAnalysis":"已知 A、B和 C 车间分别需隔2、4天和7天巡检一次，则巡查频率为每3、5天和8天一次。\n3月1日吴工巡检三个车间，已知3月份有31天，剩下的30天中：\nA 需要巡检30÷3=10次， B 需要巡检30÷5=6次， C需要巡检30÷8=3次；\nA和 B同时需要巡检的次数为30÷15=2次， A和 C同时需要巡检的次数为 30÷24=1次， B 和 C同时需要巡检的次数为30÷40=0次；也没有A、B、C同时被巡检的情况。\n则巡检的总天数=10+6+3-2-1=16天⑤,则休息30-16=14天，答案为D选项。\n⑤","notes":[{"marker":"⑤","text":"同时巡检2个车间的日子被数了2次，需要减去1次。","matchScore":0.127}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500456,4,'工程问题','文印中心要在34小时内完成一批资料的制作任务。复印机甲和乙共同印制， 10小时后复印机甲完成总任务的12%,复印机乙完成总任务的16%。复印机乙因入碳粉率较低，此后工作效率下降到原来的75%。为按时完成任务新配加一台复印机丙，那么复印机丙的效率至少应是复印机甲的多少倍?
数量关系60 0 四','[{"label":"A","content":"0.5"},{"label":"B","content":"0.6"},{"label":"C","content":"0.8"},{"label":"D","content":"1.2"}]','A','甲乙10小时完成工作之比为12%:16%=3:4,可设甲效率为3, 乙效率为4,则工作总量=3×10÷12%=250;
甲乙工作10小时后，剩余工作量=250-10×(3+4)=180;
之后乙效率变为4×75%=3,要想24小时完工，三人效率和=180÷24=7.5. 其中丙的效率=7.5-3-3=1.5,即丙效率是甲的1.5÷3=0.5倍，答案为A选项。','数量关系600题','进阶','published','{"globalNumber":456,"sourceNumber":6,"typeLabel":"工程问题","stemRich":[{"text":"文印中心要在34小时内完成一批资料的制作任务。复印机甲和乙共同印制， 10小时后复印机甲完成总任务的12%,复印机乙完成总任务的16%。复印机乙 因入碳粉率较低，此后工作效率下降到原来的75%。为按时完成任务新配加一 台复印机丙，那么复印机丙的效率至少应是复印机甲的多少倍?\n数 量 关 系60    0  四"}],"annotatedStemRich":[{"text":"文印中心要在34小时内完成一批资料的制作任务。复印机甲和乙共同印制， 10小时后复印机甲完成总任务的12%,复印机乙完成总任务的16%。复印机乙 因入碳粉率较低，此后工作效率下降到原来的75%。为按时完成任务新配加一 台复印机丙，那么复印机丙的效率至少应是复印机甲的多少倍?\n数 量 关 系60    0  四"}],"annotatedOptionRich":{"A":[{"text":"0.5"}],"B":[{"text":"0.6"}],"C":[{"text":"0.8","bold":true}],"D":[{"text":"1.2","bold":true},{"text":"\n"}]},"practicalAnalysis":"甲乙10小时完成工作之比为12%:16%=3:4,可设甲效率为3, 乙效率为4,则工作总量=3×10÷12%=250;\n甲乙工作10小时后，剩余工作量=250-10×(3+4)=180;\n之后乙效率变为4×75%=3,要想24小时完工，三人效率和=180÷24=7.5. 其中丙的效率=7.5-3-3=1.5,即丙效率是甲的1.5÷3=0.5倍，答案为A选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500457,4,'几何问题','如图所示，为测量珠穆朗玛峰上某点C 的海拔高度，测量队选择了两个海

拔高度相差100米的珠峰测量点A 和 B, 测得∠ ABC为 9 0 ° , 从A观 测B、C
的仰角分别为30°和45°,从B 观 测C的仰角也为30°,则C点的海拔高度
比 A点高多少?','[{"label":"A","content":"100 √2 米"},{"label":"B","content":"150 米"},{"label":"C","content":"100 √3 米"},{"label":"D","content":"200 米"}]','D','如图所示，△ ADC、△AEB、△ABC均为直角三角形；
△ AEB 为30°60°直角三角形，AB=2BE=200;
△ ADC为等腰直角三角形，CD=CF+FD=x+100,则AC =√2(x+100);
△ CBF 为30°60°直角三角形， CB=2CF=2x;
此时，△ ABC 的各边均已可表示，根据勾股定理可得： AC²=AB²+BC²,
, 解得 x=100,C 点比A点高x+100=200 米，答案为D选项。

⑥花生批注：
A. 100 √2 米 B.150 米
C. 100 √3 米 D.200 米','数量关系600题','进阶','published','{"globalNumber":457,"sourceNumber":7,"typeLabel":"几何问题","stemRich":[{"text":"如图所示，为测量珠穆朗玛峰上某点C 的海拔高度，测量队选择了两个海\n\n拔高度相差100米的珠峰测量点A 和 B, 测得∠ ABC为 9 0 ° , 从A观 测B、C\n的仰角分别为30°和45°,从B 观 测C的仰角也为30°,则C点的海拔高度\n比 A点高多少?"}],"annotatedStemRich":[{"text":"如图所示，为测量珠穆朗玛峰上某点C 的海拔高度，测量队选择了两个海\n\n拔高度相差100米的珠峰测量点A 和 B, 测得∠ ABC为 9 0 ° , 从A观 测B、C\n的仰角分别为30°和45°,从B 观 测C的仰角也为30°,则C点的海拔高度\n比 A点高多少?"}],"annotatedOptionRich":{"A":[{"text":"   100 √2 米"}],"B":[{"text":"150    米"}],"C":[{"text":"   100","bold":true},{"text":" "},{"text":"√3 米","bold":true}],"D":[{"text":"200    米","bold":true},{"text":"\n"}]},"practicalAnalysis":"如图所示，△ ADC、△AEB、△ABC均为直角三角形；\n△ AEB 为30°60°直角三角形，AB=2BE=200;\n△ ADC为等腰直角三角形，CD=CF+FD=x+100,则AC =√2(x+100);\n△ CBF 为30°60°直角三角形， CB=2CF=2x;\n此时，△ ABC 的各边均已可表示，根据勾股定理可得： AC²=AB²+BC²,\n, 解得 x=100,C 点比A点高x+100=200 米，答案为D选项。","notes":[{"marker":"⑥","text":"A. 100 √2 米 B.150 米\nC. 100 √3 米 D.200 米","matchScore":0.057}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500458,4,'行程问题+周期循环问题','如图所示，长度均为六分之五千米的三个圆形跑道汇聚于点0,若甲、乙、丙三人分别以5千米/小时、8千米/小时、12千米/小时的速度同时从0点出发分别绕三个圈奔跑，则三人再次相聚于0点需经过多少分钟?','[{"label":"A","content":"40"},{"label":"B","content":"50"},{"label":"C","content":"52"},{"label":"D","content":"60"}]','B','甲、乙、丙三人的速度比为5:8:12。再次相遇的相同时间内，路程比等于速度比，即再次相遇时三人的路程比为5:8:12;
此时三人均要回到0点，都跑了整数圈，即甲跑了5圈，乙跑了8圈，丙
跑了12圈，所用时小时=50分钟，答案为B选项。','数量关系600题','进阶','published','{"globalNumber":458,"sourceNumber":8,"typeLabel":"行程问题+周期循环问题","stemRich":[{"text":"如图所示，长度均为六分之五千米的三个圆形跑道汇聚于点0,若甲、乙、 丙三人分别以5千米/小时、8千米/小时、12千米/小时的速度同时从0点 出发分别绕三个圈奔跑，则三人再次相聚于0点需经过多少分钟?"}],"annotatedStemRich":[{"text":"如图所示，长度均为六分之五千米的三个圆形跑道汇聚于点0,若甲、乙、 丙三人分别以5千米/小时、8千米/小时、12千米/小时的速度同时从0点 出发分别绕三个圈奔跑，则三人再次相聚于0点需经过多少分钟?"}],"annotatedOptionRich":{"A":[{"text":"40"}],"B":[{"text":"50"}],"C":[{"text":"52"}],"D":[{"text":"60\n"}]},"practicalAnalysis":"甲、乙、丙三人的速度比为5:8:12。再次相遇的相同时间内，路程比等于速度比，即再次相遇时三人的路程比为5:8:12;\n此时三人均要回到0点，都跑了整数圈，即甲跑了5圈，乙跑了8圈，丙\n跑了12圈，所用时小时=50分钟，答案为B选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500459,4,'行程问题','一条长方形跑道ABCD中 ，AB长度是AD的1.5倍。小张从A点

出发以9千 米/小时的速度向B点方向匀速慢跑，40秒后尚未到达B

点，距离B点还有35米。 如他继续沿跑道匀速慢跑，再过1分钟后，
他与A点的直线距离在以下哪个范 围内?','[{"label":"A","content":"不到135米"},{"label":"B","content":"135～140 米之间"},{"label":"C","content":"140～145 米之间"},{"label":"D","content":"超过145米"}]','C','9千米/小时=2.5米/秒②,,AB 长度=40×2.5+35=135米，则AD 长度=135÷1.5=90米，如图所示⑧。
再过1分钟，共慢跑100秒，路程=100×2.5=250米，此时小张运动到E点，与A点距离= √90²+110²= √20200≈100 √2≈141米，答案为 C选项。
⑦','数量关系600题','进阶','published','{"globalNumber":459,"sourceNumber":9,"typeLabel":"行程问题","stemRich":[{"text":"一条长方形跑道ABCD中 ，AB长度是AD的1.5倍。小张从A点\n\n出发以9千 米/小时的速度向B点方向匀速慢跑，40秒后尚未到达B\n\n点，距离B点还有35米。 如他继续沿跑道匀速慢跑，再过1分钟后，\n他与A点的直线距离在以下哪个范 围内?"}],"annotatedStemRich":[{"text":"一条长方形跑道ABCD中 ，AB长度是AD的1.5倍。小张从A点\n\n出发以9千 米/小时的速度向B点方向匀速慢跑，40秒后尚未到达B\n\n点，距离B点还有35米。 如他继续沿跑道匀速慢跑，再过1分钟后，\n他与A点的直线距离在以下哪个范 围内?"}],"annotatedOptionRich":{"A":[{"text":" 不到135米"}],"B":[{"text":"135～140    米之间"}],"C":[{"text":"140～145  米之间"}],"D":[{"text":" 超过145米\n"}]},"practicalAnalysis":"9千米/小时=2.5米/秒②,,AB 长度=40×2.5+35=135米，则AD 长度=135÷1.5=90米，如图所示⑧。\n再过1分钟，共慢跑100秒，路程=100×2.5=250米，此时小张运动到E点，与A点距离= √90²+110²= √20200≈100 √2≈141米，答案为 C选项。\n⑦","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500460,4,'容斥问题','方阵训练时，教官让40名学生站成一行面向自己。教官喊出某个

