INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500468,4,'统筹规划问题','办公楼高24层，小王在底楼，他有一个文件急需交给在顶楼的

