INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500471,4,'工程问题','小林因病入院需挂瓶输液，上午9点开始输液，输液袋上标有
“容量300 毫升，每毫升15滴”等药液信息。输液开始时，药液

滴速为75滴/分钟。输 液5分钟后小林感觉身体不适，护士帮忙调

整了药液滴速(调整时间不计), 又继续输液10分钟，药液还剩235
毫升，那么输液结束的时间是几点?','[{"label":"A","content":"10 点26分"},{"label":"B","content":"10 点18分"},{"label":"C","content":"10 点14分"},{"label":"D","content":"10 点10分"}]','C','根据题意，前5分钟共输液75÷15×5=25毫升，此时还剩
余300-25=275毫升，则调整后输液的速度为毫升/分钟；
剩余的235毫升输完需要235÷4≈59分钟，全程用时约为5+10+59=74 分钟；
