INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500479,4,'比赛问题','一次围棋比赛共有10名选手参加，他们来自甲、乙、丙三个队，每队不少于2人，每个人都与其他的9人比赛，每盘胜者得2分，负者得0分，平局各得1分。结果乙队平均得分为5.2分，丙队平均得分为17分，则甲队的平均分最高为多少?','[{"label":"A","content":"10"},{"label":"B","content":"11"},{"label":"C","content":"12"},{"label":"D","content":"13"}]','A','10个人单循环赛，则共有场比赛，总得分为90分。
