INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500484,4,'行程问题+容斥问题','大雪后的一天，丁丁和爸爸一起步测一个圆形鱼塘的周长。他们
的起点和 走的方向完全相同，丁丁的步长是36厘米，爸爸的步长

是60厘米，由于两人 的脚印有重合(不考虑脚印的大小),并且他
们走了一圈后都回到起点，这时 雪地上只留下了70个脚印，则这

个池塘的周长为多少厘米?','[{"label":"A","content":"1800"},{"label":"B","content":"2520"},{"label":"C","content":"3360"},{"label":"D","content":"4200"}]','A','36和60的最小公倍数为180,该池塘的周长应能被180整除，排除C 和 D选项；
可代入1800验证，1800÷36=50,1800÷60=30,1800÷180=10,50+30- 10=70 ⑤,符合要求，答案为A选项。

⑤花生批注：
容斥思想：两个人分别走了50步和30步，去掉重合的10步，雪地上只留下 70个脚印。','数量关系600题','进阶','published','{"globalNumber":484,"sourceNumber":4,"typeLabel":"行程问题+容斥问题","stemRich":[{"text":"大雪后的一天，丁丁和爸爸一起步测一个圆形鱼塘的周长。他们\n的起点和 走的方向完全相同，丁丁的步长是36厘米，爸爸的步长\n\n是60厘米，由于两人 的脚印有重合(不考虑脚印的大小),并且他\n们走了一圈后都回到起点，这时 雪地上只留下了70个脚印，则这\n\n个池塘的周长为多少厘米?"}],"annotatedStemRich":[{"text":"大雪后的一天，丁丁和爸爸一起步测一个圆形鱼塘的周长。他们\n的起点和 走的方向完全相同，丁丁的步长是36厘米，爸爸的步长\n\n是60厘米，由于两人 的脚印有重合(不考虑脚印的大小),并且他\n们走了一圈后都回到起点，这时 雪地上只留下了70个脚印，则这\n\n个池塘的周长为多少厘米?"}],"annotatedOptionRich":{"A":[{"text":"1800"}],"B":[{"text":"2520"}],"C":[{"text":"3360"}],"D":[{"text":"4200\n"}]},"practicalAnalysis":"36和60的最小公倍数为180,该池塘的周长应能被180整除，排除C 和 D选项；\n可代入1800验证，1800÷36=50,1800÷60=30,1800÷180=10,50+30- 10=70 ⑤,符合要求，答案为A选项。","notes":[{"marker":"⑤","text":"容斥思想：两个人分别走了50步和30步，去掉重合的10步，雪地上只留下 70个脚印。","matchScore":0.143}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500485,4,'工程问题','某工程队计划每天修路560米，恰好可按期完成任务。如每天比

计划多修 80米，则可以提前2天完成，且最后1天只需修320米。

问如果要提前6天完 成，每天要比计划多修多少米?','[{"label":"A","content":"160"},{"label":"B","content":"240"},{"label":"C","content":"320"},{"label":"D","content":"400"}]','B','设原计划修路时间为x 天，可根据总工作量列式：560x=(560 +80)×(x-3)+320, 解得：x=20, 所以修路总长度为560×20=11200米。
如果要提前6天完成，则每天共需修路11200÷(20-6)=800米，所以比原计划每天多修800-560=240米，答案为B 选项。','数量关系600题','进阶','published','{"globalNumber":485,"sourceNumber":5,"typeLabel":"工程问题","stemRich":[{"text":"某工程队计划每天修路560米，恰好可按期完成任务。如每天比\n\n计划多修 80米，则可以提前2天完成，且最后1天只需修320米。\n\n问如果要提前6天完 成，每天要比计划多修多少米?"}],"annotatedStemRich":[{"text":"某工程队计划每天修路560米，恰好可按期完成任务。如每天比\n\n计划多修 80米，则可以提前2天完成，且最后1天只需修320米。\n\n问如果要提前6天完 成，每天要比计划多修多少米?"}],"annotatedOptionRich":{"A":[{"text":"160"}],"B":[{"text":"240"}],"C":[{"text":"320"}],"D":[{"text":"400\n"}]},"practicalAnalysis":"设原计划修路时间为x 天，可根据总工作量列式：560x=(560 +80)×(x-3)+320, 解得：x=20, 所以修路总长度为560×20=11200米。\n如果要提前6天完成，则每天共需修路11200÷(20-6)=800米，所以比原计划每天多修800-560=240米，答案为B 选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500486,4,'概率问题之两人同组概率','某单位的会议室有5排共40个座位，每排座位数相同。小张和
小李随机 入座，则他们坐在同一排的概率是?','[{"label":"A","content":"不高于15%"},{"label":"B","content":"高于15%但低于20%"},{"label":"C","content":"正好为20%"},{"label":"D","content":"高于20%\n⑥"}]','B','两人同组概率，先让小张任意的选择一个座位，只考虑小李即可：小李一共有39个座位选择，会议室一排有8个座位.二人若想坐在同一排，小李只能坐在和小张同排的7个座位里⑥,即两人坐在同一排的概率
