INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500487,4,'年龄问题','甲处室有6人，乙处室有4人，甲处室平均年龄比乙处室大1.5

岁。甲处 室新进了小张，乙处室新进了老张，老张比小张大20岁

，他们来了之后甲处 室平均年龄比乙处室小2岁。问老张比乙处室
原来的平均年龄大多少岁?','[{"label":"A","content":"5"},{"label":"B","content":"7.5"},{"label":"C","content":"12.5"},{"label":"D","content":"15"}]','B','设乙处室平均年龄为x, 则甲处室平均年龄为x+1.5; 设小张a 岁，则老张a+20 岁；
可根据调整后年龄差列方程：解得 x-a=12.5; 老张较乙处室原平均年龄大 a+20-x=20-(x-a)=20-12.5=7.5 岁，答案为B 选项。','数量关系600题','进阶','published','{"globalNumber":487,"sourceNumber":7,"typeLabel":"年龄问题","stemRich":[{"text":"甲处室有6人，乙处室有4人，甲处室平均年龄比乙处室大1.5\n\n岁。甲处 室新进了小张，乙处室新进了老张，老张比小张大20岁\n\n，他们来了之后甲处 室平均年龄比乙处室小2岁。问老张比乙处室\n原来的平均年龄大多少岁?"}],"annotatedStemRich":[{"text":"甲处室有6人，乙处室有4人，甲处室平均年龄比乙处室大1.5\n\n岁。甲处 室新进了小张，乙处室新进了老张，老张比小张大20岁\n\n，他们来了之后甲处 室平均年龄比乙处室小2岁。问老张比乙处室\n原来的平均年龄大多少岁?"}],"annotatedOptionRich":{"A":[{"text":"5"}],"B":[{"text":"7.5"}],"C":[{"text":"12.5"}],"D":[{"text":"15\n"}]},"practicalAnalysis":"设乙处室平均年龄为x, 则甲处室平均年龄为x+1.5; 设小张a 岁，则老张a+20 岁；\n可根据调整后年龄差列方程：解得 x-a=12.5; 老张较乙处室原平均年龄大 a+20-x=20-(x-a)=20-12.5=7.5 岁，答案为B 选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
