INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500489,4,'排列组合问题','某学习软件要求用户使用字母和数字组合的8位密码。赵某使用D、E、F、
W4个大写字母(不重复使用)和 4个不同非零数字的组合作为自己的密码，要

求数字放在后四位，且4个数字的乘积须是320的倍数。那么这样的密码有多
少种不同的可能?','[{"label":"A","content":"不到1000种"},{"label":"B","content":"1000～3000 种之间"},{"label":"C","content":"3000～8000 种之间"},{"label":"D","content":"超过8000种"}]','B','320=2×2×2×2×2×2×5,合成4个不同数字，只能是 2×4×8×5: 四个数字中，只有2可扩大成2×3=6 ⑧:所以这四个数字可能有 2485和6485两种组合。
四个大写字母有A4 种排列，四个数字有2×A4 种排列，则该密码一共有 A4×2×A4=1152 种可能，答案为B 选项。

⑧花生批注：
在10以内：
2变为原来2倍，和4重复； 4变为原来2倍，和8重复；
2变为原来4倍，和8重复；只有2变为原来3倍，符合要求。','数量关系600题','进阶','published','{"globalNumber":489,"sourceNumber":9,"typeLabel":"排列组合问题","stemRich":[{"text":"某学习软件要求用户使用字母和数字组合的8位密码。赵某使用D、E、F、\nW4个大写字母(不重复使用)和 4个不同非零数字的组合作为自己的密码，要\n\n求数字放在后四位，且4个数字的乘积须是320的倍数。那么这样的密码有多\n少种不同的可能?"}],"annotatedStemRich":[{"text":"某学习软件要求用户使用字母和数字组合的8位密码。赵某使用D、E、F、\nW4个大写字母(不重复使用)和 4个不同非零数字的组合作为自己的密码，要\n\n求数字放在后四位，且4个数字的乘积须是320的倍数。那么这样的密码有多\n少种不同的可能?"}],"annotatedOptionRich":{"A":[{"text":"  不到1000种"}],"B":[{"text":"1000～3000        种之间"}],"C":[{"text":"3000～8000        种之间"}],"D":[{"text":"  超过8000种\n"}]},"practicalAnalysis":"320=2×2×2×2×2×2×5,合成4个不同数字，只能是 2×4×8×5: 四个数字中，只有2可扩大成2×3=6 ⑧:所以这四个数字可能有 2485和6485两种组合。\n四个大写字母有A4 种排列，四个数字有2×A4 种排列，则该密码一共有 A4×2×A4=1152 种可能，答案为B 选项。","notes":[{"marker":"⑧","text":"在10以内：\n2变为原来2倍，和4重复； 4变为原来2倍，和8重复；\n2变为原来4倍，和8重复；只有2变为原来3倍，符合要求。","matchScore":0.056}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500490,4,'排列组合问题之特殊情境','某学院由行政教辅和三个不同的教学研究室构成，现引进8台相同教学设备，每个教学研究室至少分2台，行政教辅无要求，问一共有多少种不同分法?','[{"label":"A","content":"6"},{"label":"B","content":"8"},{"label":"C","content":"10"},{"label":"D","content":"12"}]','C','8台相同教学设备为相同元素，本题可看作相同元素分配问题⑨ :
先给每个教研室分一台教学设备，再向行政教辅“借得”一台教学设备，此时总元素变为8-3+1=6台，此时用插板法解题，6个元素5个“空”插入3个板，即一共有C³=10 种分配方式，答案为C 选项。
⑧

⑨花生批注：
排列组合八大特殊情境之一的相同元素分配(其他七大为相邻问题、不相邻问题、定序问题、平均分堆、环形排列、错位排序、
重复排列):
相同元素分配问题常用插板法，但插板法的使用条件有二：
一是要分配的元素相同，
二是满足“每人至少一个”的要求；
若无法满足条件二，可构造：没有“每人至少一个”的要求：先向此人借得一个元素(总元素加1),即“至少还他一个”;若有“每人至少n 个”的要求，先
给每人 n-1 个(总元素相
应减少),此时每人还至少分配一个。
例如本题：行政教辅没要求，先向其“借得”一个，总元素加1;教学研究室
需要“至少两个”,先给
三个教研室各一个，总元素减3。
数量关系','数量关系600题','进阶','published','{"globalNumber":490,"sourceNumber":10,"typeLabel":"排列组合问题之特殊情境","stemRich":[{"text":"某学院由行政教辅和三个不同的教学研究室构成，现引进8台相同教学设 备，每个教学研究室至少分2台，行政教辅无要求，问一共有多少种不同分法?"}],"annotatedStemRich":[{"text":"某学院由行政教辅和三个不同的教学研究室构成，现引进8台相同教学设 备，每个教学研究室至少分2台，行政教辅无要求，问一共有多少种不同分法?"}],"annotatedOptionRich":{"A":[{"text":"6"}],"B":[{"text":"8"}],"C":[{"text":"10"}],"D":[{"text":"12\n"}]},"practicalAnalysis":"8台相同教学设备为相同元素，本题可看作相同元素分配问题⑨ :\n先给每个教研室分一台教学设备，再向行政教辅“借得”一台教学设备，此时总元素变为8-3+1=6台，此时用插板法解题，6个元素5个“空”插入3个板，即一共有C³=10 种分配方式，答案为C 选项。\n⑧","notes":[{"marker":"⑨","text":"排列组合八大特殊情境之一的相同元素分配(其他七大为相邻问题、不相邻问题、定序问题、平均分堆、环形排列、错位排序、\n重复排列):\n相同元素分配问题常用插板法，但插板法的使用条件有二：\n一是要分配的元素相同，\n二是满足“每人至少一个”的要求；\n若无法满足条件二，可构造：没有“每人至少一个”的要求：先向此人借得一个元素(总元素加1),即“至少还他一个”;若有“每人至少n 个”的要求，先\n给每人 n-1 个(总元素相\n应减少),此时每人还至少分配一个。\n例如本题：行政教辅没要求，先向其“借得”一个，总元素加1;教学研究室\n需要“至少两个”,先给\n三个教研室各一个，总元素减3。\n数量关系","matchScore":0.234}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500491,4,'工程问题','甲、乙两个施工队共同完成一项工程需要20天。甲乙两队合作
4天后， 乙队因故退出6天后回归，回归时工程总量已完成40%。

为保证按时完工，乙 队回归时带来了丙施工队，甲、乙、丙三队共

同工作10天后刚好完成工程。问甲、 乙、丙队的效率比为多少?','[{"label":"A","content":"3:6:10"},{"label":"B","content":"4:8:15"},{"label":"C","content":"6:3:2"},{"label":"D","content":"10:5:3"}]','D','已知条件为不同完工情况，可设甲乙效率分别为甲、乙，根据完工情况可列等式：40%×20×(甲+乙)=4×(甲+乙)+6甲，解得甲=2乙，赋值乙=1,甲=2,则工作总量=20×(甲+乙)=60;
后10天三人完成工作总量的60%,可列式： 60%×60=10×(2+1+丙), 解得丙=0 . 6,则三人效率比=2:1:0 . 6=10:5:3,答案为D 选项。','数量关系600题','进阶','published','{"globalNumber":491,"sourceNumber":1,"typeLabel":"工程问题","stemRich":[{"text":"甲、乙两个施工队共同完成一项工程需要20天。甲乙两队合作\n4天后， 乙队因故退出6天后回归，回归时工程总量已完成40%。\n\n为保证按时完工，乙 队回归时带来了丙施工队，甲、乙、丙三队共\n\n同工作10天后刚好完成工程。问甲、 乙、丙队的效率比为多少?"}],"annotatedStemRich":[{"text":"甲、乙两个施工队共同完成一项工程需要20天。甲乙两队合作\n4天后， 乙队因故退出6天后回归，回归时工程总量已完成40%。\n\n为保证按时完工，乙 队回归时带来了丙施工队，甲、乙、丙三队共\n\n同工作10天后刚好完成工程。问甲、 乙、丙队的效率比为多少?"}],"annotatedOptionRich":{"A":[{"text":"3:6:10"}],"B":[{"text":"4:8:15"}],"C":[{"text":"6:3:2"}],"D":[{"text":"10:5:3\n"}]},"practicalAnalysis":"已知条件为不同完工情况，可设甲乙效率分别为甲、乙，根据完工情况可列等式：40%×20×(甲+乙)=4×(甲+乙)+6甲，解得甲=2乙，赋值乙=1,甲=2,则工作总量=20×(甲+乙)=60;\n后10天三人完成工作总量的60%,可列式： 60%×60=10×(2+1+丙), 解得丙=0 . 6,则三人效率比=2:1:0 . 6=10:5:3,答案为D 选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500492,4,'几何问题','如图所示，ABCD为边长10米的正方形路线，E 为AD中点，F 为与B相距 3米的BC上一点，从E点到F点有小路EGHF,小路的每一段都与AB垂直或平行，且GH相距2米。甲经EABF 从 E点匀速运动到F 点用时9秒，则其以相同速度经 EGHF从 E 点匀速运动到F 点用时多少秒?','[{"label":"A","content":"12"},{"label":"B","content":"10"},{"label":"C","content":"9"},{"label":"D","content":"8"}]','D','如图所示①,EABF=EA+AB+BF=5+10+3=18 米，其速度=18÷9=2;
EGHF=EG+GH+HP+MP+MF, 其中横向路线 EG+HP+MF=AB=10② : 纵向路线， GH=2, MP=MN+NP,其中 MN=AE-BF=5-3=2,NP=GH=2, 则 MP=2+2=4,即纵向路线一共为2+4=6;
EGHF 总长为10+6=16,所以EGHF用时=16÷2=8,答案为D 选项。
①

②花生批注：
将EGHF 中三条横向线段向上平移可与AB重叠，长度是10米。只需考虑纵向长度即可。','数量关系600题','进阶','published','{"globalNumber":492,"sourceNumber":2,"typeLabel":"几何问题","stemRich":[{"text":"如图所示，ABCD为边长10米的正方形路线，E 为AD中点，F 为与B相距 3米的BC上一点，从E点到F点有小路EGHF,小路的每一段都与AB垂直或平行，且GH相距2米。甲经EABF 从 E点匀速运动到F 点用时9秒，则其以相同速度经 EGHF从 E 点匀速运动到F 点用时多少秒?"}],"annotatedStemRich":[{"text":"如图所示，ABCD为边长10米的正方形路线，E 为AD中点，F 为与B相距 3米的BC上一点，从E点到F点有小路EGHF,小路的每一段都与AB垂直或平行，且GH相距2米。甲经EABF 从 E点匀速运动到F 点用时9秒，则其以相同速度经 EGHF从 E 点匀速运动到F 点用时多少秒?"}],"annotatedOptionRich":{"A":[{"text":"12"}],"B":[{"text":"10"}],"C":[{"text":"9","bold":true}],"D":[{"text":"8","bold":true},{"text":"\n"}]},"practicalAnalysis":"如图所示①,EABF=EA+AB+BF=5+10+3=18 米，其速度=18÷9=2;\nEGHF=EG+GH+HP+MP+MF, 其中横向路线 EG+HP+MF=AB=10② : 纵向路线， GH=2, MP=MN+NP,其中 MN=AE-BF=5-3=2,NP=GH=2, 则 MP=2+2=4,即纵向路线一共为2+4=6;\nEGHF 总长为10+6=16,所以EGHF用时=16÷2=8,答案为D 选项。\n①","notes":[{"marker":"②","text":"将EGHF 中三条横向线段向上平移可与AB重叠，长度是10米。只需考虑纵向长度即可。","matchScore":0.086}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500493,4,'溶液问题','甲、乙、丙3杯浓度不同的同种溶液，取150克甲溶液与50克乙溶液，

混合后浓度与丙溶液相同，取 100克乙溶液与200克丙溶液，混合后浓度是甲
溶液浓度的1.5倍，问甲、乙、丙三种溶液的浓度之比是多少?','[{"label":"A","content":"4:8:5"},{"label":"B","content":"4:5:8"},{"label":"C","content":"5:10:8"},{"label":"D","content":"5:8:10"}]','A','③设三种溶液浓度分别为甲、乙、丙，可根据溶质不变列方程： ①150甲+50乙=200丙，②100乙+200丙=1.5×300甲；可解得甲：乙：丙 = 4 : 8 : 5 , 答案为A选项。
③

③花生批注：
考场秒杀：
150甲和50克乙混合后，混合溶液浓度应在甲乙之间且靠近“量”更大的甲溶液，即丙溶液浓度在甲乙之间，且靠近甲，只有 A 选项符合要求。','数量关系600题','进阶','published','{"globalNumber":493,"sourceNumber":3,"typeLabel":"溶液问题","stemRich":[{"text":"甲、乙、丙3杯浓度不同的同种溶液，取150克甲溶液与50克乙溶液，\n\n混合后浓度与丙溶液相同，取 100克乙溶液与200克丙溶液，混合后浓度是甲\n溶液浓度的1.5倍，问甲、乙、丙三种溶液的浓度之比是多少?"}],"annotatedStemRich":[{"text":"甲、乙、丙3杯浓度不同的同种溶液，取150克甲溶液与50克乙溶液，\n\n混合后浓度与丙溶液相同，取 100克乙溶液与200克丙溶液，混合后浓度是甲\n溶液浓度的1.5倍，问甲、乙、丙三种溶液的浓度之比是多少?"}],"annotatedOptionRich":{"A":[{"text":"4:8:5"}],"B":[{"text":"4:5:8"}],"C":[{"text":"5:10:8","bold":true}],"D":[{"text":"5:8:10","bold":true},{"text":"\n"}]},"practicalAnalysis":"③设三种溶液浓度分别为甲、乙、丙，可根据溶质不变列方程： ①150甲+50乙=200丙，②100乙+200丙=1.5×300甲；可解得甲：乙：丙 = 4 : 8 : 5 , 答案为A选项。\n③","notes":[{"marker":"③","text":"考场秒杀：\n150甲和50克乙混合后，混合溶液浓度应在甲乙之间且靠近“量”更大的甲溶液，即丙溶液浓度在甲乙之间，且靠近甲，只有 A 选项符合要求。","matchScore":0.211}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500494,4,'行程问题','小张从甲地出发匀速前往乙地，同时小李和小王从乙地出发匀速前往甲地，
小张和小李在途中的丙地相遇，小张和小王在途中的丁地相遇。已知小张的速

度比小李快一半，小王的速度比小李慢一半，则丙、丁两地之间的距离与甲、
乙两地之间的距离之比为多少?','[{"label":"A","content":"2:15"},{"label":"B","content":"1:4"},{"label":"C","content":"3:20"},{"label":"D","content":"1:15"}]','C','已知小张的速度比小李快一半，小王的速度比小李慢一半，可赋值小李速度为2,则小张速度为3,小王速度为1,即张，李，王速度之比为3:2:1。分别分析相遇过程：
①张李在丙地相遇，张速度3,李速度2,时间相同，路程比等于速度比，则甲丙：乙丙=3:2;
④

④花生批注：
②张王在丁地相遇，张速度3,王速度1,时间相同，路程比等于速度比，则甲丁：乙丁=3:1;
