INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500497,4,'牛吃草问题','汛期临近，某水库计划提前泄洪腾空库容迎峰度汛。如果开启5个闸门放水，7天可以腾空；如果开启8个闸门放水，4天后可以腾空。根据天气预报，现准备2天腾空库容，则应开启多少个闸门?(假定汛前上游来水稳定)','[{"label":"A","content":"10"},{"label":"B","content":"14"},{"label":"C","content":"15"},{"label":"D","content":"16"}]','C','本题可看作牛吃草问题，分三步解题：
第一步：流
第二步：原有水量=(5-1)×7=28;
综上，答案为C 选项。
⑧

⑨花生批注：
牛吃草问题的常见解法：
将牛分成两类，吃掉每日生长草的称之白吃牛，一直在吃原有草的称之干活牛；
第一步：
白吃牛=每日草生长量= 时间×牛数-时间×牛数时间差 (注意时间大的在前);
第二步：
草场原有草量= 干活牛×时间=
(牛数-白吃牛)×时间；第三步：
问时间，则时间= 原有草÷干活牛；问牛数，则牛数=
