INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500505,4,'统筹规划问题之 空瓶换酒','某超市为了增加收入，开展“8个空啤酒瓶换1瓶啤酒”的促销活动，老

李在活动期间共购买了127瓶啤酒，期间老李不断用空啤酒瓶去换啤酒，请问
