INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500510,4,'行程问题','A、B两辆车在一段窄路上相遇，必须其中一辆车倒车让行才能继续行驶。 A车在窄路上正常行驶需1分钟通过，B 车正常行驶需2分钟通过。 A 车在窄路 上倒车的速度是它正常行驶速度的 , B 车倒车的速度是正常行驶的 。 A 车 需倒车的路程是B 车的4倍。假设两车均匀速行驶，则两车相遇后都通过窄路 的最短时间是多少?','[{"label":"A","content":"6 分 钟"},{"label":"B","content":"5 分钟"},{"label":"C","content":"4 分钟"},{"label":"D","content":"3 分钟"}]','B','赋值A的速度为80,列表：
路程
倒车距离
时间
速度(正常)
速度(倒车)
A
80
1min
80
B
2min
40
(1) 若A倒车四：
通过时间=A 倒车时间+A通过时间(全部路段)=64÷16+1min=5min;
(2) 若 B 倒车：
通过时间=B 倒车时间+B 通过时间(全部路段)=16÷5+2min=5.2min; 二者比较，A 倒车时间更短，答案为B 选项。
⑨

⑪花生批注：
结合常识，A 一边倒车，B 一边前进，所以无需计算 B 通过路段的时间。
