INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500511,4,'工程问题','7名防疫人员负责甲、乙两个社区的居民排查工作，已知每人走访一户居
