INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500514,4,'和差倍比问题','张三打算将一筐新鲜水果做成果干，水果含筐重45千克。若新鲜水果含
水量为80%,晾晒后含水量下降到20%,此时水果含筐重15千克，则筐的重量
为多少千克?','[{"label":"A","content":"1"},{"label":"B","content":"3"},{"label":"C","content":"5"},{"label":"D","content":"7"}]','C','设筐的重量为 x 千克，晾晒过程中水果的果肉质量是不变的，根据题意，新鲜水果中果肉占比为20%,晾晒后占比为80%,根据果肉质量不变可列方程：(45-x)×20%=(15-x)×80%, 解得x=5, 答案为C 选项。','数量关系600题','进阶','published','{"globalNumber":514,"sourceNumber":4,"typeLabel":"和差倍比问题","stemRich":[{"text":"张三打算将一筐新鲜水果做成果干，水果含筐重45千克。若新鲜水果含\n水量为80%,晾晒后含水量下降到20%,此时水果含筐重15千克，则筐的重量\n为多少千克?"}],"annotatedStemRich":[{"text":"张三打算将一筐新鲜水果做成果干，水果含筐重45千克。若新鲜水果含\n水量为80%,晾晒后含水量下降到20%,此时水果含筐重15千克，则筐的重量\n为多少千克?"}],"annotatedOptionRich":{"A":[{"text":"1"}],"B":[{"text":"3"}],"C":[{"text":"5"}],"D":[{"text":"7\n"}]},"practicalAnalysis":"设筐的重量为 x 千克，晾晒过程中水果的果肉质量是不变的，根据题意，新鲜水果中果肉占比为20%,晾晒后占比为80%,根据果肉质量不变可列方程：(45-x)×20%=(15-x)×80%, 解得x=5, 答案为C 选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500515,4,'统筹规划问题','有只松鼠在某处发现了90粒松子，欲搬回25米远的家中储存，但这只松鼠每次最多只携带45粒且其往返途中每走1米必须要吃1粒松子。那么松鼠最多能搬多少粒松子回家?','[{"label":"A","content":"0"},{"label":"B","content":"10"},{"label":"C","content":"35"},{"label":"D","content":"40"}]','C','⑤直接携带45粒回家，可搬回家20粒松子，排除A、B选项；剩下两个选项可以依次验证：
若最终搬回35粒松子，应在距离家10米处储存45粒松子(直接一次搬回家，无需再往返),“去暂存地-回松子所在地-再去暂存地”两次共搬运 90粒松子(一次45粒),路上消耗15×3=45粒，恰巧剩余45粒松子，当选；
若最终搬回40粒松子，应在距离家5米处储存45粒松子，“去暂存地- 回松子所在地一再去暂存地”两次共搬运90粒松子(一次45粒),路上消耗 20×3=60粒，不能剩余45粒松子，排除；
综上，答案为C 选项。

⑤花生批注：
本题也可列方程解决：
根据题意可知，来回路程需要消耗25×2=50 粒松子，而松鼠一次只能携带 45粒，不够消耗量，故需要在路途中设置一个暂存地，设暂存地距离松子所在的距离为x 米，则松鼠第一次去到暂存地留下了 45-2x 粒松子(往返消耗 2x 粒);
家暂存地松子所在
从暂存地返回到松子所在地后携带剩余的45粒松子再次到暂存地，此时的暂存地拥有45-2x+45-x=90- 3x 粒松子；
若要使松鼠搬尽可能多的松子回家，则此时暂存地的松子应为45粒( 一次运回家，不需再往返)。可列式 90-3 x=45, 解得 x=15, 可得暂存地到家的距离为25-15=10米，可搬运回家45-10=35粒松子。','数量关系600题','进阶','published','{"globalNumber":515,"sourceNumber":5,"typeLabel":"统筹规划问题","stemRich":[{"text":"有只松鼠在某处发现了90粒松子，欲搬回25米远的家中储存，但这只松 鼠每次最多只携带45粒且其往返途中每走1米必须要吃1粒松子。那么松鼠 最多能搬多少粒松子回家?"}],"annotatedStemRich":[{"text":"有只松鼠在某处发现了90粒松子，欲搬回25米远的家中储存，但这只松 鼠每次最多只携带45粒且其往返途中每走1米必须要吃1粒松子。那么松鼠 最多能搬多少粒松子回家?"}],"annotatedOptionRich":{"A":[{"text":"0"}],"B":[{"text":"10"}],"C":[{"text":"35"}],"D":[{"text":"40\n"}]},"practicalAnalysis":"⑤直接携带45粒回家，可搬回家20粒松子，排除A、B选项；剩下两个选项可以依次验证：\n若最终搬回35粒松子，应在距离家10米处储存45粒松子(直接一次搬回家，无需再往返),“去暂存地-回松子所在地-再去暂存地”两次共搬运 90粒松子(一次45粒),路上消耗15×3=45粒，恰巧剩余45粒松子，当选；\n若最终搬回40粒松子，应在距离家5米处储存45粒松子，“去暂存地- 回松子所在地一再去暂存地”两次共搬运90粒松子(一次45粒),路上消耗 20×3=60粒，不能剩余45粒松子，排除；\n综上，答案为C 选项。","notes":[{"marker":"⑤","text":"本题也可列方程解决：\n根据题意可知，来回路程需要消耗25×2=50 粒松子，而松鼠一次只能携带 45粒，不够消耗量，故需要在路途中设置一个暂存地，设暂存地距离松子所在的距离为x 米，则松鼠第一次去到暂存地留下了 45-2x 粒松子(往返消耗 2x 粒);\n家暂存地松子所在\n从暂存地返回到松子所在地后携带剩余的45粒松子再次到暂存地，此时的暂存地拥有45-2x+45-x=90- 3x 粒松子；\n若要使松鼠搬尽可能多的松子回家，则此时暂存地的松子应为45粒( 一次运回家，不需再往返)。可列式 90-3 x=45, 解得 x=15, 可得暂存地到家的距离为25-15=10米，可搬运回家45-10=35粒松子。","matchScore":0.206}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500516,4,'植树问题','某电厂的主干道两侧各安装有33个路灯，每侧路灯相邻之间的距离相同，该厂计划近期改造主干道，决定在道路两侧各加装8个路灯，要求加装后相邻路灯之间的距离也相同，则最多有多少个原路灯不需挪动?','[{"label":"A","content":"14"},{"label":"B","content":"18"},{"label":"C","content":"20"},{"label":"D","content":"10"}]','B','原有33个路灯，中间小间隔有32个 ⑥。加装8个路灯，此时路灯有33+8=41个，小间隔为40个。
不需要挪动的大间隔数为 3 2 和 4 0 的最大公约数 8 , 即每一侧有 8 个大间隔对应的9个路灯无需挪动，即一共不需要挪动18个路灯，答案为B 选项。

⑥花生批注：
植树问题常用公式为：
两端植树，植树总棵数= 路长÷间隔+1;
一端植树或环形植树，植树总棵数=路长÷间隔；两端不植树，植树总棵数 =路长 ÷间隔-1;
植树问题易错点：
忘记道路两侧植树，求出单侧植树棵数后别忘记乘2。本题未特意强调并且根据
整除性质猜测，本题为两
端植树问题。

⑦花生批注：
原来每4个小间隔合成1 个大间隔；
因为要多加装路灯，则1 个大间隔要平均分出5个新的小间隔；
