INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500520,4,'行程问题之相遇追及','一辆货车与一辆客车分别从甲、乙两地同时出发相向而行，货车每小时行

32千米，客车每小时行40千米，到达乙地和甲地后(不计停车时间)立即原
路返回。返回时，货车由于空车速度增加8千米/小 时 ，而客车由于客满速度

减少8千米/小时。已知两次相遇点相距40千米，则甲、乙两地相距多少千米?','[{"label":"A","content":"450"},{"label":"B","content":"360"},{"label":"C","content":"200"},{"label":"D","content":"160"}]','B','在第一次相遇之前货车、客车速度之比为32:40=4:5,设总路程为9S, 时间相同，两者路程比=速度比=4:5,第一次相遇点A距离甲 4S⑥。
货车返程时速度变为40,客车速度变为32,则货车去程速度=客车返程速度，货车返程速度=客车去程速度，二者走完全程时间相等；
二者第二次相遇时时间相同，则从第二次相遇点B到回到各自出发点时间也相等⑧,路程比等于此时速度比(40:32=5:4),则第二次相遇点距离甲5S⑥
综上，第二次相遇与第一次相遇点相差路程为S=40千米，全程为9S=360 千米，答案为B选项。

⑭花生批注：
全程时间相等，到达第二次相遇点时间也相等，则从第二次相遇点回到各自起点时间也相等。','数量关系600题','进阶','published','{"globalNumber":520,"sourceNumber":10,"typeLabel":"行程问题之相遇追及","stemRich":[{"text":"一辆货车与一辆客车分别从甲、乙两地同时出发相向而行，货车每小时行\n\n32千米，客车每小时行40千米，到达乙地和甲地后(不计停车时间)立即原\n路返回。返回时，货车由于空车速度增加8千米/小 时 ，而客车由于客满速度\n\n减少8千米/小时。已知两次相遇点相距40千米，则甲、乙两地相距多少千米?"}],"annotatedStemRich":[{"text":"一辆货车与一辆客车分别从甲、乙两地同时出发相向而行，货车每小时行\n\n32千米，客车每小时行40千米，到达乙地和甲地后(不计停车时间)立即原\n路返回。返回时，货车由于空车速度增加8千米/小 时 ，而客车由于客满速度\n\n减少8千米/小时。已知两次相遇点相距40千米，则甲、乙两地相距多少千米?"}],"annotatedOptionRich":{"A":[{"text":"450"}],"B":[{"text":"360"}],"C":[{"text":"200","bold":true}],"D":[{"text":"160","bold":true},{"text":"\n"}]},"practicalAnalysis":"在第一次相遇之前货车、客车速度之比为32:40=4:5,设总路程为9S, 时间相同，两者路程比=速度比=4:5,第一次相遇点A距离甲 4S⑥。\n货车返程时速度变为40,客车速度变为32,则货车去程速度=客车返程速度，货车返程速度=客车去程速度，二者走完全程时间相等；\n二者第二次相遇时时间相同，则从第二次相遇点B到回到各自出发点时间也相等⑧,路程比等于此时速度比(40:32=5:4),则第二次相遇点距离甲5S⑥\n综上，第二次相遇与第一次相遇点相差路程为S=40千米，全程为9S=360 千米，答案为B选项。","notes":[{"marker":"⑭","text":"全程时间相等，到达第二次相遇点时间也相等，则从第二次相遇点回到各自起点时间也相等。","matchScore":0.177}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500521,4,'年龄问题','某单位有2个处室，甲处室有12人，乙处室有20人。现在将甲处室最年
