INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500524,4,'排列组合问题','某自助餐厅提供羊肉串，小王怕浪费每次最多只拿3串。已知他正好吃了
可
那
10串，那么他共有多少种不同的拿法?
多少','[{"label":"A","content":"44"},{"label":"B","content":"81"},{"label":"C","content":"149"},{"label":"D","content":"274"}]','D','本题可看作爬楼梯③模型：记吃了n串羊肉串的拿法为。
拿10串时，最后一次可以拿1串、2串、3串；若最后一次拿1串，则之
IHA海IGOGK0
前共拿了9串，即此时的拿法与拿9串相同；同理，最后一次拿2串的拿法与 拿8串相同；最后一次拿3串的拿法与拿7串相同。所以S₁₀=S₉+Sg+S₇。
同理可推出：S₉=S₈+S₇+S₆、S₈=S₇+S₆+S₅ 、……、S₄=S₃+S₂+S1。
S₁=1, S₂=2,S₃=4④, 故 S₁~S1 0分别为： 1,2,4,7,13,24,44,81, 149,274,答案为D 选项。

③花生批注：
爬楼梯模型：如果每次可以爬1个或2个楼梯，那
么爬到第n个楼梯有多少种不同的方法：
最后一次可以爬1个或2 个楼梯，则爬第n 个楼梯可以视为爬 n-1个和n-2 个楼梯的方法之和，以此类推，爬1～ n 个楼梯的方法数为2项递推的斐波那契数列：1、2、3、5、8、

④花生批注：
拿1串的情况有且只有1种；拿2串时，拿法可以为(1, 1)、(2),共2种；
拿3串时，拿法可以为(1, 1,1)、(1,2)、(2,1)、
(3),共4种。','数量关系600题','进阶','published','{"globalNumber":524,"sourceNumber":4,"typeLabel":"排列组合问题","stemRich":[{"text":"某自助餐厅提供羊肉串，小王怕浪费每次最多只拿3串。已知他正好吃了\n可\n那\n10串，那么他共有多少种不同的拿法?\n多少"}],"annotatedStemRich":[{"text":"某自助餐厅提供羊肉串，小王怕浪费每次最多只拿3串。已知他正好吃了\n可\n那\n10串，那么他共有多少种不同的拿法?\n多少"}],"annotatedOptionRich":{"A":[{"text":"44"}],"B":[{"text":"81"}],"C":[{"text":"149"}],"D":[{"text":"274\n"}]},"practicalAnalysis":"本题可看作爬楼梯③模型：记吃了n串羊肉串的拿法为。\n拿10串时，最后一次可以拿1串、2串、3串；若最后一次拿1串，则之\nIHA海IGOGK0\n前共拿了9串，即此时的拿法与拿9串相同；同理，最后一次拿2串的拿法与 拿8串相同；最后一次拿3串的拿法与拿7串相同。所以S₁₀=S₉+Sg+S₇。\n同理可推出：S₉=S₈+S₇+S₆、S₈=S₇+S₆+S₅ 、……、S₄=S₃+S₂+S1。\nS₁=1, S₂=2,S₃=4④, 故 S₁~S1 0分别为： 1,2,4,7,13,24,44,81, 149,274,答案为D 选项。","notes":[{"marker":"③","text":"爬楼梯模型：如果每次可以爬1个或2个楼梯，那\n么爬到第n个楼梯有多少种不同的方法：\n最后一次可以爬1个或2 个楼梯，则爬第n 个楼梯可以视为爬 n-1个和n-2 个楼梯的方法之和，以此类推，爬1～ n 个楼梯的方法数为2项递推的斐波那契数列：1、2、3、5、8、","matchScore":0.182},{"marker":"④","text":"拿1串的情况有且只有1种；拿2串时，拿法可以为(1, 1)、(2),共2种；\n拿3串时，拿法可以为(1, 1,1)、(1,2)、(2,1)、\n(3),共4种。","matchScore":0.139}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500525,4,'数列问题','9个人参加知识竞赛，前五名和后五名平均分相差16分，除第五名外其余
8人的分数成等差数列。问前两名的分差为多少?','[{"label":"A","content":"1"},{"label":"B","content":"2"},{"label":"C","content":"4"},{"label":"D","content":"5"}]','D','已知前五名和后五名平均分相差16分，则总分相差16×5=80 分，二者均包含第五名，即前四名与后四名总分差为80分，这8人构成等差数列 a、a₂、a₃、a4、a5、a6、a₇、ag, 根据等差数列性质可得：4(a₁-a₅)=4×4d=80, 可得公差d=-5, 即前两名分差为5,答案为D选项。
