INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500526,4,'行程问题','甲、乙同时从400米环形跑道的某个点出发，沿相反方向匀速跑步。甲保

持4米/秒的速度，乙第一次与甲相遇时跑了150米，且每次与甲相遇后，其
速度都提高0.2米/秒。问两人第五次和第六次相遇的位置在跑道上的距离在

以下哪一个区间?','[{"label":"A","content":"160～ 170 米"},{"label":"B","content":"170～ 180 米"},{"label":"C","content":"180～190 米"},{"label":"D","content":"190～200 米"}]','C','第一次相遇时，乙走150米，则甲走250米，甲乙速度比= 路程比=250:150=5:3,可求出乙原始速度(提速前)为2.4米/秒；
第五次相遇后，乙的速度提高到2.4+0.2×5=3.4米/秒⑨,此后的一圈中⑦,
甲乙路程比=速度比=4:3.4=20:17,乙走了4米，答案为C选项。
⑥

⑥花生批注：
每次相遇速度提升0.2米/ 秒，五次相遇，速度提升五次。

⑦花生批注：
从第五次相遇开始，到第六次相遇结束，乙走的距离即是两个相遇点的距离。','数量关系600题','进阶','published','{"globalNumber":526,"sourceNumber":6,"typeLabel":"行程问题","stemRich":[{"text":"甲、乙同时从400米环形跑道的某个点出发，沿相反方向匀速跑步。甲保\n\n持4米/秒的速度，乙第一次与甲相遇时跑了150米，且每次与甲相遇后，其\n速度都提高0.2米/秒。问两人第五次和第六次相遇的位置在跑道上的距离在\n\n以下哪一个区间?"}],"annotatedStemRich":[{"text":"甲、乙同时从400米环形跑道的某个点出发，沿相反方向匀速跑步。甲保\n\n持4米/秒的速度，乙第一次与甲相遇时跑了150米，且每次与甲相遇后，其\n速度都提高0.2米/秒。问两人第五次和第六次相遇的位置在跑道上的距离在\n\n以下哪一个区间?"}],"annotatedOptionRich":{"A":[{"text":"  160～ 170 米"}],"B":[{"text":"  170～ 180 米"}],"C":[{"text":"180～190  米"}],"D":[{"text":"190～200    米\n"}]},"practicalAnalysis":"第一次相遇时，乙走150米，则甲走250米，甲乙速度比= 路程比=250:150=5:3,可求出乙原始速度(提速前)为2.4米/秒；\n第五次相遇后，乙的速度提高到2.4+0.2×5=3.4米/秒⑨,此后的一圈中⑦,\n甲乙路程比=速度比=4:3.4=20:17,乙走了4米，答案为C选项。\n⑥","notes":[{"marker":"⑥","text":"每次相遇速度提升0.2米/ 秒，五次相遇，速度提升五次。","matchScore":0.109},{"marker":"⑦","text":"从第五次相遇开始，到第六次相遇结束，乙走的距离即是两个相遇点的距离。","matchScore":0.118}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500527,4,'概率问题','D. 甲和乙进行半决赛时，甲夺冠可能性大于甲和丙进行半决赛的情况','[{"label":"A","content":"一定存在一种分组方式，丁比丙夺冠的几率更大"},{"label":"B","content":"一定存在一种分组方式，乙夺冠的几率能超过10%。"},{"label":"C","content":"当甲和丁，乙和丙进行半决赛时，甲夺冠的可能性最大"},{"label":"D","content":"甲和乙进行半决赛时，甲夺冠可能性大于甲和丙进行半决赛的情况"}]','D','观察选项可知，C、D 选项为确定情况，只需求得概率即可，但A、B选项要讨论所有可能，所以应先从 C、D 选项考虑：
C选项：半决赛时，甲丁势均力敌，丙胜乙的概率为决赛时无论甲丁，
面对丙均处于劣势，则此时丙夺冠概率显然最大，排除；
D选项：半决赛甲对乙时，甲夺冠的概率为甲战胜乙同时决赛战胜丙(半决赛
丙胜出)或丁(半决赛丁胜出),概率为
半决赛甲对丙时，甲夺冠的概率为甲战胜丙同时决赛战胜乙或丁，则概率为

