INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500530,4,'几何问题','人行步道ABC如图所示，BC两地之间的距离为286米，D地为BC中点， AD两点间的直线距离为324米。现经B点作直线BE, 从C 点作垂直于BE 的直线CE并与BE相交于E点。问EA 之间的最短距离为多少米?
A.38 B.168 C.176 D.181','[{"label":"A","content":"38"},{"label":"B","content":"168"},{"label":"C","content":"176"},{"label":"D","content":"181"}]','D','ED是直角三角形BCE斜边中线，故 ×286=143米。在△ ADE 中，EA+ED>AD, 即 EA>AD-ED;
当点E在AD上时⑤,EA距离最短，此时EA=AD-ED=324-143=181 米，答案为 D 选项。
练习题 5 4 套

⑭花生批注：
斜边中线定理：如果一个三角形是直角三角形，那么这个三角形斜边上的中线等于斜边的一半。

⑮花生批注：
【难度评价】★★★
【 实战解析 】ED是直角三角形BCE斜边中线，故 ×286=143米。在△ ADE 中，EA+ED>AD, 即 EA>AD-ED;
当点E在AD上时⑤,EA距离最短，此时EA=AD-ED=324-143=181 米，答案为 D 选项。
