INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500531,4,'不定方程问题','A、B两个运动队分别有x 人和y 人，两队所有人员刚好组成一个不到100 人的正方形实心方队。在为两个运动队分配运动服时，错给A队分了y 套，给 B队分了x 套。发现后A队将领到的运动服拿出20%给B 队 ，B 队又拿出1套 给A队，此时两队的队员刚好一人分到一套运动服。则x 的值为多少?','[{"label":"A","content":"17"},{"label":"B","content":"25"},{"label":"C","content":"29"},{"label":"D","content":"35"}]','C','由两队人员组成正方形方队可知， x+y 的和为小于100的平方数。A 队的运动服y 减少20%再加1,就等于实际人数 x, 可列等式：x=y- 0.2y+1=0.8y+1。
依次验证选项①.
A项，若x=17, y=20,17+20=37 人，不是平方数，排除；
B项，若x=25,y=30, 25+30=55 人，不是平方数，排除；
C项，若x=29 ,y=35,29+35=64 人，满足题目条件，当选；
D项，若x=35,y=42.5, 不是整数，排除。
答案为C 选项
①

①花生批注：
根据两队运动服数量的等量关系，确定两队人数关系，代入选项验证，看是否符合两队人员组成正方形实心方队这一条件，即两队人数和为平方数。','数量关系600题','进阶','published','{"globalNumber":531,"sourceNumber":1,"typeLabel":"不定方程问题","stemRich":[{"text":"A、B两个运动队分别有x 人和y 人，两队所有人员刚好组成一个不到100 人的正方形实心方队。在为两个运动队分配运动服时，错给A队分了y 套，给 B队分了x 套。发现后A队将领到的运动服拿出20%给B 队 ，B 队又拿出1套 给A队，此时两队的队员刚好一人分到一套运动服。则x 的值为多少?"}],"annotatedStemRich":[{"text":"A、B两个运动队分别有x 人和y 人，两队所有人员刚好组成一个不到100 人的正方形实心方队。在为两个运动队分配运动服时，错给A队分了y 套，给 B队分了x 套。发现后A队将领到的运动服拿出20%给B 队 ，B 队又拿出1套 给A队，此时两队的队员刚好一人分到一套运动服。则x 的值为多少?"}],"annotatedOptionRich":{"A":[{"text":"B两个运动队分别有x 人和y 人，两队所有人员刚好组成一个不到100 人的正方形实心方队。在为两个运动队分配运动服时，错给A队分了y 套，给 B队分了x 套。发现后A队将领到的运动服拿出20%给B 队 ，B 队又拿出1套 给A队，此时两队的队员刚好一人分到一套运动服。则x 的值为多少?\nA.17"}],"B":[{"text":"25"}],"C":[{"text":"29"}],"D":[{"text":"35\n"}]},"practicalAnalysis":"由两队人员组成正方形方队可知， x+y 的和为小于100的平方数。A 队的运动服y 减少20%再加1,就等于实际人数 x, 可列等式：x=y- 0.2y+1=0.8y+1。\n依次验证选项①.\nA项，若x=17, y=20,17+20=37 人，不是平方数，排除；\nB项，若x=25,y=30, 25+30=55 人，不是平方数，排除；\nC项，若x=29 ,y=35,29+35=64 人，满足题目条件，当选；\nD项，若x=35,y=42.5, 不是整数，排除。\n答案为C 选项\n①","notes":[{"marker":"①","text":"根据两队运动服数量的等量关系，确定两队人数关系，代入选项验证，看是否符合两队人员组成正方形实心方队这一条件，即两队人数和为平方数。","matchScore":0.323}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500532,4,'几何问题','某市江滨有一处边长为50米的等边三角形广场。广场里设计有三个大小

