INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500534,4,'排列组合问题','将5个相邻的铺位出租给2家餐厅和2家水果店。要求租完不能有空余铺
