INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500536,4,'统筹规划问题','某水果店销售水果有三种方式：

(1)直接出售，每公斤价格10元，1吨水果一周时间可以全部卖完；
(2)对水果进行粗加工(例如去皮等)后出售，每公斤价格15元，每天
能够售出100公斤；

(3)对水果进行精加工(例如制作水果捞等)后出售，每公斤价格30元，
每天能够售出10公斤。

该水果店进了1吨水果，一周内需要卖完，否则水果就会腐烂。如果上述
三种销售方式可同时组合使用，那么该水果店出售这1吨水果的销售额最大为

多少元?','[{"label":"A","content":"10000"},{"label":"B","content":"14900"},{"label":"C","content":"15000"},{"label":"D","content":"30000"}]','B','据题意可知，精加工单价最高，粗加工其次，若想一周内总销售额最大，则需要多卖单价高的⑥,故一周内总销售额最大的情况为：精加工的卖10×7=70公斤；粗加工的卖100×7=700公斤，直接出售1000-70- 700=230公斤；
最大总销售额=30×70+15×700+10×230=14900元，答案为B选项。','数量关系600题','进阶','published','{"globalNumber":536,"sourceNumber":6,"typeLabel":"统筹规划问题","stemRich":[{"text":"某水果店销售水果有三种方式：\n\n(1)直接出售，每公斤价格10元，1吨水果一周时间可以全部卖完；\n(2)对水果进行粗加工(例如去皮等)后出售，每公斤价格15元，每天\n能够售出100公斤；\n\n(3)对水果进行精加工(例如制作水果捞等)后出售，每公斤价格30元，\n每天能够售出10公斤。\n\n该水果店进了1吨水果，一周内需要卖完，否则水果就会腐烂。如果上述\n三种销售方式可同时组合使用，那么该水果店出售这1吨水果的销售额最大为\n\n多少元?"}],"annotatedStemRich":[{"text":"某水果店销售水果有三种方式：\n\n(1)直接出售，每公斤价格10元，1吨水果一周时间可以全部卖完；\n(2)对水果进行粗加工(例如去皮等)后出售，每公斤价格15元，每天\n能够售出100公斤；\n\n(3)对水果进行精加工(例如制作水果捞等)后出售，每公斤价格30元，\n每天能够售出10公斤。\n\n该水果店进了1吨水果，一周内需要卖完，否则水果就会腐烂。如果上述\n三种销售方式可同时组合使用，那么该水果店出售这1吨水果的销售额最大为\n\n多少元?"}],"annotatedOptionRich":{"A":[{"text":"10000"}],"B":[{"text":"14900"}],"C":[{"text":"15000","bold":true}],"D":[{"text":"30000","bold":true},{"text":"\n"}]},"practicalAnalysis":"据题意可知，精加工单价最高，粗加工其次，若想一周内总销售额最大，则需要多卖单价高的⑥,故一周内总销售额最大的情况为：精加工的卖10×7=70公斤；粗加工的卖100×7=700公斤，直接出售1000-70- 700=230公斤；\n最大总销售额=30×70+15×700+10×230=14900元，答案为B选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500537,4,'行程问题之流水问题','A、B 两座港口相距300公里且仅有1条固定航道，在某一时刻甲船从A港 顺流而下前往B港，同时乙船从B港逆流而上前往A港，甲船在5小时之后抵 达了B港，停留1小时后开始返回A港，又过了6小时追上了乙船。则乙船在 静水中的时速为多少公里?','[{"label":"A","content":"20"},{"label":"B","content":"25"},{"label":"C","content":"30"},{"label":"D","content":"40"}]','C','根据“甲船从A港顺流而下前往B港，甲船在5小时之后抵达了B 港”可列方程：① (V甲+V乙)×5=300 ⑦;
⑦ 花生批注：
V =V +V水 V逆=V船-V 水
流水问题考点离不开速度，抓住船速和水速关系即可。
根据“乙船从B 港逆流而上前往A港，甲船停留1小时后开始返回 A 港，又过了6小时追上了乙船”可列方程：② (V甲-V水)×6=(V乙-V水)×(5+1+6),
联立①②,解得 V乙=30公里/小时，答案为C 选项。

⑦花生批注：
V =V +V水 V逆=V船-V 水
流水问题考点离不开速度，抓住船速和水速关系即可。
根据“乙船从B 港逆流而上前往A港，甲船停留1小时后开始返回 A 港，又过了6小时追上了乙船”可列方程：② (V甲-V水)×6=(V乙-V水)×(5+1+6),
联立①②,解得 V乙=30公里/小时，答案为C 选项。','数量关系600题','进阶','published','{"globalNumber":537,"sourceNumber":7,"typeLabel":"行程问题之流水问题","stemRich":[{"text":"A、B 两座港口相距300公里且仅有1条固定航道，在某一时刻甲船从A港 顺流而下前往B港，同时乙船从B港逆流而上前往A港，甲船在5小时之后抵 达了B港，停留1小时后开始返回A港，又过了6小时追上了乙船。则乙船在 静水中的时速为多少公里?"}],"annotatedStemRich":[{"text":"A、B 两座港口相距300公里且仅有1条固定航道，在某一时刻甲船从A港 顺流而下前往B港，同时乙船从B港逆流而上前往A港，甲船在5小时之后抵 达了B港，停留1小时后开始返回A港，又过了6小时追上了乙船。则乙船在 静水中的时速为多少公里?"}],"annotatedOptionRich":{"A":[{"text":"B 两座港口相距300公里且仅有1条固定航道，在某一时刻甲船从A港 顺流而下前往B港，同时乙船从B港逆流而上前往A港，甲船在5小时之后抵 达了B港，停留1小时后开始返回A港，又过了6小时追上了乙船。则乙船在 静水中的时速为多少公里?\n"},{"text":"练习题54套","bold":true},{"text":"\n"},{"text":"四","bold":true},{"text":" "},{"text":"海","bold":true},{"text":" "},{"text":"公","bold":true},{"text":" "},{"text":"考","bold":true},{"text":"\n"},{"text":"SIHAIGONGKAO","bold":true},{"text":"\n"},{"text":"A.20","bold":true}],"B":[{"text":"25","bold":true}],"C":[{"text":"30"}],"D":[{"text":"40\n"}]},"practicalAnalysis":"根据“甲船从A港顺流而下前往B港，甲船在5小时之后抵达了B 港”可列方程：① (V甲+V乙)×5=300 ⑦;\n⑦ 花生批注：\nV =V +V水 V逆=V船-V 水\n流水问题考点离不开速度，抓住船速和水速关系即可。\n根据“乙船从B 港逆流而上前往A港，甲船停留1小时后开始返回 A 港，又过了6小时追上了乙船”可列方程：② (V甲-V水)×6=(V乙-V水)×(5+1+6),\n联立①②,解得 V乙=30公里/小时，答案为C 选项。","notes":[{"marker":"⑦","text":"V =V +V水 V逆=V船-V 水\n流水问题考点离不开速度，抓住船速和水速关系即可。\n根据“乙船从B 港逆流而上前往A港，甲船停留1小时后开始返回 A 港，又过了6小时追上了乙船”可列方程：② (V甲-V水)×6=(V乙-V水)×(5+1+6),\n联立①②,解得 V乙=30公里/小时，答案为C 选项。","matchScore":0.881}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500538,4,'概率问题','某班级只有两个宿舍的男生，每宿舍4人。每周从这8人中随机抽取一人
担任周管理员，同一人不连续两周担任管理员。问开学前三周的管理员都来自

同一宿舍的概率在以下哪个范围?','[{"label":"A","content":"0%～10%"},{"label":"B","content":"10%～20%"},{"label":"C","content":"20%～30%"},{"label":"D","content":"30%～40%"}]','B','第一周可任选1人做管理员⑧,第二周管理员出自同一宿舍概率为 ,第三周依然出自同一宿舍的概率为 ,即三周出自同一宿舍概率为
,接近20%,答案为B选项。
⑧

⑧花生批注：
可看作三人同组问题，第一周无需考虑，只需考虑后两周的安排。','数量关系600题','进阶','published','{"globalNumber":538,"sourceNumber":8,"typeLabel":"概率问题","stemRich":[{"text":"某班级只有两个宿舍的男生，每宿舍4人。每周从这8人中随机抽取一人\n担任周管理员，同一人不连续两周担任管理员。问开学前三周的管理员都来自\n\n同一宿舍的概率在以下哪个范围?"}],"annotatedStemRich":[{"text":"某班级只有两个宿舍的男生，每宿舍4人。每周从这8人中随机抽取一人\n担任周管理员，同一人不连续两周担任管理员。问开学前三周的管理员都来自\n\n同一宿舍的概率在以下哪个范围?"}],"annotatedOptionRich":{"A":[{"text":"0%～10%"}],"B":[{"text":"10%～20%"}],"C":[{"text":"20%～30%"}],"D":[{"text":"30%～40%\n"}]},"practicalAnalysis":"第一周可任选1人做管理员⑧,第二周管理员出自同一宿舍概率为 ,第三周依然出自同一宿舍的概率为 ,即三周出自同一宿舍概率为\n,接近20%,答案为B选项。\n⑧","notes":[{"marker":"⑧","text":"可看作三人同组问题，第一周无需考虑，只需考虑后两周的安排。","matchScore":0.068}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500539,4,'工程问题+统筹规划问题','有甲乙两个工程队负责某小区主干道维修及墙面粉刷。主干道维修，如果
两个工程队合作，30天完成，若乙工程队单独进行，105天完成；粉刷墙面，
若两个工程队合作，28天完成，若甲工程队单独做，140天完成。如果两项工

作两个工程队共同分工合作，最少需要多少天?','[{"label":"A","content":"34"},{"label":"B","content":"35"},{"label":"C","content":"40"},{"label":"D","content":"41"}]','C','首先需要判断两个工程队擅长的工作：
道路维修，设工作量为最小公倍数210,则乙效率为2,甲乙效率和为7, 甲效率为5;
粉刷墙面，设工作量为最小公倍数140,则甲效率为1,甲乙效率和为5, 乙效率为4;
由此可知，应安排甲进行道路维修，安排乙做粉刷墙面。
乙粉刷墙面需要140÷4=35天，此时甲道路维修已完成35×5=175份，剩余210-175=35份，二人合作还需35÷7=5天；
综上，最少需要35+5=40天，答案为C 选项。','数量关系600题','进阶','published','{"globalNumber":539,"sourceNumber":9,"typeLabel":"工程问题+统筹规划问题","stemRich":[{"text":"有甲乙两个工程队负责某小区主干道维修及墙面粉刷。主干道维修，如果\n两个工程队合作，30天完成，若乙工程队单独进行，105天完成；粉刷墙面，\n若两个工程队合作，28天完成，若甲工程队单独做，140天完成。如果两项工\n\n作两个工程队共同分工合作，最少需要多少天?"}],"annotatedStemRich":[{"text":"有甲乙两个工程队负责某小区主干道维修及墙面粉刷。主干道维修，如果\n两个工程队合作，30天完成，若乙工程队单独进行，105天完成；粉刷墙面，\n若两个工程队合作，28天完成，若甲工程队单独做，140天完成。如果两项工\n\n作两个工程队共同分工合作，最少需要多少天?"}],"annotatedOptionRich":{"A":[{"text":"34"}],"B":[{"text":"35"}],"C":[{"text":"40"}],"D":[{"text":"41\n"}]},"practicalAnalysis":"首先需要判断两个工程队擅长的工作：\n道路维修，设工作量为最小公倍数210,则乙效率为2,甲乙效率和为7, 甲效率为5;\n粉刷墙面，设工作量为最小公倍数140,则甲效率为1,甲乙效率和为5, 乙效率为4;\n由此可知，应安排甲进行道路维修，安排乙做粉刷墙面。\n乙粉刷墙面需要140÷4=35天，此时甲道路维修已完成35×5=175份，剩余210-175=35份，二人合作还需35÷7=5天；\n综上，最少需要35+5=40天，答案为C 选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500540,4,'排列组合问题+容斥问题','农科院派出6名科技人员支援甲、乙、丙三个县农业发展，每个县分配2人。

其中精通农业、牧业和渔业技术的分别有3人、3人和2人。有2人同时精通
农业和牧业技术、且精通渔业技术的人均不精通农业和牧业技术，已知丙县因

无条件发展渔业只需要农业和牧业技术专家，甲县和乙县都需要掌握3类技术
的专家支援，问有多少种不同的安排方式?','[{"label":"A","content":"4"},{"label":"B","content":"8"},{"label":"C","content":"15"},{"label":"D","content":"30"}]','A','根据题意可知，只精通渔业的有2人，余下4人中，精通农业、牧业的均有3人，则二者均精通的有3+3-4=2人，仅精通农业的有3-2=1人，仅精通牧业的有3-2=1人⑨;
因为只有2人精通渔业，甲、乙县都需要掌握渔业技术的专家，则这2人需要分别去甲、乙县，有A2种安排；又因为此2人只精通渔业(不精通另外两项技术)且甲、乙县还需要会农业、牧业的专家，则两县的另外一位专家只能是既会农业又会牧业的2位专家之一，有A2种安排；剩余两位仅会农业和仅会牧业的专家支援丙县；
综上，一共有A²×A²=4 种安排，答案为A选项。

⑨花生批注：
精通农业精通牧业
