INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500541,4,'和差倍比问题','某家庭有爸爸、妈妈、女儿3人，今年每2人的平均年龄加上余下1人的
年龄之和，分别为39、52、53,则3人中最大年龄与最小年龄之差为多少岁?','[{"label":"A","content":"22"},{"label":"B","content":"24"},{"label":"C","content":"26"},{"label":"D","content":"28"}]','D','设三个人年龄分别为a 、b 、c, 两人年龄和加上第三人年龄的2倍分别等于78、104、106①:
