INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500542,4,'不定方程问题','某学校有一笔信息化预算，用这笔预算正好可以购买16部台式电脑，或

者台式电脑、笔记本电脑和投影机各4台。 已知2台笔记本电脑的价格等于1
部台式电脑和1部投影机的价格之和，则用这笔预算购买笔记本电脑和投影机
且必须全部花完，最多可以买多少台投影机?','[{"label":"A","content":"5"},{"label":"B","content":"8"},{"label":"C","content":"10"},{"label":"D","content":"13"}]','B','设台式电脑、笔记本电脑、投影机单价分别为 x 元、y 元、z 元。可列式①16x=4(x+y+z),②2y=(x+z), 解得x:y :z=3:4:5。
