INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500545,4,'经济利润问题','某电子厂生产了一款新型电池，由于今年电池原材料价格大幅上涨，这款

新型电池的成本与去年相比上升了30%。为了推销这款新型电池，该电子厂仍
以去年的价格出售，每个新型电池的盈利下降37.5%,但销量与去年相比增加

了70%,则今年该电子厂生产这款新型电池的总盈利与去年相比增加了多少?','[{"label":"A","content":"4.75%"},{"label":"B","content":"5.25%"},{"label":"C","content":"5.75%"},{"label":"D","content":"6.25%"}]','D','总盈利=单个盈利×销量， R单个盈利=-37.5%, R=70%, 则 R总盈利=-37.5%+70%-37.5%×70%=6.25%⑧, 答案为D 选项。
此题可用赋值法进行解题，将去年的盈利赋值为100,可得今年盈利为100×(1-37.5%)=62.5;将去年的销量赋值为10,可得今年销量为 10×(1+70%)=17。
则今年总盈利为62.5×17=1062.5,去年总盈利=100×10=1000,则今年总盈利较去年增加6.25%,答案为D 选项。
④

④花生批注：
所用公式为乘积增长率公式，R=R₁+R₂+R₁R₂;
PS: 37.
总盈利只和单个盈利和销量有关，题目中成本的变化为干扰条件。

⑧花生批注：
2x²=(27+23)×(27-23) =50×4,即x²=100。
练习题 5 6 套
IHA海IGON公G KO','数量关系600题','进阶','published','{"globalNumber":545,"sourceNumber":5,"typeLabel":"经济利润问题","stemRich":[{"text":"某电子厂生产了一款新型电池，由于今年电池原材料价格大幅上涨，这款\n\n新型电池的成本与去年相比上升了30%。为了推销这款新型电池，该电子厂仍\n以去年的价格出售，每个新型电池的盈利下降37.5%,但销量与去年相比增加\n\n了70%,则今年该电子厂生产这款新型电池的总盈利与去年相比增加了多少?"}],"annotatedStemRich":[{"text":"某电子厂生产了一款新型电池，由于今年电池原材料价格大幅上涨，这款\n\n新型电池的成本与去年相比上升了30%。为了推销这款新型电池，该电子厂仍\n以去年的价格出售，每个新型电池的盈利下降37.5%,但销量与去年相比增加\n\n了70%,则今年该电子厂生产这款新型电池的总盈利与去年相比增加了多少?"}],"annotatedOptionRich":{"A":[{"text":"4.75%"}],"B":[{"text":"5.25%"}],"C":[{"text":"5.75%"}],"D":[{"text":"6.25%\n"}]},"practicalAnalysis":"总盈利=单个盈利×销量， R单个盈利=-37.5%, R=70%, 则 R总盈利=-37.5%+70%-37.5%×70%=6.25%⑧, 答案为D 选项。\n此题可用赋值法进行解题，将去年的盈利赋值为100,可得今年盈利为100×(1-37.5%)=62.5;将去年的销量赋值为10,可得今年销量为 10×(1+70%)=17。\n则今年总盈利为62.5×17=1062.5,去年总盈利=100×10=1000,则今年总盈利较去年增加6.25%,答案为D 选项。\n④","notes":[{"marker":"④","text":"所用公式为乘积增长率公式，R=R₁+R₂+R₁R₂;\nPS: 37.\n总盈利只和单个盈利和销量有关，题目中成本的变化为干扰条件。","matchScore":0.078},{"marker":"⑧","text":"2x²=(27+23)×(27-23) =50×4,即x²=100。\n练习题 5 6 套\nIHA海IGON公G KO","matchScore":0.03}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500546,4,'统筹规划问题','师徒二人在非遗展馆现场为游客剪纸，有6名游客各自挑选了心仪的花样。
已知徒弟制作这6种剪纸的时间分别为2、6、10、12、15、25(单位：分钟),
师傅的工作效率是徒弟的1.5倍，则这6名游客中最后一个拿到剪纸的游客，

需要等待的时间至少是多少分钟?','[{"label":"A","content":"25分钟"},{"label":"B","content":"27分钟"},{"label":"C","content":"28 分钟"},{"label":"D","content":"30 分钟"}]','C','题目中给了工作效率比，赋值徒弟工作效率为2,师傅工作效率3,工作总量=时间×效率=(2+6+10+12+15+25)×2=140。理想情况下，师徒合作完工需要140÷(2+3)=28分钟。
但需要判断28分钟是否恰好能完成6种剪纸，徒弟在28分钟可完成6分钟、 10分钟、12分钟的剪纸，师傅28分钟内可完成徒弟需要2分钟、15分钟、25 分钟完成的剪纸⑤。
则最后一个拿到剪纸的游客，需要等待28分钟，答案为C 选项。

⑤花生批注：
