INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500547,4,'统筹规划问题','甲、乙两地受灾，政府从丙、丁两地分别调集100吨和60吨救灾物资。
已知甲、乙两地各需救灾物资80吨，丙地到甲地、丙地到乙地、丁地到甲地、

丁地到乙地的每吨运价之比为7:4:6:5。问总运输成本可能的最高值比最
低值高多少?','[{"label":"A","content":"不到10%"},{"label":"B","content":"10%～15% 之间"},{"label":"C","content":"15%～20% 之间"},{"label":"D","content":"20% 以上"}]','B','根据运价之比可知，丙向乙运输最便宜，丙向甲运输最贵。则要使总运输成本尽量高，丙应多向甲运输：
丙地100吨物资
甲地80吨
运费=80×7=560元
乙地20吨
运费=20×4=80元
丁地60吨物资
乙地60吨
运费=60×5=300元
要使总运输成本尽量低，丙应多向乙运输：
丙地100吨物资
甲地20吨
运费=20×7=140元
乙地80吨
运费=80×4=320元
丁地60吨物资
甲地60吨
运费=60×6=360元
综上，运输成本最高值为940元，最低值为820,则前者比后者多稍小于15%,答案为B 选项。
