INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500553,4,'统筹规划问题','某单位n名职工参加安全生产和劳动保障两门考试，分别有x人和y人合格。
