INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500555,4,'排列组合问题','某单位组织干部员工分5批进行业务培训，培训地点有甲、乙、丙三个地方，

每个地方至少安排一批。受接待能力影响，第一、二批不去甲地，问有多少种
安排方式?','[{"label":"A","content":"52"},{"label":"B","content":"72"},{"label":"C","content":"62"},{"label":"D","content":"82"}]','C','5批员工去三个地方，每个地方至少安排一批，可分为113 和122两种安排方式；
若为“113”,根据甲分得1批和3批继续分类讨论：
若甲分得1批，则甲从后三批选1批，即C³,再从剩余四批中选出3批，即C³, 将此3批和剩余1批分给乙丙，即A2, 有 C³×c³×A²=24 种安排；
若甲分得3批，则甲一定分得后三批，另外两批分给乙丙，即A2,有2种安排；若为“122”,根据甲分得1批和2批继续分类讨论：
若甲分得1批，则甲从后三批选1批，即C₃, 再从剩余4批中为乙选择2批，即C2, 剩余2批分给丙，有C³×c²=18 种安排；
若甲分得2批，则甲从后三批选2批，即C³, 再从剩余3批中选出2批，即C³, 将此2批和剩余1批分给乙丙，即A2, 有 C³×C²×A²=18 种安排；
④','数量关系600题','进阶','published','{"globalNumber":555,"sourceNumber":5,"typeLabel":"排列组合问题⑤","stemRich":[{"text":"某单位组织干部员工分5批进行业务培训，培训地点有甲、乙、丙三个地方，\n\n每个地方至少安排一批。受接待能力影响，第一、二批不去甲地，问有多少种\n安排方式?"}],"annotatedStemRich":[{"text":"某单位组织干部员工分5批进行业务培训，培训地点有甲、乙、丙三个地方，\n\n每个地方至少安排一批。受接待能力影响，第一、二批不去甲地，问有多少种\n安排方式?"}],"annotatedOptionRich":{"A":[{"text":"52"}],"B":[{"text":"72"}],"C":[{"text":"62","bold":true}],"D":[{"text":"82","bold":true},{"text":"\n"}]},"practicalAnalysis":"5批员工去三个地方，每个地方至少安排一批，可分为113 和122两种安排方式；\n若为“113”,根据甲分得1批和3批继续分类讨论：\n若甲分得1批，则甲从后三批选1批，即C³,再从剩余四批中选出3批，即C³, 将此3批和剩余1批分给乙丙，即A2, 有 C³×c³×A²=24 种安排；\n若甲分得3批，则甲一定分得后三批，另外两批分给乙丙，即A2,有2种安排；若为“122”,根据甲分得1批和2批继续分类讨论：\n若甲分得1批，则甲从后三批选1批，即C₃, 再从剩余4批中为乙选择2批，即C2, 剩余2批分给丙，有C³×c²=18 种安排；\n若甲分得2批，则甲从后三批选2批，即C³, 再从剩余3批中选出2批，即C³, 将此2批和剩余1批分给乙丙，即A2, 有 C³×C²×A²=18 种安排；\n④","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500556,4,'最值问题之最不利极限题','某单位组织干部员工分5批进行业务培训，培训地点有甲、乙、丙三个地方，

每个地方至少安排一批。受接待能力影响，第一、二批不去甲地，问有多少种
安排方式?','[{"label":"A","content":"20"},{"label":"B","content":"19"},{"label":"C","content":"21"},{"label":"D","content":"22"}]','B','由问法“至少…一定”可判定本题为最不利极限题。要求5 个人来自同一科室且每个科室最少留1人值班，最不利情况为每个科室分别来 2、4、4、4、4人，共18人，此时再抽调1人(18+1=19)即可保证一定有5人来自同一科室，答案为B 选项。','数量关系600题','进阶','published','{"globalNumber":556,"sourceNumber":6,"typeLabel":"最值问题之最不利极限题","stemRich":[{"text":"某单位组织干部员工分5批进行业务培训，培训地点有甲、乙、丙三个地方，\n\n每个地方至少安排一批。受接待能力影响，第一、二批不去甲地，问有多少种\n安排方式?"}],"annotatedStemRich":[{"text":"某单位组织干部员工分5批进行业务培训，培训地点有甲、乙、丙三个地方，\n\n每个地方至少安排一批。受接待能力影响，第一、二批不去甲地，问有多少种\n安排方式?"}],"annotatedOptionRich":{"A":[{"text":"20"}],"B":[{"text":"19"}],"C":[{"text":"21"}],"D":[{"text":"22\n"}]},"practicalAnalysis":"由问法“至少…一定”可判定本题为最不利极限题。要求5 个人来自同一科室且每个科室最少留1人值班，最不利情况为每个科室分别来 2、4、4、4、4人，共18人，此时再抽调1人(18+1=19)即可保证一定有5人来自同一科室，答案为B 选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500557,4,'行程问题','小明每天从家中出发骑自行车经过一段平路，再经过一道斜坡后到达学校上课。某天早上，小明从家中骑车出发，一到校门口就发现忘带课本，马上返回，从离家到赶回家中共用了1个小时，假设小明当天平路骑行速度为9千米 /小时，上坡速度为6千米/小时，下坡速度为18千米/小时，那么小明的家距离学校多远?','[{"label":"A","content":"3.5 千米"},{"label":"B","content":"4.5 千米"},{"label":"C","content":"5.5 千米"},{"label":"D","content":"6.5 千米"}]','B','去时上坡的路段，回程下坡，则等距离平均速 =9 ⑥km/h; 同理，去时下坡的路段，回程上坡，平均速度也为9km/h, 因为平路骑行速度为9千米/小时则往返路程的平均速度为9km/h。
往返共用1小时，则共走了9km, 家距离学校距离为4.5km,答案为B 选项。

⑥花生批注：
等距离平均速度公式为：
可拓展为： A=B×C, 若 A 相等，B或C的平均值均可运用此公式；
例如，总售价=单价×数量，若两件商品总售价相等，则平均单价也为调和平均数。
综上，一共有24+2+18+18=62种安排方式，答案为C 选项。','数量关系600题','进阶','published','{"globalNumber":557,"sourceNumber":7,"typeLabel":"行程问题","stemRich":[{"text":"小明每天从家中出发骑自行车经过一段平路，再经过一道斜坡后到达学校 上课。某天早上，小明从家中骑车出发，一到校门口就发现忘带课本，马上返 回，从离家到赶回家中共用了1个小时，假设小明当天平路骑行速度为9千米 /小时，上坡速度为6千米/小时，下坡速度为18千米/小时，那么小明的家 距离学校多远?"}],"annotatedStemRich":[{"text":"小明每天从家中出发骑自行车经过一段平路，再经过一道斜坡后到达学校 上课。某天早上，小明从家中骑车出发，一到校门口就发现忘带课本，马上返 回，从离家到赶回家中共用了1个小时，假设小明当天平路骑行速度为9千米 /小时，上坡速度为6千米/小时，下坡速度为18千米/小时，那么小明的家 距离学校多远?"}],"annotatedOptionRich":{"A":[{"text":"3.5 千米"}],"B":[{"text":"4.5    "},{"text":"千米","bold":true}],"C":[{"text":"  5.5 千米"}],"D":[{"text":"6.5    "},{"text":"千","bold":true},{"text":" "},{"text":"米","bold":true},{"text":"\n"}]},"practicalAnalysis":"去时上坡的路段，回程下坡，则等距离平均速 =9 ⑥km/h; 同理，去时下坡的路段，回程上坡，平均速度也为9km/h, 因为平路骑行速度为9千米/小时则往返路程的平均速度为9km/h。\n往返共用1小时，则共走了9km, 家距离学校距离为4.5km,答案为B 选项。","notes":[{"marker":"⑥","text":"等距离平均速度公式为：\n可拓展为： A=B×C, 若 A 相等，B或C的平均值均可运用此公式；\n例如，总售价=单价×数量，若两件商品总售价相等，则平均单价也为调和平均数。\n综上，一共有24+2+18+18=62种安排方式，答案为C 选项。","matchScore":0.126}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500558,4,'几何问题','一个半径300米的圆形湖泊中有一个半径100米的圆形人工岛，该人工岛的中心在湖泊中心的正西方150米处。甲从湖正北的A 点开船出发，绕行人工岛西侧到达正南的B点。如果保持最短路线行驶，那么行驶多少米后甲到达人工岛的岸边?','[{"label":"A","content":"150√5- 100"},{"label":"B","content":"300"},{"label":"C","content":"50√41"},{"label":"D","content":"200√3"}]','C','如图所示②:要保持最短行驶路线，从A点向圆形小岛做切线，相切于点C, 设 0 、D分别为湖泊和人工岛的圆心，则CD ⊥AC,A0 ⊥OD;
在直角 △ AOD 中，AD²=DO²+AO²=112500 米。在直角 △ ACD 中，AC²=AD²- CD²=102500 米，则 AC=√102500 =50 √41米，答案为C 选项。
⑦

⑧花生批注：
因人工岛为陆地，不能划船，则应沿切线AC 到达人工岛，在绕道环形，之后再沿切线直线到达 B点。','数量关系600题','进阶','published','{"globalNumber":558,"sourceNumber":8,"typeLabel":"几何问题","stemRich":[{"text":"一个半径300米的圆形湖泊中有一个半径100米的圆形人工岛，该人工岛 的中心在湖泊中心的正西方150米处。甲从湖正北的A 点开船出发，绕行人工 岛西侧到达正南的B点。如果保持最短路线行驶，那么行驶多少米后甲到达人 工岛的岸边?"}],"annotatedStemRich":[{"text":"一个半径300米的圆形湖泊中有一个半径100米的圆形人工岛，该人工岛 的中心在湖泊中心的正西方150米处。甲从湖正北的A 点开船出发，绕行人工 岛西侧到达正南的B点。如果保持最短路线行驶，那么行驶多少米后甲到达人 工岛的岸边?"}],"annotatedOptionRich":{"A":[{"text":"150√5- 100"}],"B":[{"text":"300"}],"C":[{"text":"50√41"}],"D":[{"text":"200√3\n"}]},"practicalAnalysis":"如图所示②:要保持最短行驶路线，从A点向圆形小岛做切线，相切于点C, 设 0 、D分别为湖泊和人工岛的圆心，则CD ⊥AC,A0 ⊥OD;\n在直角 △ AOD 中，AD²=DO²+AO²=112500 米。在直角 △ ACD 中，AC²=AD²- CD²=102500 米，则 AC=√102500 =50 √41米，答案为C 选项。\n⑦","notes":[{"marker":"⑧","text":"因人工岛为陆地，不能划船，则应沿切线AC 到达人工岛，在绕道环形，之后再沿切线直线到达 B点。","matchScore":0.095}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500559,4,'日期星期问题','某月有五个星期三，且这五个星期三的日期之和恰好为80。那么这个月第

