INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500560,4,'等差数列','把2022到1的所有整数按下图所示规律依次排列，2022排在第 一 行，从

第二行开始，每 一 行比前 一 行多两个数，则第30行中间的数是多少?
2022

2021 2020 2019
2018 2017 2016 2015 2014','[{"label":"A","content":"1092"},{"label":"B","content":"1152"},{"label":"C","content":"1210"},{"label":"D","content":"1320"}]','B','观察可知：第2行中间=2022 - 2,第3行中间=2022- (2+4),
第4行中间=2022 - (2+4+6),第 5 行中间=2022-(2+4+6+8),……
由此可推得规律，第 n 行中间=2022-[2+4+6+8…+ 2(n-1)⑨];

⑨花生批注：
第3项的该位置数字：4
第4项的该位置数字：6
第5项的该位置数字：8
第 n 项的该位置数字： 2(n-1)。','数量关系600题','进阶','published','{"globalNumber":560,"sourceNumber":10,"typeLabel":"等差数列","stemRich":[{"text":"把2022到1的所有整数按下图所示规律依次排列，2022排在第 一 行，从\n\n第二行开始，每 一 行比前 一 行多两个数，则第30行中间的数是多少?\n2022\n\n2021 2020 2019\n2018 2017 2016 2015 2014"}],"annotatedStemRich":[{"text":"把2022到1的所有整数按下图所示规律依次排列，2022排在第 一 行，从\n\n第二行开始，每 一 行比前 一 行多两个数，则第30行中间的数是多少?\n2022\n\n2021 2020 2019\n2018 2017 2016 2015 2014"}],"annotatedOptionRich":{"A":[{"text":"1092"}],"B":[{"text":"1152"}],"C":[{"text":"1210"}],"D":[{"text":"1320\n"}]},"practicalAnalysis":"观察可知：第2行中间=2022 - 2,第3行中间=2022- (2+4),\n第4行中间=2022 - (2+4+6),第 5 行中间=2022-(2+4+6+8),……\n由此可推得规律，第 n 行中间=2022-[2+4+6+8…+ 2(n-1)⑨];","notes":[{"marker":"⑨","text":"第3项的该位置数字：4\n第4项的该位置数字：6\n第5项的该位置数字：8\n第 n 项的该位置数字： 2(n-1)。","matchScore":0.111}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500561,4,'工程问题','某报社引进人工智能提高审稿效率。其审核部门甲、乙和丙审阅一份稿件

分别需要10分钟、8分钟和6分钟，3人一天最多可审阅188份稿件。而AI
审稿每份仅需3分钟，审核稿件中的70%可正常完结，剩余30%争议稿件仍需

人工重新审核。若某天甲因故请假，则当天乙、丙和人工智能(其与人的工作
时间相同)最多可审阅的稿件总数为多少份?','[{"label":"A","content":"252 份"},{"label":"B","content":"264 份"},{"label":"C","content":"300 份"},{"label":"D","content":"320 份"}]','A','由“其审核部门甲、乙和丙审阅一份稿件分别需要10分钟、 8分钟和6分钟”,可知，甲、乙和丙每小时审阅的稿件数分别为6份、7.5 份和10份；
由“3人一天最多可审阅188份”,可得一天的工作时间=188÷(6+7.5+10)=8 小时。
已知 Al 每小时可审阅60÷3=20份，其中的70%可正常完结，剩余30%仍需人工重审，即 AI 每小时可正常完结20×70%=14份；
即一天乙、丙和人工智能最多可审阅的稿件总数=(7.5+10+14)×8=252 份①,答案为A选项。
①

①花生批注：
只需考虑AI 正常审阅的份数，和乙丙每日工作量的份数即可，乙丙是否帮助 AI 重审稿件，不影响三者总数。','数量关系600题','进阶','published','{"globalNumber":561,"sourceNumber":1,"typeLabel":"工程问题","stemRich":[{"text":"某报社引进人工智能提高审稿效率。其审核部门甲、乙和丙审阅一份稿件\n\n分别需要10分钟、8分钟和6分钟，3人一天最多可审阅188份稿件。而AI\n审稿每份仅需3分钟，审核稿件中的70%可正常完结，剩余30%争议稿件仍需\n\n人工重新审核。若某天甲因故请假，则当天乙、丙和人工智能(其与人的工作\n时间相同)最多可审阅的稿件总数为多少份?"}],"annotatedStemRich":[{"text":"某报社引进人工智能提高审稿效率。其审核部门甲、乙和丙审阅一份稿件\n\n分别需要10分钟、8分钟和6分钟，3人一天最多可审阅188份稿件。而AI\n审稿每份仅需3分钟，审核稿件中的70%可正常完结，剩余30%争议稿件仍需\n\n人工重新审核。若某天甲因故请假，则当天乙、丙和人工智能(其与人的工作\n时间相同)最多可审阅的稿件总数为多少份?"}],"annotatedOptionRich":{"A":[{"text":"  252 份"}],"B":[{"text":"264  份"}],"C":[{"text":" 300 份"}],"D":[{"text":"  320 份\n"}]},"practicalAnalysis":"由“其审核部门甲、乙和丙审阅一份稿件分别需要10分钟、 8分钟和6分钟”,可知，甲、乙和丙每小时审阅的稿件数分别为6份、7.5 份和10份；\n由“3人一天最多可审阅188份”,可得一天的工作时间=188÷(6+7.5+10)=8 小时。\n已知 Al 每小时可审阅60÷3=20份，其中的70%可正常完结，剩余30%仍需人工重审，即 AI 每小时可正常完结20×70%=14份；\n即一天乙、丙和人工智能最多可审阅的稿件总数=(7.5+10+14)×8=252 份①,答案为A选项。\n①","notes":[{"marker":"①","text":"只需考虑AI 正常审阅的份数，和乙丙每日工作量的份数即可，乙丙是否帮助 AI 重审稿件，不影响三者总数。","matchScore":0.097}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500562,4,'牛吃草问题','早上7点之前，某小区门口停有100辆共享单车。7点开始，每20秒就有

一辆共享单车被骑走。共享单车企业雇佣三轮车从附近的地铁站将无人使用的
车辆拉到小区门口，7点拉来第一趟，往后每15分钟拉一趟，每趟拉来30辆

共享单车。则下列哪个时间段会出现小区门口没有共享单车的情况?(不存在
共享单车损坏和被骑来小区门口的情况)','[{"label":"A","content":"8 点21分至25分"},{"label":"B","content":"8 点36分至40分"},{"label":"C","content":"8 点41分至45分"},{"label":"D","content":"8 点46分至50分"}]','C','7点时小区门口有100辆共享单车(称之为库存车)。从7 点起每15分钟拉来30辆，骑走15×60÷20=45辆②,所以每15分钟会减少15 辆库存车，即1分钟减少1辆库存车。
100辆库存车能坚持100分钟，即8点41分开始出现没车的情况，答案为 C选项。

②花生批注：
也可以理解为每分钟骑走 3辆，每分钟拉来2辆，一分钟要消耗一辆库存车。','数量关系600题','进阶','published','{"globalNumber":562,"sourceNumber":2,"typeLabel":"牛吃草问题","stemRich":[{"text":"早上7点之前，某小区门口停有100辆共享单车。7点开始，每20秒就有\n\n一辆共享单车被骑走。共享单车企业雇佣三轮车从附近的地铁站将无人使用的\n车辆拉到小区门口，7点拉来第一趟，往后每15分钟拉一趟，每趟拉来30辆\n\n共享单车。则下列哪个时间段会出现小区门口没有共享单车的情况?(不存在\n共享单车损坏和被骑来小区门口的情况)"}],"annotatedStemRich":[{"text":"早上7点之前，某小区门口停有100辆共享单车。7点开始，每20秒就有\n\n一辆共享单车被骑走。共享单车企业雇佣三轮车从附近的地铁站将无人使用的\n车辆拉到小区门口，7点拉来第一趟，往后每15分钟拉一趟，每趟拉来30辆\n\n共享单车。则下列哪个时间段会出现小区门口没有共享单车的情况?(不存在\n共享单车损坏和被骑来小区门口的情况)"}],"annotatedOptionRich":{"A":[{"text":"8  点21分至25分"}],"B":[{"text":"8   点36分至40分"}],"C":[{"text":"8  点41分至45分"}],"D":[{"text":"8   点46分至50分\n"}]},"practicalAnalysis":"7点时小区门口有100辆共享单车(称之为库存车)。从7 点起每15分钟拉来30辆，骑走15×60÷20=45辆②,所以每15分钟会减少15 辆库存车，即1分钟减少1辆库存车。\n100辆库存车能坚持100分钟，即8点41分开始出现没车的情况，答案为 C选项。","notes":[{"marker":"②","text":"也可以理解为每分钟骑走 3辆，每分钟拉来2辆，一分钟要消耗一辆库存车。","matchScore":0.12}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500563,4,'排列组合问题','某智能停车场泊车的泊车位置由电脑随机派位生成。现有两排车位，每排

4个，有4辆不同的车需要泊车。泊车要求至少有一车与其它车不同排，且甲、
乙两车在同一排。则电脑可生成多少种派位方式?','[{"label":"A","content":"672"},{"label":"B","content":"480"},{"label":"C","content":"384"},{"label":"D","content":"288"}]','A','有“至少”字样，可考虑全部减不符。
全部的情况：甲、乙同一排，其他两辆任意停车，先为甲、乙选择一排且有顺序的选择2个位置，即C2×A², 其他两辆车在剩余的6个位置中有顺序
的任选2个，即A2, 共有种情况；
不符的情况：四辆车均停在同一排，先选择一排再全排列，即
=48种情况；
