INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500564,4,'几何问题','如图所示，则∠A+∠B+∠C+∠D+∠E+∠ F 的度数是多少度?





