INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500566,4,'和差倍比问题','甲单位的员工人数是乙单位的1.5倍，两个单位的女性员工分别占该单位

人数的60%和50%。现从甲单位调10名男性员工到乙单位，从乙单位调10名
女性员工到甲单位，此时两个单位的男性员工人数相同。问此时甲单位的女性

员工人数比乙单位多多少人?','[{"label":"A","content":"60"},{"label":"B","content":"80"},{"label":"C","content":"100"},{"label":"D","content":"120"}]','C','设原来甲单位人数为15x, 乙单位为10x, 故原来两个单位男员工人数分别为15x×(1-60%)=6x 、10x×(1-50%)=5x;
甲、乙单位互换10名男、女员工后，男性员工人数相等，则原来甲单位男员工比乙单位男员工多20人，即6x-5x=20, 解得x=20;
原来甲单位有女员工9x=180, 调来10人后为190人；原来乙单位有女员工5x=100, 调走10人后为90人，即现在甲单位女员工比乙单位多190- 90=100人，答案为C选项。','数量关系600题','进阶','published','{"globalNumber":566,"sourceNumber":6,"typeLabel":"和差倍比问题","stemRich":[{"text":"甲单位的员工人数是乙单位的1.5倍，两个单位的女性员工分别占该单位\n\n人数的60%和50%。现从甲单位调10名男性员工到乙单位，从乙单位调10名\n女性员工到甲单位，此时两个单位的男性员工人数相同。问此时甲单位的女性\n\n员工人数比乙单位多多少人?"}],"annotatedStemRich":[{"text":"甲单位的员工人数是乙单位的1.5倍，两个单位的女性员工分别占该单位\n\n人数的60%和50%。现从甲单位调10名男性员工到乙单位，从乙单位调10名\n女性员工到甲单位，此时两个单位的男性员工人数相同。问此时甲单位的女性\n\n员工人数比乙单位多多少人?"}],"annotatedOptionRich":{"A":[{"text":"60"}],"B":[{"text":"80"}],"C":[{"text":"100","bold":true}],"D":[{"text":"120","bold":true},{"text":"\n"}]},"practicalAnalysis":"设原来甲单位人数为15x, 乙单位为10x, 故原来两个单位男员工人数分别为15x×(1-60%)=6x 、10x×(1-50%)=5x;\n甲、乙单位互换10名男、女员工后，男性员工人数相等，则原来甲单位男员工比乙单位男员工多20人，即6x-5x=20, 解得x=20;\n原来甲单位有女员工9x=180, 调来10人后为190人；原来乙单位有女员工5x=100, 调走10人后为90人，即现在甲单位女员工比乙单位多190- 90=100人，答案为C选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500567,4,'日期星期问题','小张每周一、周三、周五和周日各写1篇日记，其余时间不写日记，从不间断。
某年第三季度，他写的日记数量与第四季度相同。问当年劳动节是周几?','[{"label":"A","content":"周一"},{"label":"B","content":"周二"},{"label":"C","content":"周三"},{"label":"D","content":"周四"}]','B','第三季度与第四季度均为92天，92÷7=13余1, 即中间两天(9 月30日和10月1日)⑦或者都写日记或者都不写日记，根据题意可知，这两天只能是周日和周一，即10月1日为周一；
所求为5月1日，10月1日(周一)是5月1日之后的第153天⑧,153÷7=21余6, 10月1日是5月1日的星期数向后推6天，即5月1日的星期数是周一向前推 6天(即向后推1天),即5月1日是周二⑨ ,答案为B选项。

⑦花生批注：
13周 13周
三季度四季度

⑧花生批注：
先粗算再修正加上日期差： 5×30+3=153天。

⑨花生批注：
此处较为复杂，可根据余数6可知，星期要么向前推一天要么向后推一天，即要么是周日要么是周二，答案只有周二，当选。','数量关系600题','进阶','published','{"globalNumber":567,"sourceNumber":7,"typeLabel":"日期星期问题","stemRich":[{"text":"小张每周一、周三、周五和周日各写1篇日记，其余时间不写日记，从不间断。\n某年第三季度，他写的日记数量与第四季度相同。问当年劳动节是周几?"}],"annotatedStemRich":[{"text":"小张每周一、周三、周五和周日各写1篇日记，其余时间不写日记，从不间断。\n某年第三季度，他写的日记数量与第四季度相同。问当年劳动节是周几?"}],"annotatedOptionRich":{"A":[{"text":" 周一"}],"B":[{"text":" 周二"}],"C":[{"text":" 周三","bold":true}],"D":[{"text":"  周四","bold":true},{"text":"\n"}]},"practicalAnalysis":"第三季度与第四季度均为92天，92÷7=13余1, 即中间两天(9 月30日和10月1日)⑦或者都写日记或者都不写日记，根据题意可知，这两天只能是周日和周一，即10月1日为周一；\n所求为5月1日，10月1日(周一)是5月1日之后的第153天⑧,153÷7=21余6, 10月1日是5月1日的星期数向后推6天，即5月1日的星期数是周一向前推 6天(即向后推1天),即5月1日是周二⑨ ,答案为B选项。","notes":[{"marker":"⑦","text":"13周 13周\n三季度四季度","matchScore":0.056},{"marker":"⑧","text":"先粗算再修正加上日期差： 5×30+3=153天。","matchScore":0.042},{"marker":"⑨","text":"此处较为复杂，可根据余数6可知，星期要么向前推一天要么向后推一天，即要么是周日要么是周二，答案只有周二，当选。","matchScore":0.153}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
