INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500569,4,'行程问题之相遇追及问题','快，也就意味
已 知A 、B 两地相距9公里，甲、乙两人匀速从A 地 前 往B 地。甲每小时
着甲尽 可能的
走6公里，每走半小时休息15分钟；乙比甲早15分钟出发，中间不休息。若
他们在途中(不含起点和终点)相遇了2次，则乙从A地 到B 地所用的时间至 晚一些追上乙
少为多少分钟?
；','[{"label":"A","content":"75 分钟"},{"label":"B","content":"120 分钟"},{"label":"C","content":"135 分钟"},{"label":"D","content":"150 分钟"}]','C','乙先出发甲后出发，二者在途中相遇，说明甲的速度更快，这样才能追上乙；甲每走半小时休息15分钟，一定要在第一次休息前追上乙.
否则差距会越来越大，甲根本无法追上乙⑮:
在此基础上，要想乙用时最短，即乙的速度应该尽量快，也就意味着甲尽可能的晚一些追上乙；
⑩

⑮花生批注：
等比放缩性质：长度之比为1:n, 面积之比为1:n²
甲又要在第一次休息前追上乙又要尽量晚的追上乙，即甲应刚好在第一次休息时追上乙，此时甲走了6×0.5=3公里，乙早出发15分钟，即乙45分钟走了3公里；
乙走完全程9公里需要45×3=135分钟，甲分别在3公里处、6公里处、9 公里处(终点处)与乙相遇，符合在途中(不含起点和终点)相遇2次的要求，即乙从A到B最短需要135分钟，答案为C选项。','数量关系600题','进阶','published','{"globalNumber":569,"sourceNumber":9,"typeLabel":"行程问题之相遇追及问题","stemRich":[{"text":"快，也就意味\n已 知A 、B 两地相距9公里，甲、乙两人匀速从A 地 前 往B 地。甲每小时\n着甲尽 可能的\n走6公里，每走半小时休息15分钟；乙比甲早15分钟出发，中间不休息。若\n他们在途中(不含起点和终点)相遇了2次，则乙从A地 到B 地所用的时间至 晚一些追上乙\n少为多少分钟?\n；"}],"annotatedStemRich":[{"text":"快，也就意味\n已 知A 、B 两地相距9公里，甲、乙两人匀速从A 地 前 往B 地。甲每小时\n着甲尽 可能的\n走6公里，每走半小时休息15分钟；乙比甲早15分钟出发，中间不休息。若\n他们在途中(不含起点和终点)相遇了2次，则乙从A地 到B 地所用的时间至 晚一些追上乙\n少为多少分钟?\n；"}],"annotatedOptionRich":{"A":[{"text":"75    分 钟"}],"B":[{"text":"120    分 钟"}],"C":[{"text":"135    分","bold":true},{"text":" "},{"text":"钟","bold":true}],"D":[{"text":"150     分","bold":true},{"text":" "},{"text":"钟","bold":true},{"text":"\n"}]},"practicalAnalysis":"乙先出发甲后出发，二者在途中相遇，说明甲的速度更快，这样才能追上乙；甲每走半小时休息15分钟，一定要在第一次休息前追上乙.\n否则差距会越来越大，甲根本无法追上乙⑮:\n在此基础上，要想乙用时最短，即乙的速度应该尽量快，也就意味着甲尽可能的晚一些追上乙；\n⑩","notes":[{"marker":"⑮","text":"等比放缩性质：长度之比为1:n, 面积之比为1:n²\n甲又要在第一次休息前追上乙又要尽量晚的追上乙，即甲应刚好在第一次休息时追上乙，此时甲走了6×0.5=3公里，乙早出发15分钟，即乙45分钟走了3公里；\n乙走完全程9公里需要45×3=135分钟，甲分别在3公里处、6公里处、9 公里处(终点处)与乙相遇，符合在途中(不含起点和终点)相遇2次的要求，即乙从A到B最短需要135分钟，答案为C选项。","matchScore":0.25}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
