INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500571,4,'和差倍比问题','某防疫工作机构有检验人员和其他工作人员共55人，将检验人员平均分成若干个小组开展工作。近期，该机构补充了20位工作人员，其中，检验人员增加了2组，每组人数不变，其他工作人员增加了30%,则该机构原有检验人员共多少组?','[{"label":"A","content":"4"},{"label":"B","content":"5"},{"label":"C","content":"6"},{"label":"D","content":"7"}]','B','设检测人员每组有 x 人，原来其他工作人员共有y 人，根据题意可列式：2x+0.3y=20, 可知0 . 3y 为偶数①且y 为10的倍数，故y 可取

①花生批注：
常用的整除性质：
①a、b能被x 整除，a+b、a-b 也能被 x 整除。
② 对于, 若 x 、y 为整数，为最简分数，则 x 是 a 的倍数，y 是 b 的倍数。
