INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500574,4,'和差倍比问题','甲、乙、丙、丁四人去吃自助餐，因为甲没带钱包，饭钱就先由乙、丙、

丁三人支付。回去后，甲要还钱给三人。结果乙说：“不用了，我反正还欠你
25元，正好抵掉。”丙说：“你把我那份给丁吧，我正好欠他39元。”于是

甲付给丁105元，那么丁支付了多少元?','[{"label":"A","content":"130"},{"label":"B","content":"165"},{"label":"C","content":"171"},{"label":"D","content":"196"}]','D','甲应该给乙的钱和乙之前欠甲的25元正好抵消，即乙为甲支付25元；甲应该给丙的钱等于丙欠丁的39元，即丙为甲支付39元；甲付给丁的105元包含丁为甲支付的钱和丙欠丁的39元，即丁为甲支付105-39=66 元；
三人一共为甲支付25+39+66=130元，即每人应支付自助餐费130元，丁共支付130+66=196元⑥,答案为D选项。
练习题5 8 套
⑥

⑥花生批注：
自己的自助餐费130元和为甲支付的66元。','数量关系600题','进阶','published','{"globalNumber":574,"sourceNumber":4,"typeLabel":"和差倍比问题","stemRich":[{"text":"甲、乙、丙、丁四人去吃自助餐，因为甲没带钱包，饭钱就先由乙、丙、\n\n丁三人支付。回去后，甲要还钱给三人。结果乙说：“不用了，我反正还欠你\n25元，正好抵掉。”丙说：“你把我那份给丁吧，我正好欠他39元。”于是\n\n甲付给丁105元，那么丁支付了多少元?"}],"annotatedStemRich":[{"text":"甲、乙、丙、丁四人去吃自助餐，因为甲没带钱包，饭钱就先由乙、丙、\n\n丁三人支付。回去后，甲要还钱给三人。结果乙说：“不用了，我反正还欠你\n25元，正好抵掉。”丙说：“你把我那份给丁吧，我正好欠他39元。”于是\n\n甲付给丁105元，那么丁支付了多少元?"}],"annotatedOptionRich":{"A":[{"text":"130"}],"B":[{"text":"165"}],"C":[{"text":"171"}],"D":[{"text":"196\n"}]},"practicalAnalysis":"甲应该给乙的钱和乙之前欠甲的25元正好抵消，即乙为甲支付25元；甲应该给丙的钱等于丙欠丁的39元，即丙为甲支付39元；甲付给丁的105元包含丁为甲支付的钱和丙欠丁的39元，即丁为甲支付105-39=66 元；\n三人一共为甲支付25+39+66=130元，即每人应支付自助餐费130元，丁共支付130+66=196元⑥,答案为D选项。\n练习题5 8 套\n⑥","notes":[{"marker":"⑥","text":"自己的自助餐费130元和为甲支付的66元。","matchScore":0.139}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500575,4,'几何问题','一个房间地面为4.8×6米的标准长方形，现用30×30厘米或60×60厘
