INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500576,4,'行程问题','A、B、C、D四个学校分布在矩形的四个顶点上，小李早上骑自行车从A校 出发去D 校学习，半个小时后到达D校，学习3个小时后立即由D校去C校， 小李离开A校4个小时后妈妈驾车沿ABC的路线去C 校接小李，已知小李骑车 速度为15千米/小时，妈妈驾车速度为50千米/小时，最终二人同时到达C校。 若妈妈11:00出发，那么到达C 校的时间在以下哪个范围内?','[{"label":"A","content":"11:25 之前"},{"label":"B","content":"11:25～11: 30之间"},{"label":"C","content":"11:30～11:35 之间"},{"label":"D","content":"11:35 之后"}]','B','“ABCD 四个学校分布在矩形的四个顶点上”,故AD+DC=AB +BC,即小李走的路程与妈妈走的路程相等①。
