INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500577,4,'容斥问题','某基层工会共有180名会员，举行甲、乙两项工会活动，60%的会员参加

