INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500592,4,'和差倍比问题','将1至8这八个数字分别填入下图的圆圈中，已知每个三角形圆圈中的数
字之和为13,大正方形四个顶点之一的圆圈中不可能填数字?','[{"label":"A","content":"7"},{"label":"B","content":"6"},{"label":"C","content":"5"},{"label":"D","content":"4"}]','C','如图所示①,设大正方形四个顶点数字为A 、B 、C 、D,小正方形的四个顶点的数字分别为E、F、G、H。
八个顶点相加，即1～8相加，和为36;
四个三角形相加，和为13×4=52,其中E、F、G、H 被加了两次，即
E+F+G+H=52-36=16②;
②

②花生批注：
四个三角形的和=八个顶点之和+E+F+H+G。
△ DEH 中，D+E+H=13,则E+H=13-D;△BFG 中，B+F+G=13,则F+G=13-B;
则 E+H+F+G=26-B-D=16,即B+D=10,若B=5, 则 D=5, 数字重复出现，不符合题目要求，即大正方形的顶点不能填入5,答案为C选项。','数量关系600题','进阶','published','{"globalNumber":592,"sourceNumber":2,"typeLabel":"和差倍比问题","stemRich":[{"text":"将1至8这八个数字分别填入下图的圆圈中，已知每个三角形圆圈中的数\n字之和为13,大正方形四个顶点之一的圆圈中不可能填数字?"}],"annotatedStemRich":[{"text":"将1至8这八个数字分别填入下图的圆圈中，已知每个三角形圆圈中的数\n字之和为13,大正方形四个顶点之一的圆圈中不可能填数字?"}],"annotatedOptionRich":{"A":[{"text":"7"}],"B":[{"text":"6"}],"C":[{"text":"5"}],"D":[{"text":"4\n"},{"text":"数量关系600","bold":true},{"text":"\n"}]},"practicalAnalysis":"如图所示①,设大正方形四个顶点数字为A 、B 、C 、D,小正方形的四个顶点的数字分别为E、F、G、H。\n八个顶点相加，即1～8相加，和为36;\n四个三角形相加，和为13×4=52,其中E、F、G、H 被加了两次，即\nE+F+G+H=52-36=16②;\n②","notes":[{"marker":"②","text":"四个三角形的和=八个顶点之和+E+F+H+G。\n△ DEH 中，D+E+H=13,则E+H=13-D;△BFG 中，B+F+G=13,则F+G=13-B;\n则 E+H+F+G=26-B-D=16,即B+D=10,若B=5, 则 D=5, 数字重复出现，不符合题目要求，即大正方形的顶点不能填入5,答案为C选项。","matchScore":0.281}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
