INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500594,4,'日期星期问题','只有在星期六，小王才会去图书馆。如果某年3月小王一共有5天去过图
书馆，则当年4月1日可能是?','[{"label":"A","content":"星期二"},{"label":"B","content":"星期三"},{"label":"C","content":"星期五"},{"label":"D","content":"星期六"}]','A','3月有31天，有4个完整星期余3天，④在4个完整星期中，有4个星期六，但小王去过5天图书馆，说明余下3天中有一个星期六，将这 3天放在月末，这三天可以是四五六、五六日、六日一，4月1日分别是星期日、星期一、星期二，只有 A选项符合以上可能性，当选。','数量关系600题','进阶','published','{"globalNumber":594,"sourceNumber":4,"typeLabel":"日期星期问题","stemRich":[{"text":"只有在星期六，小王才会去图书馆。如果某年3月小王一共有5天去过图\n书馆，则当年4月1日可能是?"}],"annotatedStemRich":[{"text":"只有在星期六，小王才会去图书馆。如果某年3月小王一共有5天去过图\n书馆，则当年4月1日可能是?"}],"annotatedOptionRich":{"A":[{"text":" 星期二"}],"B":[{"text":"  星期三"}],"C":[{"text":"  星期五"}],"D":[{"text":"  星期六\n"}]},"practicalAnalysis":"3月有31天，有4个完整星期余3天，④在4个完整星期中，有4个星期六，但小王去过5天图书馆，说明余下3天中有一个星期六，将这 3天放在月末，这三天可以是四五六、五六日、六日一，4月1日分别是星期日、星期一、星期二，只有 A选项符合以上可能性，当选。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500595,4,'排列组合问题','某农科院准备挑选2男2女4名科技人员分别去市郊的甲乙丙丁4个乡参
加科技支农工作，在报名的人员中有3男4女符合要求，在4名女性中有1位
是农科院的副院长，考虑到工作的具体需要，这名副院长不去甲乡，且去丁乡
的是女性。符合条件的选法有多少种?','[{"label":"A","content":"198"},{"label":"B","content":"216"},{"label":"C","content":"378"},{"label":"D","content":"432"}]','A','⑤女副院长情况较特殊，可以分情况进行讨论：
若女副院长不去：从剩余3男3女中选出2男2女，即 C²×c³, 再选出1位女性去丁乡， C2,再将选出的剩余3人分配到甲乙丙乡，即A³, 共有 C³×c³×C2×A₃=108 种选法；
若女副院长去，从剩余3男3女中选出2男1女，即 C²×c3; 此时可根据女副院长是否去丁乡再分情况讨论：
①女副院长去丁乡，剩余3人分配给甲乙丙乡，即A3;② 若女副院长不去丁乡，只能在乙丙乡中选择，即C2, 剩余女性只能去丁乡，再给剩余2位男性安排地点即可，即A2;
共有 C³×C³×(A³+C2×A2)=90·种选法；
综上，一共有108+90=198种选法，答案为A选项。
⑤

④花生批注：
日期星期问题中星期推断方法：
将整个时间段分成若干星期和额外n 天，每星期内的工作日、休息日，星期几都是固定的，只有额外几天能根据题意调整。
某农科院准备挑选2男2女4名科技人员分别去市郊的甲乙丙丁4个乡参加科技支农工作，在报名的人员中有3男4女符合要求，在4名女性中有1位是农科院的副院长，考虑到工作的具体需要，这名副院长不去甲乡，且去丁乡的是女性。符合条件的选法有多少种?

⑤花生批注：
本题也可采用“全部减不符”解题：
丁乡是女性的全部情况一丁乡是女性副院长去甲乡的情况；
全部情况：
选出2男2女，即C²×c2, 一名女性去丁乡，C, 剩余 3 人全排列A³, 共有 C²×c²×02×A³=216 种情况 (此时可以直接秒杀A选项); 不符情况：
副院长去甲乡，还需选出 1 女去丁乡，即C³; 选出
2位男性去剩余2乡，即
A3, 共有C³×A₃=18种情况；符合条件的选法有216 - 18=198 种。','数量关系600题','进阶','published','{"globalNumber":595,"sourceNumber":5,"typeLabel":"排列组合问题","stemRich":[{"text":"某农科院准备挑选2男2女4名科技人员分别去市郊的甲乙丙丁4个乡参\n加科技支农工作，在报名的人员中有3男4女符合要求，在4名女性中有1位\n是农科院的副院长，考虑到工作的具体需要，这名副院长不去甲乡，且去丁乡\n的是女性。符合条件的选法有多少种?"}],"annotatedStemRich":[{"text":"某农科院准备挑选2男2女4名科技人员分别去市郊的甲乙丙丁4个乡参\n加科技支农工作，在报名的人员中有3男4女符合要求，在4名女性中有1位\n是农科院的副院长，考虑到工作的具体需要，这名副院长不去甲乡，且去丁乡\n的是女性。符合条件的选法有多少种?"}],"annotatedOptionRich":{"A":[{"text":"198"}],"B":[{"text":"216"}],"C":[{"text":"378"}],"D":[{"text":"432\n"}]},"practicalAnalysis":"⑤女副院长情况较特殊，可以分情况进行讨论：\n若女副院长不去：从剩余3男3女中选出2男2女，即 C²×c³, 再选出1位女性去丁乡， C2,再将选出的剩余3人分配到甲乙丙乡，即A³, 共有 C³×c³×C2×A₃=108 种选法；\n若女副院长去，从剩余3男3女中选出2男1女，即 C²×c3; 此时可根据女副院长是否去丁乡再分情况讨论：\n①女副院长去丁乡，剩余3人分配给甲乙丙乡，即A3;② 若女副院长不去丁乡，只能在乙丙乡中选择，即C2, 剩余女性只能去丁乡，再给剩余2位男性安排地点即可，即A2;\n共有 C³×C³×(A³+C2×A2)=90·种选法；\n综上，一共有108+90=198种选法，答案为A选项。\n⑤","notes":[{"marker":"④","text":"日期星期问题中星期推断方法：\n将整个时间段分成若干星期和额外n 天，每星期内的工作日、休息日，星期几都是固定的，只有额外几天能根据题意调整。\n某农科院准备挑选2男2女4名科技人员分别去市郊的甲乙丙丁4个乡参加科技支农工作，在报名的人员中有3男4女符合要求，在4名女性中有1位是农科院的副院长，考虑到工作的具体需要，这名副院长不去甲乡，且去丁乡的是女性。符合条件的选法有多少种?","matchScore":0.756},{"marker":"⑤","text":"本题也可采用“全部减不符”解题：\n丁乡是女性的全部情况一丁乡是女性副院长去甲乡的情况；\n全部情况：\n选出2男2女，即C²×c2, 一名女性去丁乡，C, 剩余 3 人全排列A³, 共有 C²×c²×02×A³=216 种情况 (此时可以直接秒杀A选项); 不符情况：\n副院长去甲乡，还需选出 1 女去丁乡，即C³; 选出\n2位男性去剩余2乡，即\nA3, 共有C³×A₃=18种情况；符合条件的选法有216 - 18=198 种。","matchScore":0.327}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500596,4,'植树问题','在一条100米笔直的路上种树，已知该路的两端分别已经各种了一棵树，现要求每次在已种树的中点位置新种一棵，保证两两树之间的距离相等且大于 5米。问这条路上最多有多少棵树?','[{"label":"A","content":"16"},{"label":"B","content":"17"},{"label":"C","content":"18"},{"label":"D","content":"19"}]','B','注意题目要求，每次必须在中点植树， 1 0 0 ÷ 2 = 5 0 , 50÷2=25,25÷2=12.5, 12.5÷2=6.25,即最小距离为6.25米，此时一共有 100÷6.25=16个间隔，即一共有17棵树，答案为B 选项。','数量关系600题','进阶','published','{"globalNumber":596,"sourceNumber":6,"typeLabel":"植树问题","stemRich":[{"text":"在一条100米笔直的路上种树，已知该路的两端分别已经各种了一棵树， 现要求每次在已种树的中点位置新种一棵，保证两两树之间的距离相等且大于 5米。问这条路上最多有多少棵树?"}],"annotatedStemRich":[{"text":"在一条100米笔直的路上种树，已知该路的两端分别已经各种了一棵树， 现要求每次在已种树的中点位置新种一棵，保证两两树之间的距离相等且大于 5米。问这条路上最多有多少棵树?"}],"annotatedOptionRich":{"A":[{"text":"16"}],"B":[{"text":"17"}],"C":[{"text":"18"}],"D":[{"text":"19\n"}]},"practicalAnalysis":"注意题目要求，每次必须在中点植树， 1 0 0 ÷ 2 = 5 0 , 50÷2=25,25÷2=12.5, 12.5÷2=6.25,即最小距离为6.25米，此时一共有 100÷6.25=16个间隔，即一共有17棵树，答案为B 选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500597,4,'年龄问题','小张和小王的年龄之和为45岁。5年之后小李的年龄比小张的3倍少16岁。
，
已知小张的年龄比小王小，那么再过5年，3人的平均年龄最大可能为多少岁?','[{"label":"A","content":"45"},{"label":"B","content":"48"},{"label":"C","content":"50"},{"label":"D","content":"54"}]','A','设小张五年之后的年龄为x,根据题意可得出以下表格：
小张
小李
小王
五年之后
x
3x-16
55-x⁶
再过五年
x+5
3x-11
60-x
小张的年龄比小王小，所以x<55 - x . x<27 . 5 . x最大取27.则再过五年三人平均年龄最大可能为(x+5+3x-11+60-x)÷3=(3x+54)÷3=135÷3=45.答案为A选项。 ⑦

⑦花生批注：
本题也可采用以下方法：
根据题意小张小王年龄是定值，那么让3人平均年龄大，则需要小李尽量大小李年龄和小张有关，则需要小张年龄尽量大。
小张年龄小于小王，所以小张最大22岁(45=23+22), 小张 5 年后 2 7 岁，小李 =27×3-16=65岁；
再过5年，一共过去10年，则小张+小王=45+10+10=65, 小李=65+5=70,所以三人平均135÷3=45。
【难度评价】★★☆
【 实战解析 】 注意题目要求，每次必须在中点植树， 1 0 0 ÷ 2 = 5 0 , 50÷2=25,25÷2=12.5, 12.5÷2=6.25,即最小距离为6.25米，此时一共有 100÷6.25=16个间隔，即一共有17棵树，答案为B 选项。','数量关系600题','进阶','published','{"globalNumber":597,"sourceNumber":7,"typeLabel":"年龄问题","stemRich":[{"text":"小张和小王的年龄之和为45岁。5年之后小李的年龄比小张的3倍少16岁。\n，\n已知小张的年龄比小王小，那么再过5年，3人的平均年龄最大可能为多少岁?"}],"annotatedStemRich":[{"text":"小张和小王的年龄之和为45岁。5年之后小李的年龄比小张的3倍少16岁。\n，\n已知小张的年龄比小王小，那么再过5年，3人的平均年龄最大可能为多少岁?"}],"annotatedOptionRich":{"A":[{"text":"45"}],"B":[{"text":"48"}],"C":[{"text":"50"}],"D":[{"text":"54\n"}]},"practicalAnalysis":"设小张五年之后的年龄为x,根据题意可得出以下表格：\n小张\n小李\n小王\n五年之后\nx\n3x-16\n55-x⁶\n再过五年\nx+5\n3x-11\n60-x\n小张的年龄比小王小，所以x<55 - x . x<27 . 5 . x最大取27.则再过五年三人平均年龄最大可能为(x+5+3x-11+60-x)÷3=(3x+54)÷3=135÷3=45.答案为A选项。 ⑦","notes":[{"marker":"⑦","text":"本题也可采用以下方法：\n根据题意小张小王年龄是定值，那么让3人平均年龄大，则需要小李尽量大小李年龄和小张有关，则需要小张年龄尽量大。\n小张年龄小于小王，所以小张最大22岁(45=23+22), 小张 5 年后 2 7 岁，小李 =27×3-16=65岁；\n再过5年，一共过去10年，则小张+小王=45+10+10=65, 小李=65+5=70,所以三人平均135÷3=45。\n【难度评价】★★☆\n【 实战解析 】 注意题目要求，每次必须在中点植树， 1 0 0 ÷ 2 = 5 0 , 50÷2=25,25÷2=12.5, 12.5÷2=6.25,即最小距离为6.25米，此时一共有 100÷6.25=16个间隔，即一共有17棵树，答案为B 选项。","matchScore":0.245}],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500598,4,'和差倍比问题','甲、乙二人合伙成立公司，约定每年利润的60%留作公司发展用途，40%

按二人投资比例分配。已知公司成立第三年的利润比第二年高300万元，是第
一年利润的3倍；甲第二年分配的金额是第三年的一半，且比第一年多20万元。

问乙的投资额占比为多少?','[{"label":"A","content":"40%"},{"label":"B","content":"50%"},{"label":"C","content":"60%"},{"label":"D","content":"75%"}]','B','设第一年总利润为x, 甲第二年分配金额为a; 可将相关数据填入下表：
甲分配金额
总利润
第一年
a-20
X
第二年
a
3x-300
第三年
2a
3x
甲分配比例不变，则分配金额之比等于总利润之比；由第三年总利润是第一年的3倍可知：2a=3(a-20), 解得 a=60; 由第三年甲分配金额是第二年的2 倍可知，3x=2(3x-300), 解得x=200;
即第三年总利润为3x=600, 用于分配的有600×40%=240,甲分得2a=120, 占比为一半，则乙的投资占比也为一半，答案为B 选项。','数量关系600题','进阶','published','{"globalNumber":598,"sourceNumber":8,"typeLabel":"和差倍比问题","stemRich":[{"text":"甲、乙二人合伙成立公司，约定每年利润的60%留作公司发展用途，40%\n\n按二人投资比例分配。已知公司成立第三年的利润比第二年高300万元，是第\n一年利润的3倍；甲第二年分配的金额是第三年的一半，且比第一年多20万元。\n\n问乙的投资额占比为多少?"}],"annotatedStemRich":[{"text":"甲、乙二人合伙成立公司，约定每年利润的60%留作公司发展用途，40%\n\n按二人投资比例分配。已知公司成立第三年的利润比第二年高300万元，是第\n一年利润的3倍；甲第二年分配的金额是第三年的一半，且比第一年多20万元。\n\n问乙的投资额占比为多少?"}],"annotatedOptionRich":{"A":[{"text":"40%"}],"B":[{"text":"50%"}],"C":[{"text":"60%"}],"D":[{"text":"75%\n"}]},"practicalAnalysis":"设第一年总利润为x, 甲第二年分配金额为a; 可将相关数据填入下表：\n甲分配金额\n总利润\n第一年\na-20\nX\n第二年\na\n3x-300\n第三年\n2a\n3x\n甲分配比例不变，则分配金额之比等于总利润之比；由第三年总利润是第一年的3倍可知：2a=3(a-20), 解得 a=60; 由第三年甲分配金额是第二年的2 倍可知，3x=2(3x-300), 解得x=200;\n即第三年总利润为3x=600, 用于分配的有600×40%=240,甲分得2a=120, 占比为一半，则乙的投资占比也为一半，答案为B 选项。","notes":[],"missingOptionLabels":[],"pairingMode":"word-type-anchor-and-number"}',NULL);
INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (500599,4,'几何问题','正方形水池ABCD的边长为80米。 E 在AB边正中的正北30米处，F 在C 点东偏南45°方向，F 点到C点距离为40 √2米。甲从E点出发前往F 点，问他的最短行进距离比途经D点的最短行进距离短多少米?
E
.F','[{"label":"A","content":"30"},{"label":"B","content":"50"},{"label":"C","content":"40√2"},{"label":"D","content":"80"}]','D','由题意可知，正方形 ABCD 是水池，故不考虑两点之间直线最短 ( 即 EF 连线)的可能性，最短的行进距离为EB+BF; 过 D 点的最短行进距离为EA+AD+DF。
因为E点在AB正中的正北方，所以点E到点A点B的距离相等，即 EA=EB⑧。因为F在C点东偏南45°方向，所以点F到点B点D的距离相等⑨, 即BF=DF。综上所述，两种方案之间只相差AD线段的长，AD=80米，答案为D选项。
⑧

