INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (600025,5,'基期','能够从上述材料中推出的是：','[{"label":"A","content":"2020 年城镇常住居民工资性收入低于2020年全市居民人均消费支出"},{"label":"B","content":"2021 年城镇常住居民财产性收入增长率高于农村常住居民财产性收入增\n\n长率"},{"label":"C","content":"2019 年农村常住居民人均可支配收入增长率高于城镇常住居民人均可\n支配收入增长率"},{"label":"D","content":"2021 年城镇居民人均可支配收入增长率高于农村居民人均可支配收入增\n\n长率"}]','C','B 选项，定位材料第二段，2023年第14周H市哨点医院共报 告流感样病例总数为5187例，上一题已求出2022年第14周H 市哨点医院共报 告流感样病例总数约为11800例，11800-5187≈6600例，即减少超过6000例， 正确，当选；
其他选项：
A选项，定位材料第三段，2023年第14周H 市哨点医院IL1%为5 . 98%,比 2022年同期低7.56个百分点，因2023年第14周H市哨点医院 IL1%比2022年 同期低，故并非逐年上升，错误；
C选项，定位材料第二段，2023年第14周H市哨点医院共报告流感样病例 总数为5187例( B), 比上周增加4 .4% ( R₂), 其中国家级哨点医院455 例
( A), 比上周减少6 . 57% ( R) 。 根 据 基 期 比 重 公
错误；
D选项，定位材料第一、四段，2023年第14周总数为5187例；各年龄组
报告的流感样病例构成情况为：0～4岁组1472例，5～14岁组1103例，15~
24岁组406例，25～59岁组1266例，60岁以上组940例。
“占比低于20%的年龄组”,即“流感样病例低于1040例的年龄组”,有 15～24岁组(406例)、60岁以上组(940例),共2个，错误。
2016年，农民工月均收入3275元，比上年增加203元，增长6.6%,增速
比上年回落0.6个百分点(第一题，第四题A 选项数据)。 外出务工农民工月
均收入3572元，比上年增加213元，增长6.3%;本地务工农民工月均收入2985 元，比上年增加204元，增长7.3% (第五题数据)。 本地务工农民工月均收入 比外出务工农民工低587元，但增速比外出务工农民工高1个百分点(第四题
B选项数据)。
分行业看，制造业收入增速较上年提高；居民服务、修理和其他服务业增速 与上年持平(第四题C 选项数据);建筑业，批发和零售业，交通运输、仓储和 邮政业，住宿和餐饮业农民工月均收入增速分别较上年回落1.5、1.9、1.5和 0.7个百分点。
(第二题数据)
元 %
4000 10
3500 9

