INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (600110,5,'增长量','以下折线图中，最能准确反映2017～2021年间北京市集成电路产量同比增

量变化趋势的是：','[{"label":"A","content":"（图形选项，见题目原图）"},{"label":"B","content":"（图形选项，见题目原图）"},{"label":"C","content":"（图形选项，见题目原图）"},{"label":"D","content":"（图形选项，见题目原图）"}]','A','定位统计表，北京市2017～2021年间集成电路产量同比增量 分别为12、44、17、17、37亿块，可发现第三年和第四年增长量相等，即第三 四点高度一致，答案只能为A选项。
2023年，全国新增发电装机容量3.7亿千瓦 (第一、二题数据，第五题A 选项数据) ,同比多投产1.7亿千瓦。其中，新增并网太阳能发电装机容量2.2 亿千瓦，同比多投产1.3亿千瓦 (第五题A 选项数据), 占新增发电装机总容 量的比重达到58.5%。截至2023年底，全国全口径发电装机容量29.2亿千瓦( 第 一 、二 题数据) ,其中，非化石能源发电装机容量15.7亿千瓦，占总装机容量 比重在2023年首次突破50% (第一题数据),达到53.9%。分类型看，水电4.2 亿千瓦，其中抽水蓄能5094万千瓦 (第五题B选项数据);核电5691万千瓦； 并网风电4.4亿千瓦，其中，陆上风电4.0亿千瓦、海上风电3729万千瓦；并 网太阳能发电6.1亿千瓦。全国并网风电和太阳能发电合计装机规模从2022年 底的7.6亿千瓦 (第二题数据),连续突破8亿千瓦、9亿千瓦、10亿千瓦大 关，2023年底达到10.5亿千瓦，同比增长38.6%,火电13.9亿千瓦，其中，
煤电11.6亿千瓦，同比增长3.4%,占总发电装机容量的比重为39.9%,首次降 至40%以下。2023年，全国6000千瓦及以上电厂发电设备利用小时3592小时，
同比降低101小时。分类型看，水电3133小时，同比降低285小时，其中，常 规水电3423小时，同比降低278小时；抽水蓄能1175小时，同比降低6小时( 第 三题数据)。火电4466小时，同比提高76小时 (第五题C选项数据);其中， 煤电4685小时，同比提高92小时。核电7670小时，同比提高54小时。并网风 电2225小时，同比提高7小时。并网太阳能发电1286小时，同比降低54小时 (第三题数据)。2023年，全国各电力交易中心累计组织完成市场交易电量5.61 万亿千瓦时，同比增长7.9%,( 第五题D选项数据)占全社会用电量比重为61.4%, 同比提高0.6个百分点 (第四题数据)。其中，全国电力市场中长期电力直接交 易电量合计为44288.9亿千瓦时同比增长7% (第五题D选项数据)。','资料分析600题','进阶','published','{"globalNumber":110,"sourceNumber":10,"typeLabel":"比较类之增量大小比较","practicalAnalysis":"定位统计表，北京市2017～2021年间集成电路产量同比增量 分别为12、44、17、17、37亿块，可发现第三年和第四年增长量相等，即第三 四点高度一致，答案只能为A选项。\n2023年，全国新增发电装机容量3.7亿千瓦 (第一、二题数据，第五题A 选项数据) ,同比多投产1.7亿千瓦。其中，新增并网太阳能发电装机容量2.2 亿千瓦，同比多投产1.3亿千瓦 (第五题A 选项数据), 占新增发电装机总容 量的比重达到58.5%。截至2023年底，全国全口径发电装机容量29.2亿千瓦( 第 一 、二 题数据) ,其中，非化石能源发电装机容量15.7亿千瓦，占总装机容量 比重在2023年首次突破50% (第一题数据),达到53.9%。分类型看，水电4.2 亿千瓦，其中抽水蓄能5094万千瓦 (第五题B选项数据);核电5691万千瓦； 并网风电4.4亿千瓦，其中，陆上风电4.0亿千瓦、海上风电3729万千瓦；并 网太阳能发电6.1亿千瓦。全国并网风电和太阳能发电合计装机规模从2022年 底的7.6亿千瓦 (第二题数据),连续突破8亿千瓦、9亿千瓦、10亿千瓦大 关，2023年底达到10.5亿千瓦，同比增长38.6%,火电13.9亿千瓦，其中，\n煤电11.6亿千瓦，同比增长3.4%,占总发电装机容量的比重为39.9%,首次降 至40%以下。2023年，全国6000千瓦及以上电厂发电设备利用小时3592小时，\n同比降低101小时。分类型看，水电3133小时，同比降低285小时，其中，常 规水电3423小时，同比降低278小时；抽水蓄能1175小时，同比降低6小时( 第 三题数据)。火电4466小时，同比提高76小时 (第五题C选项数据);其中， 煤电4685小时，同比提高92小时。核电7670小时，同比提高54小时。并网风 电2225小时，同比提高7小时。并网太阳能发电1286小时，同比降低54小时 (第三题数据)。2023年，全国各电力交易中心累计组织完成市场交易电量5.61 万亿千瓦时，同比增长7.9%,( 第五题D选项数据)占全社会用电量比重为61.4%, 同比提高0.6个百分点 (第四题数据)。其中，全国电力市场中长期电力直接交 易电量合计为44288.9亿千瓦时同比增长7% (第五题D选项数据)。","notes":[],"missingOptionLabels":["A","B","C","D"],"stemRich":[{"text":"10."},{"text":"  "},{"text":"以下折线图中，最能准确反映2017～2021年间北京市集成电路产量同比增"},{"text":"\n"},{"text":"量变化趋势的是："},{"text":"\n"},{"text":""},{"text":"\n"},{"text":""},{"text":"\n"},{"text":""},{"text":"\n"},{"text":""},{"text":"\n"},{"text":""}],"annotatedStemRich":[{"text":"10."},{"text":"  "},{"text":"以下折线图中，最能准确反映2017～2021年间北京市集成电路产量同比增"},{"text":"\n"},{"text":"量变化趋势的是："},{"text":"\n"},{"text":""},{"text":"\n"},{"text":""},{"text":"\n"},{"text":""},{"text":"\n"},{"text":""},{"text":"\n"},{"text