INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (600175,5,'基期','关于2020年前三季度，以下说法正确的是：','[{"label":"A","content":"文化新业态特征较为明显的16个行业小类营业收入同比增速高于2021\n年同期"},{"label":"B","content":"内容创作生产营业收入超过15000亿元"},{"label":"C","content":"文化核心领域收入超过文化相关领域收入2倍"},{"label":"D","content":"东部地区与中部地区营业收入之比低于2021年同期"}]','D','前四题答案为AACB,可从 D 选项看起。
D 选项，定位材料第六段，分子(东部地区)增速22.58%,分母(中部地 区)增速19.7%,分子长得快，比值上升，即2020年小于2021年，表述正确， 当选；
其他选项：
A 选项，定位材料第二段，2021年同比增长26.1%,若2020年同比增速高
于26.1%,则两年平均增速必然超过26.1%;而实际两年平均增速为24%,说明
2020年增速必然小于26.1%(即2020年低于2021年同期),错误；
B选项，定位材料第三段，2021年内容创作17693亿元，同比增长18.6%, 假设分配可得A<15000②, 错误；
C选项，定位到材料第五段， 错误。
2021年，15个副省级城市规模以上文化及相关产业企业实现营业收入 38660亿元，占全国的比重比上年提高0.1个百分点(第二题数据),数字文化 新业态的16个行业实现营业收入39623亿元，比上年增长18.9% (第五题B选 项数据)。 两年年均增长20.5%,高于文化企业平均水平11.6个百分点；占文 化企业收入的比重为33.3%,比上年提高0.8个百分点，其中，可穿戴智能文化 设备制造，互联网广告服务2个细分行业营业收入两年平均增速分别为46.4% 和31.8% (第五题D选项数据)。
