INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (600190,5,'比重','以下各项能够从上述材料中推出的是： 简单修正，增速少估0.5%,
则实际增量=35.8+358×','[{"label":"A","content":"2023 年，全国茶叶总产值超过3400亿元 0.5%≈35.8+1.8=37.6。"},{"label":"B","content":"2023 年，全国红茶内销量占产量的比重高于黑茶"},{"label":"C","content":"2023 年，全国乌龙茶内销额同比增长了30亿元以上"},{"label":"D","content":"2023 年，全国黄茶平均每吨产值是黑茶的1.5倍以上"}]','D','D 选项，定位材料第一段和第二段，黄茶和黑茶产值分别为
30.5亿元、310.4亿元，二者产量分别为2.3万吨、45.8万吨；平均每吨产值




大于1.5倍，正确，当选；

⑦花生批注：
415 份数法计算过程如下：
R=11.6%≈1/9,
则份数比=9:1:10, 本期对应10份，
X=1份=358.6÷10 ≈35.8;
简单修正，增速少估0.5%, 则实际增量=35.8+358× 0.5%≈35.8+1.8=37.6。
