INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (600320,5,'增长率','根据给定材料，不能推出的是：','[{"label":"A","content":"从整体上看，2011年我国电子商务市场持续保持稳定的增长态势\n⑪⑰"},{"label":"B","content":"从行业上看，2011年我国中小企业 B2B交易规模最大但增速最小\n此选项单独计算与B选项\n同样复杂，一般来说两个"},{"label":"C","content":"从结构上看，2011年我国电子商务市场格局基本稳定，企业B2B仍占主\n不同数据很难出现完全相\n导地位 同的增量，可大胆排除。"},{"label":"D","content":"从趋势上看，若保持当前增速，不用两年⑧我国电子商务市场整体交易\n⑧"}]','A','由于前四题选项为 BADA,没有选C 的，本题优先看C 选项。

