INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (600395,5,'基期','根据材料，下列说法错误的是：','[{"label":"A","content":"2021 年我国天然气产量大于进口量"},{"label":"B","content":"2019 年我国天然气产量不足1500亿立方米"},{"label":"C","content":"2020 年我国天然气进口量超过了1亿吨"},{"label":"D","content":"2021 年9～12月，我国天然气日均产量逐月增加"}]','B','B选项，定位材料第一段，2021年全国共生产天然气2053亿
误，当选；
A 选项，定位材料第一段和第二段，2021年全国共生产天然气2053亿立方 米，2021年全国共进口天然气超1.2亿吨，二者单位不一致，需进行换算⑩,
2021年全国共生产天然气2053×7.174>2000×7=1.4亿吨>1.2亿吨，A选项 正确；
C 选项，定位材料第二段，2021年全国共进口天然气超1.2亿吨，同比增 长19.9%,可通过假设法①判断C 选项正确；
