INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (600495,5,'综合分析','能够从上述材料中推出的是：','[{"label":"A","content":"2013～2017 年，国内旅游市场游客人次和旅游收入双增长"},{"label":"B","content":"2017 年国内旅游市场的游客人次是2012年的两倍"},{"label":"C","content":"2018 年上半年，农村居民旅游平均花费超过800元/人次"},{"label":"D","content":"2018 年全年旅游收入将超过2017年"}]','A','B 选项，定位材料第二段，2023年第14周H市哨点医院共报 告流感样病例总数为5187例，上一题已求出2022年第14周H 市哨点医院共报 告流感样病例总数约为11800例，11800-5187≈6600例，即减少超过6000例， 正确，当选；
其他选项：
A选项，定位材料第三段，2023年第14周H 市哨点医院IL1%为5 . 98%,比 2022年同期低7.56个百分点，因2023年第14周H市哨点医院 IL1%比2022年 同期低，故并非逐年上升，错误；
