INSERT INTO questions (id,category_id,type,stem,options_json,answer,explanation,source,difficulty,status,details_json,image_key) VALUES (600585,5,'综合分析','根据上述材料，下列说法正确的是：','[{"label":"A","content":"该网站科技频道对31岁以上用户的吸引力远大于该频道对20岁及以下\n\n用户的吸引力"},{"label":"B","content":"20 岁及以下用户已经成为该网站继21～30岁用户之后的第二大用户群"},{"label":"C","content":"在该网站所有频道中，41～50岁用户数量均大于51岁及以上用户数量"},{"label":"D","content":"与其他频道相比，该网站的文化频道对21～30岁用户的吸引力最低"}]','B','前四题答案为DADC,可 以 从B 选项看起；
